	[Obsolete("Use GlobalDiagnosticsContext class instead. Marked obsolete on NLog 2.0")]
	public static class GDC
	{
		public static void Set(string item, string value)
		{
			GlobalDiagnosticsContext.Set(item, value);
		}

		public static string Get(string item)
		{
			return GlobalDiagnosticsContext.Get(item);
		}

		public static string Get(string item, IFormatProvider formatProvider)
		{
			return GlobalDiagnosticsContext.Get(item, formatProvider);
		}

		public static object GetObject(string item)
		{
			return GlobalDiagnosticsContext.GetObject(item);
		}

		public static bool Contains(string item)
		{
			return GlobalDiagnosticsContext.Contains(item);
		}

		public static void Remove(string item)
		{
			GlobalDiagnosticsContext.Remove(item);
		}

		public static void Clear()
		{
			GlobalDiagnosticsContext.Clear();
		}
	}
	public static class GlobalDiagnosticsContext
	{
		private static readonly object _lockObject = new object();

		private static Dictionary<string, object> _dict = new Dictionary<string, object>();

		private static Dictionary<string, object> _dictReadOnly;

		public static void Set(string item, string value)
		{
			Set(item, (object)value);
		}

		public static void Set(string item, object value)
		{
			lock (_lockObject)
			{
				GetWritableDict(_dictReadOnly != null && !_dict.ContainsKey(item))[item] = value;
			}
		}

		public static string Get(string item)
		{
			return Get(item, null);
		}

		public static string Get(string item, IFormatProvider formatProvider)
		{
			return FormatHelper.ConvertToString(GetObject(item), formatProvider);
		}

		public static object GetObject(string item)
		{
			GetReadOnlyDict().TryGetValue(item, out var value);
			return value;
		}

		public static ICollection<string> GetNames()
		{
			return GetReadOnlyDict().Keys;
		}

		public static bool Contains(string item)
		{
			return GetReadOnlyDict().ContainsKey(item);
		}

		public static void Remove(string item)
		{
			lock (_lockObject)
			{
				GetWritableDict(_dictReadOnly != null && _dict.ContainsKey(item)).Remove(item);
			}
		}

		public static void Clear()
		{
			lock (_lockObject)
			{
				GetWritableDict(_dictReadOnly != null && _dict.Count > 0, clearDictionary: true).Clear();
			}
		}

		private static Dictionary<string, object> GetReadOnlyDict()
		{
			Dictionary<string, object> dictionary = _dictReadOnly;
			if (dictionary == null)
			{
				lock (_lockObject)
				{
					dictionary = (_dictReadOnly = _dict);
				}
			}
			return dictionary;
		}

		private static Dictionary<string, object> GetWritableDict(bool requireCopyOnWrite, bool clearDictionary = false)
		{
			if (requireCopyOnWrite)
			{
				_dict = CopyDictionaryOnWrite(clearDictionary);
				_dictReadOnly = null;
			}
			return _dict;
		}

		private static Dictionary<string, object> CopyDictionaryOnWrite(bool clearDictionary)
		{
			Dictionary<string, object> dictionary = new Dictionary<string, object>((!clearDictionary) ? (_dict.Count + 1) : 0);
			if (!clearDictionary)
			{
				foreach (KeyValuePair<string, object> item in _dict)
				{
					dictionary[item.Key] = item.Value;
				}
			}
			return dictionary;
		}
	}
