		internal void AddCachedLayoutValue(Layout layout, object value)
		{
			if (_layoutCache == null)
			{
				Dictionary<Layout, object> dictionary = new Dictionary<Layout, object>();
				dictionary[layout] = value;
				if (Interlocked.CompareExchange(ref _layoutCache, dictionary, null) == null)
				{
					return;
				}
			}
			lock (_layoutCache)
			{
				_layoutCache[layout] = value;
			}
		}

		internal bool TryGetCachedLayoutValue(Layout layout, out object value)
		{
			if (_layoutCache == null)
			{
				value = null;
				return false;
			}
			lock (_layoutCache)
			{
				if (_layoutCache.Count == 0)
				{
					value = null;
					return false;
				}
				return _layoutCache.TryGetValue(layout, out value);
			}
		}

		private static bool NeedToPreformatMessage(object[] parameters)
		{
			if (parameters == null || parameters.Length == 0)
			{
				return false;
			}
			if (parameters.Length > 5)
			{
				return true;
			}
			for (int i = 0; i < parameters.Length; i++)
			{
				if (!IsSafeToDeferFormatting(parameters[i]))
				{
					return true;
				}
			}
			return false;
		}

		private static bool IsSafeToDeferFormatting(object value)
		{
			return Convert.GetTypeCode(value) != TypeCode.Object;
		}

		internal bool IsLogEventMutableSafe()
		{
			if (Exception != null || _formattedMessage != null)
			{
				return false;
			}
			PropertiesDictionary propertiesDictionary = CreateOrUpdatePropertiesInternal(forceCreate: false);
			if (propertiesDictionary == null || propertiesDictionary.Count == 0)
			{
				return true;
			}
			if (propertiesDictionary.Count > 5)
			{
				return false;
			}
			if (propertiesDictionary.Count == _parameters?.Length && propertiesDictionary.Count == propertiesDictionary.MessageProperties.Count)
			{
				return true;
			}
			return HasImmutableProperties(propertiesDictionary);
		}

		private static bool HasImmutableProperties(PropertiesDictionary properties)
		{
			if (properties.Count == properties.MessageProperties.Count)
			{
				for (int i = 0; i < properties.MessageProperties.Count; i++)
				{
					if (!IsSafeToDeferFormatting(properties.MessageProperties[i].Value))
					{
						return false;
					}
				}
			}
			else
			{
				foreach (KeyValuePair<object, object> property in properties)
				{
					if (!IsSafeToDeferFormatting(property.Value))
					{
						return false;
					}
				}
			}
			return true;
		}

		internal bool CanLogEventDeferMessageFormat()
		{
			if (_formattedMessage != null)
			{
				return false;
			}
			if (_parameters == null || _parameters.Length == 0)
			{
				return false;
			}
			string message = _message;
			if (message != null && message.Length < 256 && (object)MessageFormatter == LogMessageTemplateFormatter.DefaultAuto.MessageFormatter)
			{
				return true;
			}
			return false;
		}

		private static string GetStringFormatMessageFormatter(LogEventInfo logEvent)
		{
			if (logEvent.Parameters == null || logEvent.Parameters.Length == 0)
			{
				return logEvent.Message;
			}
			return string.Format(logEvent.FormatProvider ?? CultureInfo.CurrentCulture, logEvent.Message, logEvent.Parameters);
		}

		private void CalcFormattedMessage()
		{
			try
			{
				_formattedMessage = _messageFormatter(this);
			}
			catch (Exception ex)
			{
				_formattedMessage = Message;
				InternalLogger.Warn(ex, "Error when formatting a message.");
				if (ex.MustBeRethrown())
				{
					throw;
				}
			}
		}

		internal void AppendFormattedMessage(ILogMessageFormatter messageFormatter, StringBuilder builder)
		{
			if (_formattedMessage != null)
			{
				builder.Append(_formattedMessage);
				return;
			}
			int length = builder.Length;
			try
			{
				messageFormatter.AppendFormattedMessage(this, builder);
			}
			catch (Exception ex)
			{
				builder.Length = length;
				builder.Append(_message ?? string.Empty);
				InternalLogger.Warn(ex, "Error when formatting a message.");
				if (ex.MustBeRethrown())
				{
					throw;
				}
			}
		}

		private void ResetFormattedMessage(bool rebuildMessageTemplateParameters)
		{
			_formattedMessage = null;
			if (rebuildMessageTemplateParameters && HasMessageTemplateParameters)
			{
				CalcFormattedMessage();
			}
		}

		private bool ResetMessageTemplateParameters()
		{
			if (_properties != null)
			{
				if (HasMessageTemplateParameters)
				{
					_properties.MessageProperties = null;
				}
				return _properties.MessageProperties.Count == 0;
			}
			return false;
		}

		internal static void SetDefaultMessageFormatter(bool? mode)
		{
			if (mode == true)
			{
				InternalLogger.Info("Message Template Format always enabled");
				DefaultMessageFormatter = LogMessageTemplateFormatter.Default.MessageFormatter;
			}
			else if (mode == false)
			{
				InternalLogger.Info("Message Template String Format always enabled");
				DefaultMessageFormatter = StringFormatMessageFormatter;
			}
			else
			{
				InternalLogger.Info("Message Template Auto Format enabled");
				DefaultMessageFormatter = LogMessageTemplateFormatter.DefaultAuto.MessageFormatter;
			}
		}
	}
	public class LogFactory<T> : LogFactory where T : Logger
	{
		public new T GetLogger(string name)
		{
			return (T)GetLogger(name, typeof(T));
		}

		[MethodImpl(MethodImplOptions.NoInlining)]
		public new T GetCurrentClassLogger()
		{
			string classFullName = StackTraceUsageUtils.GetClassFullName(new StackFrame(1, fNeedFileInfo: false));
			return GetLogger(classFullName);
		}
	}
	public class LogFactory : IDisposable
	{
		private struct LoggerCacheKey(string name, Type concreteType) : IEquatable<LoggerCacheKey>
		{
			public readonly string Name = name;

			public readonly Type ConcreteType = concreteType;

			public override int GetHashCode()
			{
				return ConcreteType.GetHashCode() ^ Name.GetHashCode();
			}

			public override bool Equals(object obj)
			{
				if (obj is LoggerCacheKey other)
				{
					return Equals(other);
				}
				return false;
			}

			public bool Equals(LoggerCacheKey other)
			{
				if (ConcreteType == other.ConcreteType)
				{
					return string.Equals(other.Name, Name, StringComparison.Ordinal);
				}
				return false;
			}
		}

		private class LoggerCache
		{
			private readonly Dictionary<LoggerCacheKey, WeakReference> _loggerCache = new Dictionary<LoggerCacheKey, WeakReference>();

			public void InsertOrUpdate(LoggerCacheKey cacheKey, Logger logger)
			{
				_loggerCache[cacheKey] = new WeakReference(logger);
			}

			public Logger Retrieve(LoggerCacheKey cacheKey)
			{
				if (_loggerCache.TryGetValue(cacheKey, out var value))
				{
					return value.Target as Logger;
				}
				return null;
			}

			public List<Logger> GetLoggers()
			{
				List<Logger> list = new List<Logger>(_loggerCache.Count);
				foreach (WeakReference value in _loggerCache.Values)
				{
					if (value.Target is Logger item)
					{
						list.Add(item);
					}
				}
				return list;
			}

			public void Reset()
			{
				_loggerCache.Clear();
			}
		}

		private class LogEnabler : IDisposable
		{
			private readonly LogFactory _factory;

			public LogEnabler(LogFactory factory)
			{
				_factory = factory;
			}

			void IDisposable.Dispose()
			{
				_factory.ResumeLogging();
			}
		}

		private static readonly TimeSpan DefaultFlushTimeout = TimeSpan.FromSeconds(15.0);

		private static IAppDomain currentAppDomain;

		private static AppEnvironmentWrapper defaultAppEnvironment;

		internal readonly object _syncRoot = new object();

		internal LoggingConfiguration _config;

		private IAppEnvironment _currentAppEnvironment;

		private LogLevel _globalThreshold = LogLevel.MinLevel;

		private bool _configLoaded;

		private int _logsEnabled;

		private readonly LoggerCache _loggerCache = new LoggerCache();

		private List<string> _candidateConfigFilePaths;

		private readonly ILoggingConfigurationLoader _configLoader;

		private bool _autoShutdown = true;

		private bool _isDisposing;

		public static IAppDomain CurrentAppDomain
		{
			get
			{
				return currentAppDomain ?? DefaultAppEnvironment.AppDomain;
			}
			set
			{
				UnregisterEvents(currentAppDomain);
				UnregisterEvents(value);
				RegisterEvents(value);
				currentAppDomain = value;
				if (value != null && defaultAppEnvironment != null)
				{
					defaultAppEnvironment.AppDomain = value;
				}
			}
		}

		internal static IAppEnvironment DefaultAppEnvironment => defaultAppEnvironment ?? (defaultAppEnvironment = new AppEnvironmentWrapper(currentAppDomain ?? (currentAppDomain = new AppDomainWrapper(AppDomain.CurrentDomain))));

		internal IAppEnvironment CurrentAppEnvironment
		{
			get
			{
				return _currentAppEnvironment ?? DefaultAppEnvironment;
			}
			set
			{
				_currentAppEnvironment = value;
			}
		}

		public bool ThrowExceptions { get; set; }

		public bool? ThrowConfigExceptions { get; set; }

		public bool KeepVariablesOnReload { get; set; }

		public bool AutoShutdown
		{
			get
			{
				return _autoShutdown;
			}
			set
			{
				if (value != _autoShutdown)
				{
					_autoShutdown = value;
				}
			}
		}

		public LoggingConfiguration Configuration
		{
			get
			{
				if (_configLoaded)
				{
					return _config;
				}
				lock (_syncRoot)
				{
					if (_configLoaded || _isDisposing)
					{
						return _config;
					}
					LoggingConfiguration loggingConfiguration = _configLoader.Load(this);
					if (loggingConfiguration != null)
					{
						try
						{
							_config = loggingConfiguration;
							_configLoader.Activated(this, _config);
							_config.Dump();
							ReconfigExistingLoggers();
							LogConfigurationInitialized();
						}
						finally
						{
							_configLoaded = true;
						}
					}
					return _config;
				}
			}
			set
			{
				lock (_syncRoot)
				{
					LoggingConfiguration config = _config;
					if (config != null)
					{
						InternalLogger.Info("Closing old configuration.");
						Flush();
						config.Close();
					}
					_config = value;
					if (_config == null)
					{
						_configLoaded = false;
						_configLoader.Activated(this, _config);
					}
					else
					{
						try
						{
							_configLoader.Activated(this, _config);
							_config.Dump();
							ReconfigExistingLoggers();
						}
						finally
						{
							_configLoaded = true;
						}
					}
					OnConfigurationChanged(new LoggingConfigurationChangedEventArgs(value, config));
				}
			}
		}

