		public void Flush(AsyncContinuation asyncContinuation, TimeSpan timeout)
		{
			FlushInternal(timeout, asyncContinuation ?? ((AsyncContinuation)delegate
			{
			}));
		}

		private void FlushInternal(TimeSpan timeout, AsyncContinuation asyncContinuation)
		{
			try
			{
				InternalLogger.Debug("LogFactory Flush with timeout={0} secs", timeout.TotalSeconds);
				LoggingConfiguration config;
				lock (_syncRoot)
				{
					config = _config;
				}
				if (config != null)
				{
					if (asyncContinuation != null)
					{
						FlushAllTargetsAsync(config, asyncContinuation, timeout);
					}
					else if (!FlushAllTargetsSync(config, timeout, ThrowExceptions))
					{
					}
				}
				else
				{
					asyncContinuation?.Invoke(null);
				}
			}
			catch (Exception ex)
			{
				if (ThrowExceptions)
				{
					throw;
				}
				InternalLogger.Error(ex, "Error with flush.");
				asyncContinuation?.Invoke(ex);
			}
		}

		private static AsyncContinuation FlushAllTargetsAsync(LoggingConfiguration loggingConfiguration, AsyncContinuation asyncContinuation, TimeSpan? asyncTimeout)
		{
			List<Target> allTargetsToFlush = loggingConfiguration.GetAllTargetsToFlush();
			HashSet<Target> pendingTargets = new HashSet<Target>(allTargetsToFlush, SingleItemOptimizedHashSet<Target>.ReferenceEqualityComparer.Default);
			AsynchronousAction<Target> action = delegate(Target target, AsyncContinuation cont)
			{
				target.Flush(delegate(Exception ex)
				{
					if (ex != null)
					{
						InternalLogger.Warn(ex, "Flush failed for target {0}(Name={1})", target.GetType(), target.Name);
					}
					lock (pendingTargets)
					{
						pendingTargets.Remove(target);
					}
					cont(ex);
				});
			};
			AsyncContinuation asyncContinuation2 = delegate(Exception ex)
			{
				lock (pendingTargets)
				{
					foreach (Target item in pendingTargets)
					{
						InternalLogger.Debug("Flush timeout for target {0}(Name={1})", item.GetType(), item.Name);
					}
					pendingTargets.Clear();
				}
				if (ex != null)
				{
					InternalLogger.Warn(ex, "Flush completed with errors");
				}
				else
				{
					InternalLogger.Debug("Flush completed");
				}
				asyncContinuation(ex);
			};
			asyncContinuation2 = ((!asyncTimeout.HasValue) ? AsyncHelpers.PreventMultipleCalls(asyncContinuation2) : AsyncHelpers.WithTimeout(asyncContinuation2, asyncTimeout.Value));
			InternalLogger.Trace("Flushing all {0} targets...", allTargetsToFlush.Count);
			AsyncHelpers.ForEachItemInParallel(allTargetsToFlush, asyncContinuation2, action);
			return asyncContinuation2;
		}

		private static bool FlushAllTargetsSync(LoggingConfiguration oldConfig, TimeSpan timeout, bool throwExceptions)
		{
			Exception lastException = null;
			try
			{
				ManualResetEvent flushCompletedEvent = new ManualResetEvent(initialState: false);
				AsyncContinuation asyncContinuation = FlushAllTargetsAsync(oldConfig, delegate(Exception ex2)
				{
					if (ex2 != null)
					{
						lastException = ex2;
					}
					flushCompletedEvent.Set();
				}, null);
				if (!flushCompletedEvent.WaitOne(timeout))
				{
					asyncContinuation(new TimeoutException($"Timeout when flushing all targets, after waiting {timeout.TotalSeconds} seconds."));
				}
			}
			catch (Exception ex)
			{
				if (ex.MustBeRethrownImmediately())
				{
					throw;
				}
				if (throwExceptions)
				{
					throw new NLogRuntimeException("Asynchronous exception has occurred.", ex);
				}
				InternalLogger.Error(ex, "Error with flush.");
				return false;
			}
			if (lastException != null)
			{
				if (throwExceptions)
				{
					throw new NLogRuntimeException("Asynchronous exception has occurred.", lastException);
				}
				return false;
			}
			return true;
		}

