		public IDisposable SuspendLogging()
		{
			lock (_syncRoot)
			{
				_logsEnabled--;
				if (_logsEnabled == -1)
				{
					ReconfigExistingLoggers();
				}
			}
			return new LogEnabler(this);
		}

		public void ResumeLogging()
		{
			lock (_syncRoot)
			{
				_logsEnabled++;
				if (_logsEnabled == 0)
				{
					ReconfigExistingLoggers();
				}
			}
		}

		public bool IsLoggingEnabled()
		{
			return _logsEnabled >= 0;
		}

		protected virtual void OnConfigurationChanged(LoggingConfigurationChangedEventArgs e)
		{
			this.ConfigurationChanged?.Invoke(this, e);
		}

		private bool GetTargetsByLevelForLogger(string name, List<LoggingRule> loggingRules, TargetWithFilterChain[] targetsByLevel, TargetWithFilterChain[] lastTargetsByLevel, bool[] suppressedLevels)
		{
			bool flag = false;
			foreach (LoggingRule loggingRule in loggingRules)
			{
				if (!loggingRule.NameMatches(name))
				{
					continue;
				}
				for (int i = 0; i <= LogLevel.MaxLevel.Ordinal; i++)
				{
					if (i < GlobalThreshold.Ordinal || suppressedLevels[i] || !loggingRule.IsLoggingEnabledForLevel(LogLevel.FromOrdinal(i)))
					{
						continue;
					}
					if (loggingRule.Final)
					{
						suppressedLevels[i] = true;
					}
					foreach (Target item in loggingRule.GetTargetsThreadSafe())
					{
						flag = true;
						TargetWithFilterChain targetWithFilterChain = new TargetWithFilterChain(item, loggingRule.Filters, loggingRule.DefaultFilterResult);
						if (lastTargetsByLevel[i] != null)
						{
							lastTargetsByLevel[i].NextInChain = targetWithFilterChain;
						}
						else
						{
							targetsByLevel[i] = targetWithFilterChain;
						}
						lastTargetsByLevel[i] = targetWithFilterChain;
					}
				}
				if (loggingRule.ChildRules.Count != 0)
				{
					flag = GetTargetsByLevelForLogger(name, loggingRule.GetChildRulesThreadSafe(), targetsByLevel, lastTargetsByLevel, suppressedLevels) || flag;
				}
			}
			for (int j = 0; j <= LogLevel.MaxLevel.Ordinal; j++)
			{
				targetsByLevel[j]?.PrecalculateStackTraceUsage();
			}
			return flag;
		}

		internal LoggerConfiguration GetConfigurationForLogger(string name, LoggingConfiguration configuration)
		{
			TargetWithFilterChain[] array = new TargetWithFilterChain[LogLevel.MaxLevel.Ordinal + 1];
			TargetWithFilterChain[] lastTargetsByLevel = new TargetWithFilterChain[LogLevel.MaxLevel.Ordinal + 1];
			bool[] suppressedLevels = new bool[LogLevel.MaxLevel.Ordinal + 1];
			bool flag = false;
			if (configuration != null && IsLoggingEnabled())
			{
				List<LoggingRule> loggingRulesThreadSafe = configuration.GetLoggingRulesThreadSafe();
				flag = GetTargetsByLevelForLogger(name, loggingRulesThreadSafe, array, lastTargetsByLevel, suppressedLevels);
			}
			if (InternalLogger.IsDebugEnabled)
			{
				if (flag)
				{
					InternalLogger.Debug("Targets for {0} by level:", name);
					for (int i = 0; i <= LogLevel.MaxLevel.Ordinal; i++)
					{
						StringBuilder stringBuilder = new StringBuilder();
						stringBuilder.AppendFormat(CultureInfo.InvariantCulture, "{0} =>", LogLevel.FromOrdinal(i));
						for (TargetWithFilterChain targetWithFilterChain = array[i]; targetWithFilterChain != null; targetWithFilterChain = targetWithFilterChain.NextInChain)
						{
							stringBuilder.AppendFormat(CultureInfo.InvariantCulture, " {0}", targetWithFilterChain.Target.Name);
							if (targetWithFilterChain.FilterChain.Count > 0)
							{
								stringBuilder.AppendFormat(CultureInfo.InvariantCulture, " ({0} filters)", targetWithFilterChain.FilterChain.Count);
							}
						}
						InternalLogger.Debug(stringBuilder.ToString());
					}
				}
				else
				{
					InternalLogger.Debug("Targets not configured for logger: {0}", name);
				}
			}
			bool exceptionLoggingOldStyle = configuration?.ExceptionLoggingOldStyle ?? false;
			return new LoggerConfiguration(array, exceptionLoggingOldStyle);
		}

		private void Close(TimeSpan flushTimeout)
		{
			if (_isDisposing)
			{
				return;
			}
			_isDisposing = true;
			if (Monitor.TryEnter(_syncRoot, 500))
			{
				try
				{
					_configLoader.Dispose();
					LoggingConfiguration config = _config;
					if (_configLoaded && config != null)
					{
						CloseOldConfig(flushTimeout, config);
					}
				}
				finally
				{
					Monitor.Exit(_syncRoot);
				}
			}
			this.ConfigurationChanged = null;
		}

		private void CloseOldConfig(TimeSpan flushTimeout, LoggingConfiguration oldConfig)
		{
			try
			{
				_config = null;
				ReconfigExistingLoggers();
				if (1 == 0)
				{
					InternalLogger.Warn("Target flush timeout. One or more targets did not complete flush operation, skipping target close.");
					return;
				}
				oldConfig.Close();
				OnConfigurationChanged(new LoggingConfigurationChangedEventArgs(null, oldConfig));
			}
			catch (Exception ex)
			{
				InternalLogger.Error(ex, "Error with close.");
			}
		}

		protected virtual void Dispose(bool disposing)
		{
			if (disposing)
			{
				Close(TimeSpan.Zero);
			}
		}

		internal void Shutdown()
		{
			InternalLogger.Info("Shutdown() called. Logger closing...");
			if (!_isDisposing && _configLoaded)
			{
				lock (_syncRoot)
				{
					if (_isDisposing || !_configLoaded)
					{
						return;
					}
					Configuration = null;
					_configLoaded = true;
					ReconfigExistingLoggers();
				}
			}
			InternalLogger.Info("Logger has been closed down.");
		}

		public IEnumerable<string> GetCandidateConfigFilePaths()
		{
			if (_candidateConfigFilePaths != null)
			{
				return _candidateConfigFilePaths.AsReadOnly();
