		public void ResetCandidateConfigFilePath()
		{
			_candidateConfigFilePaths = null;
		}

		private Logger GetLoggerThreadSafe(string name, Type loggerType)
		{
			if (name == null)
			{
				throw new ArgumentNullException("name", "Name of logger cannot be null");
			}
			LoggerCacheKey cacheKey = new LoggerCacheKey(name, loggerType ?? typeof(Logger));
			lock (_syncRoot)
			{
				Logger logger = _loggerCache.Retrieve(cacheKey);
				if (logger != null)
				{
					return logger;
				}
				Logger logger2 = CreateNewLogger(cacheKey.ConcreteType);
				if (logger2 == null)
				{
					cacheKey = new LoggerCacheKey(cacheKey.Name, typeof(Logger));
					logger2 = new Logger();
				}
				logger2.Initialize(name, GetConfigurationForLogger(name, Configuration), this);
				_loggerCache.InsertOrUpdate(cacheKey, logger2);
				return logger2;
			}
		}

		internal Logger CreateNewLogger(Type loggerType)
		{
			if (loggerType != null && loggerType != typeof(Logger))
			{
				try
				{
					return CreateCustomLoggerType(loggerType);
				}
				catch (Exception ex)
				{
					InternalLogger.Error(ex, "GetLogger / GetCurrentClassLogger. Cannot create instance of type '{0}'. It should have an default contructor.", loggerType);
					if (ex.MustBeRethrown())
					{
						throw;
					}
					return null;
				}
			}
			return new Logger();
		}

		private Logger CreateCustomLoggerType(Type customLoggerType)
		{
			if (customLoggerType.IsStaticClass())
			{
				string message = $"GetLogger / GetCurrentClassLogger is '{customLoggerType}' as loggerType is static class and should instead inherit from Logger";
				InternalLogger.Error(message);
				if (ThrowExceptions)
				{
					throw new NLogRuntimeException(message);
				}
				return null;
			}
			if (!(FactoryHelper.CreateInstance(customLoggerType) is Logger result))
			{
				string message2 = $"GetLogger / GetCurrentClassLogger got '{customLoggerType}' as loggerType doesn't inherit from Logger";
				InternalLogger.Error(message2);
				if (ThrowExceptions)
				{
					throw new NLogRuntimeException(message2);
				}
				return null;
			}
			return result;
		}

		public LogFactory LoadConfiguration(string configFile)
		{
			return LoadConfiguration(configFile, optional: false);
		}

		internal LogFactory LoadConfiguration(string configFile, bool optional)
		{
			string text = (string.IsNullOrEmpty(configFile) ? "NLog.config" : configFile);
			if (optional && string.Equals(text.Trim(), "NLog.config", StringComparison.OrdinalIgnoreCase) && _config != null)
			{
				return this;
			}
			LoggingConfiguration loggingConfiguration = _configLoader.Load(this, configFile);
			if (loggingConfiguration == null)
			{
				if (!optional)
				{
					throw new FileNotFoundException(CreateFileNotFoundMessage(configFile), text);
				}
				return this;
			}
			Configuration = loggingConfiguration;
			return this;
		}

		private string CreateFileNotFoundMessage(string configFile)
		{
			StringBuilder stringBuilder = new StringBuilder("Failed to load NLog LoggingConfiguration.");
			try
			{
				HashSet<string> hashSet = new HashSet<string>(_configLoader.GetDefaultCandidateConfigFilePaths(configFile));
				stringBuilder.AppendLine(" Searched the following locations:");
				foreach (string item in hashSet)
				{
					stringBuilder.Append("- ");
					stringBuilder.AppendLine(item);
				}
			}
			catch (Exception arg)
			{
				InternalLogger.Debug("Failed to GetDefaultCandidateConfigFilePaths in CreateFileNotFoundMessage: {0}", arg);
			}
			return stringBuilder.ToString();
		}

		internal void ResetLoggerCache()
		{
			_loggerCache.Reset();
		}

		private static void RegisterEvents(IAppDomain appDomain)
		{
			if (appDomain == null)
			{
				return;
			}
			try
			{
				appDomain.ProcessExit += OnLoggerShutdown;
				appDomain.DomainUnload += OnLoggerShutdown;
			}
			catch (Exception ex)
			{
				InternalLogger.Warn(ex, "Error setting up termination events.");
				if (ex.MustBeRethrown())
				{
					throw;
				}
			}
		}

		private static void UnregisterEvents(IAppDomain appDomain)
		{
			if (appDomain != null)
			{
				appDomain.DomainUnload -= OnLoggerShutdown;
				appDomain.ProcessExit -= OnLoggerShutdown;
			}
		}

		private static void OnLoggerShutdown(object sender, EventArgs args)
		{
			try
			{
				LogFactory.LoggerShutdown?.Invoke(sender, args);
			}
			catch (Exception ex)
			{
				if (ex.MustBeRethrownImmediately())
				{
					throw;
				}
				InternalLogger.Error(ex, "LogFactory failed to shut down properly.");
			}
			finally
			{
				LogFactory.LoggerShutdown = null;
				if (currentAppDomain != null)
				{
					CurrentAppDomain = null;
				}
			}
		}

		private void OnStopLogging(object sender, EventArgs args)
		{
			try
			{
				InternalLogger.Info("AppDomain Shutting down. Logger closing...");
				Close(TimeSpan.FromMilliseconds(1500.0));
				InternalLogger.Info("Logger has been shut down.");
			}
			catch (Exception ex)
			{
				if (ex.MustBeRethrownImmediately())
				{
					throw;
				}
				InternalLogger.Error(ex, "Logger failed to shut down properly.");
			}
		}
	}
