		protected internal Logger()
		{
			_contextLogger = this;
		}

		public bool IsEnabled(LogLevel level)
		{
			if (level == null)
			{
				throw new InvalidOperationException("Log level must be defined");
			}
			return GetTargetsForLevel(level) != null;
		}

		public Logger WithProperty(string propertyKey, object propertyValue)
		{
			if (string.IsNullOrEmpty(propertyKey))
			{
				throw new ArgumentException("propertyKey");
			}
			Logger obj = Factory.CreateNewLogger(GetType()) ?? new Logger();
			obj.Initialize(Name, _configuration, Factory);
			obj._contextProperties = CreateContextPropertiesDictionary(_contextProperties);
			obj._contextProperties[propertyKey] = propertyValue;
			obj._contextLogger = _contextLogger;
			return obj;
		}

		public void SetProperty(string propertyKey, object propertyValue)
		{
			if (string.IsNullOrEmpty(propertyKey))
			{
				throw new ArgumentException("propertyKey");
			}
			Properties[propertyKey] = propertyValue;
		}

		private static ThreadSafeDictionary<string, object> CreateContextPropertiesDictionary(ThreadSafeDictionary<string, object> contextProperties)
		{
			contextProperties = ((contextProperties != null) ? new ThreadSafeDictionary<string, object>(contextProperties) : new ThreadSafeDictionary<string, object>());
			return contextProperties;
		}

		public void Log(LogEventInfo logEvent)
		{
			TargetWithFilterChain targetWithFilterChain = (IsEnabled(logEvent.Level) ? GetTargetsForLevel(logEvent.Level) : null);
			if (targetWithFilterChain != null)
			{
				if (logEvent.LoggerName == null)
				{
					logEvent.LoggerName = Name;
				}
				WriteToTargets(logEvent, targetWithFilterChain);
			}
		}

		public void Log(Type wrapperType, LogEventInfo logEvent)
		{
			TargetWithFilterChain targetWithFilterChain = (IsEnabled(logEvent.Level) ? GetTargetsForLevel(logEvent.Level) : null);
			if (targetWithFilterChain != null)
			{
				if (logEvent.LoggerName == null)
				{
					logEvent.LoggerName = Name;
				}
				WriteToTargets(wrapperType, logEvent, targetWithFilterChain);
			}
		}

		public void Log<T>(LogLevel level, T value)
		{
			if (IsEnabled(level))
			{
				WriteToTargets(level, null, value);
			}
		}

		public void Log<T>(LogLevel level, IFormatProvider formatProvider, T value)
		{
			if (IsEnabled(level))
			{
				WriteToTargets(level, formatProvider, value);
			}
		}

		public void Log(LogLevel level, LogMessageGenerator messageFunc)
		{
			if (IsEnabled(level))
			{
				if (messageFunc == null)
				{
					throw new ArgumentNullException("messageFunc");
				}
				WriteToTargets(level, null, messageFunc());
			}
		}

