		private LogEventInfo PrepareLogEventInfo(LogEventInfo logEvent)
		{
			if (logEvent.FormatProvider == null)
			{
				logEvent.FormatProvider = Factory.DefaultCultureInfo;
			}
			if (_contextProperties != null)
			{
				foreach (KeyValuePair<string, object> contextProperty in _contextProperties)
				{
					if (!logEvent.Properties.ContainsKey(contextProperty.Key))
					{
						logEvent.Properties[contextProperty.Key] = contextProperty.Value;
					}
				}
			}
			return logEvent;
		}

		public void Swallow(Action action)
		{
			try
			{
				action();
			}
			catch (Exception value)
			{
				Error(value);
			}
		}

		public T Swallow<T>(Func<T> func)
		{
			return Swallow(func, default(T));
		}

		public T Swallow<T>(Func<T> func, T fallback)
		{
			try
			{
				return func();
			}
			catch (Exception value)
			{
				Error(value);
				return fallback;
			}
		}

		internal void Initialize(string name, LoggerConfiguration loggerConfiguration, LogFactory factory)
		{
			Name = name;
			Factory = factory;
			SetConfiguration(loggerConfiguration);
		}

		private void WriteToTargets(LogLevel level, [Localizable(false)] string message, object[] args)
		{
			WriteToTargets(level, Factory.DefaultCultureInfo, message, args);
		}

		private void WriteToTargets(LogLevel level, IFormatProvider formatProvider, [Localizable(false)] string message, object[] args)
		{
			TargetWithFilterChain targetsForLevel = GetTargetsForLevel(level);
			if (targetsForLevel != null)
			{
				LogEventInfo logEvent = LogEventInfo.Create(level, Name, formatProvider, message, args);
				WriteToTargets(logEvent, targetsForLevel);
			}
		}

		private void WriteToTargets(LogLevel level, IFormatProvider formatProvider, [Localizable(false)] string message)
		{
			TargetWithFilterChain targetsForLevel = GetTargetsForLevel(level);
			if (targetsForLevel != null)
			{
				LogEventInfo logEvent = LogEventInfo.Create(level, Name, formatProvider, message, null);
				WriteToTargets(logEvent, targetsForLevel);
			}
		}

		private void WriteToTargets<T>(LogLevel level, IFormatProvider formatProvider, T value)
		{
			TargetWithFilterChain targetsForLevel = GetTargetsForLevel(level);
			if (targetsForLevel != null)
			{
				LogEventInfo logEvent = LogEventInfo.Create(level, Name, formatProvider, value);
				WriteToTargets(logEvent, targetsForLevel);
			}
		}

		private void WriteToTargets(LogLevel level, Exception ex, [Localizable(false)] string message, object[] args)
		{
			TargetWithFilterChain targetsForLevel = GetTargetsForLevel(level);
			if (targetsForLevel != null)
			{
				LogEventInfo logEvent = LogEventInfo.Create(level, Name, ex, Factory.DefaultCultureInfo, message, args);
				WriteToTargets(logEvent, targetsForLevel);
			}
		}

		private void WriteToTargets(LogLevel level, Exception ex, IFormatProvider formatProvider, [Localizable(false)] string message, object[] args)
		{
			TargetWithFilterChain targetsForLevel = GetTargetsForLevel(level);
			if (targetsForLevel != null)
			{
				LogEventInfo logEvent = LogEventInfo.Create(level, Name, ex, formatProvider, message, args);
				WriteToTargets(logEvent, targetsForLevel);
			}
		}

		private void WriteToTargets([NotNull] LogEventInfo logEvent, [NotNull] TargetWithFilterChain targetsForLevel)
		{
			LoggerImpl.Write(DefaultLoggerType, targetsForLevel, PrepareLogEventInfo(logEvent), Factory);
		}

		private void WriteToTargets(Type wrapperType, [NotNull] LogEventInfo logEvent, [NotNull] TargetWithFilterChain targetsForLevel)
		{
			LoggerImpl.Write(wrapperType ?? DefaultLoggerType, targetsForLevel, PrepareLogEventInfo(logEvent), Factory);
		}

		internal void SetConfiguration(LoggerConfiguration newConfiguration)
		{
			_configuration = newConfiguration;
			_isTraceEnabled = IsEnabled(LogLevel.Trace);
			_isDebugEnabled = IsEnabled(LogLevel.Debug);
			_isInfoEnabled = IsEnabled(LogLevel.Info);
			_isWarnEnabled = IsEnabled(LogLevel.Warn);
			_isErrorEnabled = IsEnabled(LogLevel.Error);
			_isFatalEnabled = IsEnabled(LogLevel.Fatal);
			OnLoggerReconfigured(EventArgs.Empty);
		}

		private TargetWithFilterChain GetTargetsForLevel(LogLevel level)
		{
			if (_contextLogger == this)
			{
				return _configuration.GetTargetsForLevel(level);
			}
			return _contextLogger.GetTargetsForLevel(level);
		}

		protected virtual void OnLoggerReconfigured(EventArgs e)
		{
			this.LoggerReconfigured?.Invoke(this, e);
		}
	}
	internal static class LoggerImpl
	{
		private const int StackTraceSkipMethods = 0;

		internal static void Write([NotNull] Type loggerType, [NotNull] TargetWithFilterChain targetsForLevel, LogEventInfo logEvent, LogFactory factory)
		{
			StackTraceUsage stackTraceUsage = targetsForLevel.GetStackTraceUsage();
			if (stackTraceUsage != StackTraceUsage.None && !logEvent.HasStackTrace)
			{
				CaptureCallSiteInfo(factory, loggerType, logEvent, stackTraceUsage);
			}
			AsyncContinuation onException = delegate
			{
			};
			if (factory.ThrowExceptions)
			{
				int originalThreadId = AsyncHelpers.GetManagedThreadId();
				onException = delegate(Exception ex)
				{
					if (ex != null && AsyncHelpers.GetManagedThreadId() == originalThreadId)
					{
						throw new NLogRuntimeException("Exception occurred in NLog", ex);
					}
				};
			}
			if (targetsForLevel.NextInChain == null && logEvent.CanLogEventDeferMessageFormat())
			{
				logEvent.MessageFormatter = LogMessageTemplateFormatter.DefaultAutoSingleTarget.MessageFormatter;
			}
			IList<Filter> list = null;
			FilterResult filterResult = FilterResult.Neutral;
			TargetWithFilterChain targetWithFilterChain = targetsForLevel;
			while (targetWithFilterChain != null)
			{
				FilterResult filterResult2 = ((list == targetWithFilterChain.FilterChain) ? filterResult : GetFilterResult(targetWithFilterChain.FilterChain, logEvent, targetWithFilterChain.DefaultResult));
				if (WriteToTargetWithFilterChain(targetWithFilterChain.Target, filterResult2, logEvent, onException))
				{
					filterResult = filterResult2;
					list = targetWithFilterChain.FilterChain;
					targetWithFilterChain = targetWithFilterChain.NextInChain;
					continue;
				}
				break;
			}
		}

		private static void CaptureCallSiteInfo(LogFactory factory, Type loggerType, LogEventInfo logEvent, StackTraceUsage stackTraceUsage)
		{
			try
			{
				StackTrace stackTrace = new StackTrace(0, stackTraceUsage == StackTraceUsage.WithSource);
				logEvent.GetCallSiteInformationInternal().SetStackTrace(stackTrace, null, loggerType);
			}
			catch (Exception ex)
			{
				if (factory.ThrowExceptions || ex.MustBeRethrownImmediately())
				{
					throw;
				}
				InternalLogger.Error(ex, "Failed to capture CallSite for Logger {0}. Platform might not support ${{callsite}}", logEvent.LoggerName);
			}
		}

		private static bool WriteToTargetWithFilterChain(Target target, FilterResult result, LogEventInfo logEvent, AsyncContinuation onException)
		{
			if (result == FilterResult.Ignore || result == FilterResult.IgnoreFinal)
			{
				if (InternalLogger.IsDebugEnabled)
				{
					InternalLogger.Debug("{0}.{1} Rejecting message because of a filter.", logEvent.LoggerName, logEvent.Level);
				}
				if (result == FilterResult.IgnoreFinal)
				{
					return false;
				}
				return true;
			}
			target.WriteAsyncLogEvent(logEvent.WithContinuation(onException));
			if (result == FilterResult.LogFinal)
			{
				return false;
			}
			return true;
		}

		private static FilterResult GetFilterResult(IList<Filter> filterChain, LogEventInfo logEvent, FilterResult defaultFilterResult)
		{
			FilterResult result = defaultFilterResult;
			if (filterChain == null || filterChain.Count == 0)
			{
				return result;
			}
			try
			{
				for (int i = 0; i < filterChain.Count; i++)
				{
					result = filterChain[i].GetFilterResult(logEvent);
					if (result != FilterResult.Neutral)
					{
						return result;
					}
				}
				return defaultFilterResult;
			}
			catch (Exception ex)
			{
				InternalLogger.Warn(ex, "Exception during filter evaluation. Message will be ignore.");
				if (ex.MustBeRethrown())
				{
					throw;
				}
				return FilterResult.Ignore;
			}
		}
	}
	[TypeConverter(typeof(LogLevelTypeConverter))]
	public sealed class LogLevel : IComparable, IEquatable<LogLevel>, IConvertible
	{
		public static readonly LogLevel Trace = new LogLevel("Trace", 0);

		public static readonly LogLevel Debug = new LogLevel("Debug", 1);

		public static readonly LogLevel Info = new LogLevel("Info", 2);

		public static readonly LogLevel Warn = new LogLevel("Warn", 3);

		public static readonly LogLevel Error = new LogLevel("Error", 4);

		public static readonly LogLevel Fatal = new LogLevel("Fatal", 5);

		public static readonly LogLevel Off = new LogLevel("Off", 6);

		private static readonly IList<LogLevel> allLevels = new List<LogLevel> { Trace, Debug, Info, Warn, Error, Fatal, Off }.AsReadOnly();

		private static readonly IList<LogLevel> allLoggingLevels = new List<LogLevel> { Trace, Debug, Info, Warn, Error, Fatal }.AsReadOnly();

		private readonly int _ordinal;

		private readonly string _name;

		public static IEnumerable<LogLevel> AllLevels => allLevels;

		public static IEnumerable<LogLevel> AllLoggingLevels => allLoggingLevels;

		public string Name => _name;

		internal static LogLevel MaxLevel => Fatal;

		internal static LogLevel MinLevel => Trace;

		public int Ordinal => _ordinal;

		private LogLevel(string name, int ordinal)
		{
			_name = name;
			_ordinal = ordinal;
		}

		public static bool operator ==(LogLevel level1, LogLevel level2)
		{
			if ((object)level1 == null)
			{
				return (object)level2 == null;
			}
			if ((object)level2 == null)
			{
				return false;
			}
			return level1.Ordinal == level2.Ordinal;
		}

		public static bool operator !=(LogLevel level1, LogLevel level2)
		{
			if ((object)level1 == null)
			{
				return (object)level2 != null;
			}
			if ((object)level2 == null)
			{
				return true;
			}
			return level1.Ordinal != level2.Ordinal;
		}

		public static bool operator >(LogLevel level1, LogLevel level2)
		{
			if (level1 == null)
			{
				throw new ArgumentNullException("level1");
