			if (level2 == null)
			{
				throw new ArgumentNullException("level2");
			}
			return level1.Ordinal > level2.Ordinal;
		}

		public static bool operator >=(LogLevel level1, LogLevel level2)
		{
			if (level1 == null)
			{
				throw new ArgumentNullException("level1");
			}
			if (level2 == null)
			{
				throw new ArgumentNullException("level2");
