	public static class MappedDiagnosticsContext
	{
		private sealed class ItemRemover : IDisposable
		{
			private readonly string _item;

			private bool _disposed;

			public ItemRemover(string item)
			{
				_item = item;
			}

			public void Dispose()
			{
				if (!_disposed)
				{
					_disposed = true;
					Remove(_item);
				}
			}
		}

		private static readonly object DataSlot = ThreadLocalStorageHelper.AllocateDataSlot();

		private static readonly IDictionary<string, object> EmptyDefaultDictionary = default(SortHelpers.ReadOnlySingleBucketDictionary<string, object>);

		private static IDictionary<string, object> GetThreadDictionary(bool create = true)
		{
			Dictionary<string, object> dataForSlot = ThreadLocalStorageHelper.GetDataForSlot<Dictionary<string, object>>(DataSlot, create);
			if (dataForSlot == null && !create)
			{
				return EmptyDefaultDictionary;
			}
			return dataForSlot;
		}

		public static IDisposable SetScoped(string item, string value)
		{
			Set(item, value);
			return new ItemRemover(item);
		}

		public static IDisposable SetScoped(string item, object value)
		{
			Set(item, value);
			return new ItemRemover(item);
		}

		public static void Set(string item, string value)
		{
			GetThreadDictionary()[item] = value;
		}

		public static void Set(string item, object value)
		{
			GetThreadDictionary()[item] = value;
		}

		public static string Get(string item)
		{
			return Get(item, null);
		}

		public static string Get(string item, IFormatProvider formatProvider)
		{
			return FormatHelper.ConvertToString(GetObject(item), formatProvider);
		}

		public static object GetObject(string item)
		{
			if (!GetThreadDictionary(create: false).TryGetValue(item, out var value))
			{
				return null;
			}
			return value;
		}

		public static ICollection<string> GetNames()
		{
			return GetThreadDictionary(create: false).Keys;
		}

		public static bool Contains(string item)
		{
			return GetThreadDictionary(create: false).ContainsKey(item);
		}

		public static void Remove(string item)
		{
			GetThreadDictionary().Remove(item);
		}

		public static void Clear()
		{
			GetThreadDictionary().Clear();
		}
	}
	public static class MappedDiagnosticsLogicalContext
	{
		private sealed class ItemRemover : IDisposable
		{
			private readonly string _item1;

			private readonly string _item2;

			private readonly string _item3;

			private readonly string[] _itemArray;

			private int _disposed;

			private readonly bool _wasEmpty;

			public ItemRemover(string item, bool wasEmpty)
			{
				_item1 = item;
				_wasEmpty = wasEmpty;
			}

			public ItemRemover(IReadOnlyList<KeyValuePair<string, object>> items, bool wasEmpty)
			{
				int count = items.Count;
				if (count > 2)
				{
					_item1 = items[0].Key;
					_item2 = items[1].Key;
					_item3 = items[2].Key;
					for (int i = 3; i < count; i++)
					{
						_itemArray = _itemArray ?? new string[count - 3];
						_itemArray[i - 3] = items[i].Key;
					}
				}
				else if (count > 1)
				{
					_item1 = items[0].Key;
					_item2 = items[1].Key;
				}
				else
				{
					_item1 = items[0].Key;
				}
				_wasEmpty = wasEmpty;
			}

			public void Dispose()
			{
				if (Interlocked.Exchange(ref _disposed, 1) != 0)
				{
					return;
				}
				if (_wasEmpty && RemoveScopeWillClearContext())
				{
					Clear(free: true);
					return;
				}
				IDictionary<string, object> logicalThreadDictionary = GetLogicalThreadDictionary(clone: true);
				logicalThreadDictionary.Remove(_item1);
				if (_item2 == null)
				{
					return;
				}
				logicalThreadDictionary.Remove(_item2);
				if (_item3 != null)
				{
					logicalThreadDictionary.Remove(_item3);
				}
				if (_itemArray == null)
				{
					return;
				}
				for (int i = 0; i < _itemArray.Length; i++)
				{
					if (_itemArray[i] != null)
					{
						logicalThreadDictionary.Remove(_itemArray[i]);
					}
				}
			}

			private bool RemoveScopeWillClearContext()
			{
				if (_itemArray == null)
				{
					IDictionary<string, object> logicalThreadDictionary = GetLogicalThreadDictionary();
					if ((logicalThreadDictionary.Count == 1 && _item2 == null && logicalThreadDictionary.ContainsKey(_item1)) || (logicalThreadDictionary.Count == 2 && _item2 != null && _item3 == null && logicalThreadDictionary.ContainsKey(_item1) && logicalThreadDictionary.ContainsKey(_item2) && !_item1.Equals(_item2)) || (logicalThreadDictionary.Count == 3 && _item3 != null && logicalThreadDictionary.ContainsKey(_item1) && logicalThreadDictionary.ContainsKey(_item2) && logicalThreadDictionary.ContainsKey(_item3) && !_item1.Equals(_item2) && !_item1.Equals(_item3) && !_item2.Equals(_item3)))
					{
						return true;
					}
				}
				return false;
			}

			public override string ToString()
			{
				return _item1?.ToString() ?? base.ToString();
			}
		}

		private const string LogicalThreadDictionaryKey = "NLog.AsyncableMappedDiagnosticsContext";

		private static readonly IDictionary<string, object> EmptyDefaultDictionary = default(SortHelpers.ReadOnlySingleBucketDictionary<string, object>);

		private static IDictionary<string, object> GetLogicalThreadDictionary(bool clone = false, int initialCapacity = 0)
		{
			Dictionary<string, object> dictionary = GetThreadLocal();
			if (dictionary == null)
			{
				if (!clone)
				{
					return EmptyDefaultDictionary;
				}
				dictionary = new Dictionary<string, object>(initialCapacity);
				SetThreadLocal(dictionary);
			}
			else if (clone)
			{
				Dictionary<string, object> dictionary2 = new Dictionary<string, object>(dictionary.Count + initialCapacity);
				foreach (KeyValuePair<string, object> item in dictionary)
				{
					dictionary2[item.Key] = item.Value;
				}
				SetThreadLocal(dictionary2);
				return dictionary2;
			}
			return dictionary;
		}

		public static string Get(string item)
		{
			return Get(item, null);
		}

		public static string Get(string item, IFormatProvider formatProvider)
		{
			return FormatHelper.ConvertToString(GetObject(item), formatProvider);
		}

		public static object GetObject(string item)
		{
			if (!GetLogicalThreadDictionary().TryGetValue(item, out var value))
			{
				return null;
			}
			if (value is ObjectHandleSerializer objectHandleSerializer)
			{
				return objectHandleSerializer.Unwrap();
			}
			return value;
		}

		public static IDisposable SetScoped(string item, string value)
		{
			return MappedDiagnosticsLogicalContext.SetScoped<string>(item, value);
		}

		public static IDisposable SetScoped(string item, object value)
		{
			return MappedDiagnosticsLogicalContext.SetScoped<object>(item, value);
		}

		public static IDisposable SetScoped<T>(string item, T value)
		{
			IDictionary<string, object> logicalThreadDictionary = GetLogicalThreadDictionary(clone: true, 1);
			bool wasEmpty = logicalThreadDictionary.Count == 0;
			SetItemValue(item, value, logicalThreadDictionary);
			return new ItemRemover(item, wasEmpty);
		}

		public static IDisposable SetScoped(IReadOnlyList<KeyValuePair<string, object>> items)
		{
			if (items != null && items.Count > 0)
			{
				IDictionary<string, object> logicalThreadDictionary = GetLogicalThreadDictionary(clone: true, items.Count);
				bool wasEmpty = logicalThreadDictionary.Count == 0;
				for (int i = 0; i < items.Count; i++)
				{
					SetItemValue(items[i].Key, items[i].Value, logicalThreadDictionary);
				}
				return new ItemRemover(items, wasEmpty);
			}
			return null;
		}

		public static void Set(string item, string value)
		{
			MappedDiagnosticsLogicalContext.Set<string>(item, value);
		}

		public static void Set(string item, object value)
		{
			MappedDiagnosticsLogicalContext.Set<object>(item, value);
		}

		public static void Set<T>(string item, T value)
		{
			IDictionary<string, object> logicalThreadDictionary = GetLogicalThreadDictionary(clone: true, 1);
			SetItemValue(item, value, logicalThreadDictionary);
		}

		private static void SetItemValue<T>(string item, T value, IDictionary<string, object> logicalContext)
		{
			if (typeof(T).IsValueType || Convert.GetTypeCode(value) != TypeCode.Object)
			{
				logicalContext[item] = value;
			}
			else
			{
				logicalContext[item] = new ObjectHandleSerializer(value);
			}
		}

		public static ICollection<string> GetNames()
		{
			return GetLogicalThreadDictionary().Keys;
		}

		public static bool Contains(string item)
		{
			return GetLogicalThreadDictionary().ContainsKey(item);
		}

		public static void Remove(string item)
		{
			GetLogicalThreadDictionary(clone: true).Remove(item);
		}

		public static void Clear()
		{
			Clear(free: true);
		}

		public static void Clear(bool free)
		{
			if (free)
			{
				SetThreadLocal(null);
			}
			else
			{
				GetLogicalThreadDictionary(clone: true).Clear();
			}
		}

		private static void SetThreadLocal(Dictionary<string, object> newValue)
		{
			if (newValue == null)
			{
				CallContext.FreeNamedDataSlot("NLog.AsyncableMappedDiagnosticsContext");
			}
			else
			{
				CallContext.LogicalSetData("NLog.AsyncableMappedDiagnosticsContext", newValue);
			}
		}

		private static Dictionary<string, object> GetThreadLocal()
		{
			return CallContext.LogicalGetData("NLog.AsyncableMappedDiagnosticsContext") as Dictionary<string, object>;
		}
	}
