	public static class NestedDiagnosticsContext
	{
		private class StackPopper : IDisposable
		{
			private readonly Stack<object> _stack;

			private readonly int _previousCount;

			public StackPopper(Stack<object> stack, int previousCount)
			{
				_stack = stack;
				_previousCount = previousCount;
			}

			void IDisposable.Dispose()
			{
				while (_stack.Count > _previousCount)
				{
					_stack.Pop();
				}
			}
		}

		private static readonly object dataSlot = ThreadLocalStorageHelper.AllocateDataSlot();

		public static string TopMessage => FormatHelper.ConvertToString(TopObject, null);

		public static object TopObject => PeekObject();

		private static Stack<object> GetThreadStack(bool create = true)
		{
			return ThreadLocalStorageHelper.GetDataForSlot<Stack<object>>(dataSlot, create);
		}

		public static IDisposable Push(string text)
		{
			return Push((object)text);
		}

		public static IDisposable Push(object value)
		{
			Stack<object> threadStack = GetThreadStack();
			int count = threadStack.Count;
			threadStack.Push(value);
			return new StackPopper(threadStack, count);
		}

		public static string Pop()
		{
			return Pop(null);
		}

		public static string Pop(IFormatProvider formatProvider)
		{
			return FormatHelper.ConvertToString(PopObject() ?? string.Empty, formatProvider);
		}

		public static object PopObject()
		{
			Stack<object> threadStack = GetThreadStack();
			if (threadStack.Count <= 0)
			{
				return null;
			}
			return threadStack.Pop();
		}

		public static object PeekObject()
		{
			Stack<object> threadStack = GetThreadStack(create: false);
			if (threadStack == null || threadStack.Count <= 0)
			{
				return null;
			}
			return threadStack.Peek();
		}

		public static void Clear()
		{
			GetThreadStack(create: false)?.Clear();
		}

		public static string[] GetAllMessages()
		{
			return GetAllMessages(null);
		}

		public static string[] GetAllMessages(IFormatProvider formatProvider)
		{
			Stack<object> threadStack = GetThreadStack(create: false);
			if (threadStack == null)
			{
				return ArrayHelper.Empty<string>();
			}
			return threadStack.Select((object o) => FormatHelper.ConvertToString(o, formatProvider)).ToArray();
		}

		public static object[] GetAllObjects()
		{
			Stack<object> threadStack = GetThreadStack(create: false);
			if (threadStack == null)
			{
				return ArrayHelper.Empty<object>();
			}
			return threadStack.ToArray();
		}
	}
	public static class NestedDiagnosticsLogicalContext
	{
		private interface INestedContext : IDisposable
		{
			INestedContext Parent { get; }

			int FrameLevel { get; }

			object Value { get; }

			long CreatedTimeUtcTicks { get; }
		}

		[Serializable]
		private class NestedContext<T> : INestedContext, IDisposable
		{
			private int _disposed;

			public INestedContext Parent { get; }

			public T Value { get; }

			public long CreatedTimeUtcTicks { get; }

			public int FrameLevel { get; }

			object INestedContext.Value
			{
				get
				{
					object obj = Value;
					if (obj is ObjectHandleSerializer objectHandleSerializer)
					{
						return objectHandleSerializer.Unwrap();
					}
					return obj;
				}
			}

			public static INestedContext CreateNestedContext(INestedContext parent, T value)
			{
				if (typeof(T).IsValueType || Convert.GetTypeCode(value) != TypeCode.Object)
				{
					return new NestedContext<T>(parent, value);
				}
				return new NestedContext<ObjectHandleSerializer>(parent, new ObjectHandleSerializer(value));
			}

			public NestedContext(INestedContext parent, T value)
			{
				Parent = parent;
				Value = value;
				CreatedTimeUtcTicks = DateTime.UtcNow.Ticks;
				FrameLevel = ((parent == null) ? 1 : (parent.FrameLevel + 1));
			}

			void IDisposable.Dispose()
			{
				if (Interlocked.Exchange(ref _disposed, 1) != 1)
				{
					PopObject();
				}
			}

			public override string ToString()
			{
				return ((object)Value)?.ToString() ?? "null";
			}
		}

		private const string NestedDiagnosticsContextKey = "NLog.AsyncableNestedDiagnosticsContext";

		public static IDisposable Push<T>(T value)
		{
			INestedContext nestedContext = NestedContext<T>.CreateNestedContext(GetThreadLocal(), value);
			SetThreadLocal(nestedContext);
			return nestedContext;
		}

		public static IDisposable PushObject(object value)
		{
			return Push(value);
		}

		public static object Pop()
		{
			return PopObject();
		}

		public static string Pop(IFormatProvider formatProvider)
		{
			return FormatHelper.ConvertToString(PopObject() ?? string.Empty, formatProvider);
		}

		public static object PopObject()
		{
			INestedContext threadLocal = GetThreadLocal();
			if (threadLocal != null)
			{
				SetThreadLocal(threadLocal.Parent);
			}
			return threadLocal?.Value;
		}

		public static object PeekObject()
		{
			return PeekContext(bottomScope: false)?.Value;
		}

		internal static DateTime PeekTopScopeBeginTime()
		{
			INestedContext nestedContext = PeekContext(bottomScope: false);
			long ticks;
			if (nestedContext == null)
			{
				DateTime minValue = DateTime.MinValue;
				ticks = minValue.Ticks;
			}
			else
			{
				ticks = nestedContext.CreatedTimeUtcTicks;
			}
			return new DateTime(ticks, DateTimeKind.Utc);
		}

		internal static DateTime PeekBottomScopeBeginTime()
		{
			INestedContext nestedContext = PeekContext(bottomScope: true);
			long ticks;
			if (nestedContext == null)
			{
				DateTime minValue = DateTime.MinValue;
				ticks = minValue.Ticks;
			}
			else
			{
				ticks = nestedContext.CreatedTimeUtcTicks;
			}
			return new DateTime(ticks, DateTimeKind.Utc);
		}

		private static INestedContext PeekContext(bool bottomScope)
		{
			INestedContext nestedContext = GetThreadLocal();
			if (nestedContext != null)
			{
				if (bottomScope)
				{
					while (nestedContext.Parent != null)
					{
						nestedContext = nestedContext.Parent;
					}
				}
				return nestedContext;
			}
			return null;
		}

		public static void Clear()
		{
			SetThreadLocal(null);
		}

		public static string[] GetAllMessages()
		{
			return GetAllMessages(null);
		}

		public static string[] GetAllMessages(IFormatProvider formatProvider)
		{
			return (from o in GetAllObjects()
				select FormatHelper.ConvertToString(o, formatProvider)).ToArray();
		}

		public static object[] GetAllObjects()
		{
			INestedContext nestedContext = GetThreadLocal();
			if (nestedContext == null)
			{
				return ArrayHelper.Empty<object>();
			}
			int num = 0;
			object[] array = new object[nestedContext.FrameLevel];
			while (nestedContext != null)
			{
				array[num++] = nestedContext.Value;
				nestedContext = nestedContext.Parent;
			}
			return array;
		}

		private static void SetThreadLocal(INestedContext newValue)
		{
			if (newValue == null)
			{
				CallContext.FreeNamedDataSlot("NLog.AsyncableNestedDiagnosticsContext");
			}
			else
			{
				CallContext.LogicalSetData("NLog.AsyncableNestedDiagnosticsContext", newValue);
			}
		}

		private static INestedContext GetThreadLocal()
		{
			return CallContext.LogicalGetData("NLog.AsyncableNestedDiagnosticsContext") as INestedContext;
		}
	}
