	[Target("Debugger")]
	public sealed class DebuggerTarget : TargetWithLayoutHeaderAndFooter
	{
		public DebuggerTarget()
		{
			base.OptimizeBufferReuse = true;
		}

		public DebuggerTarget(string name)
			: this()
		{
			base.Name = name;
		}

		protected override void InitializeTarget()
		{
			base.InitializeTarget();
			if (!Debugger.IsLogging())
			{
				InternalLogger.Debug("Debugger(Name={0}): System.Diagnostics.Debugger.IsLogging()==false. Output has been disabled.", base.Name);
			}
			if (base.Header != null)
			{
				Debugger.Log(LogLevel.Off.Ordinal, string.Empty, RenderLogEvent(base.Header, LogEventInfo.CreateNullEvent()) + "\n");
			}
		}

		protected override void CloseTarget()
		{
			if (base.Footer != null)
			{
				Debugger.Log(LogLevel.Off.Ordinal, string.Empty, RenderLogEvent(base.Footer, LogEventInfo.CreateNullEvent()) + "\n");
			}
			base.CloseTarget();
		}

		protected override void Write(LogEventInfo logEvent)
		{
			if (!Debugger.IsLogging())
			{
				return;
			}
			string message;
			if (base.OptimizeBufferReuse)
			{
				ReusableObjectCreator<StringBuilder>.LockOject lockOject = ReusableLayoutBuilder.Allocate();
				try
				{
					Layout.RenderAppendBuilder(logEvent, lockOject.Result);
					lockOject.Result.Append('\n');
					message = lockOject.Result.ToString();
				}
				finally
				{
					((IDisposable)lockOject/*cast due to .constrained prefix*/).Dispose();
				}
			}
			else
			{
				message = RenderLogEvent(Layout, logEvent) + "\n";
			}
			Debugger.Log(logEvent.Level.Ordinal, logEvent.LoggerName, message);
		}
	}
	[Target("Debug")]
	public sealed class DebugTarget : TargetWithLayout
	{
		public int Counter { get; private set; }

		public string LastMessage { get; private set; }

		public DebugTarget()
		{
			LastMessage = string.Empty;
			Counter = 0;
			base.OptimizeBufferReuse = true;
		}

		public DebugTarget(string name)
			: this()
		{
			base.Name = name;
		}

		protected override void Write(LogEventInfo logEvent)
		{
			Counter++;
			LastMessage = RenderLogEvent(Layout, logEvent);
		}
	}
	public class DefaultJsonSerializer : IJsonConverter, IJsonSerializer
	{
		private readonly ObjectReflectionCache _objectReflectionCache = new ObjectReflectionCache();

		private readonly MruCache<Enum, string> _enumCache = new MruCache<Enum, string>(1500);

		private readonly JsonSerializeOptions _serializeOptions = new JsonSerializeOptions();

		private readonly JsonSerializeOptions _exceptionSerializeOptions = new JsonSerializeOptions
		{
			SanitizeDictionaryKeys = true
		};

		private readonly IFormatProvider _defaultFormatProvider = CreateFormatProvider();

