						return stringBuilder.ToString();
					}
				}
				return QuoteValue(text);
			}
			IConvertible convertible = value as IConvertible;
			TypeCode typeCode = convertible?.GetTypeCode() ?? TypeCode.Object;
			if (typeCode != TypeCode.Object && typeCode != TypeCode.Char && StringHelpers.IsNullOrWhiteSpace(options.Format) && options.FormatProvider == null)
			{
				if (!options.EnumAsInteger && IsNumericTypeCode(typeCode, includeDecimals: false) && value is Enum value2)
