		private void SerializeSimpleTypeCodeValue(IConvertible value, TypeCode objTypeCode, StringBuilder destination, JsonSerializeOptions options, bool forceToString = false)
		{
			if (value == null)
			{
				destination.Append(forceToString ? "\"\"" : "null");
				return;
			}
			if (objTypeCode == TypeCode.String || objTypeCode == TypeCode.Char)
			{
				destination.Append('"');
				AppendStringEscape(destination, value.ToString(), options);
				destination.Append('"');
				return;
			}
			bool flag = !StringHelpers.IsNullOrWhiteSpace(options.Format);
			if ((options.FormatProvider != null || flag) && value is IFormattable formattable)
			{
				bool includeQuotes = forceToString || objTypeCode == TypeCode.Object || !SkipQuotes(value, objTypeCode);
				SerializeWithFormatProvider(formattable, includeQuotes, destination, options, flag);
			}
			else
			{
				SerializeSimpleTypeCodeValueNoEscape(value, objTypeCode, destination, options, forceToString);
			}
		}

		private void SerializeSimpleTypeCodeValueNoEscape(IConvertible value, TypeCode objTypeCode, StringBuilder destination, JsonSerializeOptions options, bool forceToString)
		{
			if (IsNumericTypeCode(objTypeCode, includeDecimals: false))
			{
				SerializeSimpleNumericValue(value, objTypeCode, destination, options, forceToString);
				return;
			}
			if (objTypeCode == TypeCode.DateTime)
			{
				destination.Append('"');
				destination.AppendXmlDateTimeRoundTrip(value.ToDateTime(CultureInfo.InvariantCulture));
				destination.Append('"');
				return;
			}
			string text = XmlHelper.XmlConvertToString(value, objTypeCode);
			if (!forceToString && text != null && SkipQuotes(value, objTypeCode))
			{
				destination.Append(text);
			}
			else
			{
				QuoteValue(destination, text);
			}
		}

		private void SerializeSimpleNumericValue(IConvertible value, TypeCode objTypeCode, StringBuilder destination, JsonSerializeOptions options, bool forceToString)
		{
			if (!options.EnumAsInteger && value is Enum value2)
			{
				QuoteValue(destination, EnumAsString(value2));
				return;
			}
			if (forceToString)
			{
				destination.Append('"');
			}
			destination.AppendIntegerAsString(value, objTypeCode);
			if (forceToString)
			{
				destination.Append('"');
			}
		}

		private static CultureInfo CreateFormatProvider()
		{
			CultureInfo cultureInfo = new CultureInfo("en-US", useUserOverride: false);
			NumberFormatInfo numberFormat = cultureInfo.NumberFormat;
			numberFormat.NumberGroupSeparator = string.Empty;
			numberFormat.NumberDecimalSeparator = ".";
			numberFormat.NumberGroupSizes = new int[1];
			return cultureInfo;
		}

		private static string QuoteValue(string value)
		{
			return "\"" + value + "\"";
		}

		private static void QuoteValue(StringBuilder destination, string value)
		{
			destination.Append('"');
			destination.Append(value);
			destination.Append('"');
		}

		private string EnumAsString(Enum value)
		{
			if (!_enumCache.TryGetValue(value, out var value2))
			{
				value2 = Convert.ToString(value, CultureInfo.InvariantCulture);
				_enumCache.TryAddValue(value, value2);
			}
			return value2;
		}

		private static bool SkipQuotes(IConvertible value, TypeCode objTypeCode)
		{
			switch (objTypeCode)
			{
			case TypeCode.String:
				return false;
			case TypeCode.Char:
				return false;
			case TypeCode.DateTime:
				return false;
			case TypeCode.Empty:
				return true;
			case TypeCode.Boolean:
				return true;
			case TypeCode.Decimal:
				return true;
			case TypeCode.Double:
			{
				double d = value.ToDouble(CultureInfo.InvariantCulture);
				if (!double.IsNaN(d))
				{
					return !double.IsInfinity(d);
				}
				return false;
			}
			case TypeCode.Single:
			{
				float f = value.ToSingle(CultureInfo.InvariantCulture);
				if (!float.IsNaN(f))
				{
					return !float.IsInfinity(f);
				}
				return false;
			}
			default:
				return IsNumericTypeCode(objTypeCode, includeDecimals: false);
			}
		}

		private static bool IsNumericTypeCode(TypeCode objTypeCode, bool includeDecimals)
		{
			switch (objTypeCode)
			{
			case TypeCode.SByte:
			case TypeCode.Byte:
			case TypeCode.Int16:
			case TypeCode.UInt16:
			case TypeCode.Int32:
			case TypeCode.UInt32:
			case TypeCode.Int64:
			case TypeCode.UInt64:
				return true;
			case TypeCode.Single:
			case TypeCode.Double:
			case TypeCode.Decimal:
				return includeDecimals;
			default:
				return false;
			}
		}

		private static void AppendStringEscape(StringBuilder destination, string text, JsonSerializeOptions options)
		{
			AppendStringEscape(destination, text, options.EscapeUnicode, options.EscapeForwardSlash);
		}

		internal static void AppendStringEscape(StringBuilder destination, string text, bool escapeUnicode, bool escapeForwardSlash)
		{
			if (string.IsNullOrEmpty(text))
			{
				return;
			}
			StringBuilder stringBuilder = null;
			for (int i = 0; i < text.Length; i++)
			{
				char c = text[i];
				if (!RequiresJsonEscape(c, escapeUnicode, escapeForwardSlash))
				{
					stringBuilder?.Append(c);
					continue;
				}
				if (stringBuilder == null)
				{
					stringBuilder = destination;
					stringBuilder.Append(text, 0, i);
				}
				switch (c)
				{
				case '"':
					stringBuilder.Append("\\\"");
					break;
				case '\\':
					stringBuilder.Append("\\\\");
					break;
				case '\b':
					stringBuilder.Append("\\b");
					break;
				case '/':
					if (escapeForwardSlash)
					{
						stringBuilder.Append("\\/");
					}
					else
					{
						stringBuilder.Append(c);
					}
					break;
				case '\r':
					stringBuilder.Append("\\r");
					break;
				case '\n':
					stringBuilder.Append("\\n");
					break;
				case '\f':
					stringBuilder.Append("\\f");
					break;
				case '\t':
					stringBuilder.Append("\\t");
					break;
				default:
					if (EscapeChar(c, escapeUnicode))
					{
						stringBuilder.AppendFormat(CultureInfo.InvariantCulture, "\\u{0:x4}", (int)c);
					}
					else
					{
						stringBuilder.Append(c);
					}
					break;
				}
			}
			if (stringBuilder == null)
			{
				destination.Append(text);
			}
		}

		internal static bool RequiresJsonEscape(char ch, JsonSerializeOptions options)
		{
			return RequiresJsonEscape(ch, options.EscapeUnicode, options.EscapeForwardSlash);
		}

		internal static bool RequiresJsonEscape(char ch, bool escapeUnicode, bool escapeForwardSlash)
		{
			if (!EscapeChar(ch, escapeUnicode))
			{
				switch (ch)
				{
				case '/':
					return escapeForwardSlash;
				case '"':
				case '\\':
					return true;
				default:
					return false;
				}
			}
			return true;
		}

		private static bool EscapeChar(char ch, bool escapeUnicode)
		{
			if (ch < ' ')
			{
				return true;
			}
			if (escapeUnicode)
			{
				return ch > '\u007f';
			}
			return false;
		}

		private bool SerializeObjectProperties(ObjectReflectionCache.ObjectPropertyList objectPropertyList, StringBuilder destination, JsonSerializeOptions options, SingleItemOptimizedHashSet<object> objectsInPath, int depth)
		{
			destination.Append('{');
			bool flag = true;
			foreach (ObjectReflectionCache.ObjectPropertyList.PropertyValue item in objectPropertyList)
			{
				int length = destination.Length;
				try
				{
					if (HasNameAndValue(item))
					{
						if (!flag)
						{
							destination.Append(", ");
						}
						if (options.QuoteKeys)
						{
							QuoteValue(destination, item.Name);
						}
						else
						{
							destination.Append(item.Name);
						}
						destination.Append(':');
						TypeCode typeCode = item.TypeCode;
						if (typeCode != TypeCode.Object)
						{
							SerializeSimpleTypeCodeValue((IConvertible)item.Value, typeCode, destination, options);
							flag = false;
						}
						else if (!SerializeObject(item.Value, destination, options, objectsInPath, depth + 1))
						{
							destination.Length = length;
						}
						else
						{
							flag = false;
						}
					}
				}
				catch
				{
					destination.Length = length;
				}
			}
			destination.Append('}');
			return true;
		}

		private static bool HasNameAndValue(ObjectReflectionCache.ObjectPropertyList.PropertyValue propertyValue)
		{
			if (propertyValue.Name != null)
			{
				return propertyValue.Value != null;
			}
			return false;
		}

		private bool SerializeObjectAsString(object value, StringBuilder destination, JsonSerializeOptions options)
		{
			int length = destination.Length;
			try
			{
				if (SerializeSimpleObjectValue(value, destination, options, forceToString: true))
				{
					return true;
				}
				bool flag = !StringHelpers.IsNullOrWhiteSpace(options.Format);
				if ((options.FormatProvider != null || flag) && value is IFormattable formattable)
				{
					SerializeWithFormatProvider(formattable, includeQuotes: true, destination, options, flag);
					return true;
				}
				string text = Convert.ToString(value, CultureInfo.InvariantCulture);
				destination.Append('"');
				AppendStringEscape(destination, text, options);
				destination.Append('"');
				return true;
			}
			catch
			{
				destination.Length = length;
				return false;
			}
		}
	}
