	[TypeConverter(typeof(LineEndingModeConverter))]
	public sealed class LineEndingMode : IEquatable<LineEndingMode>
	{
		public class LineEndingModeConverter : TypeConverter
		{
			public override bool CanConvertFrom(ITypeDescriptorContext context, Type sourceType)
			{
				if (!(sourceType == typeof(string)))
				{
					return base.CanConvertFrom(context, sourceType);
				}
				return true;
			}

			public override object ConvertFrom(ITypeDescriptorContext context, CultureInfo culture, object value)
			{
				if (!(value is string name))
				{
					return base.ConvertFrom(context, culture, value);
				}
				return FromString(name);
			}
		}

		public static readonly LineEndingMode Default = new LineEndingMode("Default", EnvironmentHelper.NewLine);

		public static readonly LineEndingMode CRLF = new LineEndingMode("CRLF", "\r\n");

		public static readonly LineEndingMode CR = new LineEndingMode("CR", "\r");

		public static readonly LineEndingMode LF = new LineEndingMode("LF", "\n");

		public static readonly LineEndingMode Null = new LineEndingMode("Null", "\0");

		public static readonly LineEndingMode None = new LineEndingMode("None", string.Empty);

		private readonly string _name;

		private readonly string _newLineCharacters;

		public string Name => _name;

		public string NewLineCharacters => _newLineCharacters;

		private LineEndingMode()
		{
		}

		private LineEndingMode(string name, string newLineCharacters)
		{
			_name = name;
			_newLineCharacters = newLineCharacters;
		}

		public static LineEndingMode FromString([NotNull] string name)
		{
			if (name == null)
			{
				throw new ArgumentNullException("name");
			}
			if (name.Equals(CRLF.Name, StringComparison.OrdinalIgnoreCase))
			{
				return CRLF;
			}
			if (name.Equals(LF.Name, StringComparison.OrdinalIgnoreCase))
			{
				return LF;
			}
			if (name.Equals(CR.Name, StringComparison.OrdinalIgnoreCase))
			{
				return CR;
			}
			if (name.Equals(Default.Name, StringComparison.OrdinalIgnoreCase))
			{
				return Default;
			}
			if (name.Equals(Null.Name, StringComparison.OrdinalIgnoreCase))
			{
				return Null;
			}
			if (name.Equals(None.Name, StringComparison.OrdinalIgnoreCase))
			{
				return None;
			}
			throw new ArgumentOutOfRangeException("name", name, "LineEndingMode is out of range");
		}

		public static bool operator ==(LineEndingMode mode1, LineEndingMode mode2)
		{
			if ((object)mode1 == null)
			{
				return (object)mode2 == null;
			}
			if ((object)mode2 == null)
			{
				return false;
			}
			return mode1.NewLineCharacters == mode2.NewLineCharacters;
		}

		public static bool operator !=(LineEndingMode mode1, LineEndingMode mode2)
		{
			if ((object)mode1 == null)
			{
				return (object)mode2 != null;
			}
			if ((object)mode2 == null)
			{
				return true;
			}
			return mode1.NewLineCharacters != mode2.NewLineCharacters;
		}

		public override string ToString()
		{
			return Name;
		}

		public override int GetHashCode()
		{
			if (_newLineCharacters == null)
			{
				return 0;
			}
			return _newLineCharacters.GetHashCode();
		}

		public override bool Equals(object obj)
		{
			if (obj == null)
			{
				return false;
			}
			if (this == obj)
			{
				return true;
			}
			if (obj is LineEndingMode other)
			{
				return Equals(other);
			}
			return false;
		}

		public bool Equals(LineEndingMode other)
		{
			if ((object)other == null)
			{
				return false;
			}
			if ((object)this == other)
			{
				return true;
			}
			return string.Equals(_newLineCharacters, other._newLineCharacters);
		}
	}
	[Target("Mail")]
	public class MailTarget : TargetWithLayoutHeaderAndFooter
	{
		private const string RequiredPropertyIsEmptyFormat = "After the processing of the MailTarget's '{0}' property it appears to be empty. The email message will not be sent.";

		private Layout _from;

		public Layout From
		{
			get
			{
				return _from;
			}
			set
			{
				_from = value;
			}
		}

		[RequiredParameter]
		public Layout To { get; set; }

		public Layout CC { get; set; }

		public Layout Bcc { get; set; }

		public bool AddNewLines { get; set; }

		[DefaultValue("Message from NLog on ${machinename}")]
		[RequiredParameter]
		public Layout Subject { get; set; }

		[DefaultValue("${message}${newline}")]
		public Layout Body
		{
			get
			{
				return Layout;
			}
			set
			{
				Layout = value;
			}
		}

		[DefaultValue("UTF8")]
		public Encoding Encoding { get; set; }

		[DefaultValue(false)]
		public bool Html { get; set; }

		public Layout SmtpServer { get; set; }

		[DefaultValue("None")]
		public SmtpAuthenticationMode SmtpAuthentication { get; set; }

		public Layout SmtpUserName { get; set; }

		public Layout SmtpPassword { get; set; }

		[DefaultValue(false)]
		public bool EnableSsl { get; set; }

		[DefaultValue(25)]
		public int SmtpPort { get; set; }

		[DefaultValue(false)]
		public bool UseSystemNetMailSettings { get; set; }

		[DefaultValue(SmtpDeliveryMethod.Network)]
		public SmtpDeliveryMethod DeliveryMethod { get; set; }

		[DefaultValue(null)]
		public string PickupDirectoryLocation { get; set; }

		public Layout Priority { get; set; }

		[DefaultValue(false)]
		public bool ReplaceNewlineWithBrTagInHtml { get; set; }

		[DefaultValue(10000)]
		public int Timeout { get; set; }

		public MailTarget()
		{
			Body = "${message}${newline}";
			Subject = "Message from NLog on ${machinename}";
			Encoding = Encoding.UTF8;
			SmtpPort = 25;
			SmtpAuthentication = SmtpAuthenticationMode.None;
			Timeout = 10000;
		}

		public MailTarget(string name)
			: this()
		{
			base.Name = name;
		}

		internal virtual ISmtpClient CreateSmtpClient()
		{
			return new MySmtpClient();
		}

		protected override void Write(AsyncLogEventInfo logEvent)
		{
			Write((IList<AsyncLogEventInfo>)new AsyncLogEventInfo[1] { logEvent });
		}

		[Obsolete("Instead override Write(IList<AsyncLogEventInfo> logEvents. Marked obsolete on NLog 4.5")]
		protected override void Write(AsyncLogEventInfo[] logEvents)
		{
			Write((IList<AsyncLogEventInfo>)logEvents);
		}

		protected override void Write(IList<AsyncLogEventInfo> logEvents)
		{
			foreach (KeyValuePair<string, IList<AsyncLogEventInfo>> item in logEvents.BucketSort((AsyncLogEventInfo c) => GetSmtpSettingsKey(c.LogEvent)))
			{
				IList<AsyncLogEventInfo> value = item.Value;
				ProcessSingleMailMessage(value);
			}
		}

		protected override void InitializeTarget()
		{
			CheckRequiredParameters();
			base.InitializeTarget();
		}

		private void ProcessSingleMailMessage([NotNull] IList<AsyncLogEventInfo> events)
		{
			try
			{
				if (events.Count == 0)
				{
					throw new NLogRuntimeException("We need at least one event.");
				}
				LogEventInfo logEvent = events[0].LogEvent;
				LogEventInfo logEvent2 = events[events.Count - 1].LogEvent;
				StringBuilder stringBuilder = CreateBodyBuffer(events, logEvent, logEvent2);
				using MailMessage mailMessage = CreateMailMessage(logEvent2, stringBuilder.ToString());
				using ISmtpClient smtpClient = CreateSmtpClient();
				if (!UseSystemNetMailSettings)
				{
					ConfigureMailClient(logEvent2, smtpClient);
				}
				if (smtpClient.EnableSsl)
				{
					InternalLogger.Debug("MailTarget(Name={0}): Sending mail to {1} using {2}:{3} (ssl=true)", base.Name, mailMessage.To, smtpClient.Host, smtpClient.Port);
				}
				else
				{
					InternalLogger.Debug("MailTarget(Name={0}): Sending mail to {1} using {2}:{3} (ssl=false)", base.Name, mailMessage.To, smtpClient.Host, smtpClient.Port);
				}
				InternalLogger.Trace("MailTarget(Name={0}):   Subject: '{1}'", base.Name, mailMessage.Subject);
				InternalLogger.Trace("MailTarget(Name={0}):   From: '{1}'", base.Name, mailMessage.From.ToString());
				smtpClient.Send(mailMessage);
				foreach (AsyncLogEventInfo @event in events)
				{
					@event.Continuation(null);
				}
			}
			catch (Exception ex)
			{
				InternalLogger.Error(ex, "MailTarget(Name={0}): Error sending mail.", base.Name);
				if (ExceptionMustBeRethrown(ex))
				{
					throw;
				}
				foreach (AsyncLogEventInfo event2 in events)
				{
					event2.Continuation(ex);
				}
			}
		}

		private StringBuilder CreateBodyBuffer(IEnumerable<AsyncLogEventInfo> events, LogEventInfo firstEvent, LogEventInfo lastEvent)
		{
			StringBuilder stringBuilder = new StringBuilder();
			if (base.Header != null)
			{
				stringBuilder.Append(base.Header.Render(firstEvent));
				if (AddNewLines)
				{
					stringBuilder.Append("\n");
				}
			}
			foreach (AsyncLogEventInfo @event in events)
			{
				stringBuilder.Append(Layout.Render(@event.LogEvent));
				if (AddNewLines)
				{
					stringBuilder.Append("\n");
				}
			}
			if (base.Footer != null)
			{
				stringBuilder.Append(base.Footer.Render(lastEvent));
				if (AddNewLines)
				{
					stringBuilder.Append("\n");
				}
			}
			return stringBuilder;
		}

		internal void ConfigureMailClient(LogEventInfo lastEvent, ISmtpClient client)
		{
			CheckRequiredParameters();
			if (SmtpServer == null && string.IsNullOrEmpty(PickupDirectoryLocation))
			{
				throw new NLogRuntimeException(string.Format("After the processing of the MailTarget's '{0}' property it appears to be empty. The email message will not be sent.", "SmtpServer/PickupDirectoryLocation"));
			}
			if (DeliveryMethod == SmtpDeliveryMethod.Network && SmtpServer == null)
			{
				throw new NLogRuntimeException(string.Format("After the processing of the MailTarget's '{0}' property it appears to be empty. The email message will not be sent.", "SmtpServer"));
			}
			if (DeliveryMethod == SmtpDeliveryMethod.SpecifiedPickupDirectory && string.IsNullOrEmpty(PickupDirectoryLocation))
			{
				throw new NLogRuntimeException(string.Format("After the processing of the MailTarget's '{0}' property it appears to be empty. The email message will not be sent.", "PickupDirectoryLocation"));
			}
			if (SmtpServer != null && DeliveryMethod == SmtpDeliveryMethod.Network)
			{
				string text = SmtpServer.Render(lastEvent);
				if (string.IsNullOrEmpty(text))
				{
					throw new NLogRuntimeException(string.Format("After the processing of the MailTarget's '{0}' property it appears to be empty. The email message will not be sent.", "SmtpServer"));
				}
				client.Host = text;
				client.Port = SmtpPort;
				client.EnableSsl = EnableSsl;
				if (SmtpAuthentication == SmtpAuthenticationMode.Ntlm)
				{
					InternalLogger.Trace("MailTarget(Name={0}):   Using NTLM authentication.", base.Name);
					client.Credentials = CredentialCache.DefaultNetworkCredentials;
				}
				else if (SmtpAuthentication == SmtpAuthenticationMode.Basic)
				{
					string text2 = SmtpUserName.Render(lastEvent);
					string text3 = SmtpPassword.Render(lastEvent);
					InternalLogger.Trace("MailTarget(Name={0}):   Using basic authentication: Username='{1}' Password='{2}'", base.Name, text2, new string('*', text3.Length));
					client.Credentials = new NetworkCredential(text2, text3);
				}
			}
			if (!string.IsNullOrEmpty(PickupDirectoryLocation) && DeliveryMethod == SmtpDeliveryMethod.SpecifiedPickupDirectory)
			{
				client.PickupDirectoryLocation = ConvertDirectoryLocation(PickupDirectoryLocation);
			}
			client.DeliveryMethod = DeliveryMethod;
			client.Timeout = Timeout;
		}

		internal static string ConvertDirectoryLocation(string pickupDirectoryLocation)
		{
			if (!pickupDirectoryLocation.StartsWith("~/"))
			{
				return pickupDirectoryLocation;
			}
			string baseDirectory = AppDomain.CurrentDomain.BaseDirectory;
			string path = pickupDirectoryLocation.Substring("~/".Length).Replace('/', Path.DirectorySeparatorChar);
			return Path.Combine(baseDirectory, path);
		}

		private void CheckRequiredParameters()
		{
			if (!UseSystemNetMailSettings && SmtpServer == null && DeliveryMethod == SmtpDeliveryMethod.Network)
			{
				throw new NLogConfigurationException("The MailTarget's '{0}' properties are not set - but needed because useSystemNetMailSettings=false and DeliveryMethod=Network. The email message will not be sent.", "SmtpServer");
			}
			if (!UseSystemNetMailSettings && string.IsNullOrEmpty(PickupDirectoryLocation) && DeliveryMethod == SmtpDeliveryMethod.SpecifiedPickupDirectory)
			{
				throw new NLogConfigurationException("The MailTarget's '{0}' properties are not set - but needed because useSystemNetMailSettings=false and DeliveryMethod=SpecifiedPickupDirectory. The email message will not be sent.", "PickupDirectoryLocation");
			}
			if (From == null)
			{
				throw new NLogConfigurationException("After the processing of the MailTarget's '{0}' property it appears to be empty. The email message will not be sent.", "From");
			}
		}

		private string GetSmtpSettingsKey(LogEventInfo logEvent)
		{
			StringBuilder stringBuilder = new StringBuilder();
			AppendLayout(stringBuilder, logEvent, From);
			AppendLayout(stringBuilder, logEvent, To);
			AppendLayout(stringBuilder, logEvent, CC);
			AppendLayout(stringBuilder, logEvent, Bcc);
			AppendLayout(stringBuilder, logEvent, SmtpServer);
			AppendLayout(stringBuilder, logEvent, SmtpPassword);
			AppendLayout(stringBuilder, logEvent, SmtpUserName);
			return stringBuilder.ToString();
		}

		private static void AppendLayout(StringBuilder sb, LogEventInfo logEvent, Layout layout)
		{
			sb.Append("|");
			if (layout != null)
			{
				sb.Append(layout.Render(logEvent));
			}
		}

		private MailMessage CreateMailMessage(LogEventInfo lastEvent, string body)
		{
			MailMessage mailMessage = new MailMessage();
			string text = From?.Render(lastEvent);
			if (string.IsNullOrEmpty(text))
			{
				throw new NLogRuntimeException("After the processing of the MailTarget's '{0}' property it appears to be empty. The email message will not be sent.", "From");
			}
			mailMessage.From = new MailAddress(text);
			bool num = AddAddresses(mailMessage.To, To, lastEvent);
			bool flag = AddAddresses(mailMessage.CC, CC, lastEvent);
			bool flag2 = AddAddresses(mailMessage.Bcc, Bcc, lastEvent);
			if (!num && !flag && !flag2)
			{
				throw new NLogRuntimeException("After the processing of the MailTarget's '{0}' property it appears to be empty. The email message will not be sent.", "To/Cc/Bcc");
			}
			mailMessage.Subject = ((Subject == null) ? string.Empty : Subject.Render(lastEvent).Trim());
			mailMessage.BodyEncoding = Encoding;
			mailMessage.IsBodyHtml = Html;
			if (Priority != null)
			{
				string text2 = Priority.Render(lastEvent);
				MailPriority resultValue;
				if (string.IsNullOrEmpty(text2))
				{
					mailMessage.Priority = MailPriority.Normal;
				}
				else if (ConversionHelpers.TryParseEnum(text2, out resultValue, MailPriority.Normal))
				{
					mailMessage.Priority = resultValue;
				}
				else
				{
					mailMessage.Priority = MailPriority.Normal;
					InternalLogger.Warn("MailTarget(Name={0}): Could not convert '{1}' to MailPriority, valid values are Low, Normal and High. Using normal priority as fallback.", base.Name, text2);
				}
			}
			mailMessage.Body = body;
			if (mailMessage.IsBodyHtml && ReplaceNewlineWithBrTagInHtml && mailMessage.Body != null)
			{
				mailMessage.Body = mailMessage.Body.Replace(EnvironmentHelper.NewLine, "<br/>");
			}
			return mailMessage;
		}

		private static bool AddAddresses(MailAddressCollection mailAddressCollection, Layout layout, LogEventInfo logEvent)
		{
			bool result = false;
			if (layout != null)
			{
				string[] array = layout.Render(logEvent).SplitAndTrimTokens(';');
				foreach (string addresses in array)
				{
					mailAddressCollection.Add(addresses);
					result = true;
				}
			}
			return result;
		}
	}
	[Target("Memory")]
	public sealed class MemoryTarget : TargetWithLayout
	{
		public IList<string> Logs { get; }

		[DefaultValue(0)]
		public int MaxLogsCount { get; set; }

		public MemoryTarget()
		{
			Logs = new List<string>();
			base.OptimizeBufferReuse = true;
		}

		public MemoryTarget(string name)
			: this()
		{
			base.Name = name;
		}

		protected override void Write(LogEventInfo logEvent)
		{
			if (MaxLogsCount > 0 && Logs.Count >= MaxLogsCount)
			{
				Logs.RemoveAt(0);
			}
			Logs.Add(RenderLogEvent(Layout, logEvent));
		}
	}
