	[Target("MethodCall")]
	public sealed class MethodCallTarget : MethodCallTargetBase
	{
		private Action<LogEventInfo, object[]> _logEventAction;

		public string ClassName { get; set; }

		public string MethodName { get; set; }

		public MethodCallTarget()
		{
		}

		public MethodCallTarget(string name)
			: this(name, null)
		{
		}

		public MethodCallTarget(string name, Action<LogEventInfo, object[]> logEventAction)
			: this()
		{
			base.Name = name;
			_logEventAction = logEventAction;
		}

		protected override void InitializeTarget()
		{
			base.InitializeTarget();
			if (ClassName == null || MethodName == null)
			{
				return;
			}
			Type type = Type.GetType(ClassName);
			if (type != null)
			{
				MethodInfo method = type.GetMethod(MethodName);
				if (method == null)
				{
					InternalLogger.Warn("Initialize MethodCallTarget, method '{0}' in class '{1}' not found - it should be static", MethodName, ClassName);
				}
				else
				{
					_logEventAction = BuildLogEventAction(method);
				}
			}
			else
			{
				InternalLogger.Warn("Initialize MethodCallTarget, class '{0}' not found", ClassName);
			}
		}

		private static Action<LogEventInfo, object[]> BuildLogEventAction(MethodInfo methodInfo)
		{
			int neededParameters = methodInfo.GetParameters().Length;
			return delegate(LogEventInfo logEvent, object[] parameters)
			{
				if (neededParameters - parameters.Length > 0)
				{
					object[] array = new object[neededParameters];
					for (int i = 0; i < parameters.Length; i++)
					{
						array[i] = parameters[i];
					}
					for (int j = parameters.Length; j < neededParameters; j++)
					{
						array[j] = Type.Missing;
					}
					parameters = array;
				}
				methodInfo.Invoke(null, parameters);
			};
		}

		protected override void DoInvoke(object[] parameters, AsyncLogEventInfo logEvent)
		{
			try
			{
				ExecuteLogMethod(parameters, logEvent.LogEvent);
				logEvent.Continuation(null);
			}
			catch (Exception exception)
			{
				if (ExceptionMustBeRethrown(exception))
				{
					throw;
				}
				logEvent.Continuation(exception);
			}
		}

		protected override void DoInvoke(object[] parameters)
		{
			ExecuteLogMethod(parameters, null);
		}

		private void ExecuteLogMethod(object[] parameters, LogEventInfo logEvent)
		{
			if (_logEventAction != null)
			{
				_logEventAction(logEvent, parameters);
			}
			else
			{
				InternalLogger.Trace("No invoke because class/method was not found or set");
			}
		}
	}
	public abstract class MethodCallTargetBase : Target
	{
		private IPropertyTypeConverter _propertyTypeConverter;

		[ArrayParameter(typeof(MethodCallParameter), "parameter")]
		public IList<MethodCallParameter> Parameters { get; private set; }

		private IPropertyTypeConverter PropertyTypeConverter
		{
			get
			{
				return _propertyTypeConverter ?? (_propertyTypeConverter = ConfigurationItemFactory.Default.PropertyTypeConverter);
			}
			set
			{
				_propertyTypeConverter = value;
			}
		}

		protected MethodCallTargetBase()
		{
			Parameters = new List<MethodCallParameter>();
		}

		protected override void CloseTarget()
		{
			PropertyTypeConverter = null;
			base.CloseTarget();
		}

		protected override void Write(AsyncLogEventInfo logEvent)
		{
			object[] array = ((Parameters.Count > 0) ? new object[Parameters.Count] : ArrayHelper.Empty<object>());
			for (int i = 0; i < array.Length; i++)
			{
				try
				{
					array[i] = GetParameterValue(logEvent.LogEvent, Parameters[i]);
				}
				catch (Exception ex)
				{
					if (ex.MustBeRethrownImmediately())
					{
						throw;
					}
					InternalLogger.Warn(ex, "{0}(Name={1}): Failed to get parameter value {2}", GetType(), base.Name, Parameters[i].Name);
					throw;
				}
			}
			DoInvoke(array, logEvent);
		}

		private object GetParameterValue(LogEventInfo logEvent, MethodCallParameter param)
		{
			Type type = param.ParameterType ?? typeof(string);
			string text = RenderLogEvent(param.Layout, logEvent) ?? string.Empty;
			if (type == typeof(string) || type == typeof(object))
			{
				return text;
			}
			if (string.IsNullOrEmpty(text) && type.IsValueType())
			{
				return Activator.CreateInstance(param.ParameterType);
			}
			return PropertyTypeConverter.Convert(text, type, null, CultureInfo.InvariantCulture);
		}

		protected virtual void DoInvoke(object[] parameters, AsyncLogEventInfo logEvent)
		{
			DoInvoke(parameters, logEvent.Continuation);
		}

		protected virtual void DoInvoke(object[] parameters, AsyncContinuation continuation)
		{
			try
			{
				DoInvoke(parameters);
				continuation(null);
			}
			catch (Exception exception)
			{
				if (ExceptionMustBeRethrown(exception))
				{
					throw;
				}
				continuation(exception);
			}
		}

		protected abstract void DoInvoke(object[] parameters);
	}
	[Target("Network")]
	public class NetworkTarget : TargetWithLayout
	{
		private readonly Dictionary<string, LinkedListNode<NetworkSender>> _currentSenderCache = new Dictionary<string, LinkedListNode<NetworkSender>>();

		private readonly LinkedList<NetworkSender> _openNetworkSenders = new LinkedList<NetworkSender>();

		private readonly ReusableBufferCreator _reusableEncodingBuffer = new ReusableBufferCreator(16384);

		public Layout Address { get; set; }

		[DefaultValue(true)]
		public bool KeepConnection { get; set; }

		[DefaultValue(false)]
		public bool NewLine { get; set; }

		[DefaultValue("CRLF")]
		public LineEndingMode LineEnding { get; set; }

		[DefaultValue(65000)]
		public int MaxMessageSize { get; set; }

		[DefaultValue(5)]
		public int ConnectionCacheSize { get; set; }

		public int MaxConnections { get; set; }

		public NetworkTargetConnectionsOverflowAction OnConnectionOverflow { get; set; }

		[DefaultValue(0)]
		public int MaxQueueSize { get; set; }

		[DefaultValue(NetworkTargetOverflowAction.Split)]
		public NetworkTargetOverflowAction OnOverflow { get; set; }

		[DefaultValue("utf-8")]
		public Encoding Encoding { get; set; }

		public SslProtocols SslProtocols { get; set; }

		public int KeepAliveTimeSeconds { get; set; }

		internal INetworkSenderFactory SenderFactory { get; set; }

		public NetworkTarget()
		{
			SenderFactory = NetworkSenderFactory.Default;
			Encoding = Encoding.UTF8;
			OnOverflow = NetworkTargetOverflowAction.Split;
			KeepConnection = true;
			MaxMessageSize = 65000;
			ConnectionCacheSize = 5;
			LineEnding = LineEndingMode.CRLF;
			base.OptimizeBufferReuse = GetType() == typeof(NetworkTarget);
		}

		public NetworkTarget(string name)
			: this()
		{
			base.Name = name;
		}

		protected override void FlushAsync(AsyncContinuation asyncContinuation)
		{
			int remainingCount;
			lock (_openNetworkSenders)
			{
				remainingCount = _openNetworkSenders.Count;
				if (remainingCount == 0)
				{
					asyncContinuation(null);
					return;
				}
				foreach (NetworkSender openNetworkSender in _openNetworkSenders)
				{
					openNetworkSender.FlushAsync(Continuation);
				}
			}
			void Continuation(Exception ex)
			{
				if (Interlocked.Decrement(ref remainingCount) == 0)
				{
					asyncContinuation(null);
				}
			}
		}

		protected override void CloseTarget()
		{
			base.CloseTarget();
			lock (_openNetworkSenders)
			{
				foreach (NetworkSender openNetworkSender in _openNetworkSenders)
				{
					openNetworkSender.Close(delegate
					{
					});
				}
				_openNetworkSenders.Clear();
			}
		}

		protected override void Write(AsyncLogEventInfo logEvent)
		{
			string text = RenderLogEvent(Address, logEvent.LogEvent);
			InternalLogger.Trace("NetworkTarget(Name={0}): Sending to address: '{1}'", base.Name, text);
			byte[] bytesToWrite = GetBytesToWrite(logEvent.LogEvent);
			if (KeepConnection)
			{
				LinkedListNode<NetworkSender> senderNode;
				try
				{
					senderNode = GetCachedNetworkSender(text);
				}
				catch (Exception ex)
				{
					InternalLogger.Error(ex, "NetworkTarget(Name={0}): Failed to create sender to address: '{1}'", base.Name, text);
					throw;
				}
				ChunkedSend(senderNode.Value, bytesToWrite, delegate(Exception ex3)
				{
					if (ex3 != null)
					{
						InternalLogger.Error(ex3, "NetworkTarget(Name={0}): Error when sending.", base.Name);
						ReleaseCachedConnection(senderNode);
					}
					logEvent.Continuation(ex3);
				});
				return;
			}
			NetworkSender sender;
			LinkedListNode<NetworkSender> linkedListNode;
			lock (_openNetworkSenders)
			{
				if (_openNetworkSenders.Count >= MaxConnections && MaxConnections > 0)
				{
					switch (OnConnectionOverflow)
					{
					case NetworkTargetConnectionsOverflowAction.DiscardMessage:
						InternalLogger.Warn("NetworkTarget(Name={0}): Discarding message otherwise to many connections.", base.Name);
						logEvent.Continuation(null);
						return;
					case NetworkTargetConnectionsOverflowAction.AllowNewConnnection:
						InternalLogger.Debug("NetworkTarget(Name={0}): Too may connections, but this is allowed", base.Name);
						break;
					case NetworkTargetConnectionsOverflowAction.Block:
						while (_openNetworkSenders.Count >= MaxConnections)
						{
							InternalLogger.Debug("NetworkTarget(Name={0}): Blocking networktarget otherwhise too many connections.", base.Name);
							Monitor.Wait(_openNetworkSenders);
							InternalLogger.Trace("NetworkTarget(Name={0}): Entered critical section.", base.Name);
						}
						InternalLogger.Trace("NetworkTarget(Name={0}): Limit ok.", base.Name);
						break;
					}
				}
				try
				{
					sender = CreateNetworkSender(text);
				}
				catch (Exception ex2)
				{
					InternalLogger.Error(ex2, "NetworkTarget(Name={0}): Failed to create sender to address: '{1}'", base.Name, text);
					throw;
				}
				linkedListNode = _openNetworkSenders.AddLast(sender);
			}
			ChunkedSend(sender, bytesToWrite, delegate(Exception ex3)
			{
				lock (_openNetworkSenders)
				{
					TryRemove(_openNetworkSenders, linkedListNode);
					if (OnConnectionOverflow == NetworkTargetConnectionsOverflowAction.Block)
					{
						Monitor.PulseAll(_openNetworkSenders);
					}
				}
				if (ex3 != null)
				{
					InternalLogger.Error(ex3, "NetworkTarget(Name={0}): Error when sending.", base.Name);
				}
				sender.Close(delegate
				{
				});
				logEvent.Continuation(ex3);
			});
		}

		private static bool TryRemove<T>(LinkedList<T> list, LinkedListNode<T> node)
		{
			if (node == null || list != node.List)
			{
				return false;
			}
			list.Remove(node);
			return true;
		}

		protected virtual byte[] GetBytesToWrite(LogEventInfo logEvent)
		{
			if (base.OptimizeBufferReuse)
			{
				ReusableObjectCreator<char[]>.LockOject lockOject = _reusableEncodingBuffer.Allocate();
				try
				{
					if (!NewLine && logEvent.TryGetCachedLayoutValue(Layout, out var value))
					{
						return GetBytesFromString(lockOject.Result, value?.ToString() ?? string.Empty);
					}
					ReusableObjectCreator<StringBuilder>.LockOject lockOject2 = ReusableLayoutBuilder.Allocate();
					try
					{
						Layout.RenderAppendBuilder(logEvent, lockOject2.Result);
						if (NewLine)
						{
							lockOject2.Result.Append(LineEnding.NewLineCharacters);
						}
						return GetBytesFromStringBuilder(lockOject.Result, lockOject2.Result);
					}
					finally
					{
						((IDisposable)lockOject2/*cast due to .constrained prefix*/).Dispose();
					}
				}
				finally
				{
					((IDisposable)lockOject/*cast due to .constrained prefix*/).Dispose();
				}
			}
			string text = Layout.Render(logEvent);
			InternalLogger.Trace("NetworkTarget(Name={0}): Sending: {1}", base.Name, text);
			if (NewLine)
			{
				text += LineEnding.NewLineCharacters;
			}
			return Encoding.GetBytes(text);
		}

		private byte[] GetBytesFromStringBuilder(char[] charBuffer, StringBuilder stringBuilder)
		{
			InternalLogger.Trace("NetworkTarget(Name={0}): Sending {1} chars", base.Name, stringBuilder.Length);
			if (stringBuilder.Length <= charBuffer.Length)
			{
				stringBuilder.CopyTo(0, charBuffer, 0, stringBuilder.Length);
				return Encoding.GetBytes(charBuffer, 0, stringBuilder.Length);
			}
			return Encoding.GetBytes(stringBuilder.ToString());
		}

		private byte[] GetBytesFromString(char[] charBuffer, string layoutMessage)
		{
			InternalLogger.Trace("NetworkTarget(Name={0}): Sending {1}", base.Name, layoutMessage);
			if (layoutMessage.Length <= charBuffer.Length)
			{
				layoutMessage.CopyTo(0, charBuffer, 0, layoutMessage.Length);
				return Encoding.GetBytes(charBuffer, 0, layoutMessage.Length);
			}
			return Encoding.GetBytes(layoutMessage);
		}

		private LinkedListNode<NetworkSender> GetCachedNetworkSender(string address)
		{
			lock (_currentSenderCache)
			{
				if (_currentSenderCache.TryGetValue(address, out var value))
				{
					value.Value.CheckSocket();
					return value;
				}
				if (_currentSenderCache.Count >= ConnectionCacheSize)
				{
					int num = 2147483647;
					LinkedListNode<NetworkSender> linkedListNode = null;
					foreach (KeyValuePair<string, LinkedListNode<NetworkSender>> item in _currentSenderCache)
					{
						NetworkSender value2 = item.Value.Value;
						if (value2.LastSendTime < num)
						{
							num = value2.LastSendTime;
							linkedListNode = item.Value;
						}
					}
					if (linkedListNode != null)
					{
						ReleaseCachedConnection(linkedListNode);
					}
				}
				NetworkSender value3 = CreateNetworkSender(address);
				lock (_openNetworkSenders)
				{
					value = _openNetworkSenders.AddLast(value3);
				}
				_currentSenderCache.Add(address, value);
				return value;
			}
		}

		private NetworkSender CreateNetworkSender(string address)
		{
			NetworkSender networkSender = SenderFactory.Create(address, MaxQueueSize, SslProtocols, TimeSpan.FromSeconds(KeepAliveTimeSeconds));
			networkSender.Initialize();
			return networkSender;
		}

		private void ReleaseCachedConnection(LinkedListNode<NetworkSender> senderNode)
		{
			lock (_currentSenderCache)
			{
				NetworkSender value = senderNode.Value;
				lock (_openNetworkSenders)
				{
					if (TryRemove(_openNetworkSenders, senderNode))
					{
						value.Close(delegate
						{
						});
					}
				}
				if (_currentSenderCache.TryGetValue(value.Address, out var value2) && senderNode == value2)
				{
					_currentSenderCache.Remove(value.Address);
				}
			}
		}

		private void ChunkedSend(NetworkSender sender, byte[] buffer, AsyncContinuation continuation)
		{
			int tosend = buffer.Length;
			int pos;
			if (tosend <= MaxMessageSize)
			{
				InternalLogger.Trace("NetworkTarget(Name={0}): Sending chunk, position: {1}, length: {2}", base.Name, 0, tosend);
				if (tosend <= 0)
				{
					continuation(null);
				}
				else
				{
					sender.Send(buffer, 0, tosend, continuation);
				}
			}
			else
			{
				pos = 0;
				SendNextChunk(null);
			}
			void SendNextChunk(Exception ex)
			{
				if (ex != null)
				{
					continuation(ex);
				}
				else
				{
					InternalLogger.Trace("NetworkTarget(Name={0}): Sending chunk, position: {1}, length: {2}", base.Name, pos, tosend);
					if (tosend <= 0)
					{
						continuation(null);
					}
					else
					{
						int num = tosend;
						if (num > MaxMessageSize)
						{
							if (OnOverflow == NetworkTargetOverflowAction.Discard)
							{
								InternalLogger.Trace("NetworkTarget(Name={0}): Discard because chunksize > this.MaxMessageSize", base.Name);
								continuation(null);
								return;
							}
							if (OnOverflow == NetworkTargetOverflowAction.Error)
							{
								continuation(new OverflowException($"Attempted to send a message larger than MaxMessageSize ({MaxMessageSize}). Actual size was: {buffer.Length}. Adjust OnOverflow and MaxMessageSize parameters accordingly."));
								return;
							}
							num = MaxMessageSize;
						}
						int offset = pos;
						tosend -= num;
						pos += num;
						sender.Send(buffer, offset, num, SendNextChunk);
					}
				}
			}
		}
	}
	public enum NetworkTargetConnectionsOverflowAction
	{
		AllowNewConnnection,
		DiscardMessage,
		Block
	}
	public enum NetworkTargetOverflowAction
	{
		Error,
		Split,
		Discard
	}
