		}

		public void PrecalculateVolatileLayouts(LogEventInfo logEvent)
		{
			if (!_allLayoutsAreThreadAgnostic || (_oneLayoutIsMutableUnsafe && !logEvent.IsLogEventMutableSafe()))
			{
