		public void WriteAsyncLogEvents(IList<AsyncLogEventInfo> logEvents)
		{
			if (logEvents == null || logEvents.Count == 0)
			{
				return;
			}
			if (!IsInitialized)
			{
				lock (SyncRoot)
				{
					for (int i = 0; i < logEvents.Count; i++)
					{
						logEvents[i].Continuation(null);
					}
					return;
				}
			}
			if (_initializeException != null)
			{
				lock (SyncRoot)
				{
					for (int j = 0; j < logEvents.Count; j++)
					{
						logEvents[j].Continuation(CreateInitException());
					}
					return;
				}
			}
			IList<AsyncLogEventInfo> list;
			if (OptimizeBufferReuse)
			{
				for (int k = 0; k < logEvents.Count; k++)
				{
					logEvents[k] = logEvents[k].LogEvent.WithContinuation(AsyncHelpers.PreventMultipleCalls(logEvents[k].Continuation));
				}
				list = logEvents;
			}
			else
			{
				AsyncLogEventInfo[] array = new AsyncLogEventInfo[logEvents.Count];
				for (int l = 0; l < logEvents.Count; l++)
				{
					AsyncLogEventInfo asyncLogEventInfo = logEvents[l];
					array[l] = asyncLogEventInfo.LogEvent.WithContinuation(AsyncHelpers.PreventMultipleCalls(asyncLogEventInfo.Continuation));
				}
				list = array;
			}
			try
			{
				WriteAsyncThreadSafe(list);
			}
			catch (Exception exception)
			{
				if (ExceptionMustBeRethrown(exception))
				{
					throw;
				}
				for (int m = 0; m < list.Count; m++)
				{
					list[m].Continuation(exception);
				}
			}
		}

		internal void Initialize(LoggingConfiguration configuration)
		{
			lock (SyncRoot)
			{
				LoggingConfiguration = configuration;
				if (IsInitialized)
				{
					return;
				}
				if (configuration == null)
				{
					PropertyHelper.CheckRequiredParameters(this);
				}
				try
				{
					InitializeTarget();
					_initializeException = null;
					if (!_scannedForLayouts)
					{
						InternalLogger.Debug("{0}: InitializeTarget is done but not scanned For Layouts", this);
						FindAllLayouts();
					}
				}
				catch (Exception ex)
				{
					InternalLogger.Error(ex, "{0}: Error initializing target", this);
					_initializeException = ex;
					if (ExceptionMustBeRethrown(ex))
					{
						throw;
					}
				}
				finally
				{
					_isInitialized = true;
				}
			}
		}

		internal void Close()
		{
			lock (SyncRoot)
			{
				LoggingConfiguration = null;
				if (!IsInitialized)
				{
					return;
				}
				_isInitialized = false;
				try
				{
					if (_initializeException == null)
					{
						InternalLogger.Debug("Closing target '{0}'.", this);
						CloseTarget();
						InternalLogger.Debug("Closed target '{0}'.", this);
					}
				}
				catch (Exception ex)
				{
					InternalLogger.Error(ex, "{0}: Error closing target", this);
					if (ExceptionMustBeRethrown(ex))
					{
						throw;
					}
				}
			}
		}

		protected virtual void Dispose(bool disposing)
