		}

		private void FindAllLayouts()
		{
			_allLayouts = ObjectGraphScanner.FindReachableObjects<Layout>(aggressiveSearch: false, new object[1] { this });
			InternalLogger.Trace("{0} has {1} layouts", this, _allLayouts.Count);
			_allLayoutsAreThreadAgnostic = _allLayouts.All((Layout layout) => layout.ThreadAgnostic);
			_oneLayoutIsMutableUnsafe = _allLayoutsAreThreadAgnostic && _allLayouts.Any((Layout layout) => layout.MutableUnsafe);
			if (!_allLayoutsAreThreadAgnostic || _oneLayoutIsMutableUnsafe)
			{
				_allLayoutsAreThreadSafe = _allLayouts.All((Layout layout) => layout.ThreadSafe);
			}
			StackTraceUsage = _allLayouts.DefaultIfEmpty().Max((Layout layout) => layout?.StackTraceUsage ?? StackTraceUsage.None);
			if (this is IUsesStackTrace usesStackTrace && usesStackTrace.StackTraceUsage > StackTraceUsage)
			{
				StackTraceUsage = usesStackTrace.StackTraceUsage;
			}
			_scannedForLayouts = true;
		}

