	[Target("Trace")]
	public sealed class TraceTarget : TargetWithLayout
	{
		[DefaultValue(false)]
		public bool RawWrite { get; set; }

		[DefaultValue(false)]
		public bool EnableTraceFail { get; set; }

		public TraceTarget()
		{
			base.OptimizeBufferReuse = true;
		}

		public TraceTarget(string name)
			: this()
		{
			base.Name = name;
		}

		protected override void Write(LogEventInfo logEvent)
		{
			string message = RenderLogEvent(Layout, logEvent);
			if (RawWrite || logEvent.Level <= LogLevel.Debug)
			{
				Trace.WriteLine(message);
			}
			else if (logEvent.Level == LogLevel.Info)
			{
				Trace.TraceInformation(message);
			}
			else if (logEvent.Level == LogLevel.Warn)
			{
				Trace.TraceWarning(message);
			}
			else if (logEvent.Level == LogLevel.Error)
			{
				Trace.TraceError(message);
			}
			else if (logEvent.Level >= LogLevel.Fatal)
			{
				if (EnableTraceFail)
				{
					Trace.Fail(message);
				}
				else
				{
					Trace.TraceError(message);
				}
			}
			else
			{
				Trace.WriteLine(message);
			}
		}
	}
