	[Target("WebService")]
	public sealed class WebServiceTarget : MethodCallTargetBase
	{
		private abstract class HttpPostFormatterBase
		{
			private string _contentType;

			protected string ContentType => _contentType ?? (_contentType = GetContentType(Target));

			protected WebServiceTarget Target { get; private set; }

			protected HttpPostFormatterBase(WebServiceTarget target)
			{
				Target = target;
			}

			protected virtual string GetContentType(WebServiceTarget target)
			{
				return "charset=" + target.Encoding.WebName;
			}

			public MemoryStream PrepareRequest(HttpWebRequest request, object[] parameterValues)
			{
				InitRequest(request);
				MemoryStream memoryStream = new MemoryStream();
				WriteContent(memoryStream, parameterValues);
				return memoryStream;
			}

			protected virtual void InitRequest(HttpWebRequest request)
			{
				request.Method = "POST";
				request.ContentType = ContentType;
			}

			protected abstract void WriteContent(MemoryStream ms, object[] parameterValues);
		}

		private class HttpPostFormEncodedFormatter : HttpPostTextFormatterBase
		{
			private readonly UrlHelper.EscapeEncodingOptions _encodingOptions;

			public HttpPostFormEncodedFormatter(WebServiceTarget target)
				: base(target)
			{
				_encodingOptions = UrlHelper.GetUriStringEncodingFlags(target.EscapeDataNLogLegacy, spaceAsPlus: true, target.EscapeDataRfc3986);
			}

			protected override string GetContentType(WebServiceTarget target)
			{
				return "application/x-www-form-urlencoded" + "; " + base.GetContentType(target);
			}

			protected override void WriteStringContent(StringBuilder builder, object[] parameterValues)
			{
				base.Target.BuildWebServiceQueryParameters(parameterValues, builder, _encodingOptions);
			}
		}

		private class HttpPostJsonFormatter : HttpPostTextFormatterBase
		{
			private IJsonConverter _jsonConverter;

			private IJsonConverter JsonConverter => _jsonConverter ?? (_jsonConverter = ConfigurationItemFactory.Default.JsonConverter);

			public HttpPostJsonFormatter(WebServiceTarget target)
				: base(target)
			{
			}

			protected override string GetContentType(WebServiceTarget target)
			{
				return "application/json" + "; " + base.GetContentType(target);
			}

			protected override void WriteStringContent(StringBuilder builder, object[] parameterValues)
			{
				if (base.Target.Parameters.Count == 1 && string.IsNullOrEmpty(base.Target.Parameters[0].Name) && parameterValues[0] is string value)
				{
					builder.Append(value);
					return;
				}
				builder.Append("{");
				string value2 = string.Empty;
				for (int i = 0; i < base.Target.Parameters.Count; i++)
				{
					MethodCallParameter methodCallParameter = base.Target.Parameters[i];
					builder.Append(value2);
					builder.Append('"');
					builder.Append(methodCallParameter.Name);
					builder.Append("\":");
					JsonConverter.SerializeObject(parameterValues[i], builder);
					value2 = ",";
				}
				builder.Append('}');
			}
		}

		private class HttpPostSoap11Formatter : HttpPostSoapFormatterBase
		{
			private readonly string _defaultSoapAction;

			protected override string SoapEnvelopeNamespace => "http://schemas.xmlsoap.org/soap/envelope/";

			protected override string SoapName => "soap";

			public HttpPostSoap11Formatter(WebServiceTarget target)
				: base(target)
			{
				_defaultSoapAction = HttpPostSoapFormatterBase.GetDefaultSoapAction(target);
			}

			protected override string GetContentType(WebServiceTarget target)
			{
				return "text/xml" + "; " + base.GetContentType(target);
			}

			protected override void InitRequest(HttpWebRequest request)
			{
				base.InitRequest(request);
				IList<MethodCallParameter> headers = base.Target.Headers;
				if ((headers != null && headers.Count == 0) || string.IsNullOrEmpty(request.Headers["SOAPAction"]))
				{
					request.Headers["SOAPAction"] = _defaultSoapAction;
				}
			}
		}

		private class HttpPostSoap12Formatter : HttpPostSoapFormatterBase
		{
			protected override string SoapEnvelopeNamespace => "http://www.w3.org/2003/05/soap-envelope";

			protected override string SoapName => "soap12";

			public HttpPostSoap12Formatter(WebServiceTarget target)
				: base(target)
			{
			}

			protected override string GetContentType(WebServiceTarget target)
			{
				return GetContentTypeSoap12(target, HttpPostSoapFormatterBase.GetDefaultSoapAction(target));
			}

			protected override void InitRequest(HttpWebRequest request)
			{
				base.InitRequest(request);
				IList<MethodCallParameter> headers = base.Target.Headers;
				string text = ((headers != null && headers.Count > 0) ? request.Headers["SOAPAction"] : string.Empty);
				if (!string.IsNullOrEmpty(text))
				{
					request.ContentType = GetContentTypeSoap12(base.Target, text);
				}
			}

			private string GetContentTypeSoap12(WebServiceTarget target, string soapAction)
			{
				return "application/soap+xml" + "; " + base.GetContentType(target) + "; action=\"" + soapAction + "\"";
			}
		}

		private abstract class HttpPostSoapFormatterBase : HttpPostXmlFormatterBase
		{
			private readonly XmlWriterSettings _xmlWriterSettings;

			protected abstract string SoapEnvelopeNamespace { get; }

			protected abstract string SoapName { get; }

			protected HttpPostSoapFormatterBase(WebServiceTarget target)
				: base(target)
			{
				_xmlWriterSettings = new XmlWriterSettings
				{
					Encoding = target.Encoding
				};
			}

			protected override void WriteContent(MemoryStream ms, object[] parameterValues)
			{
				XmlWriter xmlWriter = XmlWriter.Create(ms, _xmlWriterSettings);
				xmlWriter.WriteStartElement(SoapName, "Envelope", SoapEnvelopeNamespace);
				xmlWriter.WriteStartElement("Body", SoapEnvelopeNamespace);
				xmlWriter.WriteStartElement(base.Target.MethodName, base.Target.Namespace);
				WriteAllParametersToCurrenElement(xmlWriter, parameterValues);
				xmlWriter.WriteEndElement();
				xmlWriter.WriteEndElement();
				xmlWriter.WriteEndElement();
				xmlWriter.Flush();
			}

			protected static string GetDefaultSoapAction(WebServiceTarget target)
			{
				if (!target.Namespace.EndsWith("/", StringComparison.Ordinal))
				{
					return target.Namespace + "/" + target.MethodName;
				}
				return target.Namespace + target.MethodName;
			}
		}

		private abstract class HttpPostTextFormatterBase : HttpPostFormatterBase
		{
			private readonly ReusableBuilderCreator _reusableStringBuilder = new ReusableBuilderCreator();

			private readonly ReusableBufferCreator _reusableEncodingBuffer = new ReusableBufferCreator(1024);

			private readonly byte[] _encodingPreamble;

			protected HttpPostTextFormatterBase(WebServiceTarget target)
				: base(target)
			{
				_encodingPreamble = target.Encoding.GetPreamble();
			}

			protected override void WriteContent(MemoryStream ms, object[] parameterValues)
			{
				lock (_reusableStringBuilder)
				{
					ReusableObjectCreator<StringBuilder>.LockOject lockOject = _reusableStringBuilder.Allocate();
					try
					{
						WriteStringContent(lockOject.Result, parameterValues);
						ReusableObjectCreator<char[]>.LockOject lockOject2 = _reusableEncodingBuffer.Allocate();
						try
						{
							if (_encodingPreamble.Length != 0)
							{
								ms.Write(_encodingPreamble, 0, _encodingPreamble.Length);
							}
							lockOject.Result.CopyToStream(ms, base.Target.Encoding, lockOject2.Result);
						}
						finally
						{
							((IDisposable)lockOject2/*cast due to .constrained prefix*/).Dispose();
						}
					}
					finally
					{
						((IDisposable)lockOject/*cast due to .constrained prefix*/).Dispose();
					}
				}
			}

			protected abstract void WriteStringContent(StringBuilder builder, object[] parameterValues);
		}

		private class HttpPostXmlDocumentFormatter : HttpPostXmlFormatterBase
		{
			private readonly XmlWriterSettings _xmlWriterSettings;

			public HttpPostXmlDocumentFormatter(WebServiceTarget target)
				: base(target)
			{
				if (string.IsNullOrEmpty(target.XmlRoot))
				{
					throw new InvalidOperationException("WebServiceProtocol.Xml requires WebServiceTarget.XmlRoot to be set.");
				}
				_xmlWriterSettings = new XmlWriterSettings
				{
					Encoding = target.Encoding,
					OmitXmlDeclaration = true,
					Indent = false
				};
			}

			protected override string GetContentType(WebServiceTarget target)
			{
				return "application/xml" + "; " + base.GetContentType(target);
			}

			protected override void WriteContent(MemoryStream ms, object[] parameterValues)
			{
				XmlWriter xmlWriter = XmlWriter.Create(ms, _xmlWriterSettings);
				xmlWriter.WriteStartElement(base.Target.XmlRoot, base.Target.XmlRootNamespace);
				WriteAllParametersToCurrenElement(xmlWriter, parameterValues);
				xmlWriter.WriteEndElement();
				xmlWriter.Flush();
			}
		}

		private abstract class HttpPostXmlFormatterBase : HttpPostFormatterBase
		{
			protected HttpPostXmlFormatterBase(WebServiceTarget target)
				: base(target)
			{
			}

			protected void WriteAllParametersToCurrenElement(XmlWriter currentXmlWriter, object[] parameterValues)
			{
				for (int i = 0; i < base.Target.Parameters.Count; i++)
				{
					string value = XmlHelper.XmlConvertToStringSafe(parameterValues[i]);
					currentXmlWriter.WriteElementString(base.Target.Parameters[i].Name, value);
				}
			}
		}

		private const string SoapEnvelopeNamespaceUri = "http://schemas.xmlsoap.org/soap/envelope/";

		private const string Soap12EnvelopeNamespaceUri = "http://www.w3.org/2003/05/soap-envelope";

		private static Dictionary<WebServiceProtocol, Func<WebServiceTarget, HttpPostFormatterBase>> _postFormatterFactories = new Dictionary<WebServiceProtocol, Func<WebServiceTarget, HttpPostFormatterBase>>
		{
			{
				WebServiceProtocol.Soap11,
				(WebServiceTarget t) => new HttpPostSoap11Formatter(t)
			},
			{
				WebServiceProtocol.Soap12,
				(WebServiceTarget t) => new HttpPostSoap12Formatter(t)
			},
			{
				WebServiceProtocol.HttpPost,
				(WebServiceTarget t) => new HttpPostFormEncodedFormatter(t)
			},
			{
				WebServiceProtocol.JsonPost,
				(WebServiceTarget t) => new HttpPostJsonFormatter(t)
			},
			{
				WebServiceProtocol.XmlPost,
				(WebServiceTarget t) => new HttpPostXmlDocumentFormatter(t)
			}
		};

		private KeyValuePair<WebServiceProtocol, HttpPostFormatterBase> _activeProtocol;

		private KeyValuePair<WebServiceProxyType, IWebProxy> _activeProxy;

		private readonly AsyncOperationCounter _pendingManualFlushList = new AsyncOperationCounter();

		public Uri Url { get; set; }

		public string MethodName { get; set; }

		public string Namespace { get; set; }

		[DefaultValue("Soap11")]
		public WebServiceProtocol Protocol
		{
			get
			{
				return _activeProtocol.Key;
			}
			set
			{
				_activeProtocol = new KeyValuePair<WebServiceProtocol, HttpPostFormatterBase>(value, null);
			}
		}

		[DefaultValue("DefaultWebProxy")]
		public WebServiceProxyType ProxyType
		{
			get
			{
				return _activeProxy.Key;
			}
			set
			{
				_activeProxy = new KeyValuePair<WebServiceProxyType, IWebProxy>(value, null);
			}
		}

		public string ProxyAddress { get; set; }

		public bool? IncludeBOM { get; set; }

		public Encoding Encoding { get; set; }

		public bool EscapeDataRfc3986 { get; set; }

		public bool EscapeDataNLogLegacy { get; set; }

		public string XmlRoot { get; set; }

		public string XmlRootNamespace { get; set; }

		[ArrayParameter(typeof(MethodCallParameter), "header")]
		public IList<MethodCallParameter> Headers { get; private set; }

		public bool PreAuthenticate { get; set; }

		public WebServiceTarget()
		{
			Protocol = WebServiceProtocol.Soap11;
			Encoding = new UTF8Encoding(encoderShouldEmitUTF8Identifier: false);
			IncludeBOM = false;
			base.OptimizeBufferReuse = true;
			Headers = new List<MethodCallParameter>();
		}

		public WebServiceTarget(string name)
			: this()
		{
			base.Name = name;
		}

		protected override void DoInvoke(object[] parameters)
		{
			throw new NotImplementedException();
		}

		protected override void DoInvoke(object[] parameters, AsyncContinuation continuation)
		{
			HttpWebRequest webRequest = (HttpWebRequest)WebRequest.Create(BuildWebServiceUrl(parameters));
			DoInvoke(parameters, webRequest, continuation);
		}

		protected override void DoInvoke(object[] parameters, AsyncLogEventInfo logEvent)
		{
			HttpWebRequest httpWebRequest = (HttpWebRequest)WebRequest.Create(BuildWebServiceUrl(parameters));
			if (Headers != null && Headers.Count > 0)
			{
				for (int i = 0; i < Headers.Count; i++)
				{
					string text = RenderLogEvent(Headers[i].Layout, logEvent.LogEvent);
					if (text != null)
					{
						httpWebRequest.Headers[Headers[i].Name] = text;
					}
				}
			}
			DoInvoke(parameters, httpWebRequest, logEvent.Continuation);
		}

		private void DoInvoke(object[] parameters, HttpWebRequest webRequest, AsyncContinuation continuation)
		{
			Func<HttpWebRequest, AsyncCallback, IAsyncResult> beginGetRequest = (HttpWebRequest request, AsyncCallback result) => request.BeginGetRequestStream(result, null);
			Func<HttpWebRequest, IAsyncResult, Stream> getRequestStream = (HttpWebRequest request, IAsyncResult result) => request.EndGetRequestStream(result);
			switch (ProxyType)
			{
			case WebServiceProxyType.AutoProxy:
				if (_activeProxy.Value == null)
				{
					IWebProxy systemWebProxy = WebRequest.GetSystemWebProxy();
					systemWebProxy.Credentials = CredentialCache.DefaultCredentials;
					_activeProxy = new KeyValuePair<WebServiceProxyType, IWebProxy>(ProxyType, systemWebProxy);
				}
				webRequest.Proxy = _activeProxy.Value;
				break;
			case WebServiceProxyType.ProxyAddress:
				if (!string.IsNullOrEmpty(ProxyAddress))
				{
					if (_activeProxy.Value == null)
					{
						IWebProxy value = new WebProxy(ProxyAddress, BypassOnLocal: true);
						_activeProxy = new KeyValuePair<WebServiceProxyType, IWebProxy>(ProxyType, value);
					}
					webRequest.Proxy = _activeProxy.Value;
				}
				break;
			default:
				webRequest.Proxy = null;
				break;
			case WebServiceProxyType.DefaultWebProxy:
				break;
			}
			if (PreAuthenticate || ProxyType == WebServiceProxyType.AutoProxy)
			{
				webRequest.PreAuthenticate = true;
			}
			DoInvoke(parameters, continuation, webRequest, beginGetRequest, getRequestStream);
		}

		internal void DoInvoke(object[] parameters, AsyncContinuation continuation, HttpWebRequest webRequest, Func<HttpWebRequest, AsyncCallback, IAsyncResult> beginGetRequest, Func<HttpWebRequest, IAsyncResult, Stream> getRequestStream)
		{
			Stream postPayload = null;
			if (Protocol == WebServiceProtocol.HttpGet)
			{
				PrepareGetRequest(webRequest);
			}
			else
			{
				if (_activeProtocol.Value == null)
				{
					_activeProtocol = new KeyValuePair<WebServiceProtocol, HttpPostFormatterBase>(Protocol, _postFormatterFactories[Protocol](this));
				}
				postPayload = _activeProtocol.Value.PrepareRequest(webRequest, parameters);
			}
			AsyncContinuation sendContinuation = CreateSendContinuation(continuation, webRequest);
			PostPayload(continuation, webRequest, beginGetRequest, getRequestStream, postPayload, sendContinuation);
		}

		private AsyncContinuation CreateSendContinuation(AsyncContinuation continuation, HttpWebRequest webRequest)
		{
			return delegate(Exception ex)
			{
				if (ex != null)
				{
					DoInvokeCompleted(continuation, ex);
					return;
				}
				try
				{
					webRequest.BeginGetResponse(delegate(IAsyncResult r)
					{
						try
						{
							using (webRequest.EndGetResponse(r))
							{
							}
							DoInvokeCompleted(continuation, null);
						}
						catch (Exception ex3)
						{
							InternalLogger.Error(ex3, "WebServiceTarget(Name={0}): Error sending request", base.Name);
							if (ex3.MustBeRethrownImmediately())
							{
								throw;
							}
							DoInvokeCompleted(continuation, ex3);
						}
					}, null);
				}
				catch (Exception ex2)
				{
					InternalLogger.Error(ex2, "WebServiceTarget(Name={0}): Error starting request", base.Name);
					if (ExceptionMustBeRethrown(ex2))
					{
						throw;
					}
					DoInvokeCompleted(continuation, ex2);
				}
			};
		}

		private void PostPayload(AsyncContinuation continuation, HttpWebRequest webRequest, Func<HttpWebRequest, AsyncCallback, IAsyncResult> beginGetRequest, Func<HttpWebRequest, IAsyncResult, Stream> getRequestStream, Stream postPayload, AsyncContinuation sendContinuation)
		{
			if (postPayload != null && postPayload.Length > 0)
			{
				postPayload.Position = 0L;
				try
				{
					_pendingManualFlushList.BeginOperation();
					beginGetRequest(webRequest, delegate(IAsyncResult result)
					{
						try
						{
							using (Stream output = getRequestStream(webRequest, result))
							{
								WriteStreamAndFixPreamble(postPayload, output, IncludeBOM, Encoding);
								postPayload.Dispose();
							}
							sendContinuation(null);
						}
						catch (Exception ex2)
						{
							InternalLogger.Error(ex2, "WebServiceTarget(Name={0}): Error sending post data", base.Name);
							if (ex2.MustBeRethrownImmediately())
							{
								throw;
							}
							postPayload.Dispose();
							DoInvokeCompleted(continuation, ex2);
						}
					});
					return;
				}
				catch (Exception ex)
				{
					InternalLogger.Error(ex, "WebServiceTarget(Name={0}): Error starting post data", base.Name);
					if (ExceptionMustBeRethrown(ex))
					{
						throw;
					}
					DoInvokeCompleted(continuation, ex);
					return;
				}
			}
			_pendingManualFlushList.BeginOperation();
			sendContinuation(null);
		}

		private void DoInvokeCompleted(AsyncContinuation continuation, Exception ex)
		{
			_pendingManualFlushList.CompleteOperation(ex);
			continuation(ex);
		}

		protected override void FlushAsync(AsyncContinuation asyncContinuation)
		{
			_pendingManualFlushList.RegisterCompletionNotification(asyncContinuation)(null);
		}

		protected override void CloseTarget()
		{
			_pendingManualFlushList.Clear();
			base.CloseTarget();
		}

		private Uri BuildWebServiceUrl(object[] parameterValues)
		{
			if (Protocol != WebServiceProtocol.HttpGet)
			{
				return Url;
			}
			ReusableObjectCreator<StringBuilder>.LockOject lockOject = (base.OptimizeBufferReuse ? ReusableLayoutBuilder.Allocate() : ReusableLayoutBuilder.None);
			string text;
			try
			{
				StringBuilder stringBuilder = lockOject.Result ?? new StringBuilder();
				UrlHelper.EscapeEncodingOptions uriStringEncodingFlags = UrlHelper.GetUriStringEncodingFlags(EscapeDataNLogLegacy, spaceAsPlus: false, EscapeDataRfc3986);
				BuildWebServiceQueryParameters(parameterValues, stringBuilder, uriStringEncodingFlags);
				text = stringBuilder.ToString();
			}
			finally
			{
				((IDisposable)lockOject/*cast due to .constrained prefix*/).Dispose();
			}
			UriBuilder uriBuilder = new UriBuilder(Url);
			if (uriBuilder.Query != null && uriBuilder.Query.Length > 1)
			{
				uriBuilder.Query = uriBuilder.Query.Substring(1) + "&" + text;
			}
			else
			{
				uriBuilder.Query = text;
			}
			return uriBuilder.Uri;
		}

		private void BuildWebServiceQueryParameters(object[] parameterValues, StringBuilder sb, UrlHelper.EscapeEncodingOptions encodingOptions)
		{
			string value = string.Empty;
			for (int i = 0; i < base.Parameters.Count; i++)
			{
				sb.Append(value);
				sb.Append(base.Parameters[i].Name);
				sb.Append("=");
				string text = XmlHelper.XmlConvertToString(parameterValues[i]);
				if (!string.IsNullOrEmpty(text))
				{
					UrlHelper.EscapeDataEncode(text, sb, encodingOptions);
				}
				value = "&";
			}
		}

		private void PrepareGetRequest(HttpWebRequest webRequest)
		{
			webRequest.Method = "GET";
		}

		private static void WriteStreamAndFixPreamble(Stream input, Stream output, bool? writeUtf8BOM, Encoding encoding)
		{
			bool flag = !writeUtf8BOM.HasValue || !(encoding is UTF8Encoding);
			if (!flag)
			{
				bool flag2 = encoding.GetPreamble().Length == 3;
				flag = (writeUtf8BOM.Value && flag2) || (!writeUtf8BOM.Value && !flag2);
			}
			int offset = ((!flag) ? 3 : 0);
			input.CopyWithOffset(output, offset);
		}
	}
}
namespace NLog.Targets.Wrappers
{
	internal class AsyncRequestQueue : AsyncRequestQueueBase
	{
		private readonly Queue<AsyncLogEventInfo> _logEventInfoQueue = new Queue<AsyncLogEventInfo>(1000);

		public int RequestCount
		{
			get
			{
				lock (_logEventInfoQueue)
				{
					return _logEventInfoQueue.Count;
				}
			}
		}

		public override bool IsEmpty => RequestCount == 0;

		public AsyncRequestQueue(int requestLimit, AsyncTargetWrapperOverflowAction overflowAction)
		{
			base.RequestLimit = requestLimit;
			base.OnOverflow = overflowAction;
		}

		public override bool Enqueue(AsyncLogEventInfo logEventInfo)
		{
			lock (_logEventInfoQueue)
			{
				if (_logEventInfoQueue.Count >= base.RequestLimit)
				{
					InternalLogger.Debug("Async queue is full");
					switch (base.OnOverflow)
					{
					case AsyncTargetWrapperOverflowAction.Discard:
						InternalLogger.Debug("Discarding one element from queue");
						OnLogEventDropped(_logEventInfoQueue.Dequeue().LogEvent);
						break;
					case AsyncTargetWrapperOverflowAction.Grow:
						InternalLogger.Debug("The overflow action is Grow, adding element anyway");
						OnLogEventQueueGrows(RequestCount + 1);
						base.RequestLimit *= 2;
						break;
					case AsyncTargetWrapperOverflowAction.Block:
						while (_logEventInfoQueue.Count >= base.RequestLimit)
						{
							InternalLogger.Debug("Blocking because the overflow action is Block...");
							Monitor.Wait(_logEventInfoQueue);
							InternalLogger.Trace("Entered critical section.");
						}
						InternalLogger.Trace("Async queue limit ok.");
						break;
					}
				}
				_logEventInfoQueue.Enqueue(logEventInfo);
				return _logEventInfoQueue.Count == 1;
			}
		}

		public override AsyncLogEventInfo[] DequeueBatch(int count)
		{
			AsyncLogEventInfo[] array;
			lock (_logEventInfoQueue)
			{
				if (_logEventInfoQueue.Count < count)
				{
					count = _logEventInfoQueue.Count;
				}
				if (count == 0)
				{
					return ArrayHelper.Empty<AsyncLogEventInfo>();
				}
				array = new AsyncLogEventInfo[count];
				for (int i = 0; i < count; i++)
				{
					array[i] = _logEventInfoQueue.Dequeue();
				}
				if (base.OnOverflow == AsyncTargetWrapperOverflowAction.Block)
				{
					Monitor.PulseAll(_logEventInfoQueue);
				}
			}
			return array;
		}

		public override void DequeueBatch(int count, IList<AsyncLogEventInfo> result)
		{
			lock (_logEventInfoQueue)
			{
				if (_logEventInfoQueue.Count < count)
				{
					count = _logEventInfoQueue.Count;
				}
				for (int i = 0; i < count; i++)
				{
					result.Add(_logEventInfoQueue.Dequeue());
				}
				if (base.OnOverflow == AsyncTargetWrapperOverflowAction.Block)
				{
					Monitor.PulseAll(_logEventInfoQueue);
				}
			}
		}

		public override void Clear()
		{
			lock (_logEventInfoQueue)
			{
				_logEventInfoQueue.Clear();
				if (base.OnOverflow == AsyncTargetWrapperOverflowAction.Block)
				{
					Monitor.PulseAll(_logEventInfoQueue);
				}
			}
		}
	}
	internal abstract class AsyncRequestQueueBase
	{
		public abstract bool IsEmpty { get; }

		public int RequestLimit { get; set; }

		public AsyncTargetWrapperOverflowAction OnOverflow { get; set; }

		public event EventHandler<LogEventDroppedEventArgs> LogEventDropped;

		public event EventHandler<LogEventQueueGrowEventArgs> LogEventQueueGrow;

		public abstract bool Enqueue(AsyncLogEventInfo logEventInfo);

		public abstract AsyncLogEventInfo[] DequeueBatch(int count);

		public abstract void DequeueBatch(int count, IList<AsyncLogEventInfo> result);

		public abstract void Clear();

		protected void OnLogEventDropped(LogEventInfo logEventInfo)
		{
			this.LogEventDropped?.Invoke(this, new LogEventDroppedEventArgs(logEventInfo));
		}

		protected void OnLogEventQueueGrows(long requestsCount)
		{
			this.LogEventQueueGrow?.Invoke(this, new LogEventQueueGrowEventArgs(RequestLimit, requestsCount));
		}
	}
	[Target("AsyncWrapper", IsWrapper = true)]
	public class AsyncTargetWrapper : WrapperTargetBase
	{
		private readonly object _writeLockObject = new object();

		private readonly object _timerLockObject = new object();

		private Timer _lazyWriterTimer;

		private readonly ReusableAsyncLogEventList _reusableAsyncLogEventList = new ReusableAsyncLogEventList(200);

		private bool? _forceLockingQueue;

		private AsyncRequestQueueBase _requestQueue;

		private AsyncHelpersTask? _flushEventsInQueueDelegate;

		[DefaultValue(200)]
		public int BatchSize { get; set; }

		[DefaultValue(1)]
		public int TimeToSleepBetweenBatches { get; set; }

		[DefaultValue("Discard")]
		public AsyncTargetWrapperOverflowAction OverflowAction
		{
			get
			{
				return _requestQueue.OnOverflow;
			}
			set
			{
				_requestQueue.OnOverflow = value;
			}
		}

		[DefaultValue(10000)]
		public int QueueLimit
		{
			get
			{
				return _requestQueue.RequestLimit;
			}
			set
			{
				_requestQueue.RequestLimit = value;
			}
		}

		[DefaultValue(5)]
		public int FullBatchSizeWriteLimit { get; set; }

		[DefaultValue(false)]
		public bool ForceLockingQueue
		{
			get
			{
				return _forceLockingQueue ?? false;
			}
			set
			{
				_forceLockingQueue = value;
			}
		}

		private event EventHandler<LogEventDroppedEventArgs> _logEventDroppedEvent;

		private event EventHandler<LogEventQueueGrowEventArgs> _eventQueueGrowEvent;

		public event EventHandler<LogEventDroppedEventArgs> LogEventDropped
		{
			add
			{
				if (this._logEventDroppedEvent == null && _requestQueue != null)
				{
					_requestQueue.LogEventDropped += OnRequestQueueDropItem;
				}
				_logEventDroppedEvent += value;
			}
			remove
			{
				_logEventDroppedEvent -= value;
				if (this._logEventDroppedEvent == null && _requestQueue != null)
				{
					_requestQueue.LogEventDropped -= OnRequestQueueDropItem;
				}
			}
		}

		public event EventHandler<LogEventQueueGrowEventArgs> EventQueueGrow
		{
			add
			{
				if (this._eventQueueGrowEvent == null && _requestQueue != null)
				{
					_requestQueue.LogEventQueueGrow += OnRequestQueueGrow;
				}
				_eventQueueGrowEvent += value;
			}
			remove
			{
				_eventQueueGrowEvent -= value;
				if (this._eventQueueGrowEvent == null && _requestQueue != null)
				{
					_requestQueue.LogEventQueueGrow -= OnRequestQueueGrow;
				}
			}
		}

		public AsyncTargetWrapper()
			: this(null)
		{
		}

		public AsyncTargetWrapper(string name, Target wrappedTarget)
			: this(wrappedTarget)
		{
			base.Name = name;
		}

		public AsyncTargetWrapper(Target wrappedTarget)
			: this(wrappedTarget, 10000, AsyncTargetWrapperOverflowAction.Discard)
		{
		}

		public AsyncTargetWrapper(Target wrappedTarget, int queueLimit, AsyncTargetWrapperOverflowAction overflowAction)
		{
			_requestQueue = new AsyncRequestQueue(10000, AsyncTargetWrapperOverflowAction.Discard);
			TimeToSleepBetweenBatches = 1;
			BatchSize = 200;
			FullBatchSizeWriteLimit = 5;
			base.WrappedTarget = wrappedTarget;
			QueueLimit = queueLimit;
			OverflowAction = overflowAction;
		}

		protected override void FlushAsync(AsyncContinuation asyncContinuation)
		{
			if (!_flushEventsInQueueDelegate.HasValue)
			{
				_flushEventsInQueueDelegate = new AsyncHelpersTask(FlushEventsInQueue);
			}
			AsyncHelpers.StartAsyncTask(_flushEventsInQueueDelegate.Value, asyncContinuation);
		}

		protected override void InitializeTarget()
		{
			base.InitializeTarget();
			if (!base.OptimizeBufferReuse && base.WrappedTarget != null && base.WrappedTarget.OptimizeBufferReuse)
			{
				base.OptimizeBufferReuse = GetType() == typeof(AsyncTargetWrapper);
				if (!base.OptimizeBufferReuse && !ForceLockingQueue)
				{
					ForceLockingQueue = true;
				}
			}
			if (!ForceLockingQueue && OverflowAction == AsyncTargetWrapperOverflowAction.Block && (decimal)BatchSize * 1.5m > (decimal)QueueLimit)
