				finally
				{
					Monitor.Exit(_writeLockObject);
				}
			}
			if (OverflowAction == AsyncTargetWrapperOverflowAction.Block)
			{
				_requestQueue.Clear();
			}
			base.CloseTarget();
		}

		protected virtual void StartLazyWriterTimer()
