	[Target("SplitGroup", IsCompound = true)]
	public class SplitGroupTarget : CompoundTargetBase
	{
		public SplitGroupTarget()
			: this(new Target[0])
		{
		}

		public SplitGroupTarget(string name, params Target[] targets)
			: this(targets)
		{
			base.Name = name;
		}

		public SplitGroupTarget(params Target[] targets)
			: base(targets)
		{
		}

		protected override void Write(AsyncLogEventInfo logEvent)
		{
			if (base.Targets.Count == 0)
			{
				logEvent.Continuation(null);
				return;
			}
			if (base.Targets.Count > 1)
			{
				logEvent = logEvent.LogEvent.WithContinuation(CreateCountedContinuation(logEvent.Continuation, base.Targets.Count));
			}
			for (int i = 0; i < base.Targets.Count; i++)
			{
				base.Targets[i].WriteAsyncLogEvent(logEvent);
			}
		}

		[Obsolete("Instead override Write(IList<AsyncLogEventInfo> logEvents. Marked obsolete on NLog 4.5")]
		protected override void Write(AsyncLogEventInfo[] logEvents)
		{
			Write((IList<AsyncLogEventInfo>)logEvents);
		}

		protected override void Write(IList<AsyncLogEventInfo> logEvents)
		{
			InternalLogger.Trace("SplitGroup(Name={0}): Writing {1} events", base.Name, logEvents.Count);
			if (logEvents.Count == 1)
			{
				Write(logEvents[0]);
				return;
			}
			if (base.Targets.Count == 0 || logEvents.Count == 0)
			{
				for (int i = 0; i < logEvents.Count; i++)
				{
					logEvents[i].Continuation(null);
				}
				return;
			}
			if (base.Targets.Count > 1)
			{
				for (int j = 0; j < logEvents.Count; j++)
				{
					AsyncLogEventInfo asyncLogEventInfo = logEvents[j];
					logEvents[j] = asyncLogEventInfo.LogEvent.WithContinuation(CreateCountedContinuation(asyncLogEventInfo.Continuation, base.Targets.Count));
				}
			}
			for (int k = 0; k < base.Targets.Count; k++)
			{
				InternalLogger.Trace("SplitGroup(Name={0}): Sending {1} events to {2}", base.Name, logEvents.Count, base.Targets[k]);
				IList<AsyncLogEventInfo> logEvents2 = logEvents;
				if (k < base.Targets.Count - 1)
				{
					AsyncLogEventInfo[] array = new AsyncLogEventInfo[logEvents.Count];
					logEvents.CopyTo(array, 0);
					logEvents2 = array;
				}
				base.Targets[k].WriteAsyncLogEvents(logEvents2);
			}
		}

		private static AsyncContinuation CreateCountedContinuation(AsyncContinuation originalContinuation, int targetCounter)
		{
			List<Exception> exceptions = new List<Exception>();
			return delegate(Exception ex)
			{
				if (ex != null)
				{
					lock (exceptions)
					{
						exceptions.Add(ex);
					}
				}
				int num = Interlocked.Decrement(ref targetCounter);
				if (num == 0)
				{
					Exception combinedException = AsyncHelpers.GetCombinedException(exceptions);
					InternalLogger.Trace("SplitGroup: Combined exception: {0}", combinedException);
					originalContinuation(combinedException);
				}
				else
				{
					InternalLogger.Trace("SplitGroup: {0} remaining.", num);
				}
			};
		}
	}
	public abstract class WrapperTargetBase : Target
	{
		[RequiredParameter]
		public Target WrappedTarget { get; set; }

		public override string ToString()
		{
			return $"{base.ToString()}({WrappedTarget})";
		}

		protected override void FlushAsync(AsyncContinuation asyncContinuation)
		{
			WrappedTarget.Flush(asyncContinuation);
		}

		protected sealed override void Write(LogEventInfo logEvent)
		{
			throw new NotSupportedException("This target must not be invoked in a synchronous way.");
		}
	}
}
namespace NLog.Targets.FileArchiveModes
{
	internal abstract class FileArchiveModeBase : IFileArchiveMode
	{
		internal sealed class FileNameTemplate
		{
			public const string PatternStartCharacters = "{#";

			public const string PatternEndCharacters = "#}";

			public string Template { get; private set; }

			public int BeginAt { get; private set; }

			public int EndAt { get; private set; }

			private bool FoundPattern
			{
				get
				{
					if (BeginAt != -1)
					{
						return EndAt != -1;
					}
					return false;
				}
			}

			public FileNameTemplate(string template)
			{
				Template = template;
				BeginAt = template.IndexOf("{#", StringComparison.Ordinal);
				if (BeginAt != -1)
				{
					EndAt = template.IndexOf("#}", StringComparison.Ordinal) + "#}".Length;
				}
			}

			public string ReplacePattern(string replacementValue)
			{
				if (FoundPattern && !string.IsNullOrEmpty(replacementValue))
				{
					return Template.Substring(0, BeginAt) + replacementValue + Template.Substring(EndAt);
				}
				return Template;
			}
		}

		private static readonly DateTime MaxAgeArchiveFileDate = new DateTime(1900, 1, 1, 0, 0, 0, DateTimeKind.Utc);

		private int _lastArchiveFileCount = 65534;

		private DateTime _oldestArchiveFileDate = MaxAgeArchiveFileDate;

		public bool IsArchiveCleanupEnabled { get; }

		protected FileArchiveModeBase(bool isArchiveCleanupEnabled)
		{
			IsArchiveCleanupEnabled = isArchiveCleanupEnabled;
		}

		public virtual bool AttemptCleanupOnInitializeFile(string archiveFilePath, int maxArchiveFiles, int maxArchiveDays)
		{
			if (maxArchiveFiles > 0 && _lastArchiveFileCount++ > maxArchiveFiles)
			{
				return true;
			}
			if (maxArchiveDays > 0 && (TimeSource.Current.Time.Date.ToUniversalTime() - _oldestArchiveFileDate.Date).TotalDays > (double)maxArchiveDays)
			{
				return true;
			}
			return false;
		}

		public string GenerateFileNameMask(string archiveFilePath)
		{
			int lastArchiveFileCount = _lastArchiveFileCount;
			DateTime oldestArchiveFileDate = _oldestArchiveFileDate;
			string result = GenerateFileNameMask(archiveFilePath, GenerateFileNameTemplate(archiveFilePath));
			_lastArchiveFileCount = lastArchiveFileCount;
			_oldestArchiveFileDate = oldestArchiveFileDate;
			return result;
		}

		public virtual List<DateAndSequenceArchive> GetExistingArchiveFiles(string archiveFilePath)
		{
			_lastArchiveFileCount = 65534;
			_oldestArchiveFileDate = MaxAgeArchiveFileDate;
			string directoryName = Path.GetDirectoryName(archiveFilePath);
			FileNameTemplate fileTemplate = GenerateFileNameTemplate(archiveFilePath);
			string text = GenerateFileNameMask(archiveFilePath, fileTemplate);
			List<DateAndSequenceArchive> list = new List<DateAndSequenceArchive>();
			if (string.IsNullOrEmpty(text))
			{
				return list;
			}
			DirectoryInfo directoryInfo = new DirectoryInfo(directoryName);
			if (!directoryInfo.Exists)
			{
				return list;
			}
			FileInfo[] files = directoryInfo.GetFiles(text);
			foreach (FileInfo archiveFile in files)
			{
				DateAndSequenceArchive dateAndSequenceArchive = GenerateArchiveFileInfo(archiveFile, fileTemplate);
				if (dateAndSequenceArchive != null)
				{
					list.Add(dateAndSequenceArchive);
				}
			}
			if (list.Count > 1)
			{
				list.Sort((DateAndSequenceArchive x, DateAndSequenceArchive y) => FileSortOrderComparison(x, y));
			}
			UpdateMaxArchiveState(list);
			return list;
		}

		protected void UpdateMaxArchiveState(List<DateAndSequenceArchive> existingArchiveFiles)
		{
			_lastArchiveFileCount = existingArchiveFiles.Count;
			_oldestArchiveFileDate = ((existingArchiveFiles.Count == 0) ? DateTime.UtcNow : existingArchiveFiles[0].Date.Date.ToUniversalTime());
		}

		private static int FileSortOrderComparison(DateAndSequenceArchive x, DateAndSequenceArchive y)
		{
			if (x.Date != y.Date && !x.HasSameFormattedDate(y.Date))
			{
				return x.Date.CompareTo(y.Date);
			}
			if (x.Sequence.CompareTo(y.Sequence) != 0)
			{
				return x.Sequence.CompareTo(y.Sequence);
			}
			return string.CompareOrdinal(x.FileName, y.FileName);
		}

		protected virtual FileNameTemplate GenerateFileNameTemplate(string archiveFilePath)
		{
			_lastArchiveFileCount++;
			return new FileNameTemplate(Path.GetFileName(archiveFilePath));
		}

		protected virtual string GenerateFileNameMask(string archiveFilePath, FileNameTemplate fileTemplate)
		{
			if (fileTemplate != null)
			{
				return fileTemplate.ReplacePattern("*");
			}
			return string.Empty;
		}

		protected abstract DateAndSequenceArchive GenerateArchiveFileInfo(FileInfo archiveFile, FileNameTemplate fileTemplate);

		public abstract DateAndSequenceArchive GenerateArchiveFileName(string archiveFilePath, DateTime archiveDate, List<DateAndSequenceArchive> existingArchiveFiles);

		public virtual IEnumerable<DateAndSequenceArchive> CheckArchiveCleanup(string archiveFilePath, List<DateAndSequenceArchive> existingArchiveFiles, int maxArchiveFiles, int maxArchiveDays)
		{
			if (maxArchiveFiles <= 0 && maxArchiveDays <= 0)
			{
				yield break;
			}
			UpdateMaxArchiveState(existingArchiveFiles);
			if (existingArchiveFiles.Count == 0 || (maxArchiveFiles > 0 && existingArchiveFiles.Count <= maxArchiveFiles && maxArchiveDays <= 0))
			{
				yield break;
			}
			for (int i = 0; i < existingArchiveFiles.Count; i++)
			{
				if (ShouldDeleteFile(existingArchiveFiles[i], existingArchiveFiles.Count - i, maxArchiveFiles, maxArchiveDays))
				{
					if (_lastArchiveFileCount > 0)
					{
						_lastArchiveFileCount--;
					}
					yield return existingArchiveFiles[i];
					continue;
				}
				_oldestArchiveFileDate = existingArchiveFiles[i].Date.Date.ToUniversalTime();
				break;
			}
		}

		private bool ShouldDeleteFile(DateAndSequenceArchive existingArchiveFile, int remainingFileCount, int maxArchiveFiles, int maxArchiveDays)
		{
			if (maxArchiveFiles > 0 && remainingFileCount > maxArchiveFiles)
			{
				return true;
			}
			if (maxArchiveDays > 0)
			{
				DateTime dateTime = existingArchiveFile.Date.Date.ToUniversalTime();
				if (dateTime > MaxAgeArchiveFileDate)
				{
					DateTime dateTime2 = TimeSource.Current.Time.Date.ToUniversalTime();
					double totalDays = (dateTime2 - dateTime).TotalDays;
					if (totalDays > (double)maxArchiveDays)
					{
						InternalLogger.Debug("FileTarget: Detected old file in archive. FileName={0}, FileDate={1:u}, FileDateUtc={2:u}, CurrentDateUtc={3:u}, Age={4} days", existingArchiveFile.FileName, existingArchiveFile.Date, dateTime, dateTime2, Math.Round(totalDays, 1));
						return true;
					}
				}
			}
			return false;
		}
	}
	internal sealed class FileArchiveModeDate : FileArchiveModeBase
	{
		private readonly string _archiveDateFormat;

		public FileArchiveModeDate(string archiveDateFormat, bool isArchiveCleanupEnabled)
			: base(isArchiveCleanupEnabled)
		{
			_archiveDateFormat = archiveDateFormat;
		}

		public override List<DateAndSequenceArchive> GetExistingArchiveFiles(string archiveFilePath)
		{
			if (base.IsArchiveCleanupEnabled)
			{
				return base.GetExistingArchiveFiles(archiveFilePath);
			}
			return new List<DateAndSequenceArchive>();
		}

		protected override DateAndSequenceArchive GenerateArchiveFileInfo(FileInfo archiveFile, FileNameTemplate fileTemplate)
		{
			string text = Path.GetFileName(archiveFile.FullName) ?? "";
			int num = fileTemplate.ReplacePattern("*").LastIndexOf('*');
			if (num + _archiveDateFormat.Length <= text.Length && DateTime.TryParseExact(text.Substring(num, _archiveDateFormat.Length), _archiveDateFormat, CultureInfo.InvariantCulture, DateTimeStyles.None, out var result))
			{
				result = DateTime.SpecifyKind(result, TimeSource.Current.Time.Kind);
				return new DateAndSequenceArchive(archiveFile.FullName, result, _archiveDateFormat, -1);
			}
			return null;
		}

		public override DateAndSequenceArchive GenerateArchiveFileName(string archiveFilePath, DateTime archiveDate, List<DateAndSequenceArchive> existingArchiveFiles)
		{
			FileNameTemplate fileNameTemplate = GenerateFileNameTemplate(archiveFilePath);
			archiveFilePath = Path.Combine(Path.GetDirectoryName(archiveFilePath), fileNameTemplate.ReplacePattern("*").Replace("*", archiveDate.ToString(_archiveDateFormat)));
			archiveFilePath = Path.GetFullPath(archiveFilePath);
			return new DateAndSequenceArchive(archiveFilePath, archiveDate, _archiveDateFormat, 0);
		}
	}
	internal sealed class FileArchiveModeDateAndSequence : FileArchiveModeBase
	{
		private readonly string _archiveDateFormat;

		public FileArchiveModeDateAndSequence(string archiveDateFormat, bool archiveCleanupEnabled)
			: base(archiveCleanupEnabled)
		{
			_archiveDateFormat = archiveDateFormat;
		}

		public override bool AttemptCleanupOnInitializeFile(string archiveFilePath, int maxArchiveFiles, int maxArchiveDays)
		{
			return false;
		}

		protected override DateAndSequenceArchive GenerateArchiveFileInfo(FileInfo archiveFile, FileNameTemplate fileTemplate)
		{
			if (!TryParseDateAndSequence(Path.GetFileName(archiveFile.FullName) ?? string.Empty, _archiveDateFormat, fileTemplate, out var date, out var sequence))
			{
				return null;
			}
			date = DateTime.SpecifyKind(date, TimeSource.Current.Time.Kind);
			return new DateAndSequenceArchive(archiveFile.FullName, date, _archiveDateFormat, sequence);
		}

		public override DateAndSequenceArchive GenerateArchiveFileName(string archiveFilePath, DateTime archiveDate, List<DateAndSequenceArchive> existingArchiveFiles)
		{
			int num = 0;
			FileNameTemplate fileNameTemplate = GenerateFileNameTemplate(archiveFilePath);
			foreach (DateAndSequenceArchive existingArchiveFile in existingArchiveFiles)
			{
				if (existingArchiveFile.HasSameFormattedDate(archiveDate))
				{
					num = Math.Max(num, existingArchiveFile.Sequence + 1);
				}
			}
			int totalWidth = fileNameTemplate.EndAt - fileNameTemplate.BeginAt - 2;
			string text = num.ToString().PadLeft(totalWidth, '0');
			string path = fileNameTemplate.ReplacePattern("*").Replace("*", archiveDate.ToString(_archiveDateFormat) + "." + text);
			archiveFilePath = Path.Combine(Path.GetDirectoryName(archiveFilePath), path);
			archiveFilePath = Path.GetFullPath(archiveFilePath);
			return new DateAndSequenceArchive(archiveFilePath, archiveDate, _archiveDateFormat, num);
		}

		private static bool TryParseDateAndSequence(string archiveFileNameWithoutPath, string dateFormat, FileNameTemplate fileTemplate, out DateTime date, out int sequence)
		{
			int num = fileTemplate.Template.Length - fileTemplate.EndAt;
			int beginAt = fileTemplate.BeginAt;
			int num2 = archiveFileNameWithoutPath.Length - num - beginAt;
			if (num2 < 0)
			{
				date = default(DateTime);
				sequence = 0;
				return false;
			}
			string text = archiveFileNameWithoutPath.Substring(beginAt, num2);
			int startIndex = text.LastIndexOf('.') + 1;
			string text2 = text.Substring(startIndex);
			if (!int.TryParse(text2, NumberStyles.None, CultureInfo.CurrentCulture, out sequence))
			{
				date = default(DateTime);
				return false;
			}
			int num3 = text.Length - text2.Length - 1;
			if (num3 < 0)
			{
				date = default(DateTime);
				return false;
			}
			string text3 = text.Substring(0, num3);
			if (!DateTime.TryParseExact(text3, dateFormat, CultureInfo.CurrentCulture, DateTimeStyles.None, out date))
			{
				return false;
			}
			InternalLogger.Trace("FileTarget: parsed date '{0}' from file-template '{1}'", text3, fileTemplate?.Template);
			return true;
		}
	}
	internal sealed class FileArchiveModeDynamicSequence : FileArchiveModeBase
	{
		private readonly ArchiveNumberingMode _archiveNumbering;

		private readonly string _archiveDateFormat;

		private readonly bool _customArchiveFileName;

		public FileArchiveModeDynamicSequence(ArchiveNumberingMode archiveNumbering, string archiveDateFormat, bool customArchiveFileName, bool archiveCleanupEnabled)
			: base(archiveCleanupEnabled)
		{
			_archiveNumbering = archiveNumbering;
			_archiveDateFormat = archiveDateFormat;
			_customArchiveFileName = customArchiveFileName;
		}

		private static bool RemoveNonLetters(string fileName, int startPosition, StringBuilder sb, out int digitsRemoved)
		{
			digitsRemoved = 0;
			sb.ClearBuilder();
			for (int i = 0; i < startPosition; i++)
			{
				sb.Append(fileName[i]);
			}
			bool? flag = null;
			for (int j = startPosition; j < fileName.Length; j++)
			{
				char c = fileName[j];
