	internal static class FileArchiveModeFactory
	{
		public static IFileArchiveMode CreateArchiveStyle(string archiveFilePath, ArchiveNumberingMode archiveNumbering, string dateFormat, bool customArchiveFileName, bool archiveCleanupEnabled)
		{
			if (ContainsFileNamePattern(archiveFilePath))
			{
				IFileArchiveMode fileArchiveMode = CreateStrictFileArchiveMode(archiveNumbering, dateFormat, archiveCleanupEnabled);
				if (fileArchiveMode != null)
				{
					return fileArchiveMode;
				}
			}
			if (archiveNumbering != ArchiveNumberingMode.Sequence)
			{
				if (!customArchiveFileName)
				{
					IFileArchiveMode fileArchiveMode2 = CreateStrictFileArchiveMode(archiveNumbering, dateFormat, archiveCleanupEnabled);
					if (fileArchiveMode2 != null)
					{
						return new FileArchiveModeDynamicTemplate(fileArchiveMode2);
					}
				}
				else
				{
					InternalLogger.Info("FileTarget: Pattern {{#}} is missing in ArchiveFileName `{0}` (Fallback to dynamic wildcard)", archiveFilePath);
				}
			}
			return new FileArchiveModeDynamicSequence(archiveNumbering, dateFormat, customArchiveFileName, archiveCleanupEnabled);
		}

		private static IFileArchiveMode CreateStrictFileArchiveMode(ArchiveNumberingMode archiveNumbering, string dateFormat, bool archiveCleanupEnabled)
		{
			return archiveNumbering switch
			{
				ArchiveNumberingMode.Rolling => new FileArchiveModeRolling(), 
				ArchiveNumberingMode.Sequence => new FileArchiveModeSequence(dateFormat, archiveCleanupEnabled), 
				ArchiveNumberingMode.Date => new FileArchiveModeDate(dateFormat, archiveCleanupEnabled), 
				ArchiveNumberingMode.DateAndSequence => new FileArchiveModeDateAndSequence(dateFormat, archiveCleanupEnabled), 
				_ => null, 
			};
		}

		public static bool ContainsFileNamePattern(string fileName)
		{
			int num = fileName.IndexOf("{#", StringComparison.Ordinal);
			int num2 = fileName.IndexOf("#}", StringComparison.Ordinal);
			if (num != -1 && num2 != -1)
			{
				return num < num2;
			}
			return false;
		}
	}
	internal sealed class FileArchiveModeRolling : IFileArchiveMode
	{
		public bool IsArchiveCleanupEnabled => true;

		public bool AttemptCleanupOnInitializeFile(string archiveFilePath, int maxArchiveFiles, int maxArchiveDays)
		{
			return false;
		}

		public string GenerateFileNameMask(string archiveFilePath)
		{
			return new FileArchiveModeBase.FileNameTemplate(Path.GetFileName(archiveFilePath)).ReplacePattern("*");
		}

		public List<DateAndSequenceArchive> GetExistingArchiveFiles(string archiveFilePath)
		{
			List<DateAndSequenceArchive> list = new List<DateAndSequenceArchive>();
			for (int i = 0; i < 2147483647; i++)
			{
				FileInfo fileInfo = new FileInfo(ReplaceNumberPattern(archiveFilePath, i));
				if (!fileInfo.Exists)
				{
					break;
				}
				list.Add(new DateAndSequenceArchive(fileInfo.FullName, DateTime.MinValue, string.Empty, i));
			}
			return list;
		}

		private static string ReplaceNumberPattern(string pattern, int value)
		{
			int num = pattern.IndexOf("{#", StringComparison.Ordinal);
			int num2 = pattern.IndexOf("#}", StringComparison.Ordinal) + 2;
			int totalWidth = num2 - num - 2;
			return pattern.Substring(0, num) + Convert.ToString(value, 10).PadLeft(totalWidth, '0') + pattern.Substring(num2);
		}

		public DateAndSequenceArchive GenerateArchiveFileName(string archiveFilePath, DateTime archiveDate, List<DateAndSequenceArchive> existingArchiveFiles)
		{
			if (existingArchiveFiles.Count > 0)
			{
				int value = existingArchiveFiles[existingArchiveFiles.Count - 1].Sequence + 1;
				string fileName = ReplaceNumberPattern(archiveFilePath, value);
				existingArchiveFiles.Add(new DateAndSequenceArchive(fileName, DateTime.MinValue, string.Empty, 2147483647));
			}
			return new DateAndSequenceArchive(Path.GetFullPath(ReplaceNumberPattern(archiveFilePath, 0)), DateTime.MinValue, string.Empty, -2147483648);
		}

		public IEnumerable<DateAndSequenceArchive> CheckArchiveCleanup(string archiveFilePath, List<DateAndSequenceArchive> existingArchiveFiles, int maxArchiveFiles, int maxArchiveDays)
		{
			if (existingArchiveFiles.Count <= 1)
			{
				yield break;
			}
			existingArchiveFiles.Sort((DateAndSequenceArchive x, DateAndSequenceArchive y) => x.Sequence.CompareTo(y.Sequence));
			if (maxArchiveFiles > 0 && existingArchiveFiles.Count > maxArchiveFiles)
			{
				for (int i = 0; i < existingArchiveFiles.Count; i++)
				{
					if (existingArchiveFiles[i].Sequence != -2147483648 && existingArchiveFiles[i].Sequence != 2147483647 && i >= maxArchiveFiles)
					{
						yield return existingArchiveFiles[i];
					}
				}
			}
			if (existingArchiveFiles.Count <= 1 || existingArchiveFiles[0].Sequence != -2147483648)
			{
				yield break;
			}
			string text = string.Empty;
			int num = existingArchiveFiles.Count - 1;
			if (maxArchiveFiles > 0 && num > maxArchiveFiles)
			{
				num = maxArchiveFiles;
			}
			for (int num2 = num; num2 >= 1; num2--)
			{
				string fileName = existingArchiveFiles[num2].FileName;
				if (!string.IsNullOrEmpty(text))
				{
					InternalLogger.Info("Roll archive {0} to {1}", fileName, text);
					File.Move(fileName, text);
				}
				text = fileName;
			}
		}
	}
	internal sealed class FileArchiveModeSequence : FileArchiveModeBase
	{
		private readonly string _archiveDateFormat;

		public FileArchiveModeSequence(string archiveDateFormat, bool isArchiveCleanupEnabled)
			: base(isArchiveCleanupEnabled)
		{
			_archiveDateFormat = archiveDateFormat;
		}

		public override bool AttemptCleanupOnInitializeFile(string archiveFilePath, int maxArchiveFiles, int maxArchiveDays)
		{
			return false;
		}

		protected override DateAndSequenceArchive GenerateArchiveFileInfo(FileInfo archiveFile, FileNameTemplate fileTemplate)
		{
			string text = Path.GetFileName(archiveFile.FullName) ?? "";
			int num = fileTemplate.Template.Length - fileTemplate.EndAt;
			string value = text.Substring(fileTemplate.BeginAt, text.Length - num - fileTemplate.BeginAt);
			int sequence;
			try
			{
				sequence = Convert.ToInt32(value, CultureInfo.InvariantCulture);
			}
			catch (FormatException)
			{
				return null;
			}
			return new DateAndSequenceArchive(archiveFile.FullName, DateTime.MinValue, string.Empty, sequence);
		}

		public override DateAndSequenceArchive GenerateArchiveFileName(string archiveFilePath, DateTime archiveDate, List<DateAndSequenceArchive> existingArchiveFiles)
		{
			int num = 0;
			FileNameTemplate fileNameTemplate = GenerateFileNameTemplate(archiveFilePath);
			foreach (DateAndSequenceArchive existingArchiveFile in existingArchiveFiles)
			{
				num = Math.Max(num, existingArchiveFile.Sequence + 1);
			}
			int totalWidth = fileNameTemplate.EndAt - fileNameTemplate.BeginAt - 2;
			string newValue = num.ToString().PadLeft(totalWidth, '0');
			archiveFilePath = Path.Combine(Path.GetDirectoryName(archiveFilePath), fileNameTemplate.ReplacePattern("*").Replace("*", newValue));
			archiveFilePath = Path.GetFullPath(archiveFilePath);
			return new DateAndSequenceArchive(archiveFilePath, archiveDate, _archiveDateFormat, num);
		}
	}
