		}

		private char Peek()
		{
			return _template[_position];
		}

		private char Read()
		{
			return _template[_position++];
		}

		private void Skip(char c)
		{
			_position++;
		}

		private void SkipSpaces()
		{
			while (_template[_position] == ' ')
