		protected virtual void RenderFormattedMessage(LogEventInfo logEvent, StringBuilder target)
		{
			target.Append(GetFormattedMessage(logEvent) ?? string.Empty);
		}

		void ISupportsInitialize.Initialize(LoggingConfiguration configuration)
		{
			Initialize(configuration);
		}

		void ISupportsInitialize.Close()
		{
			Close();
		}

		internal void Initialize(LoggingConfiguration configuration)
		{
			if (!IsInitialized)
			{
				LoggingConfiguration = configuration;
				IsInitialized = true;
				_scannedForObjects = false;
				InitializeLayout();
				if (!_scannedForObjects)
				{
					InternalLogger.Debug("{0} Initialized Layout done but not scanned for objects", GetType());
					PerformObjectScanning();
				}
			}
		}

		internal void PerformObjectScanning()
		{
			List<IRenderable> list = ObjectGraphScanner.FindReachableObjects<IRenderable>(aggressiveSearch: true, new object[1] { this });
			HashSet<Type> hashSet = new HashSet<Type>(list.Select((IRenderable o) => o.GetType()));
			hashSet.Remove(typeof(SimpleLayout));
			hashSet.Remove(typeof(LiteralLayoutRenderer));
			ThreadAgnostic = hashSet.All((Type t) => t.IsDefined(typeof(ThreadAgnosticAttribute), inherit: true));
			ThreadSafe = hashSet.All((Type t) => t.IsDefined(typeof(ThreadSafeAttribute), inherit: true));
			MutableUnsafe = hashSet.Any((Type t) => t.IsDefined(typeof(MutableUnsafeAttribute), inherit: true));
			if ((ThreadAgnostic || !MutableUnsafe) && list.Count > 1 && hashSet.Count > 0)
			{
				foreach (Layout item in list.OfType<Layout>())
				{
					if (item != this)
					{
						item.Initialize(LoggingConfiguration);
						ThreadAgnostic = item.ThreadAgnostic && ThreadAgnostic;
						MutableUnsafe = item.MutableUnsafe || MutableUnsafe;
					}
				}
			}
			StackTraceUsage = StackTraceUsage.None;
			StackTraceUsage = list.OfType<IUsesStackTrace>().DefaultIfEmpty().Max((IUsesStackTrace item) => item?.StackTraceUsage ?? StackTraceUsage.None);
			_scannedForObjects = true;
		}

		internal void Close()
		{
			if (IsInitialized)
			{
				LoggingConfiguration = null;
				IsInitialized = false;
				CloseLayout();
			}
		}

		protected virtual void InitializeLayout()
		{
			PerformObjectScanning();
		}

		protected virtual void CloseLayout()
		{
		}

		protected abstract string GetFormattedMessage(LogEventInfo logEvent);

		public static void Register<T>(string name) where T : Layout
		{
			Type typeFromHandle = typeof(T);
			Register(name, typeFromHandle);
		}

		public static void Register(string name, Type layoutType)
		{
			ConfigurationItemFactory.Default.Layouts.RegisterDefinition(name, layoutType);
		}

		internal void PrecalculateBuilderInternal(LogEventInfo logEvent, StringBuilder target)
		{
			if (!ThreadAgnostic || MutableUnsafe)
			{
				RenderAppendBuilder(logEvent, target, cacheLayoutResult: true);
			}
		}

		internal string ToStringWithNestedItems<T>(IList<T> nestedItems, Func<T, string> nextItemToString)
		{
			if (nestedItems != null && nestedItems.Count > 0)
			{
				string[] value = nestedItems.Select((T c) => nextItemToString(c)).ToArray();
				return GetType().Name + "=" + string.Join("|", value);
			}
			return base.ToString();
		}

		internal virtual bool TryGetRawValue(LogEventInfo logEvent, out object rawValue)
		{
			rawValue = null;
			return false;
		}
	}
	[AttributeUsage(AttributeTargets.Class)]
	public sealed class LayoutAttribute : NameBaseAttribute
	{
		public LayoutAttribute(string name)
			: base(name)
		{
		}
	}
	internal static class LayoutParser
	{
		internal static LayoutRenderer[] CompileLayout(ConfigurationItemFactory configurationItemFactory, SimpleStringReader sr, bool? throwConfigExceptions, bool isNested, out string text)
		{
			List<LayoutRenderer> list = new List<LayoutRenderer>();
			StringBuilder stringBuilder = new StringBuilder();
			int position = sr.Position;
			int num;
			while ((num = sr.Peek()) != -1)
			{
				if (isNested)
				{
					if (num == 92)
					{
						sr.Read();
						int num2 = sr.Peek();
						if (EndOfLayout(num2))
						{
							sr.Read();
							stringBuilder.Append((char)num2);
						}
						else
						{
							stringBuilder.Append('\\');
						}
						continue;
					}
					if (EndOfLayout(num))
					{
						break;
					}
				}
				sr.Read();
				if (num == 36 && sr.Peek() == 123)
				{
					AddLiteral(stringBuilder, list);
					LayoutRenderer layoutRenderer = ParseLayoutRenderer(configurationItemFactory, sr, throwConfigExceptions);
					if (CanBeConvertedToLiteral(layoutRenderer))
					{
						layoutRenderer = ConvertToLiteral(layoutRenderer);
					}
					list.Add(layoutRenderer);
				}
				else
				{
					stringBuilder.Append((char)num);
				}
			}
			AddLiteral(stringBuilder, list);
			int position2 = sr.Position;
			MergeLiterals(list);
			text = sr.Substring(position, position2);
			return list.ToArray();
		}

		private static void AddLiteral(StringBuilder literalBuf, List<LayoutRenderer> result)
		{
			if (literalBuf.Length > 0)
			{
				result.Add(new LiteralLayoutRenderer(literalBuf.ToString()));
				literalBuf.Length = 0;
			}
		}

		private static bool EndOfLayout(int ch)
		{
			if (ch != 125)
			{
				return ch == 58;
			}
			return true;
		}

		private static string ParseLayoutRendererName(SimpleStringReader sr)
		{
			return sr.ReadUntilMatch((int ch) => EndOfLayout(ch));
		}

		private static string ParseParameterName(SimpleStringReader sr)
		{
			int num = 0;
			StringBuilder stringBuilder = new StringBuilder();
			int num2;
			while ((num2 = sr.Peek()) != -1 && ((num2 != 61 && num2 != 125 && num2 != 58) || num != 0))
			{
				switch (num2)
				{
				case 36:
					sr.Read();
					stringBuilder.Append('$');
					if (sr.Peek() == 123)
					{
						stringBuilder.Append('{');
						num++;
						sr.Read();
					}
					continue;
				case 125:
					num--;
					break;
				}
				if (num2 == 92)
				{
					sr.Read();
					if (num != 0)
					{
						stringBuilder.Append((char)num2);
					}
					stringBuilder.Append((char)sr.Read());
				}
				else
				{
					stringBuilder.Append((char)num2);
					sr.Read();
				}
			}
			return stringBuilder.ToString();
		}

		private static string ParseParameterValue(SimpleStringReader sr)
		{
			string text = sr.ReadUntilMatch((int ch) => EndOfLayout(ch) || ch == 92);
			if (sr.Peek() == 92)
			{
				StringBuilder stringBuilder = new StringBuilder();
				stringBuilder.Append(text);
				ParseParameterUnicodeValue(sr, stringBuilder);
				return stringBuilder.ToString();
			}
			return text;
		}

		private static void ParseParameterUnicodeValue(SimpleStringReader sr, StringBuilder nameBuf)
		{
			int num;
			while ((num = sr.Peek()) != -1 && !EndOfLayout(num))
			{
				if (num == 92)
				{
					sr.Read();
					char c = (char)sr.Peek();
					switch (c)
					{
					case '"':
					case '\'':
					case ':':
					case '\\':
					case '{':
					case '}':
						sr.Read();
						nameBuf.Append(c);
						break;
					case '0':
						sr.Read();
						nameBuf.Append('\0');
						break;
					case 'a':
						sr.Read();
						nameBuf.Append('\a');
						break;
					case 'b':
						sr.Read();
						nameBuf.Append('\b');
						break;
					case 'f':
						sr.Read();
						nameBuf.Append('\f');
						break;
					case 'n':
						sr.Read();
						nameBuf.Append('\n');
						break;
					case 'r':
						sr.Read();
						nameBuf.Append('\r');
						break;
					case 't':
						sr.Read();
						nameBuf.Append('\t');
						break;
					case 'u':
					{
						sr.Read();
						char unicode3 = GetUnicode(sr, 4);
						nameBuf.Append(unicode3);
						break;
					}
					case 'U':
					{
						sr.Read();
						char unicode2 = GetUnicode(sr, 8);
						nameBuf.Append(unicode2);
						break;
					}
					case 'x':
					{
						sr.Read();
						char unicode = GetUnicode(sr, 4);
						nameBuf.Append(unicode);
						break;
					}
					case 'v':
						sr.Read();
						nameBuf.Append('\v');
						break;
					}
				}
				else
				{
					nameBuf.Append((char)num);
					sr.Read();
				}
			}
		}

		private static char GetUnicode(SimpleStringReader sr, int maxDigits)
		{
			int num = 0;
			for (int i = 0; i < maxDigits; i++)
			{
				int num2 = sr.Peek();
				if (num2 >= 48 && num2 <= 57)
				{
					num2 -= 48;
				}
				else if (num2 >= 97 && num2 <= 102)
				{
					num2 = num2 - 97 + 10;
				}
				else
				{
					if (num2 < 65 || num2 > 70)
					{
						break;
					}
					num2 = num2 - 65 + 10;
				}
				sr.Read();
				num = num * 16 + num2;
			}
			return (char)num;
		}

		private static LayoutRenderer ParseLayoutRenderer(ConfigurationItemFactory configurationItemFactory, SimpleStringReader stringReader, bool? throwConfigExceptions)
		{
			int num = stringReader.Read();
			string text = ParseLayoutRendererName(stringReader);
			LayoutRenderer layoutRenderer = GetLayoutRenderer(configurationItemFactory, text, throwConfigExceptions);
			Dictionary<Type, LayoutRenderer> dictionary = null;
			List<LayoutRenderer> list = null;
			num = stringReader.Read();
			while (num != -1 && num != 125)
			{
				string text2 = ParseParameterName(stringReader).Trim();
				if (stringReader.Peek() == 61)
				{
					stringReader.Read();
					LayoutRenderer obj = layoutRenderer;
					if (!PropertyHelper.TryGetPropertyInfo(layoutRenderer, text2, out var result) && configurationItemFactory.AmbientProperties.TryGetDefinition(text2, out var result2))
					{
						dictionary = dictionary ?? new Dictionary<Type, LayoutRenderer>();
						list = list ?? new List<LayoutRenderer>();
						if (!dictionary.TryGetValue(result2, out var value))
						{
							value = (dictionary[result2] = configurationItemFactory.AmbientProperties.CreateInstance(text2));
							list.Add(value);
						}
						if (!PropertyHelper.TryGetPropertyInfo(value, text2, out result))
						{
							result = null;
						}
						else
						{
							obj = value;
						}
					}
					if (result == null)
					{
						string text3 = ParseParameterValue(stringReader);
						if (!string.IsNullOrEmpty(text2) || !StringHelpers.IsNullOrWhiteSpace(text3))
						{
							InternalLogger.Warn("Skipping unrecognized property '{0}={1}` for ${{{2}}} ({3})", text2, text3, text, layoutRenderer?.GetType());
						}
					}
					else if (typeof(Layout).IsAssignableFrom(result.PropertyType))
					{
						string text4;
						SimpleLayout value2 = new SimpleLayout(CompileLayout(configurationItemFactory, stringReader, throwConfigExceptions, isNested: true, out text4), text4, configurationItemFactory);
						result.SetValue(obj, value2, null);
					}
					else if (typeof(ConditionExpression).IsAssignableFrom(result.PropertyType))
					{
						ConditionExpression value3 = ConditionParser.ParseExpression(stringReader, configurationItemFactory);
						result.SetValue(obj, value3, null);
					}
					else
					{
						string value4 = ParseParameterValue(stringReader);
						PropertyHelper.SetPropertyFromString(obj, text2, value4, configurationItemFactory);
					}
				}
				else
				{
					SetDefaultPropertyValue(configurationItemFactory, layoutRenderer, text2);
				}
				num = stringReader.Read();
			}
			if (list != null)
			{
				layoutRenderer = ApplyWrappers(configurationItemFactory, layoutRenderer, list);
			}
			return layoutRenderer;
		}

		private static LayoutRenderer GetLayoutRenderer(ConfigurationItemFactory configurationItemFactory, string name, bool? throwConfigExceptions)
		{
			try
			{
				return configurationItemFactory.LayoutRenderers.CreateInstance(name);
			}
			catch (Exception ex)
			{
				if (throwConfigExceptions ?? LogManager.ThrowConfigExceptions ?? LogManager.ThrowExceptions)
				{
					throw;
				}
				InternalLogger.Error(ex, "Error parsing layout {0} will be ignored.", name);
				return new LiteralLayoutRenderer(string.Empty);
			}
		}

		private static void SetDefaultPropertyValue(ConfigurationItemFactory configurationItemFactory, LayoutRenderer layoutRenderer, string value)
		{
			if (PropertyHelper.TryGetPropertyInfo(layoutRenderer, string.Empty, out var result))
			{
				PropertyHelper.SetPropertyFromString(layoutRenderer, result.Name, value, configurationItemFactory);
			}
			else
			{
				InternalLogger.Warn("{0} has no default property to assign value {1}", layoutRenderer.GetType(), value);
			}
		}

		private static LayoutRenderer ApplyWrappers(ConfigurationItemFactory configurationItemFactory, LayoutRenderer lr, List<LayoutRenderer> orderedWrappers)
		{
			for (int num = orderedWrappers.Count - 1; num >= 0; num--)
			{
				WrapperLayoutRendererBase wrapperLayoutRendererBase = (WrapperLayoutRendererBase)orderedWrappers[num];
				InternalLogger.Trace("Wrapping {0} with {1}", lr.GetType(), wrapperLayoutRendererBase.GetType());
				if (CanBeConvertedToLiteral(lr))
				{
					lr = ConvertToLiteral(lr);
				}
				wrapperLayoutRendererBase.Inner = new SimpleLayout(new LayoutRenderer[1] { lr }, string.Empty, configurationItemFactory);
				lr = wrapperLayoutRendererBase;
			}
			return lr;
		}

		private static bool CanBeConvertedToLiteral(LayoutRenderer lr)
		{
			foreach (IRenderable item in ObjectGraphScanner.FindReachableObjects<IRenderable>(aggressiveSearch: true, new object[1] { lr }))
			{
				Type type = item.GetType();
				if (!(type == typeof(SimpleLayout)) && !type.IsDefined(typeof(AppDomainFixedOutputAttribute), inherit: false))
				{
					return false;
				}
			}
			return true;
		}

		private static void MergeLiterals(List<LayoutRenderer> list)
		{
			int num = 0;
			while (num + 1 < list.Count)
			{
				LiteralLayoutRenderer literalLayoutRenderer = list[num] as LiteralLayoutRenderer;
				LiteralLayoutRenderer literalLayoutRenderer2 = list[num + 1] as LiteralLayoutRenderer;
				if (literalLayoutRenderer != null && literalLayoutRenderer2 != null)
				{
					literalLayoutRenderer.Text += literalLayoutRenderer2.Text;
					list.RemoveAt(num + 1);
				}
				else
				{
					num++;
				}
			}
		}

		private static LayoutRenderer ConvertToLiteral(LayoutRenderer renderer)
		{
			return new LiteralLayoutRenderer(renderer.Render(LogEventInfo.CreateNullEvent()));
		}
	}
