	[LayoutRenderer("all-event-properties")]
	[ThreadAgnostic]
	[ThreadSafe]
	[MutableUnsafe]
	public class AllEventPropertiesLayoutRenderer : LayoutRenderer
	{
		private string _format;

		private string _beforeKey;

		private string _afterKey;

		private string _afterValue;

		public string Separator { get; set; }

		[DefaultValue(false)]
		public bool IncludeEmptyValues { get; set; }

		public ISet<string> Exclude { get; set; }

		public string Format
		{
			get
			{
				return _format;
			}
			set
			{
				if (!value.Contains("[key]"))
				{
					throw new ArgumentException("Invalid format: [key] placeholder is missing.");
				}
				if (!value.Contains("[value]"))
				{
					throw new ArgumentException("Invalid format: [value] placeholder is missing.");
				}
				_format = value;
				string[] array = _format.Split(new string[2] { "[key]", "[value]" }, StringSplitOptions.None);
				if (array.Length == 3)
				{
					_beforeKey = array[0];
					_afterKey = array[1];
					_afterValue = array[2];
				}
				else
				{
					_beforeKey = null;
					_afterKey = null;
					_afterValue = null;
				}
			}
		}

		public AllEventPropertiesLayoutRenderer()
		{
			Separator = ", ";
			Format = "[key]=[value]";
			Exclude = new HashSet<string>(ArrayHelper.Empty<string>(), StringComparer.OrdinalIgnoreCase);
		}

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			if (!logEvent.HasProperties)
			{
				return;
			}
			IFormatProvider formatProvider = GetFormatProvider(logEvent);
			bool flag = CheckForExclude(logEvent);
			bool flag2 = _beforeKey == null || _afterKey == null || _afterValue == null;
			bool flag3 = true;
			foreach (KeyValuePair<object, object> property in logEvent.Properties)
			{
				if ((IncludeEmptyValues || !IsEmptyPropertyValue(property.Value)) && (!flag || !(property.Key is string item) || !Exclude.Contains(item)))
				{
					if (!flag3)
					{
						builder.Append(Separator);
					}
					flag3 = false;
					if (flag2)
					{
						string newValue = Convert.ToString(property.Key, formatProvider);
						string newValue2 = Convert.ToString(property.Value, formatProvider);
						string value = Format.Replace("[key]", newValue).Replace("[value]", newValue2);
						builder.Append(value);
					}
					else
					{
						builder.Append(_beforeKey);
						builder.AppendFormattedValue(property.Key, null, formatProvider);
						builder.Append(_afterKey);
						builder.AppendFormattedValue(property.Value, null, formatProvider);
						builder.Append(_afterValue);
					}
				}
			}
		}

		private bool CheckForExclude(LogEventInfo logEvent)
		{
			ISet<string> exclude = Exclude;
			if (exclude == null)
			{
				return false;
			}
			return exclude.Count > 0;
		}

		private static bool IsEmptyPropertyValue(object value)
		{
			if (value is string value2)
			{
				return string.IsNullOrEmpty(value2);
			}
			return value == null;
		}
	}
