	[LayoutRenderer("appdomain")]
	[AppDomainFixedOutput]
	[ThreadAgnostic]
	[ThreadSafe]
	public class AppDomainLayoutRenderer : LayoutRenderer
	{
		private const string ShortFormat = "{0:00}";

		private const string LongFormat = "{0:0000}:{1}";

		private const string LongFormatCode = "Long";

		private const string ShortFormatCode = "Short";

		private readonly IAppDomain _currentDomain;

		private string _assemblyName;

		[DefaultParameter]
		[DefaultValue("Long")]
		public string Format { get; set; }

		public AppDomainLayoutRenderer()
			: this(LogFactory.CurrentAppDomain)
		{
		}

		public AppDomainLayoutRenderer(IAppDomain currentDomain)
		{
			_currentDomain = currentDomain;
			Format = "Long";
		}

		protected override void InitializeLayoutRenderer()
		{
			_assemblyName = null;
			base.InitializeLayoutRenderer();
		}

		protected override void CloseLayoutRenderer()
		{
			_assemblyName = null;
			base.CloseLayoutRenderer();
		}

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			if (_assemblyName == null)
			{
				string formattingString = GetFormattingString(Format);
				_assemblyName = string.Format(formattingString, _currentDomain.Id, _currentDomain.FriendlyName);
			}
			builder.Append(_assemblyName);
		}

		private static string GetFormattingString(string format)
		{
			if (format.Equals("Long", StringComparison.OrdinalIgnoreCase))
			{
				return "{0:0000}:{1}";
			}
			if (format.Equals("Short", StringComparison.OrdinalIgnoreCase))
			{
				return "{0:00}";
			}
			return format;
		}
	}
	[LayoutRenderer("assembly-version")]
	[ThreadAgnostic]
	[ThreadSafe]
	public class AssemblyVersionLayoutRenderer : LayoutRenderer
	{
		private const string DefaultFormat = "major.minor.build.revision";

		private string _format;

		private string _assemblyVersion;

		[DefaultParameter]
		public string Name { get; set; }

		[DefaultValue("Assembly")]
		public AssemblyVersionType Type { get; set; }

		[DefaultValue("major.minor.build.revision")]
		public string Format
		{
			get
			{
				return _format;
			}
			set
			{
				_format = value?.ToLowerInvariant();
			}
		}

		public AssemblyVersionLayoutRenderer()
		{
			Type = AssemblyVersionType.Assembly;
			Format = "major.minor.build.revision";
		}

		protected override void InitializeLayoutRenderer()
		{
			_assemblyVersion = null;
			base.InitializeLayoutRenderer();
		}

		protected override void CloseLayoutRenderer()
		{
			_assemblyVersion = null;
			base.CloseLayoutRenderer();
		}

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			string value = _assemblyVersion ?? (_assemblyVersion = ApplyFormatToVersion(GetVersion()));
			if (string.IsNullOrEmpty(value))
			{
				value = string.Format("Could not find value for {0} assembly and version type {1}", string.IsNullOrEmpty(Name) ? "entry" : Name, Type);
			}
			builder.Append(value);
		}

		private string ApplyFormatToVersion(string version)
		{
			if (Format.Equals("major.minor.build.revision", StringComparison.OrdinalIgnoreCase) || string.IsNullOrEmpty(version))
			{
				return version;
			}
			string[] array = version.SplitAndTrimTokens('.');
			version = Format.Replace("major", array[0]).Replace("minor", (array.Length > 1) ? array[1] : "0").Replace("build", (array.Length > 2) ? array[2] : "0")
				.Replace("revision", (array.Length > 3) ? array[3] : "0");
			return version;
		}

		private string GetVersion()
		{
			Assembly assembly = GetAssembly();
			return GetVersion(assembly);
		}

		protected virtual Assembly GetAssembly()
		{
			if (string.IsNullOrEmpty(Name))
			{
				return Assembly.GetEntryAssembly();
			}
			return Assembly.Load(new AssemblyName(Name));
		}

		private string GetVersion(Assembly assembly)
		{
			switch (Type)
			{
			case AssemblyVersionType.File:
				if ((object)assembly == null)
				{
					return null;
				}
				return ReflectionHelpers.GetCustomAttribute<AssemblyFileVersionAttribute>(assembly)?.Version;
			case AssemblyVersionType.Informational:
				if ((object)assembly == null)
				{
					return null;
				}
				return ReflectionHelpers.GetCustomAttribute<AssemblyInformationalVersionAttribute>(assembly)?.InformationalVersion;
			default:
				return assembly?.GetName().Version?.ToString();
			}
		}
	}
	public enum AssemblyVersionType
	{
		Assembly,
		File,
		Informational
	}
	[LayoutRenderer("basedir")]
	[AppDomainFixedOutput]
	[ThreadAgnostic]
	[ThreadSafe]
	public class BaseDirLayoutRenderer : LayoutRenderer
	{
		private readonly string _baseDir;

		private string _processDir;

		private readonly IAppEnvironment _appEnvironment;

		public bool ProcessDir { get; set; }

		public bool FixTempDir { get; set; }

		public string File { get; set; }

		public string Dir { get; set; }

		public BaseDirLayoutRenderer()
			: this(LogFactory.DefaultAppEnvironment)
		{
		}

		public BaseDirLayoutRenderer(IAppDomain appDomain)
		{
			_baseDir = appDomain.BaseDirectory;
			_appEnvironment = LogFactory.DefaultAppEnvironment;
		}

		internal BaseDirLayoutRenderer(IAppEnvironment appEnvironment)
		{
			_baseDir = appEnvironment.AppDomainBaseDirectory;
			_appEnvironment = appEnvironment;
		}

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			string text = _baseDir;
			if (ProcessDir)
			{
				text = _processDir ?? (_processDir = GetProcessDir());
			}
			else if (FixTempDir)
			{
				text = _processDir ?? (_processDir = GetFixedTempBaseDir(_baseDir));
			}
			if (text != null)
			{
				string value = PathHelpers.CombinePaths(text, Dir, File);
				builder.Append(value);
			}
		}

		private string GetFixedTempBaseDir(string baseDir)
		{
			try
			{
				string userTempFilePath = _appEnvironment.UserTempFilePath;
				if (PathHelpers.IsTempDir(baseDir, userTempFilePath))
				{
					string processDir = GetProcessDir();
					if (!string.IsNullOrEmpty(processDir) && !PathHelpers.IsTempDir(processDir, userTempFilePath))
					{
						return processDir;
					}
				}
				return baseDir;
			}
			catch (Exception ex)
			{
				InternalLogger.Warn(ex, "BaseDir LayoutRenderer unexpected exception");
				return baseDir;
			}
		}

		private string GetProcessDir()
		{
			return Path.GetDirectoryName(_appEnvironment.CurrentProcessFilePath);
		}
	}
