	[LayoutRenderer("callsite")]
	[ThreadAgnostic]
	[ThreadSafe]
	public class CallSiteLayoutRenderer : LayoutRenderer, IUsesStackTrace
	{
		[DefaultValue(true)]
		public bool ClassName { get; set; }

		[DefaultValue(true)]
		public bool IncludeNamespace { get; set; }

		[DefaultValue(true)]
		public bool MethodName { get; set; }

		[DefaultValue(false)]
		public bool CleanNamesOfAnonymousDelegates { get; set; }

		[DefaultValue(false)]
		public bool CleanNamesOfAsyncContinuations { get; set; }

		[DefaultValue(0)]
		public int SkipFrames { get; set; }

		[DefaultValue(false)]
		public bool FileName { get; set; }

		[DefaultValue(true)]
		public bool IncludeSourcePath { get; set; }

		[DefaultValue(true)]
		public bool CaptureStackTrace { get; set; } = true;

		StackTraceUsage IUsesStackTrace.StackTraceUsage
		{
			get
			{
				if (!CaptureStackTrace)
				{
					return StackTraceUsage.None;
				}
				if (FileName)
				{
					return StackTraceUsage.WithSource;
				}
				return StackTraceUsage.WithoutSource;
			}
		}

		public CallSiteLayoutRenderer()
		{
			ClassName = true;
			MethodName = true;
			CleanNamesOfAnonymousDelegates = false;
			IncludeNamespace = true;
			FileName = false;
			IncludeSourcePath = true;
		}

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			if (logEvent.CallSiteInformation == null)
			{
				return;
			}
			if (ClassName || MethodName)
			{
				MethodBase callerStackFrameMethod = logEvent.CallSiteInformation.GetCallerStackFrameMethod(SkipFrames);
				if (ClassName)
				{
					string value = logEvent.CallSiteInformation.GetCallerClassName(callerStackFrameMethod, IncludeNamespace, CleanNamesOfAsyncContinuations, CleanNamesOfAnonymousDelegates);
					if (string.IsNullOrEmpty(value))
					{
						value = "<no type>";
					}
					builder.Append(value);
				}
				if (MethodName)
				{
					string value2 = logEvent.CallSiteInformation.GetCallerMemberName(callerStackFrameMethod, includeMethodInfo: false, CleanNamesOfAsyncContinuations, CleanNamesOfAnonymousDelegates);
					if (string.IsNullOrEmpty(value2))
					{
						value2 = "<no method>";
					}
					if (ClassName)
					{
						builder.Append(".");
					}
					builder.Append(value2);
				}
			}
			if (FileName)
			{
				string callerFilePath = logEvent.CallSiteInformation.GetCallerFilePath(SkipFrames);
				if (!string.IsNullOrEmpty(callerFilePath))
				{
					int callerLineNumber = logEvent.CallSiteInformation.GetCallerLineNumber(SkipFrames);
					AppendFileName(builder, callerFilePath, callerLineNumber);
				}
			}
		}

		private void AppendFileName(StringBuilder builder, string fileName, int lineNumber)
		{
			builder.Append("(");
			if (IncludeSourcePath)
			{
				builder.Append(fileName);
			}
			else
			{
				builder.Append(Path.GetFileName(fileName));
			}
			builder.Append(":");
			builder.AppendInvariant(lineNumber);
			builder.Append(")");
		}
	}
