	[LayoutRenderer("counter")]
	public class CounterLayoutRenderer : LayoutRenderer
	{
		private static Dictionary<string, int> sequences = new Dictionary<string, int>();

		[DefaultValue(1)]
		public int Value { get; set; } = 1;

		[DefaultValue(1)]
		public int Increment { get; set; } = 1;

		public Layout Sequence { get; set; }

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			int nextValue = GetNextValue(logEvent);
			builder.AppendInvariant(nextValue);
		}

		private int GetNextValue(LogEventInfo logEvent)
		{
			int result;
			if (Sequence != null)
			{
				result = GetNextSequenceValue(Sequence.Render(logEvent), Value, Increment);
			}
			else
			{
				result = Value;
				Value += Increment;
			}
			return result;
		}

		private static int GetNextSequenceValue(string sequenceName, int defaultValue, int increment)
		{
			lock (sequences)
			{
				if (!sequences.TryGetValue(sequenceName, out var value))
				{
					value = defaultValue;
				}
				int result = value;
				value += increment;
				sequences[sequenceName] = value;
				return result;
			}
		}
	}
