	[LayoutRenderer("date")]
	[ThreadAgnostic]
	[ThreadSafe]
	public class DateLayoutRenderer : LayoutRenderer, IRawValue, IStringValueRenderer
	{
		private class CachedDateFormatted
		{
			public readonly DateTime Date;

			public readonly string FormattedDate;

			public CachedDateFormatted(DateTime date, string formattedDate)
			{
				Date = date;
				FormattedDate = formattedDate;
			}
		}

		private string _format;

		private const string _lowTimeResolutionChars = "YyMDdHh";

		private CachedDateFormatted _cachedDateFormatted = new CachedDateFormatted(DateTime.MinValue, string.Empty);

		public CultureInfo Culture { get; set; }

		[DefaultParameter]
		public string Format
		{
			get
			{
				return _format;
			}
			set
			{
				_format = value;
				if (IsLowTimeResolutionLayout(_format))
				{
					_cachedDateFormatted = new CachedDateFormatted(DateTime.MaxValue, string.Empty);
				}
				else
				{
					_cachedDateFormatted = new CachedDateFormatted(DateTime.MinValue, string.Empty);
				}
			}
		}

		[DefaultValue(false)]
		public bool UniversalTime { get; set; }

		public DateLayoutRenderer()
		{
			Format = "yyyy/MM/dd HH:mm:ss.fff";
			Culture = CultureInfo.InvariantCulture;
		}

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			builder.Append(GetStringValue(logEvent));
		}

		bool IRawValue.TryGetRawValue(LogEventInfo logEvent, out object value)
		{
			value = GetDate(logEvent);
			return true;
		}

		string IStringValueRenderer.GetFormattedString(LogEventInfo logEvent)
		{
			return GetStringValue(logEvent);
		}

		private string GetStringValue(LogEventInfo logEvent)
		{
			IFormatProvider formatProvider = GetFormatProvider(logEvent, Culture);
			DateTime date = GetDate(logEvent);
			CachedDateFormatted cachedDateFormatted = _cachedDateFormatted;
			if (formatProvider != CultureInfo.InvariantCulture || cachedDateFormatted.Date == DateTime.MinValue)
			{
				cachedDateFormatted = null;
			}
			else if (cachedDateFormatted.Date == date.Date.AddHours(date.Hour))
			{
				return cachedDateFormatted.FormattedDate;
			}
			string text = date.ToString(_format, formatProvider);
			if (cachedDateFormatted != null)
			{
				_cachedDateFormatted = new CachedDateFormatted(date.Date.AddHours(date.Hour), text);
			}
			return text;
		}

		private DateTime GetDate(LogEventInfo logEvent)
		{
			DateTime result = logEvent.TimeStamp;
			if (UniversalTime)
			{
				result = result.ToUniversalTime();
			}
			return result;
		}

		private static bool IsLowTimeResolutionLayout(string dateTimeFormat)
		{
			foreach (char c in dateTimeFormat)
			{
				if (char.IsLetter(c) && "YyMDdHh".IndexOf(c) < 0)
				{
					return false;
				}
			}
			return true;
		}
	}
