	[LayoutRenderer("guid")]
	[ThreadSafe]
	[ThreadAgnostic]
	public class GuidLayoutRenderer : LayoutRenderer, IRawValue, IStringValueRenderer
	{
		[DefaultValue("N")]
		public string Format { get; set; } = "N";

		[DefaultValue(false)]
		public bool GeneratedFromLogEvent { get; set; }

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			builder.Append(GetStringValue(logEvent));
		}

		bool IRawValue.TryGetRawValue(LogEventInfo logEvent, out object value)
		{
			value = GetValue(logEvent);
			return true;
		}

		string IStringValueRenderer.GetFormattedString(LogEventInfo logEvent)
		{
			return GetStringValue(logEvent);
		}

		private string GetStringValue(LogEventInfo logEvent)
		{
			return GetValue(logEvent).ToString(Format);
		}

		private Guid GetValue(LogEventInfo logEvent)
		{
			if (GeneratedFromLogEvent)
			{
				int hashCode = logEvent.GetHashCode();
				short b = (short)((hashCode >> 16) & 0xFFFF);
				short c = (short)(hashCode & 0xFFFF);
				DateTime zeroDate = LogEventInfo.ZeroDate;
				long ticks = zeroDate.Ticks;
				byte d = (byte)((ticks >> 56) & 0xFF);
				byte e = (byte)((ticks >> 48) & 0xFF);
				byte f = (byte)((ticks >> 40) & 0xFF);
				byte g = (byte)((ticks >> 32) & 0xFF);
				byte h = (byte)((ticks >> 24) & 0xFF);
				byte i = (byte)((ticks >> 16) & 0xFF);
				byte j = (byte)((ticks >> 8) & 0xFF);
				byte k = (byte)(ticks & 0xFF);
				return new Guid(logEvent.SequenceID, b, c, d, e, f, g, h, i, j, k);
			}
			return Guid.NewGuid();
		}
	}
	[LayoutRenderer("hostname")]
	[AppDomainFixedOutput]
	[ThreadAgnostic]
	[ThreadSafe]
	public class HostNameLayoutRenderer : LayoutRenderer
	{
		private string _hostName;

		protected override void InitializeLayoutRenderer()
		{
			base.InitializeLayoutRenderer();
			try
			{
				_hostName = GetHostName();
				if (string.IsNullOrEmpty(_hostName))
				{
					InternalLogger.Info("HostName is not available.");
				}
			}
			catch (Exception ex)
			{
				InternalLogger.Error(ex, "Error getting host name.");
				if (ex.MustBeRethrown())
				{
					throw;
				}
				_hostName = string.Empty;
			}
		}

		private static string GetHostName()
		{
			return TryLookupValue(() => Environment.GetEnvironmentVariable("HOSTNAME"), "HOSTNAME") ?? TryLookupValue(() => Dns.GetHostName(), "DnsHostName") ?? TryLookupValue(() => EnvironmentHelper.GetMachineName(), "MachineName");
		}

		private static string TryLookupValue(Func<string> lookupFunc, string lookupType)
		{
			try
			{
				string text = lookupFunc()?.Trim();
				return string.IsNullOrEmpty(text) ? null : text;
			}
			catch (Exception ex)
			{
				InternalLogger.Warn(ex, "Failed to lookup {0}", lookupType);
				return null;
			}
		}

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			builder.Append(_hostName);
		}
	}
	[LayoutRenderer("identity")]
	[ThreadSafe]
	public class IdentityLayoutRenderer : LayoutRenderer
	{
		[DefaultValue(":")]
		public string Separator { get; set; } = ":";

		[DefaultValue(true)]
		public bool Name { get; set; } = true;

		[DefaultValue(true)]
		public bool AuthType { get; set; } = true;

		[DefaultValue(true)]
		public bool IsAuthenticated { get; set; } = true;

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			IIdentity value = GetValue();
			if (value != null)
			{
				string value2 = string.Empty;
				if (IsAuthenticated)
				{
					builder.Append(value2);
					value2 = Separator;
					builder.Append(value.IsAuthenticated ? "auth" : "notauth");
				}
				if (AuthType)
				{
					builder.Append(value2);
					value2 = Separator;
					builder.Append(value.AuthenticationType);
				}
				if (Name)
				{
					builder.Append(value2);
					builder.Append(value.Name);
				}
			}
		}

		private static IIdentity GetValue()
		{
			return Thread.CurrentPrincipal?.Identity;
		}
	}
	[LayoutRenderer("install-context")]
	[ThreadSafe]
	public class InstallContextLayoutRenderer : LayoutRenderer
	{
		[RequiredParameter]
		[DefaultParameter]
		public string Parameter { get; set; }

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			object value = GetValue(logEvent);
			if (value != null)
			{
				IFormatProvider formatProvider = GetFormatProvider(logEvent);
				builder.Append(Convert.ToString(value, formatProvider));
			}
		}

		private object GetValue(LogEventInfo logEvent)
		{
			if (logEvent.Properties.TryGetValue(Parameter, out var value))
			{
				return value;
			}
			return null;
		}
	}
	[NLogConfigurationItem]
	public abstract class LayoutRenderer : ISupportsInitialize, IRenderable, IDisposable
	{
		private const int MaxInitialRenderBufferLength = 16384;

		private int _maxRenderedLength;

		private bool _isInitialized;

		protected LoggingConfiguration LoggingConfiguration { get; private set; }

		public override string ToString()
		{
			LayoutRendererAttribute customAttribute = GetType().GetCustomAttribute<LayoutRendererAttribute>();
			if (customAttribute != null)
			{
				return "Layout Renderer: ${" + customAttribute.Name + "}";
			}
			return GetType().Name;
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		public string Render(LogEventInfo logEvent)
		{
			int num = _maxRenderedLength;
			if (num > 16384)
			{
				num = 16384;
			}
			StringBuilder stringBuilder = new StringBuilder(num);
			RenderAppendBuilder(logEvent, stringBuilder);
			if (stringBuilder.Length > _maxRenderedLength)
			{
				_maxRenderedLength = stringBuilder.Length;
			}
			return stringBuilder.ToString();
		}

		void ISupportsInitialize.Initialize(LoggingConfiguration configuration)
		{
			Initialize(configuration);
		}

		void ISupportsInitialize.Close()
		{
			Close();
		}

		internal void Initialize(LoggingConfiguration configuration)
		{
			if (LoggingConfiguration == null)
			{
				LoggingConfiguration = configuration;
			}
			if (!_isInitialized)
			{
				_isInitialized = true;
				InitializeLayoutRenderer();
			}
		}

		internal void Close()
		{
			if (_isInitialized)
			{
				LoggingConfiguration = null;
				_isInitialized = false;
				CloseLayoutRenderer();
			}
		}

		internal void RenderAppendBuilder(LogEventInfo logEvent, StringBuilder builder)
		{
			if (!_isInitialized)
			{
				_isInitialized = true;
				InitializeLayoutRenderer();
			}
			try
			{
				Append(builder, logEvent);
			}
			catch (Exception ex)
			{
				InternalLogger.Warn(ex, "Exception in layout renderer.");
				if (ex.MustBeRethrown())
				{
					throw;
				}
			}
		}

		protected abstract void Append(StringBuilder builder, LogEventInfo logEvent);

		protected virtual void InitializeLayoutRenderer()
		{
		}

		protected virtual void CloseLayoutRenderer()
		{
		}

		protected virtual void Dispose(bool disposing)
		{
			if (disposing)
			{
				Close();
			}
		}

		protected IFormatProvider GetFormatProvider(LogEventInfo logEvent, IFormatProvider layoutCulture = null)
		{
			object obj = logEvent.FormatProvider;
			if (obj == null)
			{
				obj = layoutCulture;
				if (obj == null)
				{
					LoggingConfiguration loggingConfiguration = LoggingConfiguration;
					if (loggingConfiguration == null)
					{
						return null;
					}
					obj = loggingConfiguration.DefaultCultureInfo;
				}
			}
			return (IFormatProvider)obj;
		}

		protected CultureInfo GetCulture(LogEventInfo logEvent, CultureInfo layoutCulture = null)
		{
			object obj = logEvent.FormatProvider as CultureInfo;
			if (obj == null)
			{
				obj = layoutCulture;
				if (obj == null)
				{
					LoggingConfiguration loggingConfiguration = LoggingConfiguration;
					if (loggingConfiguration == null)
					{
						return null;
					}
					obj = loggingConfiguration.DefaultCultureInfo;
				}
			}
			return (CultureInfo)obj;
		}

		public static void Register<T>(string name) where T : LayoutRenderer
		{
			Type typeFromHandle = typeof(T);
			Register(name, typeFromHandle);
		}

		public static void Register(string name, Type layoutRendererType)
		{
			ConfigurationItemFactory.Default.LayoutRenderers.RegisterDefinition(name, layoutRendererType);
		}

		public static void Register(string name, Func<LogEventInfo, object> func)
		{
			Register(name, (LogEventInfo info, LoggingConfiguration configuration) => func(info));
		}

		public static void Register(string name, Func<LogEventInfo, LoggingConfiguration, object> func)
		{
			FuncLayoutRenderer renderer = new FuncLayoutRenderer(name, func);
			ConfigurationItemFactory.Default.GetLayoutRenderers().RegisterFuncLayout(name, renderer);
		}
	}
	[AttributeUsage(AttributeTargets.Class)]
	public sealed class LayoutRendererAttribute : NameBaseAttribute
	{
		public LayoutRendererAttribute(string name)
			: base(name)
		{
		}
	}
	public enum LevelFormat
	{
		Name,
		FirstCharacter,
		Ordinal,
		FullName
	}
	[LayoutRenderer("level")]
	[ThreadAgnostic]
	[ThreadSafe]
	public class LevelLayoutRenderer : LayoutRenderer, IRawValue, IStringValueRenderer
	{
		[DefaultValue(LevelFormat.Name)]
		public LevelFormat Format { get; set; }

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			LogLevel value = GetValue(logEvent);
			switch (Format)
			{
			case LevelFormat.Name:
				builder.Append(value.ToString());
				break;
			case LevelFormat.FirstCharacter:
				builder.Append(value.ToString()[0]);
				break;
			case LevelFormat.Ordinal:
				builder.AppendInvariant(value.Ordinal);
				break;
			case LevelFormat.FullName:
				if (value == LogLevel.Info)
				{
					builder.Append("Information");
				}
				else if (value == LogLevel.Warn)
				{
					builder.Append("Warning");
				}
				else
				{
					builder.Append(value.ToString());
				}
				break;
			}
		}

		bool IRawValue.TryGetRawValue(LogEventInfo logEvent, out object value)
		{
			value = GetValue(logEvent);
			return true;
		}

		string IStringValueRenderer.GetFormattedString(LogEventInfo logEvent)
		{
			if (Format != LevelFormat.Name)
			{
				return null;
			}
			return GetValue(logEvent).ToString();
		}

		private static LogLevel GetValue(LogEventInfo logEvent)
		{
			return logEvent.Level;
		}
	}
