		{
			builder.Append(Text);
		}
	}
	[LayoutRenderer("log4jxmlevent")]
	[ThreadSafe]
	[MutableUnsafe]
	public class Log4JXmlEventLayoutRenderer : LayoutRenderer, IUsesStackTrace, IIncludeContext
	{
		private static readonly DateTime log4jDateBase = new DateTime(1970, 1, 1);

		private static readonly string dummyNamespace = "http://nlog-project.org/dummynamespace/" + Guid.NewGuid();

		private static readonly string dummyNamespaceRemover = " xmlns:log4j=\"" + dummyNamespace + "\"";

		private static readonly string dummyNLogNamespace = "http://nlog-project.org/dummynamespace/" + Guid.NewGuid();

		private static readonly string dummyNLogNamespaceRemover = " xmlns:nlog=\"" + dummyNLogNamespace + "\"";

		private readonly NdcLayoutRenderer _ndcLayoutRenderer = new NdcLayoutRenderer
		{
			Separator = " "
		};

		private readonly NdlcLayoutRenderer _ndlcLayoutRenderer = new NdlcLayoutRenderer
		{
			Separator = " "
		};

		private readonly string _machineName;

		private XmlWriterSettings _xmlWriterSettings;

		[DefaultValue(true)]
		public bool IncludeNLogData { get; set; }

		public bool IndentXml { get; set; }

		public string AppInfo { get; set; }

		public bool IncludeCallSite { get; set; }

		public bool IncludeSourceInfo { get; set; }

		public bool IncludeMdc { get; set; }

		public bool IncludeMdlc { get; set; }

		public bool IncludeNdlc { get; set; }

		[DefaultValue(" ")]
		public string NdlcItemSeparator
		{
			get
			{
				return _ndlcLayoutRenderer.Separator;
			}
			set
			{
				_ndlcLayoutRenderer.Separator = value;
			}
		}

		public bool IncludeAllProperties { get; set; }

		public bool IncludeNdc { get; set; }

		[DefaultValue(" ")]
		public string NdcItemSeparator
		{
			get
			{
				return _ndcLayoutRenderer.Separator;
			}
			set
			{
				_ndcLayoutRenderer.Separator = value;
			}
		}

		public Layout LoggerName { get; set; }

		StackTraceUsage IUsesStackTrace.StackTraceUsage
		{
			get
			{
				if (IncludeSourceInfo)
				{
					return StackTraceUsage.WithSource;
				}
				if (IncludeCallSite)
				{
					return StackTraceUsage.WithoutSource;
				}
				return StackTraceUsage.None;
			}
		}

		internal IList<NLogViewerParameterInfo> Parameters { get; set; }

		public Log4JXmlEventLayoutRenderer()
			: this(LogFactory.CurrentAppDomain)
		{
		}

		public Log4JXmlEventLayoutRenderer(IAppDomain appDomain)
		{
			IncludeNLogData = true;
			AppInfo = string.Format(CultureInfo.InvariantCulture, "{0}({1})", appDomain.FriendlyName, LogFactory.DefaultAppEnvironment.CurrentProcessId);
			Parameters = new List<NLogViewerParameterInfo>();
			try
			{
				_machineName = EnvironmentHelper.GetMachineName();
				if (string.IsNullOrEmpty(_machineName))
				{
					InternalLogger.Info("MachineName is not available.");
				}
			}
			catch (Exception ex)
			{
				InternalLogger.Error(ex, "Error getting machine name.");
				if (ex.MustBeRethrown())
				{
					throw;
				}
				_machineName = string.Empty;
			}
		}

		protected override void InitializeLayoutRenderer()
		{
			base.InitializeLayoutRenderer();
			_xmlWriterSettings = new XmlWriterSettings
			{
				Indent = IndentXml,
				ConformanceLevel = ConformanceLevel.Fragment,
				IndentChars = "  "
			};
		}

		internal void AppendToStringBuilder(StringBuilder sb, LogEventInfo logEvent)
		{
			Append(sb, logEvent);
		}

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			StringBuilder stringBuilder = new StringBuilder();
			using XmlWriter xmlWriter = XmlWriter.Create(stringBuilder, _xmlWriterSettings);
			xmlWriter.WriteStartElement("log4j", "event", dummyNamespace);
			xmlWriter.WriteAttributeSafeString("xmlns", "nlog", null, dummyNLogNamespace);
			xmlWriter.WriteAttributeSafeString("logger", (LoggerName != null) ? LoggerName.Render(logEvent) : logEvent.LoggerName);
			xmlWriter.WriteAttributeSafeString("level", logEvent.Level.Name.ToUpperInvariant());
			xmlWriter.WriteAttributeSafeString("timestamp", Convert.ToString((long)(logEvent.TimeStamp.ToUniversalTime() - log4jDateBase).TotalMilliseconds, CultureInfo.InvariantCulture));
			xmlWriter.WriteAttributeSafeString("thread", AsyncHelpers.GetManagedThreadId().ToString(CultureInfo.InvariantCulture));
			xmlWriter.WriteElementSafeString("log4j", "message", dummyNamespace, logEvent.FormattedMessage);
			if (logEvent.Exception != null)
			{
				xmlWriter.WriteElementSafeString("log4j", "throwable", dummyNamespace, logEvent.Exception.ToString());
			}
			AppendNdc(xmlWriter, logEvent);
			AppendException(logEvent, xmlWriter);
			AppendCallSite(logEvent, xmlWriter);
			AppendProperties(xmlWriter);
			AppendMdlc(xmlWriter);
			if (IncludeAllProperties)
			{
				AppendProperties("log4j", xmlWriter, logEvent);
			}
			AppendParameters(logEvent, xmlWriter);
			xmlWriter.WriteStartElement("log4j", "data", dummyNamespace);
			xmlWriter.WriteAttributeSafeString("name", "log4japp");
			xmlWriter.WriteAttributeSafeString("value", AppInfo);
			xmlWriter.WriteEndElement();
			xmlWriter.WriteStartElement("log4j", "data", dummyNamespace);
			xmlWriter.WriteAttributeSafeString("name", "log4jmachinename");
			xmlWriter.WriteAttributeSafeString("value", _machineName);
			xmlWriter.WriteEndElement();
			xmlWriter.WriteEndElement();
			xmlWriter.WriteEndElement();
			xmlWriter.Flush();
			stringBuilder.Replace(dummyNamespaceRemover, string.Empty);
			stringBuilder.Replace(dummyNLogNamespaceRemover, string.Empty);
			stringBuilder.CopyTo(builder);
		}

		private void AppendMdlc(XmlWriter xtw)
		{
			if (!IncludeMdlc)
			{
				return;
			}
			foreach (string name in MappedDiagnosticsLogicalContext.GetNames())
			{
				string text = XmlHelper.XmlConvertToString(MappedDiagnosticsLogicalContext.GetObject(name));
				if (text != null)
				{
					xtw.WriteStartElement("log4j", "data", dummyNamespace);
					xtw.WriteAttributeSafeString("name", name);
					xtw.WriteAttributeSafeString("value", text);
					xtw.WriteEndElement();
				}
			}
		}

		private void AppendNdc(XmlWriter xtw, LogEventInfo logEvent)
		{
			string text = null;
			if (IncludeNdc)
			{
				text = _ndcLayoutRenderer.Render(logEvent);
			}
			if (IncludeNdlc)
			{
				if (text != null)
				{
					text += NdcItemSeparator;
				}
				text += _ndlcLayoutRenderer.Render(logEvent);
			}
			if (text != null)
			{
				xtw.WriteElementSafeString("log4j", "NDC", dummyNamespace, text);
			}
		}

		private static void AppendException(LogEventInfo logEvent, XmlWriter xtw)
		{
			if (logEvent.Exception != null)
			{
				xtw.WriteStartElement("log4j", "throwable", dummyNamespace);
				xtw.WriteSafeCData(logEvent.Exception.ToString());
				xtw.WriteEndElement();
			}
		}

		private void AppendParameters(LogEventInfo logEvent, XmlWriter xtw)
		{
			for (int i = 0; i < Parameters?.Count; i++)
			{
				NLogViewerParameterInfo nLogViewerParameterInfo = Parameters[i];
				if (!string.IsNullOrEmpty(nLogViewerParameterInfo?.Name))
				{
					string value = nLogViewerParameterInfo.Layout?.Render(logEvent) ?? string.Empty;
					if (nLogViewerParameterInfo.IncludeEmptyValue || !string.IsNullOrEmpty(value))
					{
						xtw.WriteStartElement("log4j", "data", dummyNamespace);
						xtw.WriteAttributeSafeString("name", nLogViewerParameterInfo.Name);
						xtw.WriteAttributeSafeString("value", value);
						xtw.WriteEndElement();
					}
				}
			}
		}

		private void AppendProperties(XmlWriter xtw)
		{
			xtw.WriteStartElement("log4j", "properties", dummyNamespace);
			if (!IncludeMdc)
			{
				return;
			}
			foreach (string name in MappedDiagnosticsContext.GetNames())
			{
				string text = XmlHelper.XmlConvertToString(MappedDiagnosticsContext.GetObject(name));
				if (text != null)
				{
					xtw.WriteStartElement("log4j", "data", dummyNamespace);
					xtw.WriteAttributeSafeString("name", name);
					xtw.WriteAttributeSafeString("value", text);
					xtw.WriteEndElement();
				}
			}
		}

		private void AppendCallSite(LogEventInfo logEvent, XmlWriter xtw)
		{
			if ((!IncludeCallSite && !IncludeSourceInfo) || logEvent.CallSiteInformation == null)
			{
				return;
			}
			MethodBase callerStackFrameMethod = logEvent.CallSiteInformation.GetCallerStackFrameMethod(0);
			string callerClassName = logEvent.CallSiteInformation.GetCallerClassName(callerStackFrameMethod, includeNameSpace: true, cleanAsyncMoveNext: true, cleanAnonymousDelegates: true);
			string callerMemberName = logEvent.CallSiteInformation.GetCallerMemberName(callerStackFrameMethod, includeMethodInfo: true, cleanAsyncMoveNext: true, cleanAnonymousDelegates: true);
			xtw.WriteStartElement("log4j", "locationInfo", dummyNamespace);
			if (!string.IsNullOrEmpty(callerClassName))
			{
				xtw.WriteAttributeSafeString("class", callerClassName);
			}
			xtw.WriteAttributeSafeString("method", callerMemberName);
			if (IncludeSourceInfo)
			{
				xtw.WriteAttributeSafeString("file", logEvent.CallSiteInformation.GetCallerFilePath(0));
				xtw.WriteAttributeSafeString("line", logEvent.CallSiteInformation.GetCallerLineNumber(0).ToString(CultureInfo.InvariantCulture));
			}
			xtw.WriteEndElement();
			if (IncludeNLogData)
			{
				xtw.WriteElementSafeString("nlog", "eventSequenceNumber", dummyNLogNamespace, logEvent.SequenceID.ToString(CultureInfo.InvariantCulture));
				xtw.WriteStartElement("nlog", "locationInfo", dummyNLogNamespace);
				Type type = callerStackFrameMethod?.DeclaringType;
				if (type != null)
				{
					xtw.WriteAttributeSafeString("assembly", type.GetAssembly().FullName);
				}
				xtw.WriteEndElement();
				xtw.WriteStartElement("nlog", "properties", dummyNLogNamespace);
				AppendProperties("nlog", xtw, logEvent);
				xtw.WriteEndElement();
			}
		}

		private void AppendProperties(string prefix, XmlWriter xtw, LogEventInfo logEvent)
		{
			if (!logEvent.HasProperties)
			{
				return;
			}
			foreach (KeyValuePair<object, object> property in logEvent.Properties)
			{
				string value = XmlHelper.XmlConvertToString(property.Key);
				if (!string.IsNullOrEmpty(value))
				{
					string text = XmlHelper.XmlConvertToString(property.Value);
					if (text != null)
					{
						xtw.WriteStartElement(prefix, "data", dummyNamespace);
						xtw.WriteAttributeSafeString("name", value);
						xtw.WriteAttributeSafeString("value", text);
						xtw.WriteEndElement();
					}
				}
			}
		}
	}
	[LayoutRenderer("logger")]
	[ThreadAgnostic]
	[ThreadSafe]
	public class LoggerNameLayoutRenderer : LayoutRenderer, IStringValueRenderer
	{
		[DefaultValue(false)]
		public bool ShortName { get; set; }

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			if (ShortName)
			{
				int num = TryGetLastDotForShortName(logEvent);
				if (num >= 0)
				{
					builder.Append(logEvent.LoggerName, num + 1, logEvent.LoggerName.Length - num - 1);
					return;
				}
			}
			builder.Append(logEvent.LoggerName);
		}

		string IStringValueRenderer.GetFormattedString(LogEventInfo logEvent)
		{
			if (ShortName)
			{
				int num = TryGetLastDotForShortName(logEvent);
				if (num >= 0)
				{
					return logEvent.LoggerName.Substring(num + 1);
				}
			}
			return logEvent.LoggerName ?? string.Empty;
		}

		private int TryGetLastDotForShortName(LogEventInfo logEvent)
		{
			return logEvent.LoggerName?.LastIndexOf('.') ?? (-1);
		}
	}
	[LayoutRenderer("longdate")]
	[ThreadAgnostic]
	[ThreadSafe]
	public class LongDateLayoutRenderer : LayoutRenderer, IRawValue
	{
		[DefaultValue(false)]
		public bool UniversalTime { get; set; }

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			DateTime value = GetValue(logEvent);
			builder.Append4DigitsZeroPadded(value.Year);
			builder.Append('-');
			builder.Append2DigitsZeroPadded(value.Month);
			builder.Append('-');
			builder.Append2DigitsZeroPadded(value.Day);
			builder.Append(' ');
			builder.Append2DigitsZeroPadded(value.Hour);
			builder.Append(':');
			builder.Append2DigitsZeroPadded(value.Minute);
			builder.Append(':');
			builder.Append2DigitsZeroPadded(value.Second);
			builder.Append('.');
			builder.Append4DigitsZeroPadded((int)(value.Ticks % 10000000) / 1000);
		}

		bool IRawValue.TryGetRawValue(LogEventInfo logEvent, out object value)
		{
			value = GetValue(logEvent);
			return true;
		}

		private DateTime GetValue(LogEventInfo logEvent)
		{
			DateTime result = logEvent.TimeStamp;
			if (UniversalTime)
			{
				result = result.ToUniversalTime();
			}
			return result;
		}
	}
