	[LayoutRenderer("mdc")]
	[ThreadSafe]
	public class MdcLayoutRenderer : LayoutRenderer, IStringValueRenderer
	{
		[RequiredParameter]
		[DefaultParameter]
		public string Item { get; set; }

		public string Format { get; set; }

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			object value = GetValue();
			IFormatProvider formatProvider = GetFormatProvider(logEvent);
			builder.AppendFormattedValue(value, Format, formatProvider);
		}

		string IStringValueRenderer.GetFormattedString(LogEventInfo logEvent)
		{
			return GetStringValue(logEvent);
		}

		private string GetStringValue(LogEventInfo logEvent)
		{
			if (Format != "@")
			{
				return FormatHelper.TryFormatToString(GetValue(), Format, GetFormatProvider(logEvent));
			}
