	[LayoutRenderer("ndc")]
	[ThreadSafe]
	public class NdcLayoutRenderer : LayoutRenderer
	{
		public int TopFrames { get; set; }

		public int BottomFrames { get; set; }

		public string Separator { get; set; }

		public NdcLayoutRenderer()
		{
			Separator = " ";
			BottomFrames = -1;
			TopFrames = -1;
		}

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			if (TopFrames == 1)
			{
				object obj = NestedDiagnosticsContext.PeekObject();
				if (obj != null)
				{
					AppendAsString(obj, GetFormatProvider(logEvent), builder);
				}
				return;
			}
			object[] allObjects = NestedDiagnosticsContext.GetAllObjects();
			if (allObjects.Length != 0)
			{
				int num = 0;
				int num2 = allObjects.Length;
				if (TopFrames != -1)
				{
					num2 = Math.Min(TopFrames, allObjects.Length);
				}
				else if (BottomFrames != -1)
				{
					num = allObjects.Length - Math.Min(BottomFrames, allObjects.Length);
				}
				IFormatProvider formatProvider = GetFormatProvider(logEvent);
				string value = string.Empty;
				for (int num3 = num2 - 1; num3 >= num; num3--)
				{
					builder.Append(value);
					AppendAsString(allObjects[num3], formatProvider, builder);
					value = Separator;
				}
			}
		}

		private static void AppendAsString(object message, IFormatProvider formatProvider, StringBuilder builder)
		{
