	public enum StackTraceFormat
	{
		Raw,
		Flat,
		DetailedFlat
	}
	[LayoutRenderer("stacktrace")]
	[ThreadAgnostic]
	[ThreadSafe]
	public class StackTraceLayoutRenderer : LayoutRenderer, IUsesStackTrace
	{
		[DefaultValue("Flat")]
		public StackTraceFormat Format { get; set; }

		[DefaultValue(3)]
		public int TopFrames { get; set; }

		[DefaultValue(0)]
		public int SkipFrames { get; set; }

		[DefaultValue(" => ")]
		public string Separator { get; set; }

		[DefaultValue(true)]
		public bool CaptureStackTrace { get; set; } = true;

		StackTraceUsage IUsesStackTrace.StackTraceUsage
		{
			get
			{
				if (!CaptureStackTrace)
				{
					return StackTraceUsage.None;
				}
				if (Format == StackTraceFormat.Raw)
				{
					return StackTraceUsage.WithSource;
				}
				return StackTraceUsage.WithoutSource;
			}
		}

		public StackTraceLayoutRenderer()
		{
			Separator = " => ";
			TopFrames = 3;
			Format = StackTraceFormat.Flat;
		}

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			if (logEvent.StackTrace != null)
			{
				int num = logEvent.UserStackFrameNumber + TopFrames - 1;
				if (num >= logEvent.StackTrace.GetFrameCount())
				{
					num = logEvent.StackTrace.GetFrameCount() - 1;
				}
				int endingFrame = logEvent.UserStackFrameNumber + SkipFrames;
				switch (Format)
				{
				case StackTraceFormat.Raw:
					AppendRaw(builder, logEvent, num, endingFrame);
					break;
				case StackTraceFormat.Flat:
					AppendFlat(builder, logEvent, num, endingFrame);
					break;
				case StackTraceFormat.DetailedFlat:
					AppendDetailedFlat(builder, logEvent, num, endingFrame);
					break;
				}
			}
		}

		private static void AppendRaw(StringBuilder builder, LogEventInfo logEvent, int startingFrame, int endingFrame)
		{
			for (int num = startingFrame; num >= endingFrame; num--)
			{
				StackFrame frame = logEvent.StackTrace.GetFrame(num);
				builder.Append(frame.ToString());
			}
		}

		private void AppendFlat(StringBuilder builder, LogEventInfo logEvent, int startingFrame, int endingFrame)
		{
			bool flag = true;
			for (int num = startingFrame; num >= endingFrame; num--)
			{
				StackFrame frame = logEvent.StackTrace.GetFrame(num);
				if (!flag)
				{
					builder.Append(Separator);
				}
				MethodBase method = frame.GetMethod();
				if (!(method == null))
				{
					Type declaringType = method.DeclaringType;
					if (declaringType != null)
					{
						builder.Append(declaringType.Name);
					}
					else
					{
						builder.Append("<no type>");
					}
					builder.Append(".");
					builder.Append(method.Name);
					flag = false;
				}
			}
		}

		private void AppendDetailedFlat(StringBuilder builder, LogEventInfo logEvent, int startingFrame, int endingFrame)
		{
			bool flag = true;
			for (int num = startingFrame; num >= endingFrame; num--)
			{
				MethodBase method = logEvent.StackTrace.GetFrame(num).GetMethod();
				if (!(method == null))
				{
					if (!flag)
					{
						builder.Append(Separator);
					}
					builder.Append("[");
					builder.Append(method);
					builder.Append("]");
					flag = false;
				}
			}
		}
	}
