	[LayoutRenderer("var")]
	[ThreadSafe]
	public class VariableLayoutRenderer : LayoutRenderer
	{
		[RequiredParameter]
		[DefaultParameter]
		public string Name { get; set; }

		public string Default { get; set; }

		protected override void InitializeLayoutRenderer()
		{
			if (TryGetLayout(out var layout) && layout != null)
			{
				layout.Initialize(base.LoggingConfiguration);
				if (!layout.ThreadSafe)
				{
					InternalLogger.Warn("${{var={0}}} should be declared as <variable name=\"var_{0}\" value=\"...\" /> and used like this ${{var_{0}}}. Because of unsafe Layout={1}", Name, layout);
				}
			}
			base.InitializeLayoutRenderer();
		}

		private bool TryGetLayout(out SimpleLayout layout)
		{
			layout = null;
			if (Name != null)
			{
				LoggingConfiguration loggingConfiguration = base.LoggingConfiguration;
				if (loggingConfiguration == null)
				{
					return false;
				}
				return loggingConfiguration.Variables?.TryGetValue(Name, out layout) == true;
			}
			return false;
		}

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			if (Name != null)
			{
				if (TryGetLayout(out var layout))
				{
					layout?.RenderAppendBuilder(logEvent, builder);
				}
				else if (Default != null)
				{
					builder.Append(Default);
				}
			}
		}
	}
	[LayoutRenderer("windows-identity")]
	[ThreadSafe]
	public class WindowsIdentityLayoutRenderer : LayoutRenderer
	{
		[DefaultValue(true)]
		public bool Domain { get; set; }

		[DefaultValue(true)]
		public bool UserName { get; set; }

		public WindowsIdentityLayoutRenderer()
		{
			UserName = true;
			Domain = true;
		}

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			WindowsIdentity value = GetValue();
			if (value == null)
			{
				return;
			}
			string value2;
			if (UserName)
			{
				value2 = (Domain ? GetUserNameWithDomain(value) : GetUserNameWithoutDomain(value));
			}
			else
			{
				if (!Domain)
				{
					return;
				}
				value2 = GetDomainOnly(value);
			}
			builder.Append(value2);
		}

		private static string GetDomainOnly(WindowsIdentity currentIdentity)
		{
			int num = currentIdentity.Name.IndexOf('\\');
			if (num >= 0)
			{
				return currentIdentity.Name.Substring(0, num);
			}
			return currentIdentity.Name;
		}

		private static string GetUserNameWithoutDomain(WindowsIdentity currentIdentity)
		{
			int num = currentIdentity.Name.LastIndexOf('\\');
			if (num >= 0)
			{
				return currentIdentity.Name.Substring(num + 1);
			}
			return currentIdentity.Name;
		}

		private static string GetUserNameWithDomain(WindowsIdentity currentIdentity)
		{
			return currentIdentity.Name;
		}

		private static WindowsIdentity GetValue()
		{
			return WindowsIdentity.GetCurrent();
		}
	}
