	[AppDomainFixedOutput]
	[ThreadAgnostic]
	[ThreadSafe]
	public sealed class PaddingLayoutRendererWrapper : WrapperLayoutRendererBase
	{
		public int Padding { get; set; }

		[DefaultValue(' ')]
		public char PadCharacter { get; set; }

		[DefaultValue(false)]
		public bool FixedLength { get; set; }

		[DefaultValue(PaddingHorizontalAlignment.Left)]
		public PaddingHorizontalAlignment AlignmentOnTruncation { get; set; }

		public PaddingLayoutRendererWrapper()
		{
			PadCharacter = ' ';
		}

		protected override string Transform(string text)
		{
			string text2 = text ?? string.Empty;
			if (Padding != 0)
			{
				text2 = ((Padding <= 0) ? text2.PadRight(-Padding, PadCharacter) : text2.PadLeft(Padding, PadCharacter));
				int num = Padding;
				if (num < 0)
				{
					num = -num;
				}
				if (FixedLength && text2.Length > num)
				{
					text2 = ((AlignmentOnTruncation != PaddingHorizontalAlignment.Right) ? text2.Substring(0, num) : text2.Substring(text2.Length - num));
				}
			}
			return text2;
		}
	}
	[LayoutRenderer("replace")]
	[AppDomainFixedOutput]
	[ThreadAgnostic]
	[ThreadSafe]
	public sealed class ReplaceLayoutRendererWrapper : WrapperLayoutRendererBase
	{
		[ThreadAgnostic]
		[Obsolete("This class should not be used. Marked obsolete on NLog 4.7")]
		public class Replacer
		{
			private readonly string _text;

			private readonly string _replaceGroupName;

			private readonly string _replaceWith;

			internal Replacer(string text, string replaceGroupName, string replaceWith)
			{
				_text = text;
				_replaceGroupName = replaceGroupName;
				_replaceWith = replaceWith;
			}

			internal string EvaluateMatch(Match match)
			{
				return ReplaceNamedGroup(_replaceGroupName, _replaceWith, match);
			}
		}

		private RegexHelper _regexHelper;

		private MatchEvaluator _groupMatchEvaluator;

		[DefaultValue(null)]
		public string SearchFor { get; set; }

		[DefaultValue(false)]
		public bool Regex { get; set; }

		[DefaultValue(null)]
		public string ReplaceWith { get; set; }

		[DefaultValue(null)]
		public string ReplaceGroupName { get; set; }

		[DefaultValue(false)]
		public bool IgnoreCase { get; set; }

		[DefaultValue(false)]
		public bool WholeWords { get; set; }

		[DefaultValue(false)]
		public bool CompileRegex { get; set; }

		protected override void InitializeLayoutRenderer()
		{
			base.InitializeLayoutRenderer();
			_regexHelper = new RegexHelper
			{
				IgnoreCase = IgnoreCase,
				WholeWords = WholeWords,
				CompileRegex = CompileRegex
			};
			if (Regex)
			{
				_regexHelper.RegexPattern = SearchFor;
			}
			else
			{
				_regexHelper.SearchText = SearchFor;
			}
			if (!string.IsNullOrEmpty(ReplaceGroupName))
			{
				Regex regex = _regexHelper.Regex;
				if (regex != null && regex.GetGroupNames()?.Contains(ReplaceGroupName) == false)
				{
					InternalLogger.Warn("Replace-LayoutRenderer assigned unknown ReplaceGroupName: {0}", ReplaceGroupName);
				}
			}
		}

		protected override string Transform(string text)
		{
			if (string.IsNullOrEmpty(ReplaceGroupName))
			{
				return _regexHelper.Replace(text, ReplaceWith);
			}
			if (_groupMatchEvaluator == null)
			{
				_groupMatchEvaluator = (Match m) => ReplaceNamedGroup(ReplaceGroupName, ReplaceWith, m);
			}
			return _regexHelper.Regex?.Replace(text, _groupMatchEvaluator) ?? text;
		}

		[Obsolete("This method should not be used. Marked obsolete on NLog 4.7")]
		public static string ReplaceNamedGroup(string input, string groupName, string replacement, Match match)
		{
			return ReplaceNamedGroup(groupName, replacement, match);
		}

		internal static string ReplaceNamedGroup(string groupName, string replacement, Match match)
		{
			StringBuilder stringBuilder = new StringBuilder(match.Value);
			int num = match.Length;
			foreach (Capture item in from c in match.Groups[groupName].Captures.OfType<Capture>()
				orderby c.Index descending
				select c)
			{
				num += replacement.Length - item.Length;
				stringBuilder.Remove(item.Index - match.Index, item.Length);
				stringBuilder.Insert(item.Index - match.Index, replacement);
			}
			int num2 = num;
			stringBuilder.Remove(num2, stringBuilder.Length - num2);
			return stringBuilder.ToString();
		}
	}
