	[LayoutRenderer("whenEmpty")]
	[AmbientProperty("WhenEmpty")]
	[ThreadAgnostic]
	[ThreadSafe]
	public sealed class WhenEmptyLayoutRendererWrapper : WrapperLayoutRendererBuilderBase, IRawValue, IStringValueRenderer
	{
		private bool _skipStringValueRenderer;

		[RequiredParameter]
		public Layout WhenEmpty { get; set; }

		protected override void InitializeLayoutRenderer()
		{
			base.InitializeLayoutRenderer();
			WhenEmpty?.Initialize(base.LoggingConfiguration);
			_skipStringValueRenderer = !TryGetStringValue(out var _, out var _);
		}

		protected override void RenderInnerAndTransform(LogEventInfo logEvent, StringBuilder builder, int orgLength)
		{
			base.Inner.RenderAppendBuilder(logEvent, builder);
			if (builder.Length <= orgLength)
			{
				WhenEmpty.RenderAppendBuilder(logEvent, builder);
			}
		}

		string IStringValueRenderer.GetFormattedString(LogEventInfo logEvent)
		{
			if (_skipStringValueRenderer)
			{
				return null;
			}
			if (TryGetStringValue(out var innerLayout, out var whenEmptyLayout))
			{
				string text = innerLayout.Render(logEvent);
				if (!string.IsNullOrEmpty(text))
				{
					return text;
				}
				return whenEmptyLayout.Render(logEvent);
			}
			_skipStringValueRenderer = true;
			return null;
		}

		private bool TryGetStringValue(out SimpleLayout innerLayout, out SimpleLayout whenEmptyLayout)
		{
			whenEmptyLayout = WhenEmpty as SimpleLayout;
			innerLayout = base.Inner as SimpleLayout;
			if (IsStringLayout(innerLayout))
			{
				return IsStringLayout(whenEmptyLayout);
			}
			return false;
		}

		private static bool IsStringLayout(SimpleLayout innerLayout)
		{
			if (innerLayout != null)
			{
				if (!innerLayout.IsFixedText)
				{
					return innerLayout.IsSimpleStringText;
				}
				return true;
			}
			return false;
		}

		bool IRawValue.TryGetRawValue(LogEventInfo logEvent, out object value)
		{
			if (base.Inner.TryGetRawValue(logEvent, out var rawValue))
			{
				if (rawValue != null && !rawValue.Equals(string.Empty))
				{
					value = rawValue;
					return true;
				}
			}
			else if (!string.IsNullOrEmpty(base.Inner.Render(logEvent)))
			{
				value = null;
				return false;
			}
			return WhenEmpty.TryGetRawValue(logEvent, out value);
		}

		[Obsolete("Inherit from WrapperLayoutRendererBase and override RenderInnerAndTransform() instead. Marked obsolete in NLog 4.6")]
		protected override void TransformFormattedMesssage(StringBuilder target)
		{
		}
	}
	[LayoutRenderer("when")]
	[AmbientProperty("When")]
	[ThreadAgnostic]
	[ThreadSafe]
	public sealed class WhenLayoutRendererWrapper : WrapperLayoutRendererBuilderBase, IRawValue
	{
		[RequiredParameter]
		public ConditionExpression When { get; set; }

		public Layout Else { get; set; }

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			int length = builder.Length;
			try
			{
				if (ShouldRenderInner(logEvent))
				{
					base.Inner?.RenderAppendBuilder(logEvent, builder);
				}
				else
				{
					Else?.RenderAppendBuilder(logEvent, builder);
				}
			}
			catch
			{
				builder.Length = length;
				throw;
			}
		}

		private bool ShouldRenderInner(LogEventInfo logEvent)
		{
			if (When != null)
			{
				return true.Equals(When.Evaluate(logEvent));
			}
			return true;
		}

		[Obsolete("Inherit from WrapperLayoutRendererBase and override RenderInnerAndTransform() instead. Marked obsolete in NLog 4.6")]
		protected override void TransformFormattedMesssage(StringBuilder target)
		{
		}

		public bool TryGetRawValue(LogEventInfo logEvent, out object value)
		{
			if (ShouldRenderInner(logEvent))
			{
				return TryGetRawValueFromLayout(logEvent, base.Inner, out value);
			}
			return TryGetRawValueFromLayout(logEvent, Else, out value);
		}

		private static bool TryGetRawValueFromLayout(LogEventInfo logEvent, Layout layout, out object value)
		{
			if (layout == null)
			{
				value = null;
				return false;
			}
			return layout.TryGetRawValue(logEvent, out value);
		}
	}
	[LayoutRenderer("wrapline")]
	[AmbientProperty("WrapLine")]
	[AppDomainFixedOutput]
	[ThreadAgnostic]
	[ThreadSafe]
	public sealed class WrapLineLayoutRendererWrapper : WrapperLayoutRendererBase
	{
		[DefaultValue(80)]
		public int WrapLine { get; set; }

		public WrapLineLayoutRendererWrapper()
		{
			WrapLine = 80;
		}

		protected override string Transform(string text)
		{
			if (WrapLine <= 0)
			{
				return text;
			}
			int num = WrapLine;
			if (text.Length <= num)
			{
				return text;
			}
			StringBuilder stringBuilder = new StringBuilder(text.Length + text.Length / num * Environment.NewLine.Length);
			for (int i = 0; i < text.Length; i += num)
			{
				if (num + i > text.Length)
				{
					num = text.Length - i;
				}
				stringBuilder.Append(text.Substring(i, num));
				if (num + i < text.Length)
				{
					stringBuilder.Append(Environment.NewLine);
				}
			}
			return stringBuilder.ToString();
		}
	}
	public abstract class WrapperLayoutRendererBase : LayoutRenderer
	{
		[DefaultParameter]
		public Layout Inner { get; set; }

		protected override void InitializeLayoutRenderer()
		{
			base.InitializeLayoutRenderer();
			Inner?.Initialize(base.LoggingConfiguration);
		}

		protected override void Append(StringBuilder builder, LogEventInfo logEvent)
		{
			if (Inner == null)
			{
				InternalLogger.Warn("{0} has no configured Inner-Layout, so skipping", this);
				return;
			}
			int length = builder.Length;
			try
			{
				RenderInnerAndTransform(logEvent, builder, length);
			}
			catch
			{
				builder.Length = length;
				throw;
			}
		}

		protected virtual void RenderInnerAndTransform(LogEventInfo logEvent, StringBuilder builder, int orgLength)
		{
			string text = RenderInner(logEvent);
			builder.Append(Transform(logEvent, text));
		}

		protected virtual string Transform(LogEventInfo logEvent, string text)
		{
			return Transform(text);
		}

		protected abstract string Transform(string text);

		protected virtual string RenderInner(LogEventInfo logEvent)
		{
			return Inner?.Render(logEvent) ?? string.Empty;
		}
	}
	public abstract class WrapperLayoutRendererBuilderBase : WrapperLayoutRendererBase
	{
		protected override void RenderInnerAndTransform(LogEventInfo logEvent, StringBuilder builder, int orgLength)
		{
			using AppendBuilderCreator appendBuilderCreator = new AppendBuilderCreator(builder, mustBeEmpty: true);
			RenderFormattedMessage(logEvent, appendBuilderCreator.Builder);
			TransformFormattedMesssage(logEvent, appendBuilderCreator.Builder);
		}

		[Obsolete("Inherit from WrapperLayoutRendererBase and override RenderInnerAndTransform() instead. Marked obsolete in NLog 4.6")]
		protected virtual void TransformFormattedMesssage(LogEventInfo logEvent, StringBuilder target)
		{
			TransformFormattedMesssage(target);
		}

		[Obsolete("Inherit from WrapperLayoutRendererBase and override RenderInnerAndTransform() instead. Marked obsolete in NLog 4.6")]
		protected abstract void TransformFormattedMesssage(StringBuilder target);

		[Obsolete("Inherit from WrapperLayoutRendererBase and override RenderInnerAndTransform() instead. Marked obsolete in NLog 4.6")]
		protected virtual void RenderFormattedMessage(LogEventInfo logEvent, StringBuilder target)
		{
			base.Inner.RenderAppendBuilder(logEvent, target);
		}

		protected sealed override string Transform(string text)
		{
			throw new NotSupportedException("Use TransformFormattedMesssage");
		}

		protected sealed override string RenderInner(LogEventInfo logEvent)
		{
			throw new NotSupportedException("Use RenderFormattedMessage");
		}
	}
	[LayoutRenderer("xml-encode")]
	[AmbientProperty("XmlEncode")]
	[AppDomainFixedOutput]
	[ThreadAgnostic]
	[ThreadSafe]
	public sealed class XmlEncodeLayoutRendererWrapper : WrapperLayoutRendererBase
	{
		[DefaultValue(true)]
		public bool XmlEncode { get; set; }

		[DefaultValue(false)]
		public bool XmlEncodeNewlines { get; set; }

		public XmlEncodeLayoutRendererWrapper()
		{
			XmlEncode = true;
		}

		protected override void RenderInnerAndTransform(LogEventInfo logEvent, StringBuilder builder, int orgLength)
		{
			base.Inner.RenderAppendBuilder(logEvent, builder);
			if (XmlEncode && RequiresXmlEncode(builder, orgLength))
			{
				string text = builder.ToString(orgLength, builder.Length - orgLength);
				builder.Length = orgLength;
				XmlHelper.EscapeXmlString(text, XmlEncodeNewlines, builder);
			}
		}

		protected override string Transform(string text)
		{
			if (XmlEncode)
			{
				return XmlHelper.EscapeXmlString(text, XmlEncodeNewlines);
			}
			return text;
		}

		private bool RequiresXmlEncode(StringBuilder target, int startPos = 0)
		{
			for (int i = startPos; i < target.Length; i++)
			{
				switch (target[i])
				{
				case '"':
				case '&':
				case '\'':
				case '<':
				case '>':
					return true;
				case '\n':
				case '\r':
					if (XmlEncodeNewlines)
					{
						return true;
					}
					break;
				}
			}
			return false;
		}
	}
