	internal static class AssemblyHelpers
	{
		public static Assembly LoadFromPath(string assemblyFileName, string baseDirectory = null)
		{
			string text = ((baseDirectory == null) ? assemblyFileName : Path.Combine(baseDirectory, assemblyFileName));
			InternalLogger.Info("Loading assembly file: {0}", text);
			return Assembly.LoadFrom(text);
		}

		public static Assembly LoadFromName(string assemblyName)
		{
			InternalLogger.Info("Loading assembly: {0}", assemblyName);
			try
			{
				return Assembly.Load(assemblyName);
			}
			catch (FileNotFoundException)
			{
				AssemblyName name = new AssemblyName(assemblyName);
				InternalLogger.Trace("Try find '{0}' in current domain", assemblyName);
				Assembly assembly = AppDomain.CurrentDomain.GetAssemblies().FirstOrDefault((Assembly domainAssembly) => IsAssemblyMatch(name, domainAssembly.GetName()));
				if (assembly != null)
				{
					InternalLogger.Trace("Found '{0}' in current domain", assemblyName);
					return assembly;
				}
				InternalLogger.Trace("Haven't found' '{0}' in current domain", assemblyName);
				throw;
			}
		}

		private static bool IsAssemblyMatch(AssemblyName expected, AssemblyName actual)
		{
			if (expected.Name != actual.Name)
			{
				return false;
			}
			if (expected.Version != null && expected.Version != actual.Version)
			{
				return false;
			}
			if (expected.CultureInfo != null && expected.CultureInfo.Name != actual.CultureInfo.Name)
			{
				return false;
			}
			return expected.GetPublicKeyToken()?.SequenceEqual(actual.GetPublicKeyToken()) ?? true;
		}

		public static string GetAssemblyFileLocation(Assembly assembly)
		{
			string text = string.Empty;
			try
			{
				if (assembly == null)
				{
					return string.Empty;
				}
				text = assembly.FullName;
				if (!Uri.TryCreate(assembly.CodeBase, UriKind.RelativeOrAbsolute, out var result))
				{
					InternalLogger.Warn("Ignoring assembly location because code base is unknown: '{0}' ({1})", assembly.CodeBase, text);
					return string.Empty;
				}
				string directoryName = Path.GetDirectoryName(result.LocalPath);
				if (string.IsNullOrEmpty(directoryName))
				{
					InternalLogger.Warn("Ignoring assembly location because it is not a valid directory: '{0}' ({1})", result.LocalPath, text);
					return string.Empty;
				}
				DirectoryInfo directoryInfo = new DirectoryInfo(directoryName);
				if (!directoryInfo.Exists)
				{
					InternalLogger.Warn("Ignoring assembly location because directory doesn't exists: '{0}' ({1})", directoryName, text);
					return string.Empty;
				}
				InternalLogger.Debug("Found assembly location directory: '{0}' ({1})", directoryInfo.FullName, text);
				return directoryInfo.FullName;
			}
			catch (PlatformNotSupportedException ex)
			{
				InternalLogger.Warn(ex, "Ignoring assembly location because assembly lookup is not supported: {0}", text);
				if (ex.MustBeRethrown())
				{
					throw;
				}
				return string.Empty;
			}
			catch (SecurityException ex2)
			{
				InternalLogger.Warn(ex2, "Ignoring assembly location because assembly lookup is not allowed: {0}", text);
				if (ex2.MustBeRethrown())
				{
					throw;
				}
				return string.Empty;
			}
			catch (UnauthorizedAccessException ex3)
			{
				InternalLogger.Warn(ex3, "Ignoring assembly location because assembly lookup is not allowed: {0}", text);
				if (ex3.MustBeRethrown())
				{
					throw;
				}
				return string.Empty;
			}
		}
	}
	internal struct AsyncHelpersTask(WaitCallback asyncDelegate)
