		public static readonly LogMessageTemplateFormatter DefaultAuto = new LogMessageTemplateFormatter(forceTemplateRenderer: false, singleTargetOnly: false);

		public static readonly LogMessageTemplateFormatter Default = new LogMessageTemplateFormatter(forceTemplateRenderer: true, singleTargetOnly: false);

		public static readonly LogMessageTemplateFormatter DefaultAutoSingleTarget = new LogMessageTemplateFormatter(forceTemplateRenderer: false, singleTargetOnly: true);

		private static readonly StringBuilderPool _builderPool = new StringBuilderPool(Environment.ProcessorCount * 2);

		private readonly bool _forceTemplateRenderer;

		private readonly bool _singleTargetOnly;

		public LogMessageFormatter MessageFormatter { get; }

		private LogMessageTemplateFormatter(bool forceTemplateRenderer, bool singleTargetOnly)
		{
			_forceTemplateRenderer = forceTemplateRenderer;
			_singleTargetOnly = singleTargetOnly;
			MessageFormatter = FormatMessage;
		}

		public bool HasProperties(LogEventInfo logEvent)
		{
			if (!HasParameters(logEvent))
			{
				return false;
			}
			if (_singleTargetOnly)
			{
				TemplateEnumerator templateEnumerator = new TemplateEnumerator(logEvent.Message);
				if (templateEnumerator.MoveNext() && templateEnumerator.Current.MaybePositionalTemplate)
				{
					return false;
				}
			}
			return true;
		}

		private bool HasParameters(LogEventInfo logEvent)
		{
			if (logEvent.Parameters != null && !string.IsNullOrEmpty(logEvent.Message))
			{
				return logEvent.Parameters.Length != 0;
			}
			return false;
		}

		public void AppendFormattedMessage(LogEventInfo logEvent, StringBuilder builder)
		{
			if (!HasParameters(logEvent))
			{
				builder.Append(logEvent.Message ?? string.Empty);
			}
			else
			{
				logEvent.Message.Render(logEvent.FormatProvider ?? CultureInfo.CurrentCulture, logEvent.Parameters, _forceTemplateRenderer, builder, out var _);
			}
		}

		public string FormatMessage(LogEventInfo logEvent)
		{
			if (!HasParameters(logEvent))
			{
				return logEvent.Message;
			}
			StringBuilderPool.ItemHolder itemHolder = _builderPool.Acquire();
			try
			{
				AppendToBuilder(logEvent, itemHolder.Item);
				return itemHolder.Item.ToString();
			}
			finally
			{
				((IDisposable)itemHolder/*cast due to .constrained prefix*/).Dispose();
			}
		}

		private void AppendToBuilder(LogEventInfo logEvent, StringBuilder builder)
		{
			logEvent.Message.Render(logEvent.FormatProvider ?? CultureInfo.CurrentCulture, logEvent.Parameters, _forceTemplateRenderer, builder, out var messageTemplateParameters);
			logEvent.CreateOrUpdatePropertiesInternal(forceCreate: false, messageTemplateParameters ?? ArrayHelper.Empty<MessageTemplateParameter>());
		}
	}
	internal class MruCache<TKey, TValue>
	{
		private struct MruCacheItem(TValue value, long version, bool virgin)
		{
			public readonly TValue Value = value;

			public readonly long Version = version;

			public readonly bool Virgin = virgin;
		}

		private readonly Dictionary<TKey, MruCacheItem> _dictionary;

		private readonly int _maxCapacity;

		private long _currentVersion;

		public MruCache(int maxCapacity)
		{
			_maxCapacity = maxCapacity;
			_dictionary = new Dictionary<TKey, MruCacheItem>(_maxCapacity);
			_currentVersion = 1L;
		}

		public bool TryAddValue(TKey key, TValue value)
		{
			lock (_dictionary)
			{
				if (_dictionary.TryGetValue(key, out var value2))
				{
					long currentVersion = _currentVersion;
					if (value2.Version != currentVersion || !EqualityComparer<TValue>.Default.Equals(value, value2.Value))
					{
						_dictionary[key] = new MruCacheItem(value, currentVersion, virgin: false);
					}
					return false;
				}
				if (_dictionary.Count >= _maxCapacity)
				{
					_currentVersion++;
					PruneCache();
				}
				_dictionary.Add(key, new MruCacheItem(value, _currentVersion, virgin: true));
				return true;
			}
		}

		private void PruneCache()
		{
			long num = _currentVersion - 2;
			long num2 = 1L;
			List<TKey> list = new List<TKey>((int)((double)_dictionary.Count / 2.5));
			for (int i = 0; i < 3; i++)
			{
				long num3 = _currentVersion - 5;
				switch (i)
				{
				case 0:
					num3 = _currentVersion - (int)((double)_maxCapacity / 1.5);
					break;
				case 1:
					num3 = _currentVersion - 10;
					break;
				}
				if (num3 < num2)
				{
					num3 = num2;
				}
				num2 = 9223372036854775807L;
				foreach (KeyValuePair<TKey, MruCacheItem> item in _dictionary)
				{
					long version = item.Value.Version;
					if (version <= num3 || (item.Value.Virgin && (i != 0 || version < num)))
					{
						list.Add(item.Key);
						if ((double)(_dictionary.Count - list.Count) < (double)_maxCapacity / 1.5)
						{
							i = 3;
							break;
						}
					}
					else if (version < num2)
					{
						num2 = version;
					}
				}
			}
			foreach (TKey item2 in list)
			{
				_dictionary.Remove(item2);
			}
			if (_dictionary.Count >= _maxCapacity)
			{
				_dictionary.Clear();
			}
		}

		public bool TryGetValue(TKey key, out TValue value)
		{
			MruCacheItem value2;
			try
			{
				if (!_dictionary.TryGetValue(key, out value2))
				{
					value = default(TValue);
					return false;
				}
			}
			catch
			{
				value2 = default(MruCacheItem);
			}
			if (value2.Version != _currentVersion || value2.Virgin)
			{
				lock (_dictionary)
				{
					long num = _currentVersion;
					if (!_dictionary.TryGetValue(key, out value2))
					{
						value = default(TValue);
						return false;
					}
					if (value2.Version != num || value2.Virgin)
					{
						if (value2.Virgin)
						{
							num = ++_currentVersion;
						}
						_dictionary[key] = new MruCacheItem(value2.Value, num, virgin: false);
					}
				}
			}
			value = value2.Value;
			return true;
		}
	}
