	internal static class ObjectGraphScanner
	{
		public static List<T> FindReachableObjects<T>(bool aggressiveSearch, params object[] rootObjects) where T : class
		{
			if (InternalLogger.IsTraceEnabled)
			{
				InternalLogger.Trace("FindReachableObject<{0}>:", typeof(T));
			}
			List<T> result = new List<T>();
			HashSet<object> visitedObjects = new HashSet<object>(SingleItemOptimizedHashSet<object>.ReferenceEqualityComparer.Default);
			foreach (object obj in rootObjects)
			{
				if (IncludeConfigurationItem(obj))
				{
					ScanProperties(aggressiveSearch, result, obj, 0, visitedObjects);
				}
			}
			return result;
		}

		private static void ScanProperties<T>(bool aggressiveSearch, List<T> result, object o, int level, HashSet<object> visitedObjects) where T : class
		{
			if (o == null || visitedObjects.Contains(o))
			{
				return;
			}
			Type type = o.GetType();
			if (InternalLogger.IsTraceEnabled)
			{
				InternalLogger.Trace("{0}Scanning {1} '{2}'", new string(' ', level), type.Name, o);
			}
			if (o is T item)
			{
				result.Add(item);
				if (!aggressiveSearch)
				{
					return;
				}
			}
			foreach (KeyValuePair<string, PropertyInfo> allConfigItemProperty in PropertyHelper.GetAllConfigItemProperties(type))
			{
				if (string.IsNullOrEmpty(allConfigItemProperty.Key))
				{
					continue;
				}
				PropertyInfo value = allConfigItemProperty.Value;
				if (!PropertyHelper.IsSimplePropertyType(value.PropertyType))
				{
					object value2 = value.GetValue(o, null);
					if (value2 != null)
					{
						visitedObjects.Add(o);
						ScanPropertyForObject(value, value2, aggressiveSearch, result, level, visitedObjects);
					}
				}
			}
		}

		private static void ScanPropertyForObject<T>(PropertyInfo prop, object propValue, bool aggressiveSearch, List<T> result, int level, HashSet<object> visitedObjects) where T : class
		{
			if (InternalLogger.IsTraceEnabled)
			{
				InternalLogger.Trace("{0}Scanning Property {1} '{2}' {3}", new string(' ', level + 1), prop.Name, propValue.ToString(), prop.PropertyType.Namespace);
			}
			if (propValue is IEnumerable enumerable)
			{
				IList list = ConvertEnumerableToList(enumerable);
				if (list.Count > 0 && !visitedObjects.Contains(list))
				{
					visitedObjects.Add(list);
					ScanPropertiesList(list, aggressiveSearch, result, level + 1, visitedObjects);
				}
			}
			else if (IncludeConfigurationItem(propValue, prop.PropertyType))
			{
				ScanProperties(aggressiveSearch, result, propValue, level + 1, visitedObjects);
			}
		}

		private static void ScanPropertiesList<T>(IList list, bool aggressiveSearch, List<T> result, int level, HashSet<object> visitedObjects) where T : class
		{
			for (int i = 0; i < list.Count; i++)
			{
				object obj = list[i];
				if (IncludeConfigurationItem(obj))
				{
					ScanProperties(aggressiveSearch, result, obj, level, visitedObjects);
				}
			}
		}

		private static IList ConvertEnumerableToList(IEnumerable enumerable)
		{
			if (enumerable is ICollection { Count: 0 })
			{
				return ArrayHelper.Empty<object>();
			}
			if (enumerable is IList list)
			{
				if (!list.IsReadOnly)
				{
					List<object> list2 = new List<object>(list.Count);
					lock (list.SyncRoot)
					{
						for (int i = 0; i < list.Count; i++)
						{
							list2.Add(list[i]);
						}
						return list2;
					}
				}
				return list;
			}
			return enumerable.Cast<object>().ToList();
		}

		private static bool IncludeConfigurationItem(object item, Type propertyType = null)
		{
			propertyType = propertyType ?? item?.GetType();
			if (propertyType == null)
			{
				return false;
			}
			if (PropertyHelper.IsConfigurationItemType(propertyType))
			{
				return true;
			}
			Type type = item?.GetType();
			if (type != null && type != propertyType && PropertyHelper.IsConfigurationItemType(type))
			{
				return true;
			}
			return false;
		}
	}
	[Serializable]
	internal class ObjectHandleSerializer : ISerializable
	{
		[NonSerialized]
		private readonly object _wrapped;

		public ObjectHandleSerializer()
		{
		}

		public ObjectHandleSerializer(object wrapped)
		{
			_wrapped = wrapped;
		}

		protected ObjectHandleSerializer(SerializationInfo info, StreamingContext context)
		{
			Type type = null;
			try
			{
				type = (Type)info.GetValue("wrappedtype", typeof(Type));
				_wrapped = info.GetValue("wrappedvalue", type);
			}
			catch (Exception ex)
			{
				_wrapped = string.Empty;
				InternalLogger.Debug(ex, "ObjectHandleSerializer failed to deserialize object: {0}", type);
			}
		}

		public void GetObjectData(SerializationInfo info, StreamingContext context)
		{
			try
			{
				if (_wrapped is ISerializable || _wrapped.GetType().IsSerializable)
				{
					info.AddValue("wrappedtype", _wrapped.GetType());
					info.AddValue("wrappedvalue", _wrapped);
					return;
				}
				info.AddValue("wrappedtype", typeof(string));
				string text = string.Empty;
				try
				{
					text = _wrapped?.ToString();
				}
				finally
				{
					info.AddValue("wrappedvalue", text ?? string.Empty);
				}
			}
			catch (Exception ex)
			{
				InternalLogger.Debug(ex, "ObjectHandleSerializer failed to serialize object: {0}", _wrapped?.GetType());
			}
		}

		public object Unwrap()
		{
			return _wrapped ?? string.Empty;
		}
	}
	internal class ObjectPropertyHelper
	{
		private string[] _objectPropertyPath;

		private ObjectReflectionCache _objectReflectionCache;

		private ObjectReflectionCache ObjectReflectionCache => _objectReflectionCache ?? (_objectReflectionCache = new ObjectReflectionCache());

		public string ObjectPath
		{
			get
			{
				string[] objectPropertyPath = _objectPropertyPath;
				if (objectPropertyPath == null || objectPropertyPath.Length == 0)
				{
					return null;
				}
				return string.Join(".", _objectPropertyPath);
			}
			set
			{
				_objectPropertyPath = (StringHelpers.IsNullOrWhiteSpace(value) ? null : value.SplitAndTrimTokens('.'));
			}
		}

		public bool TryGetObjectProperty(object value, out object foundValue)
		{
			foundValue = null;
			if (_objectPropertyPath == null)
			{
				return false;
			}
			ObjectReflectionCache objectReflectionCache = ObjectReflectionCache;
			for (int i = 0; i < _objectPropertyPath.Length; i++)
			{
				if (value == null)
				{
					foundValue = null;
					return true;
				}
				if (objectReflectionCache.LookupObjectProperties(value).TryGetPropertyValue(_objectPropertyPath[i], out var propertyValue))
				{
					value = propertyValue.Value;
					continue;
				}
				foundValue = null;
				return false;
			}
			foundValue = value;
			return true;
		}
	}
	internal class ObjectReflectionCache : IObjectTypeTransformer
	{
		public struct ObjectPropertyList : IEnumerable<ObjectPropertyList.PropertyValue>, IEnumerable
		{
			public struct PropertyValue
			{
				public readonly string Name;

				public readonly object Value;

				private readonly TypeCode _typecode;

				public TypeCode TypeCode
				{
					get
					{
						if (Value != null)
						{
							return _typecode;
						}
						return TypeCode.Empty;
					}
				}

				public PropertyValue(string name, object value, TypeCode typeCode)
				{
					Name = name;
					Value = value;
					_typecode = typeCode;
				}

				public PropertyValue(object owner, PropertyInfo propertyInfo)
				{
					Name = propertyInfo.Name;
					Value = propertyInfo.GetValue(owner, null);
					_typecode = TypeCode.Object;
				}

				public PropertyValue(object owner, FastPropertyLookup fastProperty)
				{
					Name = fastProperty.Name;
					Value = fastProperty.ValueLookup(owner, null);
					_typecode = fastProperty.TypeCode;
				}
			}

			public struct Enumerator : IEnumerator<PropertyValue>, IDisposable, IEnumerator
			{
				private readonly object _owner;

				private readonly PropertyInfo[] _properties;

				private readonly FastPropertyLookup[] _fastLookup;

				private readonly IEnumerator<KeyValuePair<string, object>> _enumerator;

				private int _index;

				public PropertyValue Current
				{
					get
					{
						try
						{
							if (_fastLookup != null)
							{
								return new PropertyValue(_owner, _fastLookup[_index]);
							}
							if (_properties != null)
							{
								return new PropertyValue(_owner, _properties[_index]);
							}
							return new PropertyValue(_enumerator.Current.Key, _enumerator.Current.Value, TypeCode.Object);
						}
						catch (Exception ex)
						{
							InternalLogger.Warn(ex, "Failed to get property value for object: {0}", _owner);
							return default(PropertyValue);
						}
					}
				}

				object IEnumerator.Current => Current;

				internal Enumerator(object owner, PropertyInfo[] properties, FastPropertyLookup[] fastLookup)
				{
					_owner = owner;
					_properties = properties;
					_fastLookup = fastLookup;
					_index = -1;
					_enumerator = null;
				}

				internal Enumerator(IEnumerator<KeyValuePair<string, object>> enumerator)
				{
					_owner = enumerator;
					_properties = null;
					_fastLookup = null;
					_index = 0;
					_enumerator = enumerator;
				}

				public void Dispose()
				{
					_enumerator?.Dispose();
				}

				public bool MoveNext()
				{
					if (_properties != null)
					{
						int num = ++_index;
						FastPropertyLookup[] fastLookup = _fastLookup;
						return num < ((fastLookup != null) ? fastLookup.Length : _properties.Length);
					}
					return _enumerator.MoveNext();
				}

				public void Reset()
				{
					if (_properties != null)
					{
						_index = -1;
					}
					else
					{
						_enumerator.Reset();
					}
				}
			}

			internal static readonly StringComparer NameComparer;

			private static readonly FastPropertyLookup[] CreateIDictionaryEnumerator;

			private readonly object _object;

			private readonly PropertyInfo[] _properties;

			private readonly FastPropertyLookup[] _fastLookup;

