						PropertyValue current = enumerator.Current;
						if (NameComparer.Equals(current.Name, name))
						{
							propertyValue = current;
							return true;
						}
					}
				}
				propertyValue = default(PropertyValue);
				return false;
			}

			public override string ToString()
			{
