				}
				return new Enumerator((IEnumerator<KeyValuePair<string, object>>)_fastLookup[0].ValueLookup(_object, null));
			}

			IEnumerator<PropertyValue> IEnumerable<PropertyValue>.GetEnumerator()
			{
				return GetEnumerator();
			}

			IEnumerator IEnumerable.GetEnumerator()
			{
				return GetEnumerator();
			}

			static ObjectPropertyList()
			{
				NameComparer = StringComparer.Ordinal;
				CreateIDictionaryEnumerator = new FastPropertyLookup[1]
