					new FastPropertyLookup(string.Empty, TypeCode.Object, (object o, object[] p) => ((IDictionary<string, object>)o).GetEnumerator())
				};
			}
		}

		internal struct FastPropertyLookup(string name, TypeCode typeCode, ReflectionHelpers.LateBoundMethod valueLookup)
		{
			public readonly string Name = name;

			public readonly ReflectionHelpers.LateBoundMethod ValueLookup = valueLookup;

			public readonly TypeCode TypeCode = typeCode;

