	internal static class PathHelpers
	{
		private static readonly char[] DirectorySeparatorChars = new char[2]
		{
			Path.DirectorySeparatorChar,
			Path.AltDirectorySeparatorChar
		};

		internal static string CombinePaths(string path, string dir, string file)
		{
			if (dir != null)
			{
				path = Path.Combine(path, dir);
			}
			if (file != null)
			{
				path = Path.Combine(path, file);
			}
			return path;
		}

		public static string TrimDirectorySeparators(string path)
		{
			return path?.TrimEnd(DirectorySeparatorChars) ?? string.Empty;
		}

		public static bool IsTempDir(string directory, string tempDir)
		{
			tempDir = TrimDirectorySeparators(tempDir);
			if (string.IsNullOrEmpty(directory) || string.IsNullOrEmpty(tempDir))
			{
				return false;
			}
			string fullPath = Path.GetFullPath(directory);
			if (string.IsNullOrEmpty(fullPath))
			{
				return false;
			}
			if (fullPath.StartsWith(tempDir, StringComparison.OrdinalIgnoreCase))
			{
				return true;
			}
			if (tempDir.StartsWith("/tmp") && directory.StartsWith("/var/tmp/"))
			{
				return true;
			}
			return false;
		}
	}
	internal static class PlatformDetector
	{
		private static RuntimeOS currentOS = GetCurrentRuntimeOS();

		private static bool? _isMono;

		private static bool? runTimeSupportsSharableMutex;

		public static RuntimeOS CurrentOS => currentOS;

		public static bool IsWin32
		{
			get
			{
				if (currentOS != RuntimeOS.Windows)
				{
					return currentOS == RuntimeOS.WindowsNT;
				}
				return true;
			}
		}

		public static bool IsUnix
		{
			get
			{
				if (currentOS != RuntimeOS.Linux)
				{
					return currentOS == RuntimeOS.MacOSX;
				}
				return true;
			}
		}

		public static bool IsMono
		{
			get
			{
				bool? isMono = _isMono;
				if (!isMono.HasValue)
				{
					bool? flag = (_isMono = Type.GetType("Mono.Runtime") != null);
					return flag.Value;
				}
				return isMono == true;
			}
		}

		public static bool SupportsSharableMutex => false;

		private static bool RunTimeSupportsSharableMutex
		{
			get
			{
				if (runTimeSupportsSharableMutex.HasValue)
				{
					return runTimeSupportsSharableMutex.Value;
				}
				try
				{
					runTimeSupportsSharableMutex = false;
				}
				catch (Exception ex)
				{
					InternalLogger.Debug(ex, "Failed to create sharable mutex processes");
					runTimeSupportsSharableMutex = false;
				}
				return runTimeSupportsSharableMutex.Value;
			}
		}

		private static RuntimeOS GetCurrentRuntimeOS()
		{
			switch (Environment.OSVersion.Platform)
			{
			case PlatformID.Unix:
			case (PlatformID)128:
				return RuntimeOS.Linux;
			case PlatformID.Win32Windows:
				return RuntimeOS.Windows;
			case PlatformID.Win32NT:
				return RuntimeOS.WindowsNT;
			default:
				return RuntimeOS.Unknown;
			}
		}
	}
