			if (!TryGetPropertyInfo(type, propertyName, out var result))
			{
				throw new NotSupportedException("Parameter " + propertyName + " not supported on " + type.Name);
			}
			try
			{
				Type propertyType = result.PropertyType;
				if (!TryNLogSpecificConversion(propertyType, value, configurationItemFactory, out var newValue))
				{
					if (result.IsDefined(_arrayParameterAttribute.GetType(), inherit: false))
					{
