			{
				throw new NLogConfigurationException("Error when setting property '" + result.Name + "' on " + type.Name, ex.InnerException);
			}
			catch (Exception ex2)
			{
				InternalLogger.Warn(ex2, "Error when setting property '{0}' on '{1}'", result.Name, type);
				if (ex2.MustBeRethrownImmediately())
				{
					throw;
				}
				throw new NLogConfigurationException("Error when setting property '" + result.Name + "' on " + type.Name, ex2);
			}
		}

