			foreach (KeyValuePair<string, PropertyInfo> allConfigItemProperty in GetAllConfigItemProperties(o.GetType()))
			{
				PropertyInfo value = allConfigItemProperty.Value;
				if (value.IsDefined(_requiredParameterAttribute.GetType(), inherit: false) && value.GetValue(o, null) == null)
