			if (type == typeof(CultureInfo))
			{
				return true;
			}
			if (type == typeof(Type))
			{
				return true;
			}
			if (type == typeof(Encoding))
			{
				return true;
			}
			return false;
		}

		private static bool TryImplicitConversion(Type resultType, string value, out object result)
