				MethodInfo method = resultType.GetMethod("op_Implicit", BindingFlags.Static | BindingFlags.Public, null, new Type[1] { value.GetType() }, null);
				if (method == null || !resultType.IsAssignableFrom(method.ReturnType))
				{
					result = null;
					return false;
				}
				result = method.Invoke(null, new object[1] { value });
				return true;
			}
			catch (Exception ex)
			{
				InternalLogger.Warn(ex, "Implicit Conversion Failed of {0} to {1}", value, resultType);
			}
			result = null;
			return false;
		}

		private static bool TryNLogSpecificConversion(Type propertyType, string value, ConfigurationItemFactory configurationItemFactory, out object newValue)
		{
			if (DefaultPropertyConversionMapper.TryGetValue(propertyType, out var value2))
			{
				newValue = value2(value, configurationItemFactory);
				return true;
			}
			newValue = null;
			return false;
		}

		private static bool TryGetEnumValue(Type resultType, string value, out object result, bool flagsEnumAllowed)
		{
			if (!resultType.IsEnum())
			{
				result = null;
				return false;
			}
			if (flagsEnumAllowed && resultType.IsDefined(_flagsAttribute.GetType(), inherit: false))
			{
				ulong num = 0uL;
				string[] array = value.SplitAndTrimTokens(',');
				foreach (string name in array)
