				{
					if (!TryGetEnumValue(collectionItemType, item, out newValue, flagsEnumAllowed: false) && !TryNLogSpecificConversion(collectionItemType, item, configurationItemFactory, out newValue) && !TryImplicitConversion(collectionItemType, item, out newValue) && !TryTypeConverterConversion(collectionItemType, item, out newValue))
					{
						newValue = Convert.ChangeType(item, collectionItemType, CultureInfo.InvariantCulture);
					}
					collectionAddMethod.Invoke(collectionObject, new object[1] { newValue });
				}
				newValue = collectionObject;
				return true;
			}
			newValue = null;
			return false;
		}

		private static bool TryCreateCollectionObject(object obj, PropertyInfo propInfo, string valueRaw, out object collectionObject, out MethodInfo collectionAddMethod, out Type collectionItemType)
		{
			Type propertyType = propInfo.PropertyType;
			Type genericTypeDefinition = propertyType.GetGenericTypeDefinition();
			bool flag = genericTypeDefinition == typeof(ISet<>) || genericTypeDefinition == typeof(HashSet<>);
			if (flag || genericTypeDefinition == typeof(List<>) || genericTypeDefinition == typeof(IList<>) || genericTypeDefinition == typeof(IEnumerable<>))
			{
				object hashSetComparer = (flag ? ExtractHashSetComparer(obj, propInfo) : null);
				collectionItemType = propertyType.GetGenericArguments()[0];
				collectionObject = CreateCollectionObjectInstance(flag ? typeof(HashSet<>) : typeof(List<>), collectionItemType, hashSetComparer);
				if (collectionObject == null)
				{
					throw new NLogConfigurationException("Cannot create instance of {0} for value {1}", propertyType.ToString(), valueRaw);
				}
				collectionAddMethod = collectionObject.GetType().GetMethod("Add", BindingFlags.Instance | BindingFlags.Public);
				if (collectionAddMethod == null)
				{
					throw new NLogConfigurationException("Add method on type {0} for value {1} not found", propertyType.ToString(), valueRaw);
				}
				return true;
			}
			collectionObject = null;
			collectionAddMethod = null;
			collectionItemType = null;
			return false;
		}

		private static object CreateCollectionObjectInstance(Type collectionType, Type collectionItemType, object hashSetComparer)
