		private static bool TryCreatePropertyInfoDictionary(Type t, out Dictionary<string, PropertyInfo> result)
		{
			result = null;
			try
			{
				if (!t.IsDefined(typeof(NLogConfigurationItemAttribute), inherit: true))
				{
					return false;
				}
				result = new Dictionary<string, PropertyInfo>(StringComparer.OrdinalIgnoreCase);
				PropertyInfo[] properties = t.GetProperties(BindingFlags.Instance | BindingFlags.Public);
				foreach (PropertyInfo propertyInfo in properties)
				{
					try
					{
						string text = LookupPropertySymbolName(propertyInfo);
						if (!string.IsNullOrEmpty(text))
						{
							result[text] = propertyInfo;
							if (propertyInfo.IsDefined(_defaultParameterAttribute.GetType(), inherit: false))
							{
								result[string.Empty] = propertyInfo;
							}
						}
					}
					catch (Exception ex)
					{
						InternalLogger.Debug(ex, "Type reflection not possible for property {0} on type {1}. Maybe because of .NET Native.", propertyInfo.Name, t);
					}
				}
			}
			catch (Exception ex2)
			{
				InternalLogger.Debug(ex2, "Type reflection not possible for type {0}. Maybe because of .NET Native.", t);
			}
			return result != null;
		}

		private static string LookupPropertySymbolName(PropertyInfo propInfo)
		{
			if (propInfo.PropertyType == null)
			{
				return null;
			}
			if (IsSimplePropertyType(propInfo.PropertyType))
			{
				return propInfo.Name;
			}
			if (typeof(LayoutRenderer).IsAssignableFrom(propInfo.PropertyType))
			{
				return propInfo.Name;
			}
			if (typeof(Layout).IsAssignableFrom(propInfo.PropertyType))
			{
				return propInfo.Name;
			}
			if (propInfo.IsDefined(_ignorePropertyAttribute.GetType(), inherit: false))
			{
				return null;
			}
			ArrayParameterAttribute customAttribute = propInfo.GetCustomAttribute<ArrayParameterAttribute>();
			if (customAttribute != null)
			{
				return customAttribute.ElementName;
			}
			return propInfo.Name;
		}
