	internal class PropertySetter
	{
		private readonly Type _objectType;

		private readonly PropertyInfo _propertyInfo;

		private ReflectionHelpers.LateBoundMethodSingle _propertySetter;

		public static PropertySetter CreatePropertySetter(Type objectType, string propertyName)
		{
			if (TryGetProperty(objectType, propertyName, out var property))
			{
				return new PropertySetter(objectType, property);
			}
			return null;
		}

		private PropertySetter(Type objectType, PropertyInfo propertyInfo)
		{
			_objectType = objectType;
			_propertyInfo = propertyInfo;
		}

		public bool SetPropertyValue(object instance, object value)
		{
			if (instance == null)
			{
				throw new ArgumentNullException("instance");
			}
			if (_propertySetter != null)
			{
				_propertySetter(instance, value);
			}
			else
			{
				MethodInfo setMethod = _propertyInfo.GetSetMethod();
				setMethod.Invoke(instance, new object[1] { value });
				_propertySetter = ReflectionHelpers.CreateLateBoundMethodSingle(setMethod);
			}
			return true;
		}

		private static bool TryGetProperty(Type objectType, string propertyName, out PropertyInfo property)
		{
			if (objectType == null)
			{
				throw new ArgumentNullException("objectType");
			}
			if (propertyName == null)
			{
				throw new ArgumentNullException("propertyName");
			}
			property = objectType.GetProperty(propertyName, BindingFlags.IgnoreCase | BindingFlags.Instance | BindingFlags.Public);
			if (property == null)
			{
				InternalLogger.Warn("Cannot set {0} on type {1}, property not found", propertyName, objectType.FullName);
				return false;
			}
			if (!property.CanWrite)
			{
				InternalLogger.Warn("Cannot set {0} on type {1}, property not settable", propertyName, objectType.FullName);
				return false;
			}
			return true;
		}
	}
	internal static class ReflectionHelpers
	{
		public delegate object LateBoundMethod(object target, object[] arguments);

		public delegate object LateBoundMethodSingle(object target, object argument);

		public static Type[] SafeGetTypes(this Assembly assembly)
		{
			try
			{
				return assembly.GetTypes();
			}
			catch (ReflectionTypeLoadException ex)
			{
				Exception[] loaderExceptions = ex.LoaderExceptions;
				for (int i = 0; i < loaderExceptions.Length; i++)
				{
					InternalLogger.Warn(loaderExceptions[i], "Type load exception.");
				}
				List<Type> list = new List<Type>();
				Type[] types = ex.Types;
				foreach (Type type in types)
				{
					if (type != null)
					{
						list.Add(type);
					}
				}
				return list.ToArray();
			}
			catch (Exception ex2)
			{
				InternalLogger.Warn(ex2, "Type load exception.");
				return ArrayHelper.Empty<Type>();
			}
		}

		public static bool IsStaticClass(this Type type)
		{
			if (type.IsClass() && type.IsAbstract())
			{
				return type.IsSealed();
			}
			return false;
		}

		public static LateBoundMethod CreateLateBoundMethod(MethodInfo methodInfo)
		{
			ParameterExpression parameterExpression = Expression.Parameter(typeof(object), "instance");
			ParameterExpression parameterExpression2 = Expression.Parameter(typeof(object[]), "parameters");
			MethodCallExpression methodCallExpression = BuildParameterList(methodInfo, parameterExpression, parameterExpression2);
			if (methodCallExpression.Type == typeof(void))
			{
				Expression<Action<object, object[]>> expression = Expression.Lambda<Action<object, object[]>>(methodCallExpression, new ParameterExpression[2] { parameterExpression, parameterExpression2 });
				Action<object, object[]> execute = expression.Compile();
				return delegate(object instance, object[] parameters)
				{
					execute(instance, parameters);
					return (object)null;
				};
			}
			return Expression.Lambda<LateBoundMethod>(Expression.Convert(methodCallExpression, typeof(object)), new ParameterExpression[2] { parameterExpression, parameterExpression2 }).Compile();
		}

		public static LateBoundMethodSingle CreateLateBoundMethodSingle(MethodInfo methodInfo)
		{
			ParameterExpression parameterExpression = Expression.Parameter(typeof(object), "instance");
			ParameterExpression parameterExpression2 = Expression.Parameter(typeof(object), "parameters");
			MethodCallExpression methodCallExpression = BuildParameterListSingle(methodInfo, parameterExpression, parameterExpression2);
			if (methodCallExpression.Type == typeof(void))
			{
				Expression<Action<object, object>> expression = Expression.Lambda<Action<object, object>>(methodCallExpression, new ParameterExpression[2] { parameterExpression, parameterExpression2 });
				Action<object, object> execute = expression.Compile();
				return delegate(object instance, object parameters)
				{
					execute(instance, parameters);
					return (object)null;
				};
			}
			return Expression.Lambda<LateBoundMethodSingle>(Expression.Convert(methodCallExpression, typeof(object)), new ParameterExpression[2] { parameterExpression, parameterExpression2 }).Compile();
		}

		private static MethodCallExpression BuildParameterList(MethodInfo methodInfo, ParameterExpression instanceParameter, ParameterExpression parametersParameter)
		{
			List<Expression> list = new List<Expression>();
			ParameterInfo[] parameters = methodInfo.GetParameters();
			for (int i = 0; i < parameters.Length; i++)
			{
				BinaryExpression expression = Expression.ArrayIndex(parametersParameter, Expression.Constant(i));
				UnaryExpression item = CreateParameterExpression(parameters[i], expression);
				list.Add(item);
			}
			return CreateMethodCallExpression(methodInfo, instanceParameter, list);
		}

		private static MethodCallExpression BuildParameterListSingle(MethodInfo methodInfo, ParameterExpression instanceParameter, ParameterExpression parameterParameter)
		{
			List<Expression> list = new List<Expression>();
			UnaryExpression item = CreateParameterExpression(methodInfo.GetParameters().Single(), parameterParameter);
			list.Add(item);
			return CreateMethodCallExpression(methodInfo, instanceParameter, list);
		}

		private static MethodCallExpression CreateMethodCallExpression(MethodInfo methodInfo, ParameterExpression instanceParameter, IEnumerable<Expression> parameterExpressions)
		{
			return Expression.Call(methodInfo.IsStatic ? null : Expression.Convert(instanceParameter, methodInfo.DeclaringType), methodInfo, parameterExpressions);
		}

		private static UnaryExpression CreateParameterExpression(ParameterInfo parameterInfo, Expression expression)
		{
			Type type = parameterInfo.ParameterType;
			if (type.IsByRef)
			{
				type = type.GetElementType();
			}
			return Expression.Convert(expression, type);
		}

