		public static TAttr GetCustomAttribute<TAttr>(this Assembly assembly) where TAttr : Attribute
		{
			return (TAttr)Attribute.GetCustomAttribute(assembly, typeof(TAttr));
		}

		public static IEnumerable<TAttr> GetCustomAttributes<TAttr>(this Type type, bool inherit) where TAttr : Attribute
		{
			return (TAttr[])type.GetCustomAttributes(typeof(TAttr), inherit);
		}

		public static Assembly GetAssembly(this Type type)
		{
			return type.Assembly;
		}

		public static bool IsValidPublicProperty(this PropertyInfo p)
		{
			if (p.CanRead && p.GetIndexParameters().Length == 0)
			{
				return p.GetGetMethod() != null;
			}
			return false;
		}

		public static object GetPropertyValue(this PropertyInfo p, object instance)
		{
			return p.GetGetMethod().Invoke(instance, null);
		}
	}
	internal class RegexHelper
	{
		private Regex _regex;

		private string _searchText;

		private string _regexPattern;

		private bool _wholeWords;

		private bool _ignoreCase;

		private bool _simpleSearchText;

		public string SearchText
		{
			get
			{
				return _searchText;
			}
			set
			{
				_searchText = value;
				_regexPattern = null;
				ResetRegex();
			}
		}

		public string RegexPattern
		{
			get
			{
				return _regexPattern;
			}
			set
			{
				_regexPattern = value;
				_searchText = null;
				ResetRegex();
			}
		}

		public bool CompileRegex { get; set; }

		public bool WholeWords
		{
			get
			{
				return _wholeWords;
			}
			set
			{
				if (_wholeWords != value)
				{
					_wholeWords = value;
					ResetRegex();
				}
			}
		}

		public bool IgnoreCase
		{
			get
			{
				return _ignoreCase;
			}
			set
			{
				if (_ignoreCase != value)
				{
					_ignoreCase = value;
					ResetRegex();
				}
			}
		}

		public Regex Regex
		{
			get
			{
				if (_regex != null)
				{
					return _regex;
				}
				string regexPattern = RegexPattern;
				if (string.IsNullOrEmpty(regexPattern))
				{
					return null;
				}
				return _regex = new Regex(regexPattern, GetRegexOptions());
			}
		}

		private void ResetRegex()
		{
			_simpleSearchText = !WholeWords && !IgnoreCase && !string.IsNullOrEmpty(SearchText);
			if (!string.IsNullOrEmpty(SearchText))
			{
				_regexPattern = Regex.Escape(SearchText);
			}
			if (WholeWords && !string.IsNullOrEmpty(_regexPattern))
			{
				_regexPattern = "\\b" + _regexPattern + "\\b";
			}
			_regex = null;
		}

		private RegexOptions GetRegexOptions()
		{
			RegexOptions regexOptions = RegexOptions.None;
			if (IgnoreCase)
			{
				regexOptions |= RegexOptions.IgnoreCase;
			}
			if (CompileRegex)
			{
				regexOptions |= RegexOptions.Compiled;
			}
			return regexOptions;
		}

		public string Replace(string input, string replacement)
		{
			if (_simpleSearchText)
			{
				return input.Replace(SearchText, replacement);
			}
			if (CompileRegex)
			{
				return Regex?.Replace(input, replacement) ?? input;
			}
			if (_regexPattern == null)
			{
				return input;
			}
			return Regex.Replace(input, _regexPattern, replacement, GetRegexOptions());
		}

		public MatchCollection Matches(string input)
		{
			if (CompileRegex)
			{
				return Regex?.Matches(input);
			}
			if (_regexPattern == null)
			{
				return null;
			}
			return Regex.Matches(input, _regexPattern, GetRegexOptions());
		}
	}
