	internal abstract class NetworkSender : IDisposable
	{
		private static int currentSendTime;

		public string Address { get; private set; }

		public int LastSendTime { get; private set; }

		protected NetworkSender(string url)
		{
			Address = url;
			LastSendTime = Interlocked.Increment(ref currentSendTime);
		}

		public void Initialize()
		{
			DoInitialize();
		}

		public void Close(AsyncContinuation continuation)
		{
			DoClose(continuation);
		}

		public void FlushAsync(AsyncContinuation continuation)
		{
			DoFlush(continuation);
		}

		public void Send(byte[] bytes, int offset, int length, AsyncContinuation asyncContinuation)
		{
			LastSendTime = Interlocked.Increment(ref currentSendTime);
			DoSend(bytes, offset, length, asyncContinuation);
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected virtual void DoInitialize()
		{
		}

		protected virtual void DoClose(AsyncContinuation continuation)
		{
			continuation(null);
		}

		protected virtual void DoFlush(AsyncContinuation continuation)
		{
			continuation(null);
		}

		protected abstract void DoSend(byte[] bytes, int offset, int length, AsyncContinuation asyncContinuation);

		protected virtual EndPoint ParseEndpointAddress(Uri uri, AddressFamily addressFamily)
		{
			UriHostNameType hostNameType = uri.HostNameType;
			if ((uint)(hostNameType - 3) <= 1u)
			{
				return new IPEndPoint(IPAddress.Parse(uri.Host), uri.Port);
			}
			IPAddress[] addressList = Dns.GetHostEntry(uri.Host).AddressList;
			foreach (IPAddress iPAddress in addressList)
			{
				if (iPAddress.AddressFamily == addressFamily || addressFamily == AddressFamily.Unspecified)
				{
					return new IPEndPoint(iPAddress, uri.Port);
				}
			}
			throw new IOException($"Cannot resolve '{uri.Host}' to an address in '{addressFamily}'");
		}

		public virtual void CheckSocket()
		{
		}

		private void Dispose(bool disposing)
		{
			if (disposing)
			{
				Close(delegate
				{
				});
			}
		}
	}
	internal class NetworkSenderFactory : INetworkSenderFactory
	{
		public static readonly INetworkSenderFactory Default = new NetworkSenderFactory();

		public NetworkSender Create(string url, int maxQueueSize, SslProtocols sslProtocols, TimeSpan keepAliveTime)
		{
			if (url.StartsWith("http://", StringComparison.OrdinalIgnoreCase))
			{
				return new HttpNetworkSender(url)
				{
					MaxQueueSize = maxQueueSize
				};
			}
			if (url.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
			{
				return new HttpNetworkSender(url)
				{
					MaxQueueSize = maxQueueSize
				};
			}
			if (url.StartsWith("tcp://", StringComparison.OrdinalIgnoreCase))
			{
				return new TcpNetworkSender(url, AddressFamily.Unspecified)
				{
					MaxQueueSize = maxQueueSize,
					SslProtocols = sslProtocols,
					KeepAliveTime = keepAliveTime
				};
			}
			if (url.StartsWith("tcp4://", StringComparison.OrdinalIgnoreCase))
			{
				return new TcpNetworkSender(url, AddressFamily.InterNetwork)
				{
					MaxQueueSize = maxQueueSize,
					SslProtocols = sslProtocols,
					KeepAliveTime = keepAliveTime
				};
			}
			if (url.StartsWith("tcp6://", StringComparison.OrdinalIgnoreCase))
			{
				return new TcpNetworkSender(url, AddressFamily.InterNetworkV6)
				{
					MaxQueueSize = maxQueueSize,
					SslProtocols = sslProtocols,
					KeepAliveTime = keepAliveTime
				};
			}
			if (url.StartsWith("udp://", StringComparison.OrdinalIgnoreCase))
			{
				return new UdpNetworkSender(url, AddressFamily.Unspecified);
			}
			if (url.StartsWith("udp4://", StringComparison.OrdinalIgnoreCase))
			{
				return new UdpNetworkSender(url, AddressFamily.InterNetwork);
			}
			if (url.StartsWith("udp6://", StringComparison.OrdinalIgnoreCase))
			{
				return new UdpNetworkSender(url, AddressFamily.InterNetworkV6);
			}
			throw new ArgumentException("Unrecognized network address", "url");
		}
	}
	internal abstract class QueuedNetworkSender(string url) : NetworkSender(url)
	{
		protected struct NetworkRequestArgs(byte[] buffer, int offset, int length, AsyncContinuation asyncContinuation)
		{
			public readonly AsyncContinuation AsyncContinuation = asyncContinuation;

			public readonly byte[] RequestBuffer = buffer;

			public readonly int RequestBufferOffset = offset;

			public readonly int RequestBufferLength = length;
		}

		private readonly Queue<NetworkRequestArgs> _pendingRequests = new Queue<NetworkRequestArgs>();

		private Exception _pendingError;

		private bool _asyncOperationInProgress;

		private AsyncContinuation _closeContinuation;

		private AsyncContinuation _flushContinuation;

		internal int MaxQueueSize { get; set; }

		protected override void DoSend(byte[] bytes, int offset, int length, AsyncContinuation asyncContinuation)
		{
			NetworkRequestArgs networkRequestArgs = new NetworkRequestArgs(bytes, offset, length, asyncContinuation);
			lock (_pendingRequests)
			{
				if (MaxQueueSize > 0 && _pendingRequests.Count >= MaxQueueSize)
				{
					_pendingRequests.Dequeue().AsyncContinuation?.Invoke(null);
				}
				if (!_asyncOperationInProgress && _pendingError == null)
				{
					_asyncOperationInProgress = true;
					BeginRequest(networkRequestArgs);
					return;
				}
				_pendingRequests.Enqueue(networkRequestArgs);
			}
			ProcessNextQueuedItem();
		}

		protected override void DoFlush(AsyncContinuation continuation)
		{
			lock (_pendingRequests)
			{
				if (!_asyncOperationInProgress && _pendingRequests.Count == 0)
				{
					continuation(null);
				}
				else if (_flushContinuation != null)
				{
					AsyncContinuation flushChain = _flushContinuation;
					_flushContinuation = delegate(Exception ex)
					{
						flushChain(ex);
						continuation(ex);
					};
				}
				else
				{
					_flushContinuation = continuation;
				}
			}
		}

		protected override void DoClose(AsyncContinuation continuation)
		{
			lock (_pendingRequests)
			{
				if (!_asyncOperationInProgress)
				{
					continuation(null);
				}
				else
				{
					_closeContinuation = continuation;
				}
			}
		}

		protected void BeginInitialize()
		{
			lock (_pendingRequests)
			{
				_asyncOperationInProgress = true;
			}
		}

		protected void EndRequest(AsyncContinuation asyncContinuation, Exception pendingException)
		{
			lock (_pendingRequests)
			{
				_asyncOperationInProgress = false;
				if (pendingException != null)
				{
					_pendingError = pendingException;
				}
				asyncContinuation?.Invoke(pendingException);
				ProcessNextQueuedItem();
			}
		}

		protected abstract void BeginRequest(NetworkRequestArgs eventArgs);

		private void ProcessNextQueuedItem()
		{
			lock (_pendingRequests)
			{
				if (_asyncOperationInProgress)
				{
					return;
				}
				if (_pendingError != null)
				{
					while (_pendingRequests.Count != 0)
					{
						_pendingRequests.Dequeue().AsyncContinuation?.Invoke(_pendingError);
					}
				}
				if (_pendingRequests.Count == 0)
				{
					AsyncContinuation flushContinuation = _flushContinuation;
					if (flushContinuation != null)
					{
						_flushContinuation = null;
						flushContinuation(_pendingError);
					}
					AsyncContinuation closeContinuation = _closeContinuation;
					if (closeContinuation != null)
					{
						_closeContinuation = null;
						closeContinuation(_pendingError);
					}
				}
				else
				{
					NetworkRequestArgs eventArgs = _pendingRequests.Dequeue();
					_asyncOperationInProgress = true;
					BeginRequest(eventArgs);
				}
			}
		}
	}
	internal sealed class SocketProxy : ISocket, IDisposable
	{
		private readonly Socket _socket;

		public Socket UnderlyingSocket => _socket;

		internal SocketProxy(AddressFamily addressFamily, SocketType socketType, ProtocolType protocolType)
		{
			_socket = new Socket(addressFamily, socketType, protocolType);
		}

		public void Close()
		{
			_socket.Close();
		}

		public bool ConnectAsync(SocketAsyncEventArgs args)
		{
			return _socket.ConnectAsync(args);
		}

		public bool SendAsync(SocketAsyncEventArgs args)
		{
			return _socket.SendAsync(args);
		}

		public bool SendToAsync(SocketAsyncEventArgs args)
		{
			return _socket.SendToAsync(args);
		}

		public void Dispose()
		{
			((IDisposable)_socket).Dispose();
		}
	}
	internal class SslSocketProxy : ISocket, IDisposable
	{
		private readonly AsyncCallback _sendCompleted;

		private readonly SocketProxy _socketProxy;

		private readonly string _host;

		private readonly SslProtocols _sslProtocol;

		private SslStream _sslStream;

		public SslSocketProxy(string host, SslProtocols sslProtocol, SocketProxy socketProxy)
		{
			_socketProxy = socketProxy;
			_host = host;
			_sslProtocol = sslProtocol;
			_sendCompleted = delegate(IAsyncResult ar)
			{
				SocketProxySendCompleted(ar);
			};
		}

		public void Close()
		{
			if (_sslStream != null)
			{
				_sslStream.Close();
			}
			else
			{
				_socketProxy.Close();
			}
		}

		public bool ConnectAsync(SocketAsyncEventArgs args)
		{
			TcpNetworkSender.MySocketAsyncEventArgs e = new TcpNetworkSender.MySocketAsyncEventArgs();
			e.RemoteEndPoint = args.RemoteEndPoint;
			e.Completed += SocketProxyConnectCompleted;
			e.UserToken = args;
			if (!_socketProxy.ConnectAsync(e))
			{
				SocketProxyConnectCompleted(this, e);
				return false;
			}
			return true;
		}

		private void SocketProxySendCompleted(IAsyncResult asyncResult)
		{
			TcpNetworkSender.MySocketAsyncEventArgs e = asyncResult.AsyncState as TcpNetworkSender.MySocketAsyncEventArgs;
			try
			{
				_sslStream.EndWrite(asyncResult);
			}
			catch (SocketException ex)
			{
				if (e != null)
				{
					e.SocketError = ex.SocketErrorCode;
				}
			}
			catch (Exception ex2)
			{
				if (e != null)
				{
					if (ex2.InnerException is SocketException ex3)
					{
						e.SocketError = ex3.SocketErrorCode;
					}
					else
					{
						e.SocketError = SocketError.OperationAborted;
					}
				}
			}
			finally
			{
				e?.RaiseCompleted();
			}
		}

		private void SocketProxyConnectCompleted(object sender, SocketAsyncEventArgs e)
		{
			TcpNetworkSender.MySocketAsyncEventArgs e2 = e.UserToken as TcpNetworkSender.MySocketAsyncEventArgs;
			if (e.SocketError != SocketError.Success)
			{
				if (e2 != null)
				{
					e2.SocketError = e.SocketError;
					e2.RaiseCompleted();
				}
				return;
			}
			try
			{
				_sslStream = new SslStream(new NetworkStream(_socketProxy.UnderlyingSocket), leaveInnerStreamOpen: false, UserCertificateValidationCallback)
				{
					ReadTimeout = 20000
				};
				AuthenticateAsClient(_sslStream, _host, _sslProtocol);
			}
			catch (SocketException ex)
			{
				if (e2 != null)
				{
					e2.SocketError = ex.SocketErrorCode;
				}
			}
			catch (Exception ex2)
			{
				if (e2 != null)
				{
					e2.SocketError = GetSocketError(ex2);
				}
			}
			finally
			{
				e2?.RaiseCompleted();
			}
		}

		private static SocketError GetSocketError(Exception ex)
		{
			if (!(ex.InnerException is SocketException { SocketErrorCode: var socketErrorCode }))
			{
				return SocketError.ConnectionRefused;
			}
			return socketErrorCode;
		}

		private static void AuthenticateAsClient(SslStream sslStream, string targetHost, SslProtocols enabledSslProtocols)
		{
			if (enabledSslProtocols != SslProtocols.Default)
			{
				sslStream.AuthenticateAsClient(targetHost, null, enabledSslProtocols, checkCertificateRevocation: false);
			}
			else
			{
				sslStream.AuthenticateAsClient(targetHost);
			}
		}

		private static bool UserCertificateValidationCallback(object sender, object certificate, object chain, SslPolicyErrors sslPolicyErrors)
		{
			if (sslPolicyErrors == SslPolicyErrors.None)
			{
				return true;
			}
			InternalLogger.Debug("SSL certificate errors were encountered when establishing connection to the server: {0}, Certificate: {1}", sslPolicyErrors, certificate);
			return false;
		}

		public bool SendAsync(SocketAsyncEventArgs args)
		{
			_sslStream.BeginWrite(args.Buffer, args.Offset, args.Count, _sendCompleted, args);
			return true;
		}

		public bool SendToAsync(SocketAsyncEventArgs args)
		{
			return SendAsync(args);
		}

		public void Dispose()
		{
			if (_sslStream != null)
			{
				_sslStream.Dispose();
			}
			else
			{
				_socketProxy.Dispose();
			}
		}
	}
	internal class TcpNetworkSender : QueuedNetworkSender
	{
		internal class MySocketAsyncEventArgs : SocketAsyncEventArgs
		{
			public void RaiseCompleted()
			{
				OnCompleted(this);
			}
		}

		private static bool? EnableKeepAliveSuccessful;

		private readonly EventHandler<SocketAsyncEventArgs> _socketOperationCompleted;

		private ISocket _socket;

		internal AddressFamily AddressFamily { get; set; }

		internal SslProtocols SslProtocols { get; set; }

		internal TimeSpan KeepAliveTime { get; set; }

		public TcpNetworkSender(string url, AddressFamily addressFamily)
			: base(url)
		{
			AddressFamily = addressFamily;
			_socketOperationCompleted = SocketOperationCompleted;
		}

		protected internal virtual ISocket CreateSocket(string host, AddressFamily addressFamily, SocketType socketType, ProtocolType protocolType)
		{
			SocketProxy socketProxy = new SocketProxy(addressFamily, socketType, protocolType);
			if (KeepAliveTime.TotalSeconds >= 1.0 && EnableKeepAliveSuccessful != false)
			{
				EnableKeepAliveSuccessful = TryEnableKeepAlive(socketProxy.UnderlyingSocket, (int)KeepAliveTime.TotalSeconds);
			}
			if (SslProtocols != SslProtocols.None)
			{
				return new SslSocketProxy(host, SslProtocols, socketProxy);
			}
			return socketProxy;
		}

		private static bool TryEnableKeepAlive(Socket underlyingSocket, int keepAliveTimeSeconds)
		{
			if (TrySetSocketOption(underlyingSocket, SocketOptionName.KeepAlive, value: true))
			{
				SocketOptionName socketOption = SocketOptionName.TypeOfService;
				SocketOptionName socketOption2 = SocketOptionName.BlockSource;
				if (PlatformDetector.CurrentOS == RuntimeOS.Linux)
				{
					socketOption = SocketOptionName.ReuseAddress;
					socketOption2 = (SocketOptionName)5;
				}
				else if (PlatformDetector.CurrentOS == RuntimeOS.MacOSX)
				{
					socketOption = SocketOptionName.DontRoute;
					socketOption2 = (SocketOptionName)257;
				}
				if (TrySetTcpOption(underlyingSocket, socketOption, keepAliveTimeSeconds))
				{
					TrySetTcpOption(underlyingSocket, socketOption2, 1);
					return true;
				}
			}
			return false;
		}

		private static bool TrySetSocketOption(Socket underlyingSocket, SocketOptionName socketOption, bool value)
		{
			try
			{
				underlyingSocket.SetSocketOption(SocketOptionLevel.Socket, socketOption, value);
				return true;
			}
			catch (Exception ex)
			{
				InternalLogger.Warn(ex, "NetworkTarget: Failed to configure Socket-option {0} = {1}", socketOption, value);
				return false;
			}
		}

		private static bool TrySetTcpOption(Socket underlyingSocket, SocketOptionName socketOption, int value)
		{
			try
			{
				underlyingSocket.SetSocketOption(SocketOptionLevel.Tcp, socketOption, value);
				return true;
			}
			catch (Exception ex)
			{
				InternalLogger.Warn(ex, "NetworkTarget: Failed to configure TCP-option {0} = {1}", socketOption, value);
				return false;
			}
		}

		protected override void DoInitialize()
		{
			Uri uri = new Uri(base.Address);
			MySocketAsyncEventArgs e = new MySocketAsyncEventArgs();
			e.RemoteEndPoint = ParseEndpointAddress(new Uri(base.Address), AddressFamily);
			e.Completed += _socketOperationCompleted;
			e.UserToken = null;
			_socket = CreateSocket(uri.Host, e.RemoteEndPoint.AddressFamily, SocketType.Stream, ProtocolType.Tcp);
			BeginInitialize();
			bool flag = false;
			try
			{
				flag = _socket.ConnectAsync(e);
			}
			catch (SocketException ex)
			{
				e.SocketError = ex.SocketErrorCode;
			}
			catch (Exception ex2)
			{
				if (ex2.InnerException is SocketException ex3)
				{
					e.SocketError = ex3.SocketErrorCode;
				}
				else
				{
					e.SocketError = SocketError.OperationAborted;
				}
			}
			if (!flag)
			{
				SocketOperationCompleted(_socket, e);
			}
		}

		protected override void DoClose(AsyncContinuation continuation)
		{
			base.DoClose((AsyncContinuation)delegate(Exception ex)
			{
				CloseSocket(continuation, ex);
			});
		}

		private void CloseSocket(AsyncContinuation continuation, Exception pendingException)
		{
			try
			{
				ISocket socket = _socket;
				_socket = null;
				socket?.Close();
				continuation(pendingException);
			}
			catch (Exception exception)
			{
				if (exception.MustBeRethrown())
				{
					throw;
				}
				continuation(exception);
			}
		}

		private void SocketOperationCompleted(object sender, SocketAsyncEventArgs args)
		{
			AsyncContinuation asyncContinuation = args.UserToken as AsyncContinuation;
			Exception pendingException = null;
			if (args.SocketError != SocketError.Success)
			{
				pendingException = new IOException("Error: " + args.SocketError);
			}
			args.Completed -= _socketOperationCompleted;
			args.Dispose();
			EndRequest(asyncContinuation, pendingException);
		}

		protected override void BeginRequest(NetworkRequestArgs eventArgs)
		{
			MySocketAsyncEventArgs e = new MySocketAsyncEventArgs();
			e.SetBuffer(eventArgs.RequestBuffer, eventArgs.RequestBufferOffset, eventArgs.RequestBufferLength);
			e.UserToken = eventArgs.AsyncContinuation;
			e.Completed += _socketOperationCompleted;
			bool flag = false;
			try
			{
				flag = _socket.SendAsync(e);
			}
			catch (SocketException ex)
			{
				InternalLogger.Error(ex, "NetworkTarget: Error sending tcp request");
				e.SocketError = ex.SocketErrorCode;
			}
			catch (Exception ex2)
			{
				InternalLogger.Error(ex2, "NetworkTarget: Error sending tcp request");
				if (ex2.InnerException is SocketException ex3)
				{
					e.SocketError = ex3.SocketErrorCode;
				}
				else
				{
					e.SocketError = SocketError.OperationAborted;
				}
			}
			if (!flag)
			{
				SocketOperationCompleted(_socket, e);
			}
		}

		public override void CheckSocket()
		{
			if (_socket == null)
			{
				DoInitialize();
			}
		}
	}
	internal class UdpNetworkSender : NetworkSender
	{
		private readonly object _lockObject = new object();

		private ISocket _socket;

		private EndPoint _endpoint;

		internal AddressFamily AddressFamily { get; set; }

		public UdpNetworkSender(string url, AddressFamily addressFamily)
			: base(url)
		{
			AddressFamily = addressFamily;
		}

		protected internal virtual ISocket CreateSocket(AddressFamily addressFamily, SocketType socketType, ProtocolType protocolType)
		{
			SocketProxy socketProxy = new SocketProxy(addressFamily, socketType, protocolType);
			if (Uri.TryCreate(base.Address, UriKind.Absolute, out var result) && result.Host.Equals(IPAddress.Broadcast.ToString(), StringComparison.OrdinalIgnoreCase))
			{
				socketProxy.UnderlyingSocket.EnableBroadcast = true;
			}
			return socketProxy;
		}

		protected override void DoInitialize()
		{
			_endpoint = ParseEndpointAddress(new Uri(base.Address), AddressFamily);
			_socket = CreateSocket(_endpoint.AddressFamily, SocketType.Dgram, ProtocolType.Udp);
		}

		protected override void DoClose(AsyncContinuation continuation)
		{
			lock (_lockObject)
			{
				CloseSocket(continuation);
			}
		}

		private void CloseSocket(AsyncContinuation continuation)
		{
			try
			{
				ISocket socket = _socket;
				_socket = null;
				socket?.Close();
				continuation(null);
			}
			catch (Exception exception)
			{
				if (exception.MustBeRethrown())
				{
					throw;
				}
				continuation(exception);
			}
		}

		protected override void DoSend(byte[] bytes, int offset, int length, AsyncContinuation asyncContinuation)
		{
			lock (_lockObject)
			{
				SocketAsyncEventArgs e = new SocketAsyncEventArgs();
				e.SetBuffer(bytes, offset, length);
				e.UserToken = asyncContinuation;
				e.Completed += SocketOperationCompleted;
				e.RemoteEndPoint = _endpoint;
				if (!_socket.SendToAsync(e))
				{
					SocketOperationCompleted(_socket, e);
				}
			}
		}

		private void SocketOperationCompleted(object sender, SocketAsyncEventArgs e)
		{
			AsyncContinuation asyncContinuation = e.UserToken as AsyncContinuation;
			Exception exception = null;
			if (e.SocketError != SocketError.Success)
			{
				exception = new IOException("Error: " + e.SocketError);
			}
			e.Dispose();
			asyncContinuation?.Invoke(exception);
		}

		public override void CheckSocket()
		{
			if (_socket == null)
			{
				DoInitialize();
			}
		}
	}
}
namespace NLog.Internal.FileAppenders
{
	[SecuritySafeCritical]
	internal abstract class BaseFileAppender : IDisposable
	{
		private readonly Random _random = new Random();

		private DateTime _creationTimeUtc;

		public string FileName { get; }

		public DateTime CreationTimeUtc
		{
			get
			{
				return _creationTimeUtc;
			}
			internal set
			{
				_creationTimeUtc = value;
				CreationTimeSource = TimeSource.Current.FromSystemTime(value);
			}
		}

		public DateTime CreationTimeSource { get; private set; }

		public DateTime OpenTimeUtc { get; private set; }

		public ICreateFileParameters CreateFileParameters { get; private set; }

		protected BaseFileAppender(string fileName, ICreateFileParameters createParameters)
		{
			CreateFileParameters = createParameters;
			FileName = fileName;
			OpenTimeUtc = DateTime.UtcNow;
		}

		public void Write(byte[] bytes)
		{
			Write(bytes, 0, bytes.Length);
		}

		public abstract void Write(byte[] bytes, int offset, int count);

		public abstract void Flush();

		public abstract void Close();

		public abstract DateTime? GetFileCreationTimeUtc();

		public abstract long? GetFileLength();

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected virtual void Dispose(bool disposing)
		{
			if (disposing)
			{
				Close();
			}
		}

		protected FileStream CreateFileStream(bool allowFileSharedWriting, int overrideBufferSize = 0)
		{
			int num = CreateFileParameters.ConcurrentWriteAttemptDelay;
			InternalLogger.Trace("Opening {0} with allowFileSharedWriting={1}", FileName, allowFileSharedWriting);
			for (int i = 0; i < CreateFileParameters.ConcurrentWriteAttempts; i++)
			{
				try
				{
					try
					{
						return TryCreateFileStream(allowFileSharedWriting, overrideBufferSize);
					}
					catch (DirectoryNotFoundException)
					{
						if (!CreateFileParameters.CreateDirs)
						{
							throw;
						}
						string directoryName = Path.GetDirectoryName(FileName);
						try
						{
							Directory.CreateDirectory(directoryName);
						}
						catch (DirectoryNotFoundException)
						{
							throw new NLogRuntimeException("Could not create directory {0}", directoryName);
						}
						return TryCreateFileStream(allowFileSharedWriting, overrideBufferSize);
					}
				}
				catch (IOException)
				{
					if (!CreateFileParameters.ConcurrentWrites || i + 1 == CreateFileParameters.ConcurrentWriteAttempts)
					{
						throw;
					}
					int num2 = _random.Next(num);
					InternalLogger.Warn("Attempt #{0} to open {1} failed. Sleeping for {2}ms", i, FileName, num2);
					num *= 2;
					AsyncHelpers.WaitForDelay(TimeSpan.FromMilliseconds(num2));
				}
			}
			throw new InvalidOperationException("Should not be reached.");
		}

		private FileStream TryCreateFileStream(bool allowFileSharedWriting, int overrideBufferSize)
		{
			UpdateCreationTime();
			FileShare fileShare = ((!allowFileSharedWriting) ? FileShare.Read : FileShare.ReadWrite);
			if (CreateFileParameters.EnableFileDelete)
			{
				fileShare |= FileShare.Delete;
			}
			return new FileStream(FileName, FileMode.Append, FileAccess.Write, fileShare, (overrideBufferSize > 0) ? overrideBufferSize : CreateFileParameters.BufferSize);
		}

		private void UpdateCreationTime()
		{
			FileInfo fileInfo = new FileInfo(FileName);
			if (fileInfo.Exists)
			{
				CreationTimeUtc = fileInfo.LookupValidFileCreationTimeUtc().Value;
				return;
			}
			File.Create(FileName).Dispose();
			CreationTimeUtc = DateTime.UtcNow;
			File.SetCreationTimeUtc(FileName, CreationTimeUtc);
		}

		protected static bool MonitorForEnableFileDeleteEvent(string fileName, ref DateTime lastSimpleMonitorCheckTimeUtc)
		{
			long num = DateTime.UtcNow.Ticks - lastSimpleMonitorCheckTimeUtc.Ticks;
			if (num > 10000000 || num < -10000000)
			{
				lastSimpleMonitorCheckTimeUtc = DateTime.UtcNow;
				try
				{
					if (!File.Exists(fileName))
					{
						return true;
					}
				}
				catch (Exception ex)
				{
					InternalLogger.Error(ex, "Failed to check if File.Exists {0}", fileName);
					return true;
				}
			}
			return false;
		}
	}
	[SecuritySafeCritical]
	internal abstract class BaseMutexFileAppender : BaseFileAppender
	{
		protected BaseMutexFileAppender(string fileName, ICreateFileParameters createParameters)
			: base(fileName, createParameters)
		{
			if (createParameters.IsArchivingEnabled && createParameters.ConcurrentWrites && !PlatformDetector.SupportsSharableMutex)
			{
				InternalLogger.Debug("Mutex for file archive not supported");
			}
		}
	}
	[SecuritySafeCritical]
	internal class CountingSingleProcessFileAppender : BaseFileAppender
	{
		private class Factory : IFileAppenderFactory
		{
			BaseFileAppender IFileAppenderFactory.Open(string fileName, ICreateFileParameters parameters)
			{
				return new CountingSingleProcessFileAppender(fileName, parameters);
			}
		}

		public static readonly IFileAppenderFactory TheFactory = new Factory();

		private FileStream _file;

		private long _currentFileLength;

		private readonly bool _enableFileDeleteSimpleMonitor;

		private DateTime _lastSimpleMonitorCheckTimeUtc;

		public CountingSingleProcessFileAppender(string fileName, ICreateFileParameters parameters)
			: base(fileName, parameters)
		{
			FileInfo fileInfo = new FileInfo(fileName);
			_currentFileLength = (fileInfo.Exists ? fileInfo.Length : 0);
			_file = CreateFileStream(allowFileSharedWriting: false);
			_enableFileDeleteSimpleMonitor = parameters.EnableFileDeleteSimpleMonitor;
			_lastSimpleMonitorCheckTimeUtc = base.OpenTimeUtc;
		}

		public override void Close()
		{
			if (_file == null)
			{
				return;
			}
			InternalLogger.Trace("Closing '{0}'", base.FileName);
			try
			{
				_file.Close();
			}
			catch (Exception ex)
			{
				InternalLogger.Warn(ex, "Failed to close file: '{0}'", base.FileName);
				AsyncHelpers.WaitForDelay(TimeSpan.FromMilliseconds(1.0));
			}
			finally
			{
				_file = null;
			}
		}

		public override void Flush()
		{
			if (_file != null)
			{
				_file.Flush();
			}
		}

		public override DateTime? GetFileCreationTimeUtc()
		{
			return base.CreationTimeUtc;
		}

		public override long? GetFileLength()
		{
			return _currentFileLength;
		}

		public override void Write(byte[] bytes, int offset, int count)
		{
			if (_file != null)
			{
				if (_enableFileDeleteSimpleMonitor && BaseFileAppender.MonitorForEnableFileDeleteEvent(base.FileName, ref _lastSimpleMonitorCheckTimeUtc))
				{
					_file.Dispose();
					_file = CreateFileStream(allowFileSharedWriting: false);
					_currentFileLength = _file.Length;
				}
				_currentFileLength += count;
				_file.Write(bytes, offset, count);
			}
		}
	}
	internal sealed class FileAppenderCache : IFileAppenderCache, IDisposable
	{
		private readonly BaseFileAppender[] _appenders;

		private Timer _autoClosingTimer;

		public static readonly FileAppenderCache Empty = new FileAppenderCache();

		public ICreateFileParameters CreateFileParameters { get; private set; }

		public IFileAppenderFactory Factory { get; private set; }

		public int Size { get; private set; }

		public event EventHandler CheckCloseAppenders;

		private FileAppenderCache()
			: this(0, null, null)
		{
		}

		public FileAppenderCache(int size, IFileAppenderFactory appenderFactory, ICreateFileParameters createFileParams)
		{
			Size = size;
			Factory = appenderFactory;
			CreateFileParameters = createFileParams;
			_appenders = new BaseFileAppender[Size];
			_autoClosingTimer = new Timer(AutoClosingTimerCallback, null, -1, -1);
		}

		private void AutoClosingTimerCallback(object state)
		{
			this.CheckCloseAppenders?.Invoke(this, EventArgs.Empty);
		}

		public BaseFileAppender AllocateAppender(string fileName)
		{
			BaseFileAppender baseFileAppender = null;
			int freeSpot = _appenders.Length - 1;
			for (int i = 0; i < _appenders.Length; i++)
			{
				if (_appenders[i] == null)
				{
					freeSpot = i;
					break;
				}
				if (!string.Equals(_appenders[i].FileName, fileName, StringComparison.OrdinalIgnoreCase))
				{
					continue;
				}
				BaseFileAppender baseFileAppender2 = _appenders[i];
				if (i > 0)
				{
					for (int num = i; num > 0; num--)
					{
						_appenders[num] = _appenders[num - 1];
					}
					_appenders[0] = baseFileAppender2;
				}
				baseFileAppender = baseFileAppender2;
				break;
			}
			if (baseFileAppender == null)
			{
				baseFileAppender = CreateAppender(fileName, freeSpot);
			}
			return baseFileAppender;
		}

		private BaseFileAppender CreateAppender(string fileName, int freeSpot)
		{
			try
			{
				InternalLogger.Debug("Creating file appender: {0}", fileName);
				BaseFileAppender baseFileAppender = Factory.Open(fileName, CreateFileParameters);
				if (_appenders[freeSpot] != null)
				{
					CloseAppender(_appenders[freeSpot], "Stale", lastAppender: false);
					_appenders[freeSpot] = null;
				}
				for (int num = freeSpot; num > 0; num--)
				{
					_appenders[num] = _appenders[num - 1];
				}
				_appenders[0] = baseFileAppender;
				BaseFileAppender result = baseFileAppender;
				_ = this.CheckCloseAppenders;
				return result;
			}
			catch (Exception ex)
			{
				InternalLogger.Warn(ex, "Failed to create file appender: {0}", fileName);
				throw;
			}
		}

		public void CloseAppenders(string reason)
		{
			for (int i = 0; i < _appenders.Length; i++)
			{
				BaseFileAppender baseFileAppender = _appenders[i];
				if (baseFileAppender != null)
				{
					CloseAppender(baseFileAppender, reason, lastAppender: true);
					_appenders[i] = null;
					baseFileAppender.Dispose();
					continue;
				}
				break;
			}
		}

		public void CloseAppenders(DateTime expireTime)
		{
			if (!(expireTime != DateTime.MinValue))
			{
				return;
			}
			for (int i = 0; i < _appenders.Length && _appenders[i] != null; i++)
			{
				if (!(_appenders[i].OpenTimeUtc < expireTime))
				{
					continue;
				}
				for (int j = i; j < _appenders.Length; j++)
				{
					BaseFileAppender baseFileAppender = _appenders[j];
					if (baseFileAppender != null)
					{
						CloseAppender(baseFileAppender, "Expired", i == 0);
						_appenders[j] = null;
						baseFileAppender.Dispose();
						continue;
					}
					break;
				}
				break;
			}
		}

		public void FlushAppenders()
		{
			BaseFileAppender[] appenders = _appenders;
			foreach (BaseFileAppender baseFileAppender in appenders)
			{
				if (baseFileAppender != null)
				{
					try
					{
						baseFileAppender.Flush();
					}
					catch (Exception ex)
					{
						InternalLogger.Error(ex, "Failed to flush file '{0}'.", baseFileAppender.FileName);
						InvalidateAppender(baseFileAppender.FileName)?.Dispose();
						throw;
					}
					continue;
				}
				break;
			}
		}

		private BaseFileAppender GetAppender(string fileName)
		{
			for (int i = 0; i < _appenders.Length; i++)
			{
				BaseFileAppender baseFileAppender = _appenders[i];
				if (baseFileAppender == null)
				{
					break;
				}
				if (string.Equals(baseFileAppender.FileName, fileName, StringComparison.OrdinalIgnoreCase))
				{
					return baseFileAppender;
				}
			}
			return null;
		}

		public DateTime? GetFileCreationTimeSource(string filePath, DateTime? fallbackTimeSource = null)
		{
			BaseFileAppender appender = GetAppender(filePath);
			DateTime? result = null;
			if (appender != null)
			{
				try
				{
					result = FileInfoHelper.LookupValidFileCreationTimeUtc(appender, (BaseFileAppender f) => f.GetFileCreationTimeUtc(), (BaseFileAppender f) => fallbackTimeSource);
					if (result.HasValue)
					{
						DateTime creationTimeUtc = appender.CreationTimeUtc;
						if (result.Value != creationTimeUtc)
						{
							appender.CreationTimeUtc = result.Value;
						}
						return appender.CreationTimeSource;
					}
				}
				catch (Exception ex)
				{
					InternalLogger.Error(ex, "Failed to get file creation time for file '{0}'.", appender.FileName);
					InvalidateAppender(appender.FileName)?.Dispose();
					throw;
				}
			}
			FileInfo fileInfo = new FileInfo(filePath);
			if (fileInfo.Exists)
			{
				result = fileInfo.LookupValidFileCreationTimeUtc(fallbackTimeSource).Value;
				return TimeSource.Current.FromSystemTime(result.Value);
			}
			return result;
		}

		public DateTime? GetFileLastWriteTimeUtc(string filePath)
		{
			FileInfo fileInfo = new FileInfo(filePath);
			if (fileInfo.Exists)
			{
				return fileInfo.GetLastWriteTimeUtc();
			}
			return null;
		}

		public long? GetFileLength(string filePath)
		{
			BaseFileAppender appender = GetAppender(filePath);
			if (appender != null)
			{
				try
				{
					long? fileLength = appender.GetFileLength();
					if (fileLength.HasValue)
					{
						return fileLength;
					}
				}
				catch (IOException ex)
				{
					InternalLogger.Error(ex, "Failed to get length for file '{0}'.", appender.FileName);
					InvalidateAppender(appender.FileName)?.Dispose();
				}
				catch (Exception ex2)
				{
					InternalLogger.Error(ex2, "Failed to get length for file '{0}'.", appender.FileName);
					InvalidateAppender(appender.FileName)?.Dispose();
					throw;
				}
			}
			FileInfo fileInfo = new FileInfo(filePath);
			if (fileInfo.Exists)
			{
				return fileInfo.Length;
			}
			return null;
		}

		public BaseFileAppender InvalidateAppender(string filePath)
		{
			for (int i = 0; i < _appenders.Length; i++)
			{
				BaseFileAppender baseFileAppender = _appenders[i];
				if (baseFileAppender == null)
				{
					break;
				}
				if (string.Equals(baseFileAppender.FileName, filePath, StringComparison.OrdinalIgnoreCase))
				{
					for (int j = i; j < _appenders.Length - 1; j++)
					{
						_appenders[j] = _appenders[j + 1];
					}
					_appenders[_appenders.Length - 1] = null;
					CloseAppender(baseFileAppender, "Invalidate", _appenders[0] == null);
					return baseFileAppender;
				}
			}
			return null;
		}

		private void CloseAppender(BaseFileAppender appender, string reason, bool lastAppender)
		{
			InternalLogger.Debug("FileAppender Closing {0} - {1}", reason, appender.FileName);
			if (lastAppender)
			{
				_autoClosingTimer.Change(-1, -1);
			}
			appender.Close();
		}

		public void Dispose()
		{
			this.CheckCloseAppenders = null;
			Timer autoClosingTimer = _autoClosingTimer;
			if (autoClosingTimer != null)
			{
				_autoClosingTimer = null;
				autoClosingTimer.WaitForDispose(TimeSpan.Zero);
			}
		}
	}
