namespace NLog.Internal.Fakeables
{
	public class AppDomainWrapper : IAppDomain
	{
		private readonly AppDomain _currentAppDomain;

		public static AppDomainWrapper CurrentDomain => new AppDomainWrapper(AppDomain.CurrentDomain);

		public string BaseDirectory { get; private set; }

		public string ConfigurationFile { get; private set; }

		public IEnumerable<string> PrivateBinPath { get; private set; }

		public string FriendlyName { get; private set; }

		public int Id { get; private set; }

		public event EventHandler<EventArgs> ProcessExit
		{
			add
			{
				if (this.processExitEvent == null && _currentAppDomain != null)
				{
					_currentAppDomain.ProcessExit += OnProcessExit;
				}
				processExitEvent += value;
			}
			remove
			{
				processExitEvent -= value;
				if (this.processExitEvent == null && _currentAppDomain != null)
				{
					_currentAppDomain.ProcessExit -= OnProcessExit;
				}
			}
		}

		private event EventHandler<EventArgs> processExitEvent;

		public event EventHandler<EventArgs> DomainUnload
		{
			add
			{
				if (this.domainUnloadEvent == null && _currentAppDomain != null)
				{
					_currentAppDomain.DomainUnload += OnDomainUnload;
				}
				domainUnloadEvent += value;
			}
			remove
			{
				domainUnloadEvent -= value;
				if (this.domainUnloadEvent == null && _currentAppDomain != null)
				{
					_currentAppDomain.DomainUnload -= OnDomainUnload;
				}
			}
		}

		private event EventHandler<EventArgs> domainUnloadEvent;

		public AppDomainWrapper(AppDomain appDomain)
		{
			_currentAppDomain = appDomain;
			try
			{
				BaseDirectory = LookupBaseDirectory(appDomain) ?? string.Empty;
			}
			catch (Exception ex)
			{
				InternalLogger.Warn(ex, "AppDomain.BaseDirectory Failed");
				BaseDirectory = string.Empty;
			}
			try
			{
				ConfigurationFile = LookupConfigurationFile(appDomain);
			}
			catch (Exception ex2)
			{
				InternalLogger.Warn(ex2, "AppDomain.SetupInformation.ConfigurationFile Failed");
				ConfigurationFile = string.Empty;
			}
			try
			{
				PrivateBinPath = LookupPrivateBinPath(appDomain);
			}
			catch (Exception ex3)
			{
				InternalLogger.Warn(ex3, "AppDomain.SetupInformation.PrivateBinPath Failed");
				PrivateBinPath = ArrayHelper.Empty<string>();
			}
			FriendlyName = appDomain.FriendlyName;
			Id = appDomain.Id;
		}

		private static string LookupBaseDirectory(AppDomain appDomain)
		{
			return appDomain.BaseDirectory;
		}

		private static string LookupConfigurationFile(AppDomain appDomain)
		{
			return appDomain.SetupInformation.ConfigurationFile;
		}

		private static string[] LookupPrivateBinPath(AppDomain appDomain)
		{
			string privateBinPath = appDomain.SetupInformation.PrivateBinPath;
			if (!string.IsNullOrEmpty(privateBinPath))
			{
				return privateBinPath.SplitAndTrimTokens(';');
			}
			return ArrayHelper.Empty<string>();
		}

		public IEnumerable<Assembly> GetAssemblies()
		{
			if (_currentAppDomain != null)
			{
				return _currentAppDomain.GetAssemblies();
			}
			return ArrayHelper.Empty<Assembly>();
		}

		private void OnDomainUnload(object sender, EventArgs e)
		{
			this.domainUnloadEvent?.Invoke(sender, e);
		}

		private void OnProcessExit(object sender, EventArgs eventArgs)
		{
			this.processExitEvent?.Invoke(sender, eventArgs);
		}
	}
	internal class AppEnvironmentWrapper : IAppEnvironment, IFileSystem
	{
		private const string UnknownProcessName = "<unknown>";

		private string _entryAssemblyLocation;

		private string _entryAssemblyFileName;

		private string _currentProcessFilePath;

		private string _currentProcessBaseName;

		private int? _currentProcessId;

		public string EntryAssemblyLocation => _entryAssemblyLocation ?? (_entryAssemblyLocation = LookupEntryAssemblyLocation());

		public string EntryAssemblyFileName => _entryAssemblyFileName ?? (_entryAssemblyFileName = LookupEntryAssemblyFileName());

		public string CurrentProcessFilePath => _currentProcessFilePath ?? (_currentProcessFilePath = LookupCurrentProcessFilePath());

		public string CurrentProcessBaseName => _currentProcessBaseName ?? (_currentProcessBaseName = (string.IsNullOrEmpty(CurrentProcessFilePath) ? "<unknown>" : Path.GetFileNameWithoutExtension(CurrentProcessFilePath)));

		public int CurrentProcessId
		{
			get
			{
				int? currentProcessId = _currentProcessId;
				if (!currentProcessId.HasValue)
				{
					int? num = (_currentProcessId = LookupCurrentProcessId());
					return num.Value;
				}
				return currentProcessId.GetValueOrDefault();
			}
		}

		public string AppDomainBaseDirectory => AppDomain.BaseDirectory;

		public string AppDomainConfigurationFile => AppDomain.ConfigurationFile;

		public IEnumerable<string> PrivateBinPath => AppDomain.PrivateBinPath;

		public string UserTempFilePath => Path.GetTempPath();

		public IAppDomain AppDomain { get; internal set; }

		public AppEnvironmentWrapper(IAppDomain appDomain)
		{
			AppDomain = appDomain;
		}

		public bool FileExists(string path)
		{
			return File.Exists(path);
		}

		public XmlReader LoadXmlFile(string path)
		{
			return XmlReader.Create(path);
		}

		private static string LookupEntryAssemblyLocation()
		{
			return AssemblyHelpers.GetAssemblyFileLocation(Assembly.GetEntryAssembly());
		}

		private static string LookupEntryAssemblyFileName()
		{
			try
			{
				return Path.GetFileName(Assembly.GetEntryAssembly()?.Location ?? string.Empty);
			}
			catch (Exception exception)
			{
				if (exception.MustBeRethrownImmediately())
				{
					throw;
				}
				return string.Empty;
			}
		}

		private static string LookupCurrentProcessFilePath()
		{
			try
			{
				return Process.GetCurrentProcess()?.MainModule.FileName ?? string.Empty;
			}
			catch (Exception exception)
			{
				if (exception.MustBeRethrownImmediately())
				{
					throw;
				}
				return string.Empty;
			}
		}

		private static int LookupCurrentProcessId()
		{
			try
			{
				return Process.GetCurrentProcess()?.Id ?? 0;
			}
			catch (Exception exception)
			{
				if (exception.MustBeRethrownImmediately())
				{
					throw;
				}
				return 0;
			}
		}
	}
