		public INamedItemFactory<TimeSource, Type> TimeSources => _timeSources;

		public INamedItemFactory<MethodInfo, MethodInfo> ConditionMethods => _conditionMethods;

		internal MethodFactory ConditionMethodDelegates => _conditionMethods;

		public static event EventHandler<AssemblyLoadingEventArgs> AssemblyLoading;

		public ConfigurationItemFactory(params Assembly[] assemblies)
		{
			CreateInstance = FactoryHelper.CreateInstance;
			_targets = new Factory<Target, TargetAttribute>(this);
			_filters = new Factory<Filter, FilterAttribute>(this);
			_layoutRenderers = new LayoutRendererFactory(this);
			_layouts = new Factory<Layout, LayoutAttribute>(this);
			_conditionMethods = new MethodFactory((Type classType) => MethodFactory.ExtractClassMethods<ConditionMethodsAttribute, ConditionMethodAttribute>(classType));
			_ambientProperties = new Factory<LayoutRenderer, AmbientPropertyAttribute>(this);
			_timeSources = new Factory<TimeSource, TimeSourceAttribute>(this);
			_allFactories = new IFactory[7] { _targets, _filters, _layoutRenderers, _layouts, _conditionMethods, _ambientProperties, _timeSources };
			foreach (Assembly assembly in assemblies)
			{
				RegisterItemsFromAssembly(assembly);
			}
		}

		internal LayoutRendererFactory GetLayoutRenderers()
		{
			return _layoutRenderers;
		}

		public void RegisterItemsFromAssembly(Assembly assembly)
		{
			RegisterItemsFromAssembly(assembly, string.Empty);
		}

		public void RegisterItemsFromAssembly(Assembly assembly, string itemNamePrefix)
		{
			if (ConfigurationItemFactory.AssemblyLoading != null)
			{
				AssemblyLoadingEventArgs e = new AssemblyLoadingEventArgs(assembly);
				ConfigurationItemFactory.AssemblyLoading(null, e);
				if (e.Cancel)
				{
					InternalLogger.Info("Loading assembly '{0}' is canceled", assembly.FullName);
					return;
				}
			}
			InternalLogger.Debug("ScanAssembly('{0}')", assembly.FullName);
			Type[] array = assembly.SafeGetTypes();
			PreloadAssembly(array);
			IFactory[] allFactories = _allFactories;
			for (int i = 0; i < allFactories.Length; i++)
			{
				allFactories[i].ScanTypes(array, itemNamePrefix);
			}
		}

		public void PreloadAssembly(Type[] typesToScan)
		{
			foreach (Type item in typesToScan.Where((Type t) => t.Name.Equals("NLogPackageLoader", StringComparison.OrdinalIgnoreCase)))
			{
				CallPreload(item);
			}
		}

		private void CallPreload(Type type)
		{
			if (type == null)
			{
				return;
			}
			InternalLogger.Debug("Found for preload'{0}'", type.FullName);
			MethodInfo method = type.GetMethod("Preload");
			if (method != null)
			{
				if (method.IsStatic)
				{
					InternalLogger.Debug("NLogPackageLoader contains Preload method");
					try
					{
						object[] parameters = CreatePreloadParameters(method, this);
						method.Invoke(null, parameters);
						InternalLogger.Debug("Preload successfully invoked for '{0}'", type.FullName);
						return;
					}
					catch (Exception ex)
					{
						InternalLogger.Warn(ex, "Invoking Preload for '{0}' failed", type.FullName);
						return;
					}
				}
				InternalLogger.Debug("NLogPackageLoader contains a preload method, but isn't static");
			}
			else
			{
				InternalLogger.Debug("{0} doesn't contain Preload method", type.FullName);
			}
		}

		private static object[] CreatePreloadParameters(MethodInfo preloadMethod, ConfigurationItemFactory configurationItemFactory)
		{
			ParameterInfo parameterInfo = preloadMethod.GetParameters().FirstOrDefault();
			object[] result = null;
			if (parameterInfo?.ParameterType == typeof(ConfigurationItemFactory))
			{
				result = new object[1] { configurationItemFactory };
			}
			return result;
		}

		public void Clear()
		{
			IFactory[] allFactories = _allFactories;
			for (int i = 0; i < allFactories.Length; i++)
			{
				allFactories[i].Clear();
			}
		}

		public void RegisterType(Type type, string itemNamePrefix)
		{
			IFactory[] allFactories = _allFactories;
			for (int i = 0; i < allFactories.Length; i++)
			{
				allFactories[i].RegisterType(type, itemNamePrefix);
			}
		}

		private static ConfigurationItemFactory BuildDefaultFactory()
		{
			Assembly assembly = typeof(ILogger).GetAssembly();
			ConfigurationItemFactory configurationItemFactory = new ConfigurationItemFactory(assembly);
			configurationItemFactory.RegisterExtendedItems();
			try
			{
				string text = string.Empty;
				string[] array = ArrayHelper.Empty<string>();
				foreach (KeyValuePair<string, Assembly> autoLoadingFileLocation in GetAutoLoadingFileLocations())
				{
					if (!string.IsNullOrEmpty(autoLoadingFileLocation.Key))
					{
						if (string.IsNullOrEmpty(text))
						{
							text = autoLoadingFileLocation.Key;
						}
						array = GetNLogExtensionFiles(autoLoadingFileLocation.Key);
						if (array.Length != 0)
						{
							text = autoLoadingFileLocation.Key;
							break;
						}
					}
				}
				InternalLogger.Debug("Start auto loading, location: {0}", text);
				LoadNLogExtensionAssemblies(configurationItemFactory, assembly, array);
			}
			catch (SecurityException ex)
			{
				InternalLogger.Warn(ex, "Seems that we do not have permission");
				if (ex.MustBeRethrown())
				{
					throw;
				}
			}
			catch (UnauthorizedAccessException ex2)
			{
				InternalLogger.Warn(ex2, "Seems that we do not have permission");
				if (ex2.MustBeRethrown())
				{
					throw;
				}
			}
			InternalLogger.Debug("Auto loading done");
			return configurationItemFactory;
		}

		private static void LoadNLogExtensionAssemblies(ConfigurationItemFactory factory, Assembly nlogAssembly, string[] extensionDlls)
		{
			HashSet<string> hashSet = new HashSet<string>(StringComparer.OrdinalIgnoreCase) { nlogAssembly.FullName };
			foreach (string text in extensionDlls)
			{
				InternalLogger.Info("Auto loading assembly file: {0}", text);
				bool flag = false;
				try
				{
					Assembly assembly = AssemblyHelpers.LoadFromPath(text);
					InternalLogger.LogAssemblyVersion(assembly);
					factory.RegisterItemsFromAssembly(assembly);
					hashSet.Add(assembly.FullName);
					flag = true;
				}
				catch (Exception ex)
				{
					if (ex.MustBeRethrownImmediately())
					{
						throw;
					}
					InternalLogger.Warn(ex, "Auto loading assembly file: {0} failed! Skipping this file.", text);
				}
				if (flag)
				{
					InternalLogger.Info("Auto loading assembly file: {0} succeeded!", text);
				}
			}
			foreach (Assembly assembly2 in LogFactory.CurrentAppDomain.GetAssemblies())
			{
				if (assembly2.FullName.StartsWith("NLog.", StringComparison.OrdinalIgnoreCase) && !hashSet.Contains(assembly2.FullName))
				{
					factory.RegisterItemsFromAssembly(assembly2);
				}
				if (assembly2.FullName.StartsWith("NLog.Extensions.Logging,", StringComparison.OrdinalIgnoreCase) || assembly2.FullName.StartsWith("NLog.Web,", StringComparison.OrdinalIgnoreCase) || assembly2.FullName.StartsWith("NLog.Web.AspNetCore,", StringComparison.OrdinalIgnoreCase) || assembly2.FullName.StartsWith("Microsoft.Extensions.Logging,", StringComparison.OrdinalIgnoreCase) || assembly2.FullName.StartsWith("Microsoft.Extensions.Logging.Abstractions,", StringComparison.OrdinalIgnoreCase) || assembly2.FullName.StartsWith("Microsoft.Extensions.Logging.Filter,", StringComparison.OrdinalIgnoreCase) || assembly2.FullName.StartsWith("Microsoft.Logging,", StringComparison.OrdinalIgnoreCase))
				{
					LogManager.AddHiddenAssembly(assembly2);
				}
			}
		}

		internal static IEnumerable<KeyValuePair<string, Assembly>> GetAutoLoadingFileLocations()
		{
			Assembly assembly = typeof(ILogger).GetAssembly();
			string assemblyLocation = PathHelpers.TrimDirectorySeparators(AssemblyHelpers.GetAssemblyFileLocation(assembly));
			if (!string.IsNullOrEmpty(assemblyLocation))
			{
				yield return new KeyValuePair<string, Assembly>(assemblyLocation, assembly);
			}
			Assembly entryAssembly = Assembly.GetEntryAssembly();
			string text = PathHelpers.TrimDirectorySeparators(AssemblyHelpers.GetAssemblyFileLocation(Assembly.GetEntryAssembly()));
			if (!string.IsNullOrEmpty(text) && !string.Equals(text, assemblyLocation, StringComparison.OrdinalIgnoreCase))
			{
				yield return new KeyValuePair<string, Assembly>(text, entryAssembly);
			}
			string text2 = PathHelpers.TrimDirectorySeparators(LogFactory.CurrentAppDomain.BaseDirectory);
			InternalLogger.Debug("Auto loading based on AppDomain-BaseDirectory found location: {0}", text2);
			if (!string.IsNullOrEmpty(text2) && !string.Equals(text2, assemblyLocation, StringComparison.OrdinalIgnoreCase))
			{
				yield return new KeyValuePair<string, Assembly>(text2, null);
			}
		}

		private static string[] GetNLogExtensionFiles(string assemblyLocation)
		{
			try
			{
				InternalLogger.Debug("Search for auto loading files in location: {0}", assemblyLocation);
				if (string.IsNullOrEmpty(assemblyLocation))
				{
					return ArrayHelper.Empty<string>();
				}
				return (from x in Directory.GetFiles(assemblyLocation, "NLog*.dll").Select(Path.GetFileName)
					where !x.Equals("NLog.dll", StringComparison.OrdinalIgnoreCase)
					where !x.Equals("NLog.UnitTests.dll", StringComparison.OrdinalIgnoreCase)
					where !x.Equals("NLog.Extended.dll", StringComparison.OrdinalIgnoreCase)
					select Path.Combine(assemblyLocation, x)).ToArray();
			}
			catch (DirectoryNotFoundException ex)
			{
				InternalLogger.Warn(ex, "Skipping auto loading location because assembly directory does not exist: {0}", assemblyLocation);
				if (ex.MustBeRethrown())
				{
					throw;
				}
				return ArrayHelper.Empty<string>();
			}
			catch (SecurityException ex2)
			{
				InternalLogger.Warn(ex2, "Skipping auto loading location because access not allowed to assembly directory: {0}", assemblyLocation);
				if (ex2.MustBeRethrown())
				{
					throw;
				}
				return ArrayHelper.Empty<string>();
			}
			catch (UnauthorizedAccessException ex3)
			{
				InternalLogger.Warn(ex3, "Skipping auto loading location because access not allowed to assembly directory: {0}", assemblyLocation);
				if (ex3.MustBeRethrown())
				{
					throw;
				}
				return ArrayHelper.Empty<string>();
			}
		}

		private void RegisterExtendedItems()
		{
			_layoutRenderers.RegisterNamedType("configsetting", "NLog.Extensions.Logging.ConfigSettingLayoutRenderer, NLog.Extensions.Logging");
		}
	}
	[AttributeUsage(AttributeTargets.Property)]
	[MeansImplicitUse]
	public sealed class DefaultParameterAttribute : Attribute
	{
	}
	internal class DynamicLogLevelFilter : ILoggingRuleLevelFilter
	{
		private readonly LoggingRule _loggingRule;

		private readonly SimpleLayout _levelFilter;

		private KeyValuePair<string, bool[]> _activeFilter;

		public bool[] LogLevels => GenerateLogLevels();

		public DynamicLogLevelFilter(LoggingRule loggingRule, SimpleLayout levelFilter)
		{
			_loggingRule = loggingRule;
			_levelFilter = levelFilter;
			_activeFilter = new KeyValuePair<string, bool[]>(string.Empty, LoggingRuleLevelFilter.Off.LogLevels);
		}

		public LoggingRuleLevelFilter GetSimpleFilterForUpdate()
		{
			return new LoggingRuleLevelFilter(LogLevels);
		}

		private bool[] GenerateLogLevels()
		{
			string text = _levelFilter.Render(LogEventInfo.CreateNullEvent());
			if (string.IsNullOrEmpty(text))
			{
				return LoggingRuleLevelFilter.Off.LogLevels;
			}
			KeyValuePair<string, bool[]> keyValuePair = _activeFilter;
			if (keyValuePair.Key != text)
			{
				bool[] array = ((text.IndexOf(',') < 0) ? ParseSingleLevel(text) : ParseLevels(text));
				if (array == LoggingRuleLevelFilter.Off.LogLevels)
				{
					return array;
				}
				keyValuePair = (_activeFilter = new KeyValuePair<string, bool[]>(text, array));
			}
			return keyValuePair.Value;
		}

		private bool[] ParseSingleLevel(string levelFilter)
		{
			try
			{
				if (StringHelpers.IsNullOrWhiteSpace(levelFilter))
				{
					return LoggingRuleLevelFilter.Off.LogLevels;
				}
				LogLevel logLevel = LogLevel.FromString(levelFilter.Trim());
				if (logLevel == LogLevel.Off)
				{
					return LoggingRuleLevelFilter.Off.LogLevels;
				}
				bool[] array = new bool[LogLevel.MaxLevel.Ordinal + 1];
				array[logLevel.Ordinal] = true;
				return array;
			}
			catch (ArgumentException ex)
			{
				InternalLogger.Warn(ex, "Logging rule {0} with filter `{1}` has invalid level filter: {2}", _loggingRule.RuleName, _loggingRule.LoggerNamePattern, levelFilter);
				return LoggingRuleLevelFilter.Off.LogLevels;
			}
		}

		private bool[] ParseLevels(string levelFilter)
		{
			string[] array = levelFilter.SplitAndTrimTokens(',');
			if (array.Length == 0)
			{
				return LoggingRuleLevelFilter.Off.LogLevels;
			}
			if (array.Length == 1)
			{
				return ParseSingleLevel(array[0]);
			}
			bool[] array2 = new bool[LogLevel.MaxLevel.Ordinal + 1];
			string[] array3 = array;
			foreach (string levelName in array3)
			{
				try
				{
					LogLevel logLevel = LogLevel.FromString(levelName);
					if (!(logLevel == LogLevel.Off))
					{
						array2[logLevel.Ordinal] = true;
					}
				}
				catch (ArgumentException ex)
				{
					InternalLogger.Warn(ex, "Logging rule {0} with filter `{1}` has invalid level filter: {2}", _loggingRule.RuleName, _loggingRule.LoggerNamePattern, levelFilter);
				}
			}
			return array2;
		}
	}
	internal class DynamicRangeLevelFilter : ILoggingRuleLevelFilter
	{
		private struct MinMaxLevels(string minLevel, string maxLevel) : IEquatable<MinMaxLevels>
		{
			private readonly string _minLevel = minLevel;

			private readonly string _maxLevel = maxLevel;

			public bool Equals(MinMaxLevels other)
			{
				if (_minLevel == other._minLevel)
				{
					return _maxLevel == other._maxLevel;
				}
				return false;
			}
		}

		private readonly LoggingRule _loggingRule;

		private readonly SimpleLayout _minLevel;

		private readonly SimpleLayout _maxLevel;

		private KeyValuePair<MinMaxLevels, bool[]> _activeFilter;

		public bool[] LogLevels => GenerateLogLevels();

		public DynamicRangeLevelFilter(LoggingRule loggingRule, SimpleLayout minLevel, SimpleLayout maxLevel)
		{
			_loggingRule = loggingRule;
			_minLevel = minLevel;
			_maxLevel = maxLevel;
			_activeFilter = new KeyValuePair<MinMaxLevels, bool[]>(new MinMaxLevels(string.Empty, string.Empty), LoggingRuleLevelFilter.Off.LogLevels);
		}

		public LoggingRuleLevelFilter GetSimpleFilterForUpdate()
		{
			return new LoggingRuleLevelFilter(LogLevels);
		}

		private bool[] GenerateLogLevels()
		{
			string text = _minLevel?.Render(LogEventInfo.CreateNullEvent()) ?? string.Empty;
			string text2 = _maxLevel?.Render(LogEventInfo.CreateNullEvent()) ?? string.Empty;
			if (string.IsNullOrEmpty(text) && string.IsNullOrEmpty(text2))
			{
				return LoggingRuleLevelFilter.Off.LogLevels;
			}
			KeyValuePair<MinMaxLevels, bool[]> keyValuePair = _activeFilter;
			if (!keyValuePair.Key.Equals(new MinMaxLevels(text, text2)))
			{
				bool[] value = ParseLevelRange(text, text2);
				keyValuePair = (_activeFilter = new KeyValuePair<MinMaxLevels, bool[]>(new MinMaxLevels(text, text2), value));
			}
			return keyValuePair.Value;
		}

		private bool[] ParseLevelRange(string minLevelFilter, string maxLevelFilter)
		{
			LogLevel logLevel = ParseLogLevel(minLevelFilter, LogLevel.MinLevel);
			LogLevel logLevel2 = ParseLogLevel(maxLevelFilter, LogLevel.MaxLevel);
			bool[] array = new bool[LogLevel.MaxLevel.Ordinal + 1];
			if (logLevel != null && logLevel2 != null)
			{
				for (int i = logLevel.Ordinal; i <= array.Length - 1 && i <= logLevel2.Ordinal; i++)
				{
					array[i] = true;
				}
			}
			return array;
		}

		private LogLevel ParseLogLevel(string logLevel, LogLevel levelIfEmpty)
		{
			try
			{
				if (string.IsNullOrEmpty(logLevel))
				{
					return levelIfEmpty;
				}
				return LogLevel.FromString(logLevel.Trim());
			}
			catch (ArgumentException ex)
			{
				InternalLogger.Warn(ex, "Logging rule {0} with filter `{1}` has invalid level filter: {2}", _loggingRule.RuleName, _loggingRule.LoggerNamePattern, logLevel);
				return null;
			}
		}
	}
