	internal class Factory<TBaseType, TAttributeType> : INamedItemFactory<TBaseType, Type>, IFactory where TBaseType : class where TAttributeType : NameBaseAttribute
	{
		private delegate Type GetTypeDelegate();

		private readonly Dictionary<string, GetTypeDelegate> _items = new Dictionary<string, GetTypeDelegate>(StringComparer.OrdinalIgnoreCase);

		private readonly ConfigurationItemFactory _parentFactory;

		internal Factory(ConfigurationItemFactory parentFactory)
		{
			_parentFactory = parentFactory;
		}

		public void ScanTypes(Type[] types, string prefix)
		{
			foreach (Type type in types)
			{
				try
				{
					RegisterType(type, prefix);
				}
				catch (Exception ex)
				{
					InternalLogger.Error(ex, "Failed to add type '{0}'.", type.FullName);
					if (ex.MustBeRethrown())
					{
						throw;
					}
				}
			}
		}

		public void RegisterType(Type type, string itemNamePrefix)
		{
			if (!typeof(TBaseType).IsAssignableFrom(type))
			{
				return;
			}
			IEnumerable<TAttributeType> customAttributes = type.GetCustomAttributes<TAttributeType>(inherit: false);
			if (customAttributes == null)
			{
				return;
			}
			foreach (TAttributeType item in customAttributes)
			{
				RegisterDefinition(itemNamePrefix + item.Name, type);
			}
		}

		public void RegisterNamedType(string itemName, string typeName)
		{
			_items[itemName] = () => Type.GetType(typeName, throwOnError: false);
		}

		public void Clear()
		{
			_items.Clear();
		}

		public void RegisterDefinition(string itemName, Type itemDefinition)
		{
			_items[itemName] = () => itemDefinition;
		}

		public bool TryGetDefinition(string itemName, out Type result)
		{
			if (!_items.TryGetValue(itemName, out var value))
			{
				result = null;
				return false;
			}
			try
			{
				result = value();
				return result != null;
			}
			catch (Exception exception)
			{
				if (exception.MustBeRethrown())
				{
					throw;
				}
				result = null;
				return false;
			}
		}

		public virtual bool TryCreateInstance(string itemName, out TBaseType result)
		{
			if (!TryGetDefinition(itemName, out var result2))
			{
				result = null;
				return false;
			}
			result = (TBaseType)_parentFactory.CreateInstance(result2);
			return true;
		}

		public virtual TBaseType CreateInstance(string itemName)
		{
			if (TryCreateInstance(itemName, out var result))
			{
				return result;
			}
			string text = typeof(TBaseType).Name + " cannot be found: '" + itemName + "'";
			if (itemName != null && (itemName.StartsWith("aspnet", StringComparison.OrdinalIgnoreCase) || itemName.StartsWith("iis", StringComparison.OrdinalIgnoreCase)))
			{
				text += ". Is NLog.Web not included?";
			}
			throw new ArgumentException(text);
		}
	}
	internal class LayoutRendererFactory : Factory<LayoutRenderer, LayoutRendererAttribute>
	{
		private Dictionary<string, FuncLayoutRenderer> _funcRenderers;

		public LayoutRendererFactory(ConfigurationItemFactory parentFactory)
			: base(parentFactory)
		{
		}

		public void ClearFuncLayouts()
		{
			_funcRenderers = null;
		}

		public void RegisterFuncLayout(string name, FuncLayoutRenderer renderer)
		{
			_funcRenderers = _funcRenderers ?? new Dictionary<string, FuncLayoutRenderer>(StringComparer.OrdinalIgnoreCase);
			_funcRenderers[name] = renderer;
		}

		public override bool TryCreateInstance(string itemName, out LayoutRenderer result)
		{
			if (_funcRenderers != null && _funcRenderers.TryGetValue(itemName, out var value))
			{
				result = value;
				return true;
			}
			return base.TryCreateInstance(itemName, out result);
		}
	}
