		{
			ActivatedConfiguration = activatedConfiguration;
			DeactivatedConfiguration = deactivatedConfiguration;
		}
	}
	internal static class LoggingConfigurationElementExtensions
	{
		public static bool MatchesName(this ILoggingConfigurationElement section, string expectedName)
		{
			return string.Equals(section?.Name?.Trim(), expectedName, StringComparison.OrdinalIgnoreCase);
		}

		public static void AssertName(this ILoggingConfigurationElement section, params string[] allowedNames)
		{
			foreach (string expectedName in allowedNames)
			{
				if (section.MatchesName(expectedName))
				{
					return;
				}
			}
			throw new InvalidOperationException("Assertion failed. Expected element name '" + string.Join("|", allowedNames) + "', actual: '" + section?.Name + "'.");
		}

		public static string GetRequiredValue(this ILoggingConfigurationElement element, string attributeName, string section)
		{
			string optionalValue = element.GetOptionalValue(attributeName, null);
			if (optionalValue == null)
			{
				throw new NLogConfigurationException("Expected " + attributeName + " on " + element.Name + " in " + section);
			}
			if (StringHelpers.IsNullOrWhiteSpace(optionalValue))
			{
				throw new NLogConfigurationException("Expected non-empty " + attributeName + " on " + element.Name + " in " + section);
			}
			return optionalValue;
		}

		public static string GetOptionalValue(this ILoggingConfigurationElement element, string attributeName, string defaultValue)
		{
			string text = (from configItem in element.Values
				where string.Equals(configItem.Key, attributeName, StringComparison.OrdinalIgnoreCase)
				select configItem.Value).FirstOrDefault();
			if (text == null)
			{
				return defaultValue;
			}
			return text;
		}

		public static bool GetOptionalBooleanValue(this ILoggingConfigurationElement element, string attributeName, bool defaultValue)
		{
			string optionalValue = element.GetOptionalValue(attributeName, null);
			if (string.IsNullOrEmpty(optionalValue))
			{
				return defaultValue;
			}
			try
			{
				return Convert.ToBoolean(optionalValue.Trim(), CultureInfo.InvariantCulture);
			}
			catch (Exception ex)
			{
				NLogConfigurationException ex2 = new NLogConfigurationException(ex, $"'{attributeName}' hasn't a valid boolean value '{optionalValue}'. {defaultValue} will be used");
				if (ex2.MustBeRethrown())
				{
					throw ex2;
				}
				InternalLogger.Error(ex, ex2.Message);
				return defaultValue;
			}
		}

		public static string GetConfigItemTypeAttribute(this ILoggingConfigurationElement element, string sectionNameForRequiredValue = null)
		{
			return StripOptionalNamespacePrefix((sectionNameForRequiredValue != null) ? element.GetRequiredValue("type", sectionNameForRequiredValue) : element.GetOptionalValue("type", null));
		}

		private static string StripOptionalNamespacePrefix(string attributeValue)
		{
			if (attributeValue == null)
			{
				return null;
			}
			int num = attributeValue.IndexOf(':');
			if (num < 0)
			{
				return attributeValue;
			}
			return attributeValue.Substring(num + 1);
		}
	}
	internal class LoggingConfigurationFileLoader : ILoggingConfigurationLoader, IDisposable
	{
		private readonly IAppEnvironment _appEnvironment;

		public LoggingConfigurationFileLoader(IAppEnvironment appEnvironment)
		{
			_appEnvironment = appEnvironment;
		}

		public virtual LoggingConfiguration Load(LogFactory logFactory, string filename = null)
		{
			if (string.IsNullOrEmpty(filename) || FilePathLayout.DetectFilePathKind(filename) == FilePathKind.Relative)
			{
				return TryLoadFromFilePaths(logFactory, filename);
			}
			if (TryLoadLoggingConfiguration(logFactory, filename, out var config))
			{
				return config;
			}
			return null;
		}

		public virtual void Activated(LogFactory logFactory, LoggingConfiguration config)
		{
		}

		private LoggingConfiguration TryLoadFromAndroidAssets(LogFactory logFactory)
		{
			try
			{
				using Stream stream = Application.Context.Assets.Open("NLog.config");
				if (stream != null)
				{
					InternalLogger.Debug("Loading config from Assets {0}", "NLog.config");
					using XmlReader xmlReader = XmlReader.Create(stream);
					return LoadXmlLoggingConfiguration(xmlReader, null, logFactory);
				}
			}
			catch (Exception ex)
			{
				InternalLogger.Trace(ex, "no {0} in assets folder", "NLog.config");
			}
			return null;
		}

		private LoggingConfiguration TryLoadFromFilePaths(LogFactory logFactory, string filename)
		{
			foreach (string candidateConfigFilePath in logFactory.GetCandidateConfigFilePaths(filename))
			{
				if (TryLoadLoggingConfiguration(logFactory, candidateConfigFilePath, out var config))
				{
					return config;
				}
			}
			return TryLoadFromAndroidAssets(logFactory);
		}

		private bool TryLoadLoggingConfiguration(LogFactory logFactory, string configFile, out LoggingConfiguration config)
		{
			try
			{
				if (_appEnvironment.FileExists(configFile))
				{
					config = LoadXmlLoggingConfigurationFile(logFactory, configFile);
					return true;
				}
			}
			catch (IOException ex)
			{
				InternalLogger.Warn(ex, "Skipping invalid config file location: {0}", configFile);
			}
			catch (UnauthorizedAccessException ex2)
			{
				InternalLogger.Warn(ex2, "Skipping inaccessible config file location: {0}", configFile);
			}
			catch (SecurityException ex3)
			{
				InternalLogger.Warn(ex3, "Skipping inaccessible config file location: {0}", configFile);
			}
			catch (Exception ex4)
			{
				InternalLogger.Error(ex4, "Failed loading from config file location: {0}", configFile);
				if (logFactory.ThrowConfigExceptions ?? logFactory.ThrowExceptions)
				{
					throw;
				}
				if (ex4.MustBeRethrown())
				{
					throw;
				}
			}
			config = null;
			return false;
		}

		private LoggingConfiguration LoadXmlLoggingConfigurationFile(LogFactory logFactory, string configFile)
		{
			InternalLogger.Debug("Loading config from {0}", configFile);
			using XmlReader xmlReader = _appEnvironment.LoadXmlFile(configFile);
			return LoadXmlLoggingConfiguration(xmlReader, configFile, logFactory);
		}

		private LoggingConfiguration LoadXmlLoggingConfiguration(XmlReader xmlReader, string configFile, LogFactory logFactory)
		{
			try
			{
				XmlLoggingConfiguration xmlLoggingConfiguration = new XmlLoggingConfiguration(xmlReader, configFile, logFactory);
				if (xmlLoggingConfiguration.InitializeSucceeded != true)
				{
					if (ThrowXmlConfigExceptions(configFile, xmlReader, logFactory, out var autoReload))
					{
						using XmlReader reader = _appEnvironment.LoadXmlFile(configFile);
						xmlLoggingConfiguration = new XmlLoggingConfiguration(reader, configFile, logFactory);
					}
					else if (autoReload && !xmlLoggingConfiguration.AutoReload)
					{
						return CreateEmptyDefaultConfig(configFile, logFactory, autoReload);
					}
				}
				return xmlLoggingConfiguration;
			}
			catch (Exception exception)
			{
				if (exception.MustBeRethrownImmediately() || exception.MustBeRethrown() || (logFactory.ThrowConfigExceptions ?? logFactory.ThrowExceptions))
				{
					throw;
				}
				if (ThrowXmlConfigExceptions(configFile, xmlReader, logFactory, out var autoReload2))
				{
					throw;
				}
				return CreateEmptyDefaultConfig(configFile, logFactory, autoReload2);
			}
		}

		private static LoggingConfiguration CreateEmptyDefaultConfig(string configFile, LogFactory logFactory, bool autoReload)
		{
			return new XmlLoggingConfiguration($"<nlog autoReload='{autoReload}'></nlog>", configFile, logFactory);
		}

		private bool ThrowXmlConfigExceptions(string configFile, XmlReader xmlReader, LogFactory logFactory, out bool autoReload)
		{
			autoReload = false;
			try
			{
				if (string.IsNullOrEmpty(configFile))
				{
					return false;
				}
				string fileContent = File.ReadAllText(configFile);
				if (xmlReader.ReadState == ReadState.Error)
				{
					if (ScanForBooleanParameter(fileContent, "throwExceptions", parameterValue: true))
					{
						logFactory.ThrowExceptions = true;
						return true;
					}
					if (ScanForBooleanParameter(fileContent, "throwConfigExceptions", parameterValue: true))
					{
						logFactory.ThrowConfigExceptions = true;
						return true;
					}
				}
				if (ScanForBooleanParameter(fileContent, "autoReload", parameterValue: true))
				{
					autoReload = true;
				}
				return false;
			}
			catch (Exception ex)
			{
				InternalLogger.Error(ex, "Failed to scan content of config file: {0}", configFile);
				return false;
			}
		}

		private static bool ScanForBooleanParameter(string fileContent, string parameterName, bool parameterValue)
		{
			if (fileContent.IndexOf($"{parameterName}=\"{parameterValue}", StringComparison.OrdinalIgnoreCase) < 0)
			{
				return fileContent.IndexOf($"{parameterName}='{parameterValue}", StringComparison.OrdinalIgnoreCase) >= 0;
			}
			return true;
		}

		public IEnumerable<string> GetDefaultCandidateConfigFilePaths(string filename = null)
		{
			string nlogConfigFile = filename ?? "NLog.config";
			string baseDirectory = PathHelpers.TrimDirectorySeparators(_appEnvironment.AppDomainBaseDirectory);
			if (!string.IsNullOrEmpty(baseDirectory))
			{
				yield return Path.Combine(baseDirectory, nlogConfigFile);
			}
			string nLogConfigFileLowerCase = nlogConfigFile.ToLower();
			bool platformFileSystemCaseInsensitive = nlogConfigFile == nLogConfigFileLowerCase || PlatformDetector.IsWin32;
			if (!platformFileSystemCaseInsensitive && !string.IsNullOrEmpty(baseDirectory))
			{
				yield return Path.Combine(baseDirectory, nLogConfigFileLowerCase);
			}
			string entryAssemblyLocation = PathHelpers.TrimDirectorySeparators(_appEnvironment.EntryAssemblyLocation);
			if (!string.IsNullOrEmpty(entryAssemblyLocation) && !string.Equals(entryAssemblyLocation, baseDirectory, StringComparison.OrdinalIgnoreCase))
			{
				yield return Path.Combine(entryAssemblyLocation, nlogConfigFile);
				if (!platformFileSystemCaseInsensitive)
				{
					yield return Path.Combine(entryAssemblyLocation, nLogConfigFileLowerCase);
				}
			}
			if (string.IsNullOrEmpty(baseDirectory))
			{
				yield return nlogConfigFile;
				if (!platformFileSystemCaseInsensitive)
				{
					yield return nLogConfigFileLowerCase;
				}
			}
			if (filename == null)
			{
				foreach (string appSpecificNLogLocation in GetAppSpecificNLogLocations(entryAssemblyLocation))
				{
					yield return appSpecificNLogLocation;
				}
			}
			foreach (string privateBinPathNLogLocation in GetPrivateBinPathNLogLocations(baseDirectory, nlogConfigFile, platformFileSystemCaseInsensitive ? nLogConfigFileLowerCase : string.Empty))
			{
				yield return privateBinPathNLogLocation;
			}
			string text = ((filename != null) ? null : LookupNLogAssemblyLocation());
			if (text != null)
			{
				yield return text + ".nlog";
			}
		}

		private static string LookupNLogAssemblyLocation()
		{
			Assembly assembly = typeof(LogFactory).GetAssembly();
			string text = assembly?.Location;
			if (!string.IsNullOrEmpty(text) && !assembly.GlobalAssemblyCache)
			{
				return text;
			}
			return null;
		}

		public IEnumerable<string> GetAppSpecificNLogLocations(string entryAssemblyLocation)
		{
			string configurationFile = _appEnvironment.AppDomainConfigurationFile;
			if (!StringHelpers.IsNullOrWhiteSpace(configurationFile))
			{
				yield return Path.ChangeExtension(configurationFile, ".nlog");
				if (configurationFile.Contains(".vshost."))
				{
					yield return Path.ChangeExtension(configurationFile.Replace(".vshost.", "."), ".nlog");
				}
			}
		}

		private IEnumerable<string> GetPrivateBinPathNLogLocations(string baseDirectory, string nlogConfigFile, string nLogConfigFileLowerCase)
		{
			IEnumerable<string> privateBinPath = _appEnvironment.PrivateBinPath;
			if (privateBinPath == null)
			{
				yield break;
			}
			foreach (string item in privateBinPath)
			{
				string path = PathHelpers.TrimDirectorySeparators(item);
				if (!StringHelpers.IsNullOrWhiteSpace(path) && !string.Equals(path, baseDirectory, StringComparison.OrdinalIgnoreCase))
				{
					yield return Path.Combine(path, nlogConfigFile);
					if (!string.IsNullOrEmpty(nLogConfigFileLowerCase))
					{
						yield return Path.Combine(path, nLogConfigFileLowerCase);
					}
				}
			}
		}

		protected virtual void Dispose(bool disposing)
		{
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}
	}
	public abstract class LoggingConfigurationParser : LoggingConfiguration
	{
		private ConfigurationItemFactory _configurationItemFactory;

		protected LoggingConfigurationParser(LogFactory logFactory)
			: base(logFactory)
		{
		}

		protected void LoadConfig(ILoggingConfigurationElement nlogConfig, string basePath)
		{
			InternalLogger.Trace("ParseNLogConfig");
			nlogConfig.AssertName("nlog");
			SetNLogElementSettings(nlogConfig);
			List<ILoggingConfigurationElement> list = nlogConfig.Children.ToList();
			foreach (ILoggingConfigurationElement item in list.Where((ILoggingConfigurationElement child) => child.MatchesName("extensions")).ToList())
			{
				ParseExtensionsElement(item, basePath);
			}
			List<ILoggingConfigurationElement> list2 = new List<ILoggingConfigurationElement>();
			foreach (ILoggingConfigurationElement item2 in list)
			{
				if (item2.MatchesName("rules"))
				{
					list2.Add(item2);
				}
				else if (!item2.MatchesName("extensions") && !ParseNLogSection(item2))
				{
					InternalLogger.Warn("Skipping unknown 'NLog' child node: {0}", item2.Name);
				}
			}
			foreach (ILoggingConfigurationElement item3 in list2)
			{
				ParseRulesElement(item3, base.LoggingRules);
			}
		}

		private void SetNLogElementSettings(ILoggingConfigurationElement nlogConfig)
		{
			IList<KeyValuePair<string, string>> list = CreateUniqueSortedListFromConfig(nlogConfig);
			bool? parseMessageTemplates = null;
			bool flag = false;
			foreach (KeyValuePair<string, string> item in list)
			{
				switch (item.Key.ToUpperInvariant())
				{
				case "THROWEXCEPTIONS":
					base.LogFactory.ThrowExceptions = ParseBooleanValue(item.Key, item.Value, base.LogFactory.ThrowExceptions);
					break;
				case "THROWCONFIGEXCEPTIONS":
					base.LogFactory.ThrowConfigExceptions = ParseNullableBooleanValue(item.Key, item.Value, defaultValue: false);
					break;
				case "INTERNALLOGLEVEL":
					InternalLogger.LogLevel = ParseLogLevelSafe(item.Key, item.Value, InternalLogger.LogLevel);
					flag = InternalLogger.LogLevel != LogLevel.Off;
					break;
				case "USEINVARIANTCULTURE":
					if (ParseBooleanValue(item.Key, item.Value, defaultValue: false))
					{
						base.DefaultCultureInfo = CultureInfo.InvariantCulture;
					}
					break;
				case "EXCEPTIONLOGGINGOLDSTYLE":
					base.ExceptionLoggingOldStyle = ParseBooleanValue(item.Key, item.Value, base.ExceptionLoggingOldStyle);
					break;
				case "KEEPVARIABLESONRELOAD":
					base.LogFactory.KeepVariablesOnReload = ParseBooleanValue(item.Key, item.Value, base.LogFactory.KeepVariablesOnReload);
					break;
				case "INTERNALLOGTOCONSOLE":
					InternalLogger.LogToConsole = ParseBooleanValue(item.Key, item.Value, InternalLogger.LogToConsole);
					break;
				case "INTERNALLOGTOCONSOLEERROR":
					InternalLogger.LogToConsoleError = ParseBooleanValue(item.Key, item.Value, InternalLogger.LogToConsoleError);
					break;
				case "INTERNALLOGFILE":
				{
					string text = item.Value?.Trim();
					if (!string.IsNullOrEmpty(text))
					{
						text = ExpandFilePathVariables(text);
						InternalLogger.LogFile = text;
					}
					break;
				}
				case "INTERNALLOGINCLUDETIMESTAMP":
					InternalLogger.IncludeTimestamp = ParseBooleanValue(item.Key, item.Value, InternalLogger.IncludeTimestamp);
					break;
				case "GLOBALTHRESHOLD":
					base.LogFactory.GlobalThreshold = ParseLogLevelSafe(item.Key, item.Value, base.LogFactory.GlobalThreshold);
					break;
				case "PARSEMESSAGETEMPLATES":
					parseMessageTemplates = ParseNullableBooleanValue(item.Key, item.Value, defaultValue: true);
					break;
				case "AUTOSHUTDOWN":
					base.LogFactory.AutoShutdown = ParseBooleanValue(item.Key, item.Value, defaultValue: true);
					break;
				default:
					InternalLogger.Debug("Skipping unknown 'NLog' property {0}={1}", item.Key, item.Value);
					break;
				case "AUTORELOAD":
					break;
				}
			}
			if (!flag && !InternalLogger.HasActiveLoggers())
			{
				InternalLogger.LogLevel = LogLevel.Off;
			}
			_configurationItemFactory = ConfigurationItemFactory.Default;
			_configurationItemFactory.ParseMessageTemplates = parseMessageTemplates;
		}

		private static IList<KeyValuePair<string, string>> CreateUniqueSortedListFromConfig(ILoggingConfigurationElement nlogConfig)
		{
			Dictionary<string, string> dict = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
			foreach (KeyValuePair<string, string> value in nlogConfig.Values)
			{
				if (!string.IsNullOrEmpty(value.Key))
				{
					string key = value.Key.Trim();
					if (dict.ContainsKey(key))
					{
						InternalLogger.Debug("Skipping duplicate value for 'NLog' property {0}. Value={1}", value.Key, dict[key]);
					}
					dict[key] = value.Value;
				}
			}
			List<KeyValuePair<string, string>> sortedList = new List<KeyValuePair<string, string>>(dict.Count);
			AddHighPrioritySetting("ThrowExceptions");
			AddHighPrioritySetting("ThrowConfigExceptions");
			AddHighPrioritySetting("InternalLogLevel");
			AddHighPrioritySetting("InternalLogFile");
			AddHighPrioritySetting("InternalLogToConsole");
			foreach (KeyValuePair<string, string> item in dict)
			{
				sortedList.Add(item);
			}
			return sortedList;
			void AddHighPrioritySetting(string settingName)
			{
				if (dict.ContainsKey(settingName))
				{
					sortedList.Add(new KeyValuePair<string, string>(settingName, dict[settingName]));
					dict.Remove(settingName);
				}
			}
		}

		private string ExpandFilePathVariables(string internalLogFile)
		{
			try
			{
				if (ContainsSubStringIgnoreCase(internalLogFile, "${currentdir}", out var result))
				{
					string text = internalLogFile;
					string oldValue = result;
					string currentDirectory = Directory.GetCurrentDirectory();
					char directorySeparatorChar = Path.DirectorySeparatorChar;
					internalLogFile = text.Replace(oldValue, currentDirectory + directorySeparatorChar);
				}
				if (ContainsSubStringIgnoreCase(internalLogFile, "${basedir}", out var result2))
				{
					string text2 = internalLogFile;
					string oldValue2 = result2;
					string appDomainBaseDirectory = base.LogFactory.CurrentAppEnvironment.AppDomainBaseDirectory;
					char directorySeparatorChar = Path.DirectorySeparatorChar;
					internalLogFile = text2.Replace(oldValue2, appDomainBaseDirectory + directorySeparatorChar);
				}
				if (ContainsSubStringIgnoreCase(internalLogFile, "${tempdir}", out var result3))
				{
					string text3 = internalLogFile;
					string oldValue3 = result3;
					string userTempFilePath = base.LogFactory.CurrentAppEnvironment.UserTempFilePath;
					char directorySeparatorChar = Path.DirectorySeparatorChar;
					internalLogFile = text3.Replace(oldValue3, userTempFilePath + directorySeparatorChar);
				}
				if (ContainsSubStringIgnoreCase(internalLogFile, "${processdir}", out var result4))
				{
					string text4 = internalLogFile;
					string oldValue4 = result4;
					string directoryName = Path.GetDirectoryName(base.LogFactory.CurrentAppEnvironment.CurrentProcessFilePath);
					char directorySeparatorChar = Path.DirectorySeparatorChar;
					internalLogFile = text4.Replace(oldValue4, directoryName + directorySeparatorChar);
				}
				if (internalLogFile.IndexOf("%", StringComparison.OrdinalIgnoreCase) >= 0)
				{
					internalLogFile = Environment.ExpandEnvironmentVariables(internalLogFile);
				}
				return internalLogFile;
			}
			catch
			{
				return internalLogFile;
			}
		}

		private static bool ContainsSubStringIgnoreCase(string haystack, string needle, out string result)
		{
			int num = haystack.IndexOf(needle, StringComparison.OrdinalIgnoreCase);
			result = ((num >= 0) ? haystack.Substring(num, needle.Length) : null);
			return result != null;
		}

		private LogLevel ParseLogLevelSafe(string attributeName, string attributeValue, LogLevel @default)
		{
			try
			{
				return LogLevel.FromString(attributeValue?.Trim());
			}
			catch (Exception ex)
			{
				if (ex.MustBeRethrownImmediately())
				{
					throw;
				}
				NLogConfigurationException ex2 = new NLogConfigurationException(ex, "attribute '{0}': '{1}' isn't valid LogLevel. {2} will be used.", attributeName, attributeValue, @default);
				if (MustThrowConfigException(ex2))
				{
					throw ex2;
				}
				return @default;
			}
		}

		protected virtual bool ParseNLogSection(ILoggingConfigurationElement configSection)
		{
			switch (configSection.Name?.Trim().ToUpperInvariant())
			{
			case "TIME":
				ParseTimeElement(configSection);
				return true;
			case "VARIABLE":
				ParseVariableElement(configSection);
				return true;
			case "VARIABLES":
				ParseVariablesElement(configSection);
				return true;
			case "APPENDERS":
			case "TARGETS":
				ParseTargetsElement(configSection);
				return true;
			default:
				return false;
			}
		}

		private void ParseExtensionsElement(ILoggingConfigurationElement extensionsElement, string baseDirectory)
		{
			extensionsElement.AssertName("extensions");
			foreach (ILoggingConfigurationElement child in extensionsElement.Children)
			{
				string text = null;
				string text2 = null;
				string text3 = null;
				string text4 = null;
				foreach (KeyValuePair<string, string> value in child.Values)
				{
					if (MatchesName(value.Key, "prefix"))
					{
						text = value.Value + ".";
					}
					else if (MatchesName(value.Key, "type"))
					{
						text2 = value.Value;
					}
					else if (MatchesName(value.Key, "assemblyFile"))
					{
						text3 = value.Value;
					}
					else if (MatchesName(value.Key, "assembly"))
					{
						text4 = value.Value;
					}
					else
					{
						InternalLogger.Debug("Skipping unknown property {0} for element {1} in section {2}", value.Key, child.Name, extensionsElement.Name);
					}
				}
				if (!StringHelpers.IsNullOrWhiteSpace(text2))
				{
					RegisterExtension(text2, text);
				}
				if (!StringHelpers.IsNullOrWhiteSpace(text3))
				{
					ParseExtensionWithAssemblyFile(baseDirectory, text3, text);
				}
				else if (!StringHelpers.IsNullOrWhiteSpace(text4))
				{
					ParseExtensionWithAssembly(text4, text);
				}
			}
		}

		private void RegisterExtension(string type, string itemNamePrefix)
		{
			try
			{
				_configurationItemFactory.RegisterType(Type.GetType(type, throwOnError: true), itemNamePrefix);
			}
			catch (Exception ex)
			{
				if (ex.MustBeRethrownImmediately())
				{
					throw;
				}
				NLogConfigurationException ex2 = new NLogConfigurationException("Error loading extensions: " + type, ex);
				if (MustThrowConfigException(ex2))
				{
					throw ex2;
				}
			}
		}

		private void ParseExtensionWithAssemblyFile(string baseDirectory, string assemblyFile, string prefix)
		{
			try
			{
				Assembly assembly = AssemblyHelpers.LoadFromPath(assemblyFile, baseDirectory);
				_configurationItemFactory.RegisterItemsFromAssembly(assembly, prefix);
			}
			catch (Exception ex)
			{
				if (ex.MustBeRethrownImmediately())
				{
					throw;
				}
				NLogConfigurationException ex2 = new NLogConfigurationException("Error loading extensions: " + assemblyFile, ex);
				if (MustThrowConfigException(ex2))
				{
					throw ex2;
				}
			}
		}

		private void ParseExtensionWithAssembly(string assemblyName, string prefix)
		{
			try
			{
				Assembly assembly = AssemblyHelpers.LoadFromName(assemblyName);
				_configurationItemFactory.RegisterItemsFromAssembly(assembly, prefix);
			}
			catch (Exception ex)
			{
				if (ex.MustBeRethrownImmediately())
				{
					throw;
				}
				NLogConfigurationException ex2 = new NLogConfigurationException("Error loading extensions: " + assemblyName, ex);
				if (MustThrowConfigException(ex2))
				{
					throw ex2;
				}
			}
		}

		private void ParseVariableElement(ILoggingConfigurationElement variableElement)
		{
			string text = null;
			string text2 = null;
			foreach (KeyValuePair<string, string> value in variableElement.Values)
			{
				if (MatchesName(value.Key, "name"))
				{
					text = value.Value;
				}
				else if (MatchesName(value.Key, "value"))
				{
					text2 = value.Value;
				}
				else
				{
					InternalLogger.Debug("Skipping unknown property {0} for element {1} in section {2}", value.Key, variableElement.Name, "variables");
				}
			}
			if (AssertNonEmptyValue(text, "name", variableElement.Name, "variables") && AssertNotNullValue(text2, "value", variableElement.Name, "variables"))
			{
				string text3 = ExpandSimpleVariables(text2);
				base.Variables[text] = text3;
			}
		}

		private void ParseVariablesElement(ILoggingConfigurationElement variableElement)
		{
			variableElement.AssertName("variables");
			foreach (ILoggingConfigurationElement child in variableElement.Children)
			{
				ParseVariableElement(child);
			}
		}

		private void ParseTimeElement(ILoggingConfigurationElement timeElement)
		{
			timeElement.AssertName("time");
			string text = null;
			foreach (KeyValuePair<string, string> value in timeElement.Values)
			{
				if (MatchesName(value.Key, "type"))
				{
					text = value.Value;
				}
				else
				{
					InternalLogger.Debug("Skipping unknown property {0} for element {1} in section {2}", value.Key, timeElement.Name, timeElement.Name);
				}
			}
			if (AssertNonEmptyValue(text, "type", timeElement.Name, string.Empty))
			{
				TimeSource timeSource = _configurationItemFactory.TimeSources.CreateInstance(text);
				ConfigureObjectFromAttributes(timeSource, timeElement, ignoreType: true);
				InternalLogger.Info("Selecting time source {0}", timeSource);
				TimeSource.Current = timeSource;
			}
		}

		[ContractAnnotation("value:notnull => true")]
		private static bool AssertNotNullValue(string value, string propertyName, string elementName, string sectionName)
		{
			if (value != null)
			{
				return true;
			}
			return AssertNonEmptyValue(string.Empty, propertyName, elementName, sectionName);
		}

		[ContractAnnotation("value:null => false")]
		private static bool AssertNonEmptyValue(string value, string propertyName, string elementName, string sectionName)
		{
			if (!StringHelpers.IsNullOrWhiteSpace(value))
			{
				return true;
			}
			if (LogManager.ThrowConfigExceptions ?? LogManager.ThrowExceptions)
			{
				throw new NLogConfigurationException("Expected property " + propertyName + " on element name: " + elementName + " in section: " + sectionName);
			}
			InternalLogger.Warn("Skipping element name: {0} in section: {1} because property {2} is blank", elementName, sectionName, propertyName);
			return false;
		}

		private void ParseRulesElement(ILoggingConfigurationElement rulesElement, IList<LoggingRule> rulesCollection)
		{
			InternalLogger.Trace("ParseRulesElement");
			rulesElement.AssertName("rules");
			foreach (ILoggingConfigurationElement child in rulesElement.Children)
			{
				LoggingRule loggingRule = ParseRuleElement(child);
				if (loggingRule != null)
				{
					lock (rulesCollection)
					{
						rulesCollection.Add(loggingRule);
					}
				}
			}
		}

		private LogLevel LogLevelFromString(string text)
		{
			return LogLevel.FromString(ExpandSimpleVariables(text).Trim());
		}

		private LoggingRule ParseRuleElement(ILoggingConfigurationElement loggerElement)
		{
			string minLevel = null;
			string maxLevel = null;
			string enableLevels = null;
			string text = null;
			string text2 = null;
			bool flag = true;
			bool flag2 = false;
			string text3 = null;
			foreach (KeyValuePair<string, string> value in loggerElement.Values)
			{
				switch (value.Key?.Trim().ToUpperInvariant())
				{
				case "NAME":
					if (loggerElement.MatchesName("logger"))
					{
						text2 = value.Value;
					}
					else
					{
						text = value.Value;
					}
					break;
				case "RULENAME":
					text = value.Value;
					break;
				case "LOGGER":
					text2 = value.Value;
					break;
				case "ENABLED":
					flag = ParseBooleanValue(value.Key, value.Value, defaultValue: true);
					break;
				case "APPENDTO":
					text3 = value.Value;
					break;
				case "WRITETO":
					text3 = value.Value;
					break;
				case "FINAL":
					flag2 = ParseBooleanValue(value.Key, value.Value, defaultValue: false);
					break;
				case "LEVEL":
					enableLevels = value.Value;
					break;
				case "LEVELS":
					enableLevels = (StringHelpers.IsNullOrWhiteSpace(value.Value) ? "," : value.Value);
					break;
				case "MINLEVEL":
					minLevel = value.Value;
					break;
				case "MAXLEVEL":
					maxLevel = value.Value;
					break;
				default:
					InternalLogger.Debug("Skipping unknown property {0} for element {1} in section {2}", value.Key, loggerElement.Name, "rules");
					break;
				}
			}
			if (string.IsNullOrEmpty(text) && string.IsNullOrEmpty(text2) && string.IsNullOrEmpty(text3) && !flag2)
			{
				InternalLogger.Debug("Logging rule without name or filter or targets is ignored");
				return null;
			}
			text2 = text2 ?? "*";
			if (!flag)
			{
				InternalLogger.Debug("Logging rule {0} with filter `{1}` is disabled", text, text2);
				return null;
			}
			LoggingRule loggingRule = new LoggingRule(text)
			{
				LoggerNamePattern = text2,
				Final = flag2
			};
			EnableLevelsForRule(loggingRule, enableLevels, minLevel, maxLevel);
			ParseLoggingRuleTargets(text3, loggingRule);
			ParseLoggingRuleChildren(loggerElement, loggingRule);
			return loggingRule;
		}

		private void EnableLevelsForRule(LoggingRule rule, string enableLevels, string minLevel, string maxLevel)
		{
			if (enableLevels != null)
			{
				enableLevels = ExpandSimpleVariables(enableLevels);
				if (enableLevels.IndexOf('{') >= 0)
				{
					SimpleLayout simpleLayout = ParseLevelLayout(enableLevels);
					rule.EnableLoggingForLevels(simpleLayout);
					return;
				}
				if (enableLevels.IndexOf(',') >= 0)
				{
					foreach (LogLevel item in ParseLevels(enableLevels))
					{
						rule.EnableLoggingForLevel(item);
					}
					return;
				}
				rule.EnableLoggingForLevel(LogLevelFromString(enableLevels));
			}
			else
			{
				minLevel = ((minLevel != null) ? ExpandSimpleVariables(minLevel) : minLevel);
				maxLevel = ((maxLevel != null) ? ExpandSimpleVariables(maxLevel) : maxLevel);
				if ((minLevel != null && minLevel.IndexOf('{') >= 0) || (maxLevel != null && maxLevel.IndexOf('{') >= 0))
				{
					SimpleLayout minLevel2 = ParseLevelLayout(minLevel);
					SimpleLayout maxLevel2 = ParseLevelLayout(maxLevel);
					rule.EnableLoggingForRange(minLevel2, maxLevel2);
				}
				else
				{
					LogLevel minLevel3 = ((minLevel != null) ? LogLevelFromString(minLevel) : LogLevel.MinLevel);
					LogLevel maxLevel3 = ((maxLevel != null) ? LogLevelFromString(maxLevel) : LogLevel.MaxLevel);
					rule.SetLoggingLevels(minLevel3, maxLevel3);
				}
			}
		}

		private SimpleLayout ParseLevelLayout(string levelLayout)
		{
			SimpleLayout obj = ((!StringHelpers.IsNullOrWhiteSpace(levelLayout)) ? new SimpleLayout(levelLayout, _configurationItemFactory) : null);
			if (obj != null)
			{
				obj.Initialize(this);
				return obj;
			}
			return obj;
		}

		private IEnumerable<LogLevel> ParseLevels(string enableLevels)
		{
			return enableLevels.SplitAndTrimTokens(',').Select(LogLevelFromString);
		}

		private void ParseLoggingRuleTargets(string writeTargets, LoggingRule rule)
		{
			if (string.IsNullOrEmpty(writeTargets))
			{
				return;
			}
			string[] array = writeTargets.SplitAndTrimTokens(',');
			foreach (string text in array)
			{
				Target target = FindTargetByName(text);
				if (target != null)
				{
					rule.Targets.Add(target);
					continue;
				}
				NLogConfigurationException ex = new NLogConfigurationException("Target '" + text + "' not found for logging rule: " + (string.IsNullOrEmpty(rule.RuleName) ? rule.LoggerNamePattern : rule.RuleName) + ".");
				if (MustThrowConfigException(ex))
				{
					throw ex;
				}
			}
		}

		private void ParseLoggingRuleChildren(ILoggingConfigurationElement loggerElement, LoggingRule rule)
		{
			foreach (ILoggingConfigurationElement child in loggerElement.Children)
			{
				LoggingRule loggingRule = null;
				if (child.MatchesName("filters"))
				{
					ParseFilters(rule, child);
				}
				else if (child.MatchesName("logger") && loggerElement.MatchesName("logger"))
				{
					loggingRule = ParseRuleElement(child);
				}
				else if (child.MatchesName("rule") && loggerElement.MatchesName("rule"))
				{
					loggingRule = ParseRuleElement(child);
				}
				else
				{
					InternalLogger.Debug("Skipping unknown child {0} for element {1} in section {2}", child.Name, loggerElement.Name, "rules");
				}
				if (loggingRule != null)
				{
					lock (rule.ChildRules)
					{
						rule.ChildRules.Add(loggingRule);
					}
				}
			}
		}

		private void ParseFilters(LoggingRule rule, ILoggingConfigurationElement filtersElement)
		{
			filtersElement.AssertName("filters");
			string optionalValue = filtersElement.GetOptionalValue("defaultAction", null);
			if (optionalValue != null)
			{
				PropertyHelper.SetPropertyFromString(rule, "DefaultFilterResult", optionalValue, _configurationItemFactory);
			}
			foreach (ILoggingConfigurationElement child in filtersElement.Children)
			{
				string name = child.Name;
				Filter filter = _configurationItemFactory.Filters.CreateInstance(name);
				ConfigureObjectFromAttributes(filter, child, ignoreType: false);
				rule.Filters.Add(filter);
			}
		}

		private void ParseTargetsElement(ILoggingConfigurationElement targetsElement)
		{
			targetsElement.AssertName("targets", "appenders");
			KeyValuePair<string, string> keyValuePair = targetsElement.Values.FirstOrDefault((KeyValuePair<string, string> configItem) => MatchesName(configItem.Key, "async"));
			bool flag = !string.IsNullOrEmpty(keyValuePair.Value) && ParseBooleanValue(keyValuePair.Key, keyValuePair.Value, defaultValue: false);
			ILoggingConfigurationElement loggingConfigurationElement = null;
			Dictionary<string, ILoggingConfigurationElement> typeNameToDefaultTargetParameters = new Dictionary<string, ILoggingConfigurationElement>(StringComparer.OrdinalIgnoreCase);
			foreach (ILoggingConfigurationElement child in targetsElement.Children)
			{
				string configItemTypeAttribute = child.GetConfigItemTypeAttribute();
				string optionalValue = child.GetOptionalValue("name", null);
				Target target = null;
				optionalValue = (string.IsNullOrEmpty(optionalValue) ? child.Name : (child.Name + "(Name=" + optionalValue + ")"));
				switch (child.Name?.Trim().ToUpperInvariant())
				{
				case "DEFAULT-WRAPPER":
					if (AssertNonEmptyValue(configItemTypeAttribute, "type", optionalValue, targetsElement.Name))
					{
						loggingConfigurationElement = child;
					}
					break;
				case "DEFAULT-TARGET-PARAMETERS":
					if (AssertNonEmptyValue(configItemTypeAttribute, "type", optionalValue, targetsElement.Name))
					{
						ParseDefaultTargetParameters(child, configItemTypeAttribute, typeNameToDefaultTargetParameters);
					}
					break;
				case "TARGET":
				case "APPENDER":
				case "WRAPPER":
				case "WRAPPER-TARGET":
				case "COMPOUND-TARGET":
					if (AssertNonEmptyValue(configItemTypeAttribute, "type", optionalValue, targetsElement.Name))
					{
						target = CreateTargetType(configItemTypeAttribute);
						if (target != null)
						{
							ParseTargetElement(target, child, typeNameToDefaultTargetParameters);
						}
					}
					break;
				default:
					InternalLogger.Debug("Skipping unknown element {0} in section {1}", optionalValue, targetsElement.Name);
					break;
				}
				if (target != null)
				{
					if (flag)
					{
						target = WrapWithAsyncTargetWrapper(target);
					}
					if (loggingConfigurationElement != null)
					{
						target = WrapWithDefaultWrapper(target, loggingConfigurationElement);
					}
					InternalLogger.Info("Adding target {0}(Name={1})", target.GetType().Name, target.Name);
					AddTarget(target.Name, target);
				}
			}
		}

		private Target CreateTargetType(string targetTypeName)
		{
			Target target = null;
			try
			{
				target = _configurationItemFactory.Targets.CreateInstance(targetTypeName);
				if (target == null)
				{
					throw new NLogConfigurationException("Factory returned null for target type: " + targetTypeName);
				}
			}
			catch (Exception ex)
			{
				if (ex.MustBeRethrownImmediately())
				{
					throw;
				}
				NLogConfigurationException ex2 = new NLogConfigurationException("Failed to create target type: " + targetTypeName, ex);
				if (MustThrowConfigException(ex2))
				{
					throw ex2;
				}
			}
			return target;
		}

		private void ParseDefaultTargetParameters(ILoggingConfigurationElement defaultTargetElement, string targetType, Dictionary<string, ILoggingConfigurationElement> typeNameToDefaultTargetParameters)
		{
			typeNameToDefaultTargetParameters[targetType.Trim()] = defaultTargetElement;
		}

		private void ParseTargetElement(Target target, ILoggingConfigurationElement targetElement, Dictionary<string, ILoggingConfigurationElement> typeNameToDefaultTargetParameters = null)
		{
			string configItemTypeAttribute = targetElement.GetConfigItemTypeAttribute("targets");
			if (typeNameToDefaultTargetParameters != null && typeNameToDefaultTargetParameters.TryGetValue(configItemTypeAttribute, out var value))
			{
				ParseTargetElement(target, value);
			}
			CompoundTargetBase compoundTargetBase = target as CompoundTargetBase;
			WrapperTargetBase wrapperTargetBase = target as WrapperTargetBase;
			ConfigureObjectFromAttributes(target, targetElement, ignoreType: true);
			foreach (ILoggingConfigurationElement child in targetElement.Children)
			{
				string name = child.Name;
				if ((compoundTargetBase == null || !ParseCompoundTarget(typeNameToDefaultTargetParameters, name, child, compoundTargetBase, null)) && (wrapperTargetBase == null || !ParseTargetWrapper(typeNameToDefaultTargetParameters, name, child, wrapperTargetBase)))
				{
					SetPropertyFromElement(target, child, targetElement);
				}
			}
		}

		private bool ParseTargetWrapper(Dictionary<string, ILoggingConfigurationElement> typeNameToDefaultTargetParameters, string name, ILoggingConfigurationElement childElement, WrapperTargetBase wrapper)
		{
			if (IsTargetRefElement(name))
			{
				string requiredValue = childElement.GetRequiredValue("name", GetName(wrapper));
				Target target = FindTargetByName(requiredValue);
				if (target == null)
				{
					NLogConfigurationException ex = new NLogConfigurationException("Referenced target '" + requiredValue + "' not found.");
					if (MustThrowConfigException(ex))
					{
						throw ex;
					}
				}
				wrapper.WrappedTarget = target;
				return true;
			}
			if (IsTargetElement(name))
			{
				string configItemTypeAttribute = childElement.GetConfigItemTypeAttribute(GetName(wrapper));
				Target target2 = CreateTargetType(configItemTypeAttribute);
				if (target2 != null)
				{
					ParseTargetElement(target2, childElement, typeNameToDefaultTargetParameters);
					if (target2.Name != null)
					{
						AddTarget(target2.Name, target2);
					}
					if (wrapper.WrappedTarget != null)
					{
						NLogConfigurationException ex2 = new NLogConfigurationException("Failed to assign wrapped target " + configItemTypeAttribute + ", because target " + wrapper.Name + " already has one.");
						if (MustThrowConfigException(ex2))
						{
							throw ex2;
						}
					}
				}
				wrapper.WrappedTarget = target2;
				return true;
			}
			return false;
		}

		private bool ParseCompoundTarget(Dictionary<string, ILoggingConfigurationElement> typeNameToDefaultTargetParameters, string name, ILoggingConfigurationElement childElement, CompoundTargetBase compound, string targetName)
		{
			if (MatchesName(name, "targets") || MatchesName(name, "appenders"))
			{
				foreach (ILoggingConfigurationElement child in childElement.Children)
				{
					ParseCompoundTarget(typeNameToDefaultTargetParameters, child.Name, child, compound, null);
				}
				return true;
			}
			if (IsTargetRefElement(name))
			{
				targetName = childElement.GetRequiredValue("name", GetName(compound));
				Target target = FindTargetByName(targetName);
				if (target == null)
				{
					throw new NLogConfigurationException("Referenced target '" + targetName + "' not found.");
				}
				compound.Targets.Add(target);
				return true;
			}
			if (IsTargetElement(name))
			{
				string configItemTypeAttribute = childElement.GetConfigItemTypeAttribute(GetName(compound));
				Target target2 = CreateTargetType(configItemTypeAttribute);
				if (target2 != null)
				{
					if (targetName != null)
					{
						target2.Name = targetName;
					}
					ParseTargetElement(target2, childElement, typeNameToDefaultTargetParameters);
					if (target2.Name != null)
					{
						AddTarget(target2.Name, target2);
					}
					compound.Targets.Add(target2);
				}
				return true;
			}
			return false;
		}

		private void ConfigureObjectFromAttributes(object targetObject, ILoggingConfigurationElement element, bool ignoreType)
		{
			foreach (KeyValuePair<string, string> value2 in element.Values)
			{
				string key = value2.Key;
				string value = value2.Value;
				if (!ignoreType || !MatchesName(key, "type"))
				{
					try
					{
						PropertyHelper.SetPropertyFromString(targetObject, key, ExpandSimpleVariables(value), _configurationItemFactory);
					}
					catch (Exception ex)
					{
						InternalLogger.Warn(ex, "Error when setting '{0}' on attibute '{1}'", value, key);
						throw;
					}
				}
			}
		}

		private void SetPropertyFromElement(object o, ILoggingConfigurationElement childElement, ILoggingConfigurationElement parentElement)
		{
			if (!PropertyHelper.TryGetPropertyInfo(o, childElement.Name, out var result))
			{
				InternalLogger.Debug("Skipping unknown element {0} in section {1}. Not matching any property on {2} - {3}", childElement.Name, parentElement.Name, o, o?.GetType());
			}
			else if (!AddArrayItemFromElement(o, result, childElement) && !SetLayoutFromElement(o, result, childElement) && !SetFilterFromElement(o, result, childElement))
			{
				SetItemFromElement(o, result, childElement);
			}
		}

		private bool AddArrayItemFromElement(object o, PropertyInfo propInfo, ILoggingConfigurationElement element)
		{
			Type arrayItemType = PropertyHelper.GetArrayItemType(propInfo);
			if (arrayItemType != null)
			{
				IList list = (IList)propInfo.GetValue(o, null);
				if (string.Equals(propInfo.Name, element.Name, StringComparison.OrdinalIgnoreCase))
				{
					List<ILoggingConfigurationElement> list2 = element.Children.ToList();
					if (list2.Count > 0)
					{
						foreach (ILoggingConfigurationElement item in list2)
						{
							list.Add(ParseArrayItemFromElement(arrayItemType, item));
						}
						return true;
					}
				}
				object value = ParseArrayItemFromElement(arrayItemType, element);
				list.Add(value);
				return true;
			}
			return false;
		}

		private object ParseArrayItemFromElement(Type elementType, ILoggingConfigurationElement element)
		{
			object obj = TryCreateLayoutInstance(element, elementType);
			if (obj == null)
			{
				obj = FactoryHelper.CreateInstance(elementType);
			}
			ConfigureObjectFromAttributes(obj, element, ignoreType: true);
			ConfigureObjectFromElement(obj, element);
			return obj;
		}

		private bool SetLayoutFromElement(object o, PropertyInfo propInfo, ILoggingConfigurationElement element)
		{
			Layout layout = TryCreateLayoutInstance(element, propInfo.PropertyType);
			if (layout != null)
			{
				SetItemOnProperty(o, propInfo, element, layout);
				return true;
			}
			return false;
		}

		private bool SetFilterFromElement(object o, PropertyInfo propInfo, ILoggingConfigurationElement element)
		{
			Type propertyType = propInfo.PropertyType;
			Filter filter = TryCreateFilterInstance(element, propertyType);
			if (filter != null)
			{
				SetItemOnProperty(o, propInfo, element, filter);
				return true;
			}
			return false;
		}

		private Layout TryCreateLayoutInstance(ILoggingConfigurationElement element, Type type)
		{
			return TryCreateInstance(element, type, _configurationItemFactory.Layouts);
		}

		private Filter TryCreateFilterInstance(ILoggingConfigurationElement element, Type type)
		{
			return TryCreateInstance(element, type, _configurationItemFactory.Filters);
		}

		private T TryCreateInstance<T>(ILoggingConfigurationElement element, Type type, INamedItemFactory<T, Type> factory) where T : class
		{
			if (!IsAssignableFrom<T>(type))
			{
				return null;
			}
			string configItemTypeAttribute = element.GetConfigItemTypeAttribute();
			if (configItemTypeAttribute == null)
			{
				return null;
			}
			return factory.CreateInstance(ExpandSimpleVariables(configItemTypeAttribute));
		}

		private static bool IsAssignableFrom<T>(Type type)
		{
			return typeof(T).IsAssignableFrom(type);
		}

		private void SetItemOnProperty(object o, PropertyInfo propInfo, ILoggingConfigurationElement element, object properyValue)
		{
			ConfigureObjectFromAttributes(properyValue, element, ignoreType: true);
			ConfigureObjectFromElement(properyValue, element);
			propInfo.SetValue(o, properyValue, null);
		}

		private void SetItemFromElement(object o, PropertyInfo propInfo, ILoggingConfigurationElement element)
		{
			object value = propInfo.GetValue(o, null);
			ConfigureObjectFromAttributes(value, element, ignoreType: true);
			ConfigureObjectFromElement(value, element);
		}

		private void ConfigureObjectFromElement(object targetObject, ILoggingConfigurationElement element)
		{
			foreach (ILoggingConfigurationElement child in element.Children)
			{
				SetPropertyFromElement(targetObject, child, element);
			}
		}

		private static Target WrapWithAsyncTargetWrapper(Target target)
		{
			if (target is AsyncTaskTarget)
			{
				InternalLogger.Debug("Skip wrapping target '{0}' with AsyncTargetWrapper", target.Name);
				return target;
			}
			AsyncTargetWrapper asyncTargetWrapper = new AsyncTargetWrapper();
			asyncTargetWrapper.WrappedTarget = target;
			asyncTargetWrapper.Name = target.Name;
			target.Name += "_wrapped";
			InternalLogger.Debug("Wrapping target '{0}' with AsyncTargetWrapper and renaming to '{1}", asyncTargetWrapper.Name, target.Name);
			target = asyncTargetWrapper;
			return target;
		}

		private Target WrapWithDefaultWrapper(Target target, ILoggingConfigurationElement defaultParameters)
		{
			string configItemTypeAttribute = defaultParameters.GetConfigItemTypeAttribute("targets");
			Target target2 = CreateTargetType(configItemTypeAttribute);
			WrapperTargetBase wrapperTargetBase = target2 as WrapperTargetBase;
			if (wrapperTargetBase == null)
			{
				throw new NLogConfigurationException("Target type specified on <default-wrapper /> is not a wrapper.");
			}
			ParseTargetElement(target2, defaultParameters);
			while (wrapperTargetBase.WrappedTarget != null)
			{
				wrapperTargetBase = wrapperTargetBase.WrappedTarget as WrapperTargetBase;
				if (wrapperTargetBase == null)
				{
					throw new NLogConfigurationException("Child target type specified on <default-wrapper /> is not a wrapper.");
				}
			}
			if (target is AsyncTaskTarget && target2 is AsyncTargetWrapper && target2 == wrapperTargetBase)
			{
				InternalLogger.Debug("Skip wrapping target '{0}' with AsyncTargetWrapper", target.Name);
				return target;
			}
			wrapperTargetBase.WrappedTarget = target;
			target2.Name = target.Name;
			target.Name += "_wrapped";
			InternalLogger.Debug("Wrapping target '{0}' with '{1}' and renaming to '{2}", target2.Name, target2.GetType().Name, target.Name);
			return target2;
		}

		private bool ParseBooleanValue(string propertyName, string value, bool defaultValue)
		{
			try
			{
				return Convert.ToBoolean(value?.Trim(), CultureInfo.InvariantCulture);
			}
			catch (Exception ex)
			{
				if (ex.MustBeRethrownImmediately())
				{
					throw;
				}
				NLogConfigurationException ex2 = new NLogConfigurationException(ex, $"'{propertyName}' hasn't a valid boolean value '{value}'. {defaultValue} will be used");
				if (MustThrowConfigException(ex2))
				{
					throw ex2;
				}
				return defaultValue;
			}
		}

		private bool? ParseNullableBooleanValue(string propertyName, string value, bool defaultValue)
		{
			if (!StringHelpers.IsNullOrWhiteSpace(value))
			{
				return ParseBooleanValue(propertyName, value, defaultValue);
			}
			return null;
		}

		private bool MustThrowConfigException(NLogConfigurationException configException)
		{
			if (configException.MustBeRethrown())
			{
				return true;
			}
			if (base.LogFactory.ThrowConfigExceptions ?? base.LogFactory.ThrowExceptions)
			{
				return true;
			}
			return false;
		}

		private static bool MatchesName(string key, string expectedKey)
		{
			return string.Equals(key?.Trim(), expectedKey, StringComparison.OrdinalIgnoreCase);
		}

		private static bool IsTargetElement(string name)
		{
			if (!name.Equals("target", StringComparison.OrdinalIgnoreCase) && !name.Equals("wrapper", StringComparison.OrdinalIgnoreCase) && !name.Equals("wrapper-target", StringComparison.OrdinalIgnoreCase))
			{
				return name.Equals("compound-target", StringComparison.OrdinalIgnoreCase);
			}
			return true;
		}

		private static bool IsTargetRefElement(string name)
		{
			if (!name.Equals("target-ref", StringComparison.OrdinalIgnoreCase) && !name.Equals("wrapper-target-ref", StringComparison.OrdinalIgnoreCase))
			{
				return name.Equals("compound-target-ref", StringComparison.OrdinalIgnoreCase);
			}
			return true;
		}

		private static string GetName(Target target)
		{
			if (!string.IsNullOrEmpty(target.Name))
			{
				return target.Name;
			}
			return target.GetType().Name;
		}
	}
	[NLogConfigurationItem]
	public class LoggingRule
	{
		private ILoggingRuleLevelFilter _logLevelFilter = LoggingRuleLevelFilter.Off;

		private LoggerNameMatcher _loggerNameMatcher = LoggerNameMatcher.Create(null);

		public string RuleName { get; }

		public IList<Target> Targets { get; }

		public IList<LoggingRule> ChildRules { get; }

		public IList<Filter> Filters { get; }

		public bool Final { get; set; }

		public string LoggerNamePattern
		{
			get
			{
				return _loggerNameMatcher.Pattern;
			}
			set
			{
				_loggerNameMatcher = LoggerNameMatcher.Create(value);
			}
		}

		[NLogConfigurationIgnoreProperty]
		public ReadOnlyCollection<LogLevel> Levels
		{
			get
			{
				List<LogLevel> list = new List<LogLevel>();
				bool[] logLevels = _logLevelFilter.LogLevels;
				for (int i = LogLevel.MinLevel.Ordinal; i <= LogLevel.MaxLevel.Ordinal; i++)
				{
					if (logLevels[i])
					{
						list.Add(LogLevel.FromOrdinal(i));
					}
				}
				return list.AsReadOnly();
			}
		}

		public FilterResult DefaultFilterResult { get; set; }

		public LoggingRule()
			: this(null)
		{
		}

		public LoggingRule(string ruleName)
		{
			RuleName = ruleName;
			Filters = new List<Filter>();
			ChildRules = new List<LoggingRule>();
			Targets = new List<Target>();
		}

		public LoggingRule(string loggerNamePattern, LogLevel minLevel, LogLevel maxLevel, Target target)
			: this()
		{
			LoggerNamePattern = loggerNamePattern;
			Targets.Add(target);
			EnableLoggingForLevels(minLevel, maxLevel);
		}

		public LoggingRule(string loggerNamePattern, LogLevel minLevel, Target target)
			: this()
		{
			LoggerNamePattern = loggerNamePattern;
			Targets.Add(target);
			EnableLoggingForLevels(minLevel, LogLevel.MaxLevel);
		}

		public LoggingRule(string loggerNamePattern, Target target)
			: this()
		{
			LoggerNamePattern = loggerNamePattern;
			Targets.Add(target);
		}

		internal List<LoggingRule> GetChildRulesThreadSafe()
		{
			lock (ChildRules)
			{
				return ChildRules.ToList();
			}
		}

		internal List<Target> GetTargetsThreadSafe()
		{
			lock (Targets)
			{
				return Targets.ToList();
			}
		}

		internal bool RemoveTargetThreadSafe(Target target)
		{
			lock (Targets)
			{
				return Targets.Remove(target);
			}
		}

		public void EnableLoggingForLevel(LogLevel level)
		{
			if (!(level == LogLevel.Off))
			{
				_logLevelFilter = _logLevelFilter.GetSimpleFilterForUpdate().SetLoggingLevels(level, level, enable: true);
			}
		}

		public void EnableLoggingForLevels(LogLevel minLevel, LogLevel maxLevel)
		{
			_logLevelFilter = _logLevelFilter.GetSimpleFilterForUpdate().SetLoggingLevels(minLevel, maxLevel, enable: true);
		}

		internal void EnableLoggingForLevels(SimpleLayout simpleLayout)
		{
			_logLevelFilter = new DynamicLogLevelFilter(this, simpleLayout);
		}

		internal void EnableLoggingForRange(SimpleLayout minLevel, SimpleLayout maxLevel)
		{
			_logLevelFilter = new DynamicRangeLevelFilter(this, minLevel, maxLevel);
		}

		public void DisableLoggingForLevel(LogLevel level)
		{
			if (!(level == LogLevel.Off))
			{
				_logLevelFilter = _logLevelFilter.GetSimpleFilterForUpdate().SetLoggingLevels(level, level, enable: false);
			}
		}

		public void DisableLoggingForLevels(LogLevel minLevel, LogLevel maxLevel)
		{
			_logLevelFilter = _logLevelFilter.GetSimpleFilterForUpdate().SetLoggingLevels(minLevel, maxLevel, enable: false);
		}

		public void SetLoggingLevels(LogLevel minLevel, LogLevel maxLevel)
		{
			_logLevelFilter = _logLevelFilter.GetSimpleFilterForUpdate().SetLoggingLevels(LogLevel.MinLevel, LogLevel.MaxLevel, enable: false).SetLoggingLevels(minLevel, maxLevel, enable: true);
		}

		public override string ToString()
		{
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append(_loggerNameMatcher.ToString());
			stringBuilder.Append(" levels: [ ");
			bool[] logLevels = _logLevelFilter.LogLevels;
			for (int i = 0; i < logLevels.Length; i++)
			{
				if (logLevels[i])
				{
					stringBuilder.AppendFormat(CultureInfo.InvariantCulture, "{0} ", LogLevel.FromOrdinal(i).ToString());
				}
			}
			stringBuilder.Append("] appendTo: [ ");
			foreach (Target item in GetTargetsThreadSafe())
			{
				stringBuilder.AppendFormat(CultureInfo.InvariantCulture, "{0} ", item.Name);
			}
			stringBuilder.Append("]");
			return stringBuilder.ToString();
		}

		public bool IsLoggingEnabledForLevel(LogLevel level)
		{
			if (level == LogLevel.Off)
			{
				return false;
			}
			return _logLevelFilter.LogLevels[level.Ordinal];
		}

		public bool NameMatches(string loggerName)
		{
			return _loggerNameMatcher.NameMatches(loggerName);
		}
	}
	internal class LoggingRuleLevelFilter : ILoggingRuleLevelFilter
	{
		public static readonly ILoggingRuleLevelFilter Off = new LoggingRuleLevelFilter();

		public bool[] LogLevels { get; }

		public LoggingRuleLevelFilter(bool[] logLevels = null)
		{
			LogLevels = new bool[LogLevel.MaxLevel.Ordinal + 1];
			if (logLevels != null)
			{
				for (int i = 0; i < Math.Min(logLevels.Length, LogLevels.Length); i++)
				{
					LogLevels[i] = logLevels[i];
				}
			}
		}

		public LoggingRuleLevelFilter GetSimpleFilterForUpdate()
		{
			if (LogLevels != Off.LogLevels)
			{
				return this;
			}
			return new LoggingRuleLevelFilter();
		}

		public LoggingRuleLevelFilter SetLoggingLevels(LogLevel minLevel, LogLevel maxLevel, bool enable)
		{
			for (int i = minLevel.Ordinal; i <= Math.Min(maxLevel.Ordinal, LogLevels.Length - 1); i++)
			{
				LogLevels[i] = enable;
			}
			return this;
		}
	}
	internal class MethodFactory : INamedItemFactory<MethodInfo, MethodInfo>, INamedItemFactory<ReflectionHelpers.LateBoundMethod, MethodInfo>, IFactory
	{
		private readonly Dictionary<string, MethodInfo> _nameToMethodInfo = new Dictionary<string, MethodInfo>();

		private readonly Dictionary<string, ReflectionHelpers.LateBoundMethod> _nameToLateBoundMethod = new Dictionary<string, ReflectionHelpers.LateBoundMethod>();

		private readonly Func<Type, IList<KeyValuePair<string, MethodInfo>>> _methodExtractor;

		public MethodFactory(Func<Type, IList<KeyValuePair<string, MethodInfo>>> methodExtractor)
		{
			_methodExtractor = methodExtractor;
		}

		public void ScanTypes(Type[] types, string prefix)
		{
			foreach (Type type in types)
			{
				try
				{
					if (type.IsClass() || type.IsAbstract())
					{
						RegisterType(type, prefix);
					}
				}
				catch (Exception ex)
				{
					InternalLogger.Error(ex, "Failed to add type '{0}'.", type.FullName);
					if (ex.MustBeRethrown())
					{
						throw;
					}
				}
			}
		}

		public void RegisterType(Type type, string itemNamePrefix)
		{
			IList<KeyValuePair<string, MethodInfo>> list = _methodExtractor(type);
			if (list != null && list.Count > 0)
			{
				for (int i = 0; i < list.Count; i++)
				{
					RegisterDefinition(itemNamePrefix + list[i].Key, list[i].Value);
				}
			}
		}

		public static IList<KeyValuePair<string, MethodInfo>> ExtractClassMethods<TClassAttributeType, TMethodAttributeType>(Type type) where TClassAttributeType : Attribute where TMethodAttributeType : NameBaseAttribute
		{
			if (!type.IsDefined(typeof(TClassAttributeType), inherit: false))
			{
				return ArrayHelper.Empty<KeyValuePair<string, MethodInfo>>();
			}
			List<KeyValuePair<string, MethodInfo>> list = new List<KeyValuePair<string, MethodInfo>>();
			MethodInfo[] methods = type.GetMethods();
			foreach (MethodInfo methodInfo in methods)
			{
				TMethodAttributeType[] array = (TMethodAttributeType[])methodInfo.GetCustomAttributes(typeof(TMethodAttributeType), inherit: false);
				foreach (TMethodAttributeType val in array)
				{
					list.Add(new KeyValuePair<string, MethodInfo>(val.Name, methodInfo));
				}
			}
			return list;
		}

		public void Clear()
		{
			_nameToMethodInfo.Clear();
			lock (_nameToLateBoundMethod)
			{
				_nameToLateBoundMethod.Clear();
			}
		}

		public void RegisterDefinition(string itemName, MethodInfo itemDefinition)
		{
			_nameToMethodInfo[itemName] = itemDefinition;
			lock (_nameToLateBoundMethod)
			{
				_nameToLateBoundMethod.Remove(itemName);
			}
		}

		internal void RegisterDefinition(string itemName, MethodInfo itemDefinition, ReflectionHelpers.LateBoundMethod lateBoundMethod)
		{
			_nameToMethodInfo[itemName] = itemDefinition;
			lock (_nameToLateBoundMethod)
			{
				_nameToLateBoundMethod[itemName] = lateBoundMethod;
			}
		}

		public bool TryCreateInstance(string itemName, out MethodInfo result)
		{
			return _nameToMethodInfo.TryGetValue(itemName, out result);
		}

		public bool TryCreateInstance(string itemName, out ReflectionHelpers.LateBoundMethod result)
		{
			lock (_nameToLateBoundMethod)
			{
				if (_nameToLateBoundMethod.TryGetValue(itemName, out result))
				{
					return true;
				}
			}
			if (_nameToMethodInfo.TryGetValue(itemName, out var value))
			{
				result = ReflectionHelpers.CreateLateBoundMethod(value);
				lock (_nameToLateBoundMethod)
				{
					_nameToLateBoundMethod[itemName] = result;
				}
				return true;
			}
			return false;
		}

		MethodInfo INamedItemFactory<MethodInfo, MethodInfo>.CreateInstance(string itemName)
		{
			if (TryCreateInstance(itemName, out MethodInfo result))
			{
				return result;
			}
			throw new NLogConfigurationException("Unknown function: '" + itemName + "'");
		}

		public ReflectionHelpers.LateBoundMethod CreateInstance(string itemName)
		{
			if (TryCreateInstance(itemName, out ReflectionHelpers.LateBoundMethod result))
			{
				return result;
			}
			throw new NLogConfigurationException("Unknown function: '" + itemName + "'");
		}

		public bool TryGetDefinition(string itemName, out MethodInfo result)
		{
			return _nameToMethodInfo.TryGetValue(itemName, out result);
		}
	}
