	internal class NLogXmlElement : ILoggingConfigurationElement
	{
		private readonly List<string> _parsingErrors;

		public string LocalName { get; private set; }

		public Dictionary<string, string> AttributeValues { get; }

		public IList<NLogXmlElement> Children { get; }

		public string Value { get; private set; }

		public string Name => LocalName;

		public IEnumerable<KeyValuePair<string, string>> Values
		{
			get
			{
				for (int i = 0; i < Children.Count; i++)
				{
					if (SingleValueElement(Children[i]))
					{
						return (from item in Children
							where SingleValueElement(item)
							select new KeyValuePair<string, string>(item.Name, item.Value)).Concat(AttributeValues);
					}
				}
				return AttributeValues;
			}
		}

		IEnumerable<ILoggingConfigurationElement> ILoggingConfigurationElement.Children
		{
			get
			{
				for (int i = 0; i < Children.Count; i++)
				{
					if (!SingleValueElement(Children[i]))
					{
						return Children.Where((NLogXmlElement item) => !SingleValueElement(item)).Cast<ILoggingConfigurationElement>();
					}
				}
				return ArrayHelper.Empty<ILoggingConfigurationElement>();
			}
		}

		public NLogXmlElement(XmlReader reader)
			: this(reader, nestedElement: false)
		{
		}

		public NLogXmlElement(XmlReader reader, bool nestedElement)
			: this()
		{
			Parse(reader, nestedElement);
		}

		private NLogXmlElement()
		{
			AttributeValues = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
			Children = new List<NLogXmlElement>();
			_parsingErrors = new List<string>();
		}

		private static bool SingleValueElement(NLogXmlElement child)
		{
			if (child.Children.Count == 0 && child.AttributeValues.Count == 0)
			{
				return child.Value != null;
			}
			return false;
		}

		public IEnumerable<NLogXmlElement> Elements(string elementName)
		{
			List<NLogXmlElement> list = new List<NLogXmlElement>();
			foreach (NLogXmlElement child in Children)
			{
				if (child.LocalName.Equals(elementName, StringComparison.OrdinalIgnoreCase))
				{
					list.Add(child);
				}
			}
			return list;
		}

		public void AssertName(params string[] allowedNames)
		{
			foreach (string value in allowedNames)
			{
				if (LocalName.Equals(value, StringComparison.OrdinalIgnoreCase))
				{
					return;
				}
			}
			throw new InvalidOperationException("Assertion failed. Expected element name '" + string.Join("|", allowedNames) + "', actual: '" + LocalName + "'.");
		}

		public IEnumerable<string> GetParsingErrors()
		{
			foreach (string parsingError in _parsingErrors)
			{
				yield return parsingError;
			}
			foreach (NLogXmlElement child in Children)
			{
				foreach (string parsingError2 in child.GetParsingErrors())
				{
					yield return parsingError2;
				}
			}
		}

		private void Parse(XmlReader reader, bool nestedElement)
		{
			ParseAttributes(reader, nestedElement);
			LocalName = reader.LocalName;
			if (reader.IsEmptyElement)
			{
				return;
			}
			while (reader.Read() && reader.NodeType != XmlNodeType.EndElement)
			{
				if (reader.NodeType == XmlNodeType.CDATA || reader.NodeType == XmlNodeType.Text)
				{
					Value += reader.Value;
				}
				else if (reader.NodeType == XmlNodeType.Element)
				{
					Children.Add(new NLogXmlElement(reader, nestedElement: true));
				}
			}
		}

		private void ParseAttributes(XmlReader reader, bool nestedElement)
		{
			if (!reader.MoveToFirstAttribute())
			{
				return;
			}
			do
			{
				if (nestedElement || !IsSpecialXmlAttribute(reader))
				{
					if (!AttributeValues.ContainsKey(reader.LocalName))
					{
						AttributeValues.Add(reader.LocalName, reader.Value);
						continue;
					}
					string item = "Duplicate attribute detected. Attribute name: [" + reader.LocalName + "]. Duplicate value:[" + reader.Value + "], Current value:[" + AttributeValues[reader.LocalName] + "]";
					_parsingErrors.Add(item);
				}
			}
			while (reader.MoveToNextAttribute());
			reader.MoveToElement();
		}

		private static bool IsSpecialXmlAttribute(XmlReader reader)
		{
			string localName = reader.LocalName;
			if (localName != null && localName.Equals("xmlns", StringComparison.OrdinalIgnoreCase))
			{
				return true;
			}
			string prefix = reader.Prefix;
			if (prefix != null && prefix.Equals("xsi", StringComparison.OrdinalIgnoreCase))
			{
				return true;
			}
			string prefix2 = reader.Prefix;
			if (prefix2 != null && prefix2.Equals("xmlns", StringComparison.OrdinalIgnoreCase))
			{
				return true;
			}
			return false;
		}
	}
	internal class PropertyTypeConverter : IPropertyTypeConverter
	{
		public object Convert(object propertyValue, Type propertyType, string format, IFormatProvider formatProvider)
		{
			if (!NeedToConvert(propertyValue, propertyType))
			{
				return propertyValue;
			}
			Type underlyingType = Nullable.GetUnderlyingType(propertyType);
			Type type = underlyingType ?? propertyType;
			if (propertyValue is string text)
			{
				string text2;
				propertyValue = (text2 = text.Trim());
				if (underlyingType != null && StringHelpers.IsNullOrWhiteSpace(text2))
				{
					return null;
				}
				if (type == typeof(DateTime))
				{
					return ConvertDateTime(format, formatProvider, text2);
				}
				if (type == typeof(DateTimeOffset))
				{
					return ConvertDateTimeOffset(format, formatProvider, text2);
				}
				if (type == typeof(TimeSpan))
				{
					return ConvertTimeSpan(format, formatProvider, text2);
				}
				if (type == typeof(Guid))
				{
					return ConvertGuid(format, text2);
				}
			}
			else if (!string.IsNullOrEmpty(format) && propertyValue is IFormattable formattable)
			{
				propertyValue = formattable.ToString(format, formatProvider);
			}
			return System.Convert.ChangeType(propertyValue, type, formatProvider);
		}

		private static bool NeedToConvert(object propertyValue, Type propertyType)
		{
			if (propertyType != null && propertyValue != null && propertyValue.GetType() != propertyType)
			{
				return propertyType != typeof(object);
			}
			return false;
		}

		private static object ConvertGuid(string format, string propertyString)
		{
			return string.IsNullOrEmpty(format) ? Guid.Parse(propertyString) : Guid.ParseExact(propertyString, format);
		}

		private static object ConvertTimeSpan(string format, IFormatProvider formatProvider, string propertyString)
		{
			if (!string.IsNullOrEmpty(format))
			{
				return TimeSpan.ParseExact(propertyString, format, formatProvider);
			}
			return TimeSpan.Parse(propertyString, formatProvider);
		}

		private static object ConvertDateTimeOffset(string format, IFormatProvider formatProvider, string propertyString)
		{
			if (!string.IsNullOrEmpty(format))
			{
				return DateTimeOffset.ParseExact(propertyString, format, formatProvider);
			}
			return DateTimeOffset.Parse(propertyString, formatProvider);
		}

		private static object ConvertDateTime(string format, IFormatProvider formatProvider, string propertyString)
		{
			if (!string.IsNullOrEmpty(format))
			{
				return DateTime.ParseExact(propertyString, format, formatProvider);
			}
			return DateTime.Parse(propertyString, formatProvider);
		}
	}
