		public static void Fatal(Exception ex, [Localizable(false)] string message)
		{
			Write(ex, LogLevel.Fatal, message, null);
		}

		public static void Fatal(Exception ex, [Localizable(false)] Func<string> messageFunc)
		{
			if (IsFatalEnabled)
			{
				Write(ex, LogLevel.Fatal, messageFunc(), null);
			}
		}

		static InternalLogger()
		{
			LockObject = new object();
			Reset();
		}

		public static void Reset()
		{
			LogLevel = LogLevel.Info;
			LogToConsole = false;
			LogToConsoleError = false;
			LogFile = string.Empty;
			IncludeTimestamp = true;
			ExceptionThrowWhenWriting = false;
			LogWriter = null;
			InternalLogger.LogMessageReceived = null;
		}

		[StringFormatMethod("message")]
		public static void Log(LogLevel level, [Localizable(false)] string message, params object[] args)
		{
			Write(null, level, message, args);
		}

		public static void Log(LogLevel level, [Localizable(false)] string message)
		{
			Write(null, level, message, null);
		}

		public static void Log(LogLevel level, [Localizable(false)] Func<string> messageFunc)
		{
			if (IsLogLevelEnabled(level))
			{
				Write(null, level, messageFunc(), null);
			}
		}

		public static void Log(Exception ex, LogLevel level, [Localizable(false)] Func<string> messageFunc)
		{
			if (IsLogLevelEnabled(level))
			{
				Write(ex, level, messageFunc(), null);
			}
		}

		[StringFormatMethod("message")]
		public static void Log(Exception ex, LogLevel level, [Localizable(false)] string message, params object[] args)
		{
			Write(ex, level, message, args);
		}

		public static void Log(Exception ex, LogLevel level, [Localizable(false)] string message)
		{
			Write(ex, level, message, null);
		}

		private static void Write([CanBeNull] Exception ex, LogLevel level, string message, [CanBeNull] object[] args)
		{
			if (!IsLogLevelEnabled(level) || IsSeriousException(ex))
			{
				return;
			}
			bool flag = HasActiveLoggersWithLine();
			bool flag2 = HasEventListeners();
			if (!flag && !flag2)
			{
				return;
			}
			try
			{
				string message2 = CreateFullMessage(message, args);
				if (flag)
				{
					WriteLogLine(ex, level, message2);
				}
				if (flag2)
				{
					IInternalLoggerContext internalLoggerContext = ((args != null && args.Length != 0) ? (args[0] as IInternalLoggerContext) : null);
					InternalLogger.LogMessageReceived?.Invoke(null, new InternalLoggerMessageEventArgs(message2, level, ex, internalLoggerContext?.GetType(), internalLoggerContext?.Name));
					ex?.MarkAsLoggedToInternalLogger();
				}
			}
			catch (Exception exception)
			{
				ExceptionThrowWhenWriting = true;
				if (exception.MustBeRethrownImmediately())
				{
					throw;
				}
			}
		}

		private static void WriteLogLine(Exception ex, LogLevel level, string message)
		{
			try
			{
				string message2 = CreateLogLine(ex, level, message);
				WriteToLogFile(message2);
				WriteToTextWriter(message2);
				WriteToConsole(message2);
				WriteToErrorConsole(message2);
				ex?.MarkAsLoggedToInternalLogger();
			}
			catch (Exception exception)
			{
				ExceptionThrowWhenWriting = true;
				if (exception.MustBeRethrownImmediately())
				{
					throw;
				}
			}
		}

		private static string CreateLogLine([CanBeNull] Exception ex, LogLevel level, string fullMessage)
		{
			if (IncludeTimestamp)
			{
				return TimeSource.Current.Time.ToString("yyyy-MM-dd HH:mm:ss.ffff", CultureInfo.InvariantCulture) + " " + level.ToString() + " " + fullMessage + ((ex != null) ? " Exception: " : "") + (ex?.ToString() ?? "");
			}
			return level.ToString() + " " + fullMessage + ((ex != null) ? " Exception: " : "") + (ex?.ToString() ?? "");
		}

		private static string CreateFullMessage(string message, object[] args)
		{
			if (args != null)
			{
				return string.Format(CultureInfo.InvariantCulture, message, args);
			}
			return message;
		}

		private static bool IsSeriousException(Exception exception)
		{
			return exception?.MustBeRethrownImmediately() ?? false;
		}

		private static bool IsLogLevelEnabled(LogLevel logLevel)
		{
			if ((object)_logLevel != LogLevel.Off)
			{
				return logLevel >= _logLevel;
			}
			return false;
		}

		internal static bool HasActiveLoggers()
		{
			if (!HasActiveLoggersWithLine())
			{
				return HasEventListeners();
			}
			return true;
		}

		private static bool HasEventListeners()
		{
			return InternalLogger.LogMessageReceived != null;
		}

		internal static bool HasActiveLoggersWithLine()
		{
			if (string.IsNullOrEmpty(LogFile) && !LogToConsole && !LogToConsoleError)
			{
				return LogWriter != null;
			}
			return true;
		}

		private static void WriteToLogFile(string message)
		{
			string logFile = LogFile;
			if (string.IsNullOrEmpty(logFile))
			{
				return;
			}
			lock (LockObject)
			{
				using StreamWriter streamWriter = File.AppendText(logFile);
				streamWriter.WriteLine(message);
			}
		}

		private static void WriteToTextWriter(string message)
		{
			TextWriter logWriter = LogWriter;
			if (logWriter == null)
			{
				return;
			}
			lock (LockObject)
			{
				logWriter.WriteLine(message);
			}
		}

		private static void WriteToConsole(string message)
		{
			if (LogToConsole)
			{
				ConsoleTargetHelper.WriteLineThreadSafe(Console.Out, message);
			}
		}

		private static void WriteToErrorConsole(string message)
		{
			if (LogToConsoleError)
			{
				ConsoleTargetHelper.WriteLineThreadSafe(Console.Error, message);
			}
		}

		public static void LogAssemblyVersion(Assembly assembly)
		{
			try
			{
				Info(assembly.FullName);
			}
			catch (Exception ex)
			{
				Error(ex, "Error logging version of assembly {0}.", assembly.FullName);
			}
		}

		private static string GetAppSettings(string configName)
		{
			return null;
		}

		private static string GetSettingString(string configName, string envName)
		{
			try
			{
				string appSettings = GetAppSettings(configName);
				if (appSettings != null)
				{
					return appSettings;
				}
			}
			catch (Exception exception)
			{
				if (exception.MustBeRethrownImmediately())
				{
					throw;
				}
			}
			try
			{
				string safeEnvironmentVariable = EnvironmentHelper.GetSafeEnvironmentVariable(envName);
				if (!string.IsNullOrEmpty(safeEnvironmentVariable))
				{
					return safeEnvironmentVariable;
				}
			}
			catch (Exception exception2)
			{
				if (exception2.MustBeRethrownImmediately())
				{
					throw;
				}
			}
			return null;
		}

		private static LogLevel GetSetting(string configName, string envName, LogLevel defaultValue)
		{
			string settingString = GetSettingString(configName, envName);
			if (settingString == null)
			{
				return defaultValue;
			}
			try
			{
				return LogLevel.FromString(settingString);
			}
			catch (Exception exception)
			{
				if (exception.MustBeRethrownImmediately())
				{
					throw;
				}
				return defaultValue;
			}
		}

		private static T GetSetting<T>(string configName, string envName, T defaultValue)
		{
			string settingString = GetSettingString(configName, envName);
			if (settingString == null)
			{
				return defaultValue;
			}
			try
			{
				return (T)Convert.ChangeType(settingString, typeof(T), CultureInfo.InvariantCulture);
			}
			catch (Exception exception)
			{
				if (exception.MustBeRethrownImmediately())
				{
					throw;
				}
				return defaultValue;
			}
		}

		private static void CreateDirectoriesIfNeeded(string filename)
		{
			try
			{
				if (!(LogLevel == LogLevel.Off))
				{
					string directoryName = Path.GetDirectoryName(filename);
					if (!string.IsNullOrEmpty(directoryName))
					{
						Directory.CreateDirectory(directoryName);
					}
				}
			}
			catch (Exception ex)
			{
				Error(ex, "Cannot create needed directories to '{0}'.", filename);
				if (ex.MustBeRethrownImmediately())
				{
					throw;
				}
			}
		}
	}
